INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('str', 0, 'Strength measures bodily power, athletic training, and the extent to which you can exert raw physical force.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('str', 1, 'A Strength check can model any attempt to lift, push, pull, or break something, to force your body through a space, or to otherwise apply brute force to a situation. The Athletics skill reflects aptitude in certain kinds of Strength checks.');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('str', 0, 'athletics');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('str', 'STR', 'Strength', '/api/2014/ability-scores/str');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('dex', 0, 'Dexterity measures agility, reflexes, and balance.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('dex', 1, 'A Dexterity check can model any attempt to move nimbly, quickly, or quietly, or to keep from falling on tricky footing. The Acrobatics, Sleight of Hand, and Stealth skills reflect aptitude in certain kinds of Dexterity checks.');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('dex', 0, 'acrobatics');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('dex', 1, 'sleight-of-hand');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('dex', 2, 'stealth');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('dex', 'DEX', 'Dexterity', '/api/2014/ability-scores/dex');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('con', 0, 'Constitution measures health, stamina, and vital force.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('con', 1, 'Constitution checks are uncommon, and no skills apply to Constitution checks, because the endurance this ability represents is largely passive rather than involving a specific effort on the part of a character or monster.');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('con', 'CON', 'Constitution', '/api/2014/ability-scores/con');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('int', 0, 'Intelligence measures mental acuity, accuracy of recall, and the ability to reason.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('int', 1, 'An Intelligence check comes into play when you need to draw on logic, education, memory, or deductive reasoning. The Arcana, History, Investigation, Nature, and Religion skills reflect aptitude in certain kinds of Intelligence checks.');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('int', 0, 'arcana');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('int', 1, 'history');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('int', 2, 'investigation');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('int', 3, 'nature');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('int', 4, 'religion');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('int', 'INT', 'Intelligence', '/api/2014/ability-scores/int');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('wis', 0, 'Wisdom reflects how attuned you are to the world around you and represents perceptiveness and intuition.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('wis', 1, 'A Wisdom check might reflect an effort to read body language, understand someone''s feelings, notice things about the environment, or care for an injured person. The Animal Handling, Insight, Medicine, Perception, and Survival skills reflect aptitude in certain kinds of Wisdom checks.');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('wis', 0, 'animal-handling');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('wis', 1, 'insight');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('wis', 2, 'medicine');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('wis', 3, 'perception');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('wis', 4, 'survival');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('wis', 'WIS', 'Wisdom', '/api/2014/ability-scores/wis');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('cha', 0, 'Charisma measures your ability to interact effectively with others. It includes such factors as confidence and eloquence, and it can represent a charming or commanding personality.');
INSERT INTO ability_scores_desc (ability_scores_index, order_num, "value") VALUES ('cha', 1, 'A Charisma check might arise when you try to influence or entertain others, when you try to make an impression or tell a convincing lie, or when you are navigating a tricky social situation. The Deception, Intimidation, Performance, and Persuasion skills reflect aptitude in certain kinds of Charisma checks.');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('cha', 0, 'deception');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('cha', 1, 'intimidation');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('cha', 2, 'performance');
INSERT INTO ability_scores_skills (ability_scores_index, order_num, skills_index) VALUES ('cha', 3, 'persuasion');
INSERT INTO ability_scores ("index", name, full_name, url) VALUES ('cha', 'CHA', 'Charisma', '/api/2014/ability-scores/cha');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('lawful-good', 'Lawful Good', 'LG', 'Lawful good (LG) creatures can be counted on to do the right thing as expected by society. Gold dragons, paladins, and most dwarves are lawful good.', '/api/2014/alignments/lawful-good');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('neutral-good', 'Neutral Good', 'NG', 'Neutral good (NG) folk do the best they can to help others according to their needs. Many celestials, some cloud giants, and most gnomes are neutral good.', '/api/2014/alignments/neutral-good');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('chaotic-good', 'Chaotic Good', 'CG', 'Chaotic good (CG) creatures act as their conscience directs, with little regard for what others expect. Copper dragons, many elves, and unicorns are chaotic good.', '/api/2014/alignments/chaotic-good');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('lawful-neutral', 'Lawful Neutral', 'LN', 'Lawful neutral (LN) individuals act in accordance with law, tradition, or personal codes. Many monks and some wizards are lawful neutral.', '/api/2014/alignments/lawful-neutral');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('neutral', 'Neutral', 'N', 'Neutral (N) is the alignment of those who prefer to steer clear of moral questions and don''t take sides, doing what seems best at the time. Lizardfolk, most druids, and many humans are neutral.', '/api/2014/alignments/neutral');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('chaotic-neutral', 'Chaotic Neutral', 'CN', 'Chaotic neutral (CN) creatures follow their whims, holding their personal freedom above all else. Many barbarians and rogues, and some bards, are chaotic neutral.', '/api/2014/alignments/chaotic-neutral');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('lawful-evil', 'Lawful Evil', 'LE', 'Lawful evil (LE) creatures methodically take what they want, within the limits of a code of tradition, loyalty, or order. Devils, blue dragons, and hobgoblins are lawful evil.', '/api/2014/alignments/lawful-evil');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('neutral-evil', 'Neutral Evil', 'NE', 'Neutral evil (NE) is the alignment of those who do whatever they can get away with, without compassion or qualms. Many drow, some cloud giants, and goblins are neutral evil.', '/api/2014/alignments/neutral-evil');
INSERT INTO alignments ("index", name, abbreviation, "desc", url) VALUES ('chaotic-evil', 'Chaotic Evil', 'CE', 'Chaotic evil (CE) creatures act with arbitrary violence, spurred by their greed, hatred, or bloodlust. Demons, red dragons, and orcs are chaotic evil.', '/api/2014/alignments/chaotic-evil');
