INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('blinded', 0, '- A blinded creature can''t see and automatically fails any ability check that requires sight.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('blinded', 1, '- Attack rolls against the creature have advantage, and the creature''s attack rolls have disadvantage.');
INSERT INTO conditions ("index", name, url) VALUES ('blinded', 'Blinded', '/api/2014/conditions/blinded');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('charmed', 0, '- A charmed creature can''t attack the charmer or target the charmer with harmful abilities or magical effects.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('charmed', 1, '- The charmer has advantage on any ability check to interact socially with the creature.');
INSERT INTO conditions ("index", name, url) VALUES ('charmed', 'Charmed', '/api/2014/conditions/charmed');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('deafened', 0, '- A deafened creature can''t hear and automatically fails any ability check that requires hearing.');
INSERT INTO conditions ("index", name, url) VALUES ('deafened', 'Deafened', '/api/2014/conditions/deafened');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('frightened', 0, '- A frightened creature has disadvantage on ability checks and attack rolls while the source of its fear is within line of sight.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('frightened', 1, '- The creature can''t willingly move closer to the source of its fear.');
INSERT INTO conditions ("index", name, url) VALUES ('frightened', 'Frightened', '/api/2014/conditions/frightened');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('grappled', 0, '- A grappled creature''s speed becomes 0, and it can''t benefit from any bonus to its speed.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('grappled', 1, '- The condition ends if the grappler is incapacitated (see the condition).');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('grappled', 2, '- The condition also ends if an effect removes the grappled creature from the reach of the grappler or grappling effect, such as when a creature is hurled away by the thunderwave spell.');
INSERT INTO conditions ("index", name, url) VALUES ('grappled', 'Grappled', '/api/2014/conditions/grappled');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('incapacitated', 0, '- An incapacitated creature can''t take actions or reactions.');
INSERT INTO conditions ("index", name, url) VALUES ('incapacitated', 'Incapacitated', '/api/2014/conditions/incapacitated');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('invisible', 0, '- An invisible creature is impossible to see without the aid of magic or a special sense. For the purpose of hiding, the creature is heavily obscured. The creature''s location can be detected by any noise it makes or any tracks it leaves.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('invisible', 1, '- Attack rolls against the creature have disadvantage, and the creature''s attack rolls have advantage.');
INSERT INTO conditions ("index", name, url) VALUES ('invisible', 'Invisible', '/api/2014/conditions/invisible');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('paralyzed', 0, '- A paralyzed creature is incapacitated (see the condition) and can''t move or speak.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('paralyzed', 1, '- The creature automatically fails Strength and Dexterity saving throws.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('paralyzed', 2, '- Attack rolls against the creature have advantage.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('paralyzed', 3, '- Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.');
INSERT INTO conditions ("index", name, url) VALUES ('paralyzed', 'Paralyzed', '/api/2014/conditions/paralyzed');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 0, '- A petrified creature is transformed, along with any nonmagical object it is wearing or carrying, into a solid inanimate substance (usually stone). Its weight increases by a factor of ten, and it ceases aging.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 1, '- The creature is incapacitated (see the condition), can''t move or speak, and is unaware of its surroundings.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 2, '- Attack rolls against the creature have advantage.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 3, '- The creature automatically fails Strength and Dexterity saving throws.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 4, '- The creature has resistance to all damage.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('petrified', 5, '- The creature is immune to poison and disease, although a poison or disease already in its system is suspended, not neutralized.');
INSERT INTO conditions ("index", name, url) VALUES ('petrified', 'Petrified', '/api/2014/conditions/petrified');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('poisoned', 0, '- A poisoned creature has disadvantage on attack rolls and ability checks.');
INSERT INTO conditions ("index", name, url) VALUES ('poisoned', 'Poisoned', '/api/2014/conditions/poisoned');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('prone', 0, '- A prone creature''s only movement option is to crawl, unless it stands up and thereby ends the condition.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('prone', 1, '- The creature has disadvantage on attack rolls.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('prone', 2, '- An attack roll against the creature has advantage if the attacker is within 5 feet of the creature. Otherwise, the attack roll has disadvantage.');
INSERT INTO conditions ("index", name, url) VALUES ('prone', 'Prone', '/api/2014/conditions/prone');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('restrained', 0, '- A restrained creature''s speed becomes 0, and it can''t benefit from any bonus to its speed.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('restrained', 1, '- Attack rolls against the creature have advantage, and the creature''s attack rolls have disadvantage.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('restrained', 2, '- The creature has disadvantage on Dexterity saving throws.');
INSERT INTO conditions ("index", name, url) VALUES ('restrained', 'Restrained', '/api/2014/conditions/restrained');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('stunned', 0, '- A stunned creature is incapacitated (see the condition), can''t move, and can speak only falteringly.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('stunned', 1, '- The creature automatically fails Strength and Dexterity saving throws.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('stunned', 2, '- Attack rolls against the creature have advantage.');
INSERT INTO conditions ("index", name, url) VALUES ('stunned', 'Stunned', '/api/2014/conditions/stunned');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('unconscious', 0, '- An unconscious creature is incapacitated (see the condition), can''t move or speak, and is unaware of its surroundings.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('unconscious', 1, '- The creature drops whatever it''s holding and falls prone.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('unconscious', 2, '- The creature automatically fails Strength and Dexterity saving throws.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('unconscious', 3, '- Attack rolls against the creature have advantage.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('unconscious', 4, '- Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.');
INSERT INTO conditions ("index", name, url) VALUES ('unconscious', 'Unconscious', '/api/2014/conditions/unconscious');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 0, 'Some special abilities and environmental hazards, such as starvation and the long-term effects of freezing or scorching temperatures, can lead to a special condition called exhaustion. Exhaustion is measured in six levels. An effect can give a creature one or more levels of exhaustion, as specified in the effect''s description.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 1, '1 - Disadvantage on ability checks');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 2, '2 - Speed halved');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 3, '3 - Disadvantage on attack rolls and saving throws');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 4, '4 - Hit point maximum halved');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 5, '5 - Speed reduced to 0');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 6, '6 - Death');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 7, 'If an already exhausted creature suffers another effect that causes exhaustion, its current level of exhaustion increases by the amount specified in the effect''s description.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 8, 'A creature suffers the effect of its current level of exhaustion as well as all lower levels. For example, a creature suffering level 2 exhaustion has its speed halved and has disadvantage on ability checks.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 9, 'An effect that removes exhaustion reduces its level as specified in the effect''s description, with all exhaustion effects ending if a creature''s exhaustion level is reduced below 1.');
INSERT INTO conditions_desc (conditions_index, order_num, "value") VALUES ('exhaustion', 10, 'Finishing a long rest reduces a creature''s exhaustion level by 1, provided that the creature has also ingested some food and drink.');
INSERT INTO conditions ("index", name, url) VALUES ('exhaustion', 'Exhaustion', '/api/2014/conditions/exhaustion');
INSERT INTO damage_types_desc (damage_types_index, order_num, "value") VALUES ('acid', 0, 'The corrosive spray of a black dragon''s breath and the dissolving enzymes secreted by a black pudding deal acid damage.');
INSERT INTO damage_types ("index", name, url) VALUES ('acid', 'Acid', '/api/2014/damage-types/acid');
INSERT INTO damage_types_desc (damage_types_index, order_num, "value") VALUES ('bludgeoning', 0, 'Blunt force attacks, falling, constriction, and the like deal bludgeoning damage.');
INSERT INTO damage_types ("index", name, url) VALUES ('bludgeoning', 'Bludgeoning', '/api/2014/damage-types/bludgeoning');
INSERT INTO damage_types_desc (damage_types_index, order_num, "value") VALUES ('cold', 0, 'The infernal chill radiating from an ice devil''s spear and the frigid blast of a white dragon''s breath deal cold damage.');
INSERT INTO damage_types ("index", name, url) VALUES ('cold', 'Cold', '/api/2014/damage-types/cold');
INSERT INTO damage_types_desc (damage_types_index, order_num, "value") VALUES ('fire', 0, 'Red dragons breathe fire, and many spells conjure flames to deal fire damage.');
