INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('abacus', 'Abacus', 'adventuring-gear', 2, 'gp', 2, '/api/2014/equipment/abacus', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('acid-vial', 0, 'As an action, you can splash the contents of this vial onto a creature within 5 feet of you or throw the vial up to 20 feet, shattering it on impact. In either case, make a ranged attack against a creature or object, treating the acid as an improvised weapon.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('acid-vial', 1, 'On a hit, the target takes 2d6 acid damage.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('acid-vial', 'Acid (vial)', 'adventuring-gear', 25, 'gp', 1, '/api/2014/equipment/acid-vial', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('alchemists-fire-flask', 0, 'This sticky, adhesive fluid ignites when exposed to air.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('alchemists-fire-flask', 1, 'As an action, you can throw this flask up to 20 feet, shattering it on impact. Make a ranged attack against a creature or object, treating the alchemist''s fire as an improvised weapon.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('alchemists-fire-flask', 2, 'On a hit, the target takes 1d4 fire damage at the start of each of its turns. A creature can end this damage by using its action to make a DC 10 Dexterity check to extinguish the flames.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('alchemists-fire-flask', 'Alchemist''s fire (flask)', 'adventuring-gear', 50, 'gp', 1, '/api/2014/equipment/alchemists-fire-flask', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('alms-box', 0, 'A small box for alms, typically found in a priest''s pack.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('alms-box', 'Alms box', 'adventuring-gear', 0, 'cp', 0, '/api/2014/equipment/alms-box', 'standard-gear');
