INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('block-of-incense', 0, 'A block of incense, typically found in a priest''s pack.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('block-of-incense', 'Block of incense', 'adventuring-gear', 0, 'cp', 0, '/api/2014/equipment/block-of-incense', 'standard-gear');
