INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index, quantity) VALUES ('crossbow-bolt', 'Crossbow bolt', 'adventuring-gear', 1, 'gp', 1.5, '/api/2014/equipment/crossbow-bolt', 'ammunition', 20);
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index, quantity) VALUES ('sling-bullet', 'Sling bullet', 'adventuring-gear', 4, 'cp', 1.5, '/api/2014/equipment/sling-bullet', 'ammunition', 20);
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('amulet', 0, 'A holy symbol is a representation of a god or pantheon. It might be an amulet depicting a symbol representing a deity, the same symbol carefully engraved or inlaid as an emblem on a shield, or a tiny box holding a fragment of a sacred relic.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('amulet', 1, 'Appendix B lists the symbols commonly associated with many gods in the multiverse. A cleric or paladin can use a holy symbol as a spellcasting focus. To use the symbol in this way, the caster must hold it in hand, wear it visibly, or bear it on a shield.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('amulet', 'Amulet', 'adventuring-gear', 5, 'gp', 1, '/api/2014/equipment/amulet', 'holy-symbols');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('antitoxin-vial', 0, 'A creature that drinks this vial of liquid gains advantage on saving throws against poison for 1 hour. It confers no benefit to undead or constructs.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('antitoxin-vial', 'Antitoxin (vial)', 'adventuring-gear', 50, 'gp', 0, '/api/2014/equipment/antitoxin-vial', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('crystal', 0, 'An arcane focus is a special item--an orb, a crystal, a rod, a specially constructed staff, a wand-like length of wood, or some similar item--designed to channel the power of arcane spells. A sorcerer, warlock, or wizard can use such an item as a spellcasting focus.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('crystal', 'Crystal', 'adventuring-gear', 10, 'gp', 1, '/api/2014/equipment/crystal', 'arcane-foci');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('orb', 0, 'An arcane focus is a special item--an orb, a crystal, a rod, a specially constructed staff, a wand-like length of wood, or some similar item--designed to channel the power of arcane spells. A sorcerer, warlock, or wizard can use such an item as a spellcasting focus.');
