INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('wand', 'Wand', 'adventuring-gear', 10, 'gp', 1, '/api/2014/equipment/wand', 'arcane-foci');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('backpack', 'Backpack', 'adventuring-gear', 2, 'gp', 5, '/api/2014/equipment/backpack', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('ball-bearings-bag-of-1000', 0, 'As an action, you can spill these tiny metal balls from their pouch to cover a level, square area that is 10 feet on a side.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('ball-bearings-bag-of-1000', 1, 'A creature moving across the covered area must succeed on a DC 10 Dexterity saving throw or fall prone.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('ball-bearings-bag-of-1000', 2, 'A creature moving through the area at half speed doesn''t need to make the save.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, image, gear_category_index) VALUES ('ball-bearings-bag-of-1000', 'Ball bearings (bag of 1,000)', 'adventuring-gear', 1, 'gp', 2, '/api/2014/equipment/ball-bearings-bag-of-1000', '/api/images/equipment/ball-bearings-bag-of-1000.png', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('barrel', 'Barrel', 'adventuring-gear', 2, 'gp', 70, '/api/2014/equipment/barrel', 'standard-gear');
