INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('blanket', 'Blanket', 'adventuring-gear', 5, 'sp', 3, '/api/2014/equipment/blanket', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('block-and-tackle', 0, 'A set of pulleys with a cable threaded through them and a hook to attach to objects, a block and tackle allows you to hoist up to four times the weight you can normally lift.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('block-and-tackle', 'Block and tackle', 'adventuring-gear', 1, 'gp', 5, '/api/2014/equipment/block-and-tackle', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('book', 0, 'A book might contain poetry, historical accounts, information pertaining to a particular field of lore, diagrams and notes on gnomish contraptions, or just about anything else that can be represented using text or pictures. A book of spells is a spellbook (described later in this section).');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('book', 'Book', 'adventuring-gear', 25, 'gp', 5, '/api/2014/equipment/book', 'standard-gear');
