INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('caltrops', 0, 'As an action, you can spread a bag of caltrops to cover a square area that is 5 feet on a side.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('caltrops', 1, 'Any creature that enters the area must succeed on a DC 15 Dexterity saving throw or stop moving this turn and take 1 piercing damage.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('caltrops', 2, 'Taking this damage reduces the creature''s walking speed by 10 feet until the creature regains at least 1 hit point.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('caltrops', 3, 'A creature moving through the area at half speed doesn''t need to make the save.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('caltrops', 'Caltrops', 'adventuring-gear', 5, 'cp', 2, '/api/2014/equipment/caltrops', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('candle', 0, 'For 1 hour, a candle sheds bright light in a 5-foot radius and dim light for an additional 5 feet.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('candle', 'Candle', 'adventuring-gear', 1, 'cp', 0, '/api/2014/equipment/candle', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('case-crossbow-bolt', 0, 'This wooden case can hold up to twenty crossbow bolts.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('case-crossbow-bolt', 'Case, crossbow bolt', 'adventuring-gear', 1, 'gp', 1, '/api/2014/equipment/case-crossbow-bolt', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('case-map-or-scroll', 0, 'This cylindrical leather case can hold up to ten rolled-up sheets of paper or five rolled-up sheets of parchment.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('case-map-or-scroll', 'Case, map or scroll', 'adventuring-gear', 1, 'gp', 1, '/api/2014/equipment/case-map-or-scroll', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('chain-10-feet', 0, 'A chain has 10 hit points. It can be burst with a successful DC 20 Strength check.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('chain-10-feet', 'Chain (10 feet)', 'adventuring-gear', 5, 'gp', 10, '/api/2014/equipment/chain-10-feet', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('chalk-1-piece', 'Chalk (1 piece)', 'adventuring-gear', 1, 'cp', 0, '/api/2014/equipment/chalk-1-piece', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('chest', 'Chest', 'adventuring-gear', 5, 'gp', 25, '/api/2014/equipment/chest', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('clothes-common', 'Clothes, common', 'adventuring-gear', 5, 'sp', 3, '/api/2014/equipment/clothes-common', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('clothes-costume', 'Clothes, costume', 'adventuring-gear', 5, 'gp', 4, '/api/2014/equipment/clothes-costume', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('clothes-fine', 'Clothes, fine', 'adventuring-gear', 15, 'gp', 6, '/api/2014/equipment/clothes-fine', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('clothes-travelers', 'Clothes, traveler''s', 'adventuring-gear', 2, 'gp', 4, '/api/2014/equipment/clothes-travelers', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('component-pouch', 0, 'A component pouch is a small, watertight leather belt pouch that has compartments to hold all the material components and other special items you need to cast your spells, except for those components that have a specific cost (as indicated in a spell''s description).');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('component-pouch', 'Component pouch', 'adventuring-gear', 25, 'gp', 2, '/api/2014/equipment/component-pouch', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('crowbar', 0, 'Using a crowbar grants advantage to Strength checks where the crowbar''s leverage can be applied.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('crowbar', 'Crowbar', 'adventuring-gear', 2, 'gp', 5, '/api/2014/equipment/crowbar', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('sprig-of-mistletoe', 0, 'A druidic focus might be a sprig of mistletoe or holly, a wand or scepter made of yew or another special wood, a staff drawn whole out of a living tree, or a totem object incorporating feathers, fur, bones, and teeth from sacred animals. A druid can use such an object as a spellcasting focus.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('sprig-of-mistletoe', 'Sprig of mistletoe', 'adventuring-gear', 1, 'gp', 0, '/api/2014/equipment/sprig-of-mistletoe', 'druidic-foci');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('totem', 0, 'A druidic focus might be a sprig of mistletoe or holly, a wand or scepter made of yew or another special wood, a staff drawn whole out of a living tree, or a totem object incorporating feathers, fur, bones, and teeth from sacred animals. A druid can use such an object as a spellcasting focus.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('totem', 'Totem', 'adventuring-gear', 1, 'gp', 0, '/api/2014/equipment/totem', 'druidic-foci');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('wooden-staff', 0, 'A druidic focus might be a sprig of mistletoe or holly, a wand or scepter made of yew or another special wood, a staff drawn whole out of a living tree, or a totem object incorporating feathers, fur, bones, and teeth from sacred animals. A druid can use such an object as a spellcasting focus.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('wooden-staff', 'Wooden staff', 'adventuring-gear', 5, 'gp', 4, '/api/2014/equipment/wooden-staff', 'druidic-foci');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('yew-wand', 0, 'A druidic focus might be a sprig of mistletoe or holly, a wand or scepter made of yew or another special wood, a staff drawn whole out of a living tree, or a totem object incorporating feathers, fur, bones, and teeth from sacred animals. A druid can use such an object as a spellcasting focus.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('yew-wand', 'Yew wand', 'adventuring-gear', 10, 'gp', 1, '/api/2014/equipment/yew-wand', 'druidic-foci');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('emblem', 0, 'A holy symbol is a representation of a god or pantheon. It might be an amulet depicting a symbol representing a deity, the same symbol carefully engraved or inlaid as an emblem on a shield, or a tiny box holding a fragment of a sacred relic.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('emblem', 1, 'Appendix B lists the symbols commonly associated with many gods in the multiverse. A cleric or paladin can use a holy symbol as a spellcasting focus. To use the symbol in this way, the caster must hold it in hand, wear it visibly, or bear it on a shield.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('emblem', 'Emblem', 'adventuring-gear', 5, 'gp', 0, '/api/2014/equipment/emblem', 'holy-symbols');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('fishing-tackle', 0, 'This kit includes a wooden rod, silken line, corkwood bobbers, steel hooks, lead sinkers, velvet lures, and narrow netting.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('fishing-tackle', 'Fishing tackle', 'adventuring-gear', 1, 'gp', 4, '/api/2014/equipment/fishing-tackle', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('flask-or-tankard', 'Flask or tankard', 'adventuring-gear', 2, 'cp', 1, '/api/2014/equipment/flask-or-tankard', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('grappling-hook', 'Grappling hook', 'adventuring-gear', 2, 'gp', 4, '/api/2014/equipment/grappling-hook', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('hammer', 'Hammer', 'adventuring-gear', 1, 'gp', 3, '/api/2014/equipment/hammer', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('hammer-sledge', 'Hammer, sledge', 'adventuring-gear', 2, 'gp', 10, '/api/2014/equipment/hammer-sledge', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('holy-water-flask', 0, 'As an action, you can splash the contents of this flask onto a creature within 5 feet of you or throw it up to 20 feet, shattering it on impact. In either case, make a ranged attack against a target creature, treating the holy water as an improvised weapon.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('holy-water-flask', 1, 'If the target is a fiend or undead, it takes 2d6 radiant damage.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('holy-water-flask', 2, 'A cleric or paladin may create holy water by performing a special ritual.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('holy-water-flask', 3, 'The ritual takes 1 hour to perform, uses 25 gp worth of powdered silver, and requires the caster to expend a 1st-level spell slot.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('holy-water-flask', 'Holy water (flask)', 'adventuring-gear', 25, 'gp', 1, '/api/2014/equipment/holy-water-flask', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('hourglass', 'Hourglass', 'adventuring-gear', 25, 'gp', 1, '/api/2014/equipment/hourglass', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('hunting-trap', 0, 'When you use your action to set it, this trap forms a saw-toothed steel ring that snaps shut when a creature steps on a pressure plate in the center. The trap is affixed by a heavy chain to an immobile object, such as a tree or a spike driven into the ground.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('hunting-trap', 1, 'A creature that steps on the plate must succeed on a DC 13 Dexterity saving throw or take 1d4 piercing damage and stop moving. Thereafter, until the creature breaks free of the trap, its movement is limited by the length of the chain (typically 3 feet long).');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('hunting-trap', 2, 'A creature can use its action to make a DC 13 Strength check, freeing itself or another creature within its reach on a success. Each failed check deals 1 piercing damage to the trapped creature.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('hunting-trap', 'Hunting trap', 'adventuring-gear', 5, 'gp', 25, '/api/2014/equipment/hunting-trap', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('ink-1-ounce-bottle', 'Ink (1 ounce bottle)', 'adventuring-gear', 10, 'gp', 0, '/api/2014/equipment/ink-1-ounce-bottle', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('ink-pen', 'Ink pen', 'adventuring-gear', 2, 'cp', 0, '/api/2014/equipment/ink-pen', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('jug-or-pitcher', 'Jug or pitcher', 'adventuring-gear', 2, 'cp', 4, '/api/2014/equipment/jug-or-pitcher', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('climbers-kit', 0, 'A climber''s kit includes special pitons, boot tips, gloves, and a harness. You can use the climber''s kit as an action to anchor yourself; when you do, you can''t fall more than 25 feet from the point where you anchored yourself, and you can''t climb more than 25 feet away from that point without undoing the anchor.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('climbers-kit', 'Climber''s Kit', 'adventuring-gear', 25, 'gp', 12, '/api/2014/equipment/climbers-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('disguise-kit', 0, 'This pouch of cosmetics, hair dye, and small props lets you create disguises that change your physical appearance. Proficiency with this kit lets you add your proficiency bonus to any ability checks you make to create a visual disguise.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('disguise-kit', 'Disguise Kit', 'adventuring-gear', 25, 'gp', 3, '/api/2014/equipment/disguise-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('forgery-kit', 0, 'This small box contains a variety of papers and parchments, pens and inks, seals and sealing wax, gold and silver leaf, and other supplies necessary to create convincing forgeries of physical documents. Proficiency with this kit lets you add your proficiency bonus to any ability checks you make to create a physical forgery of a document.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('forgery-kit', 'Forgery Kit', 'adventuring-gear', 15, 'gp', 5, '/api/2014/equipment/forgery-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('herbalism-kit', 0, 'This kit contains a variety of instruments such as clippers, mortar and pestle, and pouches and vials used by herbalists to create remedies and potions. Proficiency with this kit lets you add your proficiency bonus to any ability checks you make to identify or apply herbs. Also, proficiency with this kit is required to create antitoxin and potions of healing.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('herbalism-kit', 'Herbalism Kit', 'adventuring-gear', 5, 'gp', 3, '/api/2014/equipment/herbalism-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('healers-kit', 0, 'This kit is a leather pouch containing bandages, salves, and splints. The kit has ten uses. As an action, you can expend one use of the kit to stabilize a creature that has 0 hit points, without needing to make a Wisdom (Medicine) check.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('healers-kit', 'Healer''s Kit', 'adventuring-gear', 5, 'gp', 3, '/api/2014/equipment/healers-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('mess-kit', 0, 'This tin box contains a cup and simple cutlery. The box clamps together, and one side can be used as a cooking pan and the other as a plate or shallow bowl.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('mess-kit', 'Mess Kit', 'adventuring-gear', 2, 'sp', 1, '/api/2014/equipment/mess-kit', 'kits');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('poisoners-kit', 0, 'A poisoner''s kit includes the vials, chemicals, and other equipment necessary for the creation of poisons. Proficiency with this kit lets you add your proficiency bonus to any ability checks you make to craft or use poisons.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('poisoners-kit', 'Poisoner''s Kit', 'adventuring-gear', 50, 'gp', 2, '/api/2014/equipment/poisoners-kit', 'kits');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('ladder-10-foot', 'Ladder (10-foot)', 'adventuring-gear', 1, 'sp', 25, '/api/2014/equipment/ladder-10-foot', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('lamp', 0, 'A lamp casts bright light in a 15-foot radius and dim light for an additional 30 feet. Once lit, it burns for 6 hours on a flask (1 pint) of oil.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('lamp', 'Lamp', 'adventuring-gear', 5, 'sp', 1, '/api/2014/equipment/lamp', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('lantern-bullseye', 0, 'A bullseye lantern casts bright light in a 60-foot cone and dim light for an additional 60 feet. Once lit, it burns for 6 hours on a flask (1 pint) of oil.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('lantern-bullseye', 'Lantern, bullseye', 'adventuring-gear', 10, 'gp', 2, '/api/2014/equipment/lantern-bullseye', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('lantern-hooded', 0, 'A hooded lantern casts bright light in a 30-foot radius and dim light for an additional 30 feet. Once lit, it burns for 6 hours on a flask (1 pint) of oil. As an action, you can lower the hood, reducing the light to dim light in a 5-foot radius.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('lantern-hooded', 'Lantern, hooded', 'adventuring-gear', 5, 'gp', 2, '/api/2014/equipment/lantern-hooded', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('little-bag-of-sand', 0, 'A small bag of sand, typically found in a scholar''s pack.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('little-bag-of-sand', 'Little bag of sand', 'adventuring-gear', 0, 'cp', 0, '/api/2014/equipment/little-bag-of-sand', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('lock', 0, 'A key is provided with the lock. Without the key, a creature proficient with thieves'' tools can pick this lock with a successful DC 15 Dexterity check. Your GM may decide that better locks are available for higher prices.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('lock', 'Lock', 'adventuring-gear', 10, 'gp', 1, '/api/2014/equipment/lock', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('magnifying-glass', 0, 'This lens allows a closer look at small objects. It is also useful as a substitute for flint and steel when starting fires. Lighting a fire with a magnifying glass requires light as bright as sunlight to focus, tinder to ignite, and about 5 minutes for the fire to ignite.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('magnifying-glass', 1, 'A magnifying glass grants advantage on any ability check made to appraise or inspect an item that is small or highly detailed.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('magnifying-glass', 'Magnifying glass', 'adventuring-gear', 100, 'gp', 0, '/api/2014/equipment/magnifying-glass', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('manacles', 0, 'These metal restraints can bind a Small or Medium creature. Escaping the manacles requires a successful DC 20 Dexterity check. Breaking them requires a successful DC 20 Strength check.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('manacles', 1, 'Each set of manacles comes with one key. Without the key, a creature proficient with thieves'' tools can pick the manacles'' lock with a successful DC 15 Dexterity check. Manacles have 15 hit points.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('manacles', 'Manacles', 'adventuring-gear', 2, 'gp', 6, '/api/2014/equipment/manacles', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('mirror-steel', 'Mirror, steel', 'adventuring-gear', 5, 'gp', 0.5, '/api/2014/equipment/mirror-steel', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('oil-flask', 0, 'Oil usually comes in a clay flask that holds 1 pint.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('oil-flask', 1, 'As an action, you can splash the oil in this flask onto a creature within 5 feet of you or throw it up to 20 feet, shattering it on impact. Make a ranged attack against a target creature or object, treating the oil as an improvised weapon.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('oil-flask', 2, 'On a hit, the target is covered in oil. If the target takes any fire damage before the oil dries (after 1 minute), the target takes an additional 5 fire damage from the burning oil.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('oil-flask', 3, 'You can also pour a flask of oil on the ground to cover a 5-foot-square area, provided that the surface is level.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('oil-flask', 4, 'If lit, the oil burns for 2 rounds and deals 5 fire damage to any creature that enters the area or ends its turn in the area. A creature can take this damage only once per turn.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('oil-flask', 'Oil (flask)', 'adventuring-gear', 1, 'sp', 1, '/api/2014/equipment/oil-flask', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('paper-one-sheet', 'Paper (one sheet)', 'adventuring-gear', 2, 'sp', 0, '/api/2014/equipment/paper-one-sheet', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('parchment-one-sheet', 'Parchment (one sheet)', 'adventuring-gear', 1, 'sp', 0, '/api/2014/equipment/parchment-one-sheet', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('perfume-vial', 'Perfume (vial)', 'adventuring-gear', 5, 'gp', 0, '/api/2014/equipment/perfume-vial', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('pick-miners', 'Pick, miner''s', 'adventuring-gear', 2, 'gp', 10, '/api/2014/equipment/pick-miners', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('piton', 'Piton', 'adventuring-gear', 5, 'cp', 0.25, '/api/2014/equipment/piton', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('poison-basic-vial', 0, 'You can use the poison in this vial to coat one slashing or piercing weapon or up to three pieces of ammunition. Applying the poison takes an action. A creature hit by the poisoned weapon or ammunition must make a DC 10 Constitution saving throw or take 1d4 poison damage. Once applied, the poison retains potency for 1 minute before drying.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('poison-basic-vial', 'Poison, basic (vial)', 'adventuring-gear', 100, 'gp', 0, '/api/2014/equipment/poison-basic-vial', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('pole-10-foot', 'Pole (10-foot)', 'adventuring-gear', 5, 'cp', 7, '/api/2014/equipment/pole-10-foot', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('pot-iron', 'Pot, iron', 'adventuring-gear', 2, 'gp', 10, '/api/2014/equipment/pot-iron', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('pouch', 0, 'A cloth or leather pouch can hold up to 20 sling bullets or 50 blowgun needles, among other things. A compartmentalized pouch for holding spell components is called a component pouch (described earlier in this section).');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('pouch', 'Pouch', 'adventuring-gear', 5, 'sp', 1, '/api/2014/equipment/pouch', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('quiver', 0, 'A quiver can hold up to 20 arrows.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('quiver', 'Quiver', 'adventuring-gear', 1, 'gp', 1, '/api/2014/equipment/quiver', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('ram-portable', 0, 'You can use a portable ram to break down doors. When doing so, you gain a +4 bonus on the Strength check. One other character can help you use the ram, giving you advantage on this check.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('ram-portable', 'Ram, portable', 'adventuring-gear', 4, 'gp', 35, '/api/2014/equipment/ram-portable', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('rations-1-day', 0, 'Rations consist of dry foods suitable for extended travel, including jerky, dried fruit, hardtack, and nuts.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('rations-1-day', 'Rations (1 day)', 'adventuring-gear', 5, 'sp', 2, '/api/2014/equipment/rations-1-day', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('reliquary', 0, 'A holy symbol is a representation of a god or pantheon. It might be an amulet depicting a symbol representing a deity, the same symbol carefully engraved or inlaid as an emblem on a shield, or a tiny box holding a fragment of a sacred relic.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('reliquary', 1, 'Appendix B lists the symbols commonly associated with many gods in the multiverse. A cleric or paladin can use a holy symbol as a spellcasting focus. To use the symbol in this way, the caster must hold it in hand, wear it visibly, or bear it on a shield.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('reliquary', 'Reliquary', 'adventuring-gear', 5, 'gp', 2, '/api/2014/equipment/reliquary', 'holy-symbols');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('robes', 'Robes', 'adventuring-gear', 1, 'gp', 4, '/api/2014/equipment/robes', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('rope-hempen-50-feet', 0, 'Rope, whether made of hemp or silk, has 2 hit points and can be burst with a DC 17 Strength check.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('rope-hempen-50-feet', 'Rope, hempen (50 feet)', 'adventuring-gear', 1, 'gp', 10, '/api/2014/equipment/rope-hempen-50-feet', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('rope-silk-50-feet', 0, 'Rope, whether made of hemp or silk, has 2 hit points and can be burst with a DC 17 Strength check.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('rope-silk-50-feet', 'Rope, silk (50 feet)', 'adventuring-gear', 10, 'gp', 5, '/api/2014/equipment/rope-silk-50-feet', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('sack', 'Sack', 'adventuring-gear', 1, 'cp', 0.5, '/api/2014/equipment/sack', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('scale-merchants', 0, 'A scale includes a small balance, pans, and a suitable assortment of weights up to 2 pounds. With it, you can measure the exact weight of small objects, such as raw precious metals or trade goods, to help determine their worth.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('scale-merchants', 'Scale, merchant''s', 'adventuring-gear', 5, 'gp', 3, '/api/2014/equipment/scale-merchants', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('sealing-wax', 'Sealing wax', 'adventuring-gear', 5, 'sp', 0, '/api/2014/equipment/sealing-wax', 'standard-gear');
