INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('signet-ring', 'Signet ring', 'adventuring-gear', 5, 'gp', 0, '/api/2014/equipment/signet-ring', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('small-knife', 0, 'A small knife, typically found in a scholar''s pack.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('small-knife', 'Small knife', 'adventuring-gear', 0, 'cp', 0, '/api/2014/equipment/small-knife', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('soap', 'Soap', 'adventuring-gear', 2, 'cp', 0, '/api/2014/equipment/soap', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('spellbook', 0, 'Essential for wizards, a spellbook is a leather-bound tome with 100 blank vellum pages suitable for recording spells.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('spellbook', 'Spellbook', 'adventuring-gear', 50, 'gp', 3, '/api/2014/equipment/spellbook', 'standard-gear');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('spike-iron', 'Spike, iron', 'adventuring-gear', 1, 'sp', 5, '/api/2014/equipment/spike-iron', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('spyglass', 0, 'Objects viewed through a spyglass are magnified to twice their size.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('spyglass', 'Spyglass', 'adventuring-gear', 1000, 'gp', 1, '/api/2014/equipment/spyglass', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('string-10-feet', 0, 'A 10-foot length of string, typically found in a burglar''s pack.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('string-10-feet', 'String (10 feet)', 'adventuring-gear', 0, 'cp', 0, '/api/2014/equipment/string-10-feet', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('tent-two-person', 0, 'A simple and portable canvas shelter, a tent sleeps two.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('tent-two-person', 'Tent, two-person', 'adventuring-gear', 2, 'gp', 20, '/api/2014/equipment/tent-two-person', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('tinderbox', 0, 'This small container holds flint, fire steel, and tinder (usually dry cloth soaked in light oil) used to kindle a fire. Using it to light a torch--or anything else with abundant, exposed fuel--takes an action.');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('tinderbox', 1, 'Lighting any other fire takes 1 minute.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('tinderbox', 'Tinderbox', 'adventuring-gear', 5, 'sp', 1, '/api/2014/equipment/tinderbox', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('torch', 0, 'A torch burns for 1 hour, providing bright light in a 20-foot radius and dim light for an additional 20 feet. If you make a melee attack with a burning torch and hit, it deals 1 fire damage.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, gear_category_index) VALUES ('torch', 'Torch', 'adventuring-gear', 1, 'cp', 1, '/api/2014/equipment/torch', 'standard-gear');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('vestments', 0, 'Religious clothing, typically found in a priest''s pack.');
