INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('dice-set', 0, 'This item encompasses a wide range of game pieces, including dice and decks of cards (for games such as Three-Dragon Ante). A few common examples appear on the Tools table, but other kinds of gaming sets exist. If you are proficient with a gaming set, you can add your proficiency bonus to ability checks you make to play a game with that set. Each type of gaming set requires a separate proficiency.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, tool_category) VALUES ('dice-set', 'Dice Set', 'tools', 1, 'sp', 0, '/api/2014/equipment/dice-set', 'Gaming Sets');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('playing-card-set', 0, 'This item encompasses a wide range of game pieces, including dice and decks of cards (for games such as Three-Dragon Ante). A few common examples appear on the Tools table, but other kinds of gaming sets exist. If you are proficient with a gaming set, you can add your proficiency bonus to ability checks you make to play a game with that set. Each type of gaming set requires a separate proficiency.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, image, tool_category) VALUES ('playing-card-set', 'Playing Card Set', 'tools', 5, 'sp', 0, '/api/2014/equipment/playing-card-set', '/api/images/equipment/playing-card-set.png', 'Gaming Sets');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('bagpipes', 0, 'Several of the most common types of musical instruments are shown on the table as examples. If you have proficiency with a given musical instrument, you can add your proficiency bonus to any ability checks you make to play music with the instrument. A bard can use a musical instrument as a spellcasting focus. Each type of musical instrument requires a separate proficiency.');
