INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('navigators-tools', 0, 'This set of instruments is used for navigation at sea. Proficiency with navigator''s tools lets you chart a ship''s course and follow navigation charts. In addition, these tools allow you to add your proficiency bonus to any ability check you make to avoid getting lost at sea.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, tool_category) VALUES ('navigators-tools', 'Navigator''s Tools', 'tools', 25, 'gp', 2, '/api/2014/equipment/navigators-tools', 'Other Tools');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('thieves-tools', 0, 'This set of tools includes a small file, a set of lock picks, a small mirror mounted on a metal handle, a set of narrow-bladed scissors, and a pair of pliers. Proficiency with these tools lets you add your proficiency bonus to any ability checks you make to disarm traps or open locks.');
