INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('barding-padded', 0, 'Barding is armor designed to protect an animal''s head, neck, chest, and body. Any type of armor shown on the Armor table can be purchased as barding. The cost is four times the equivalent armor made for humanoids, and it weighs twice as much.');
