INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, weight, url, vehicle_category) VALUES ('wagon', 'Wagon', 'mounts-and-vehicles', 35, 'gp', 400, '/api/2014/equipment/wagon', 'Tack, Harness, and Drawn Vehicles');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('galley', 'Galley', 'mounts-and-vehicles', 30000, 'gp', '/api/2014/equipment/galley', 'Waterborne Vehicles', 4, 'mph');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('keelboat', 0, 'Keelboats and rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A rowboat weighs 100 pounds, in case adventurers carry it over land.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('keelboat', 'Keelboat', 'mounts-and-vehicles', 3000, 'gp', '/api/2014/equipment/keelboat', 'Waterborne Vehicles', 1, 'mph');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('longship', 'Longship', 'mounts-and-vehicles', 10000, 'gp', '/api/2014/equipment/longship', 'Waterborne Vehicles', 3, 'mph');
INSERT INTO equipment_desc (equipment_index, order_num, "value") VALUES ('rowboat', 0, 'Keelboats and rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A rowboat weighs 100 pounds, in case adventurers carry it over land.');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('rowboat', 'Rowboat', 'mounts-and-vehicles', 50, 'gp', '/api/2014/equipment/rowboat', 'Waterborne Vehicles', 1.5, 'mph');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('sailing-ship', 'Sailing ship', 'mounts-and-vehicles', 10000, 'gp', '/api/2014/equipment/sailing-ship', 'Waterborne Vehicles', 2, 'mph');
INSERT INTO equipment ("index", name, equipment_category_index, cost_quantity, cost_unit, url, vehicle_category, speed_quantity, speed_unit) VALUES ('warship', 'Warship', 'mounts-and-vehicles', 25000, 'gp', '/api/2014/equipment/warship', 'Waterborne Vehicles', 2.5, 'mph');
INSERT INTO feats_prerequisites (feats_index, order_num, ability_score_index, minimum_score) VALUES ('grappler', 0, 'str', 13);
INSERT INTO feats_desc (feats_index, order_num, "value") VALUES ('grappler', 0, 'You’ve developed the Skills necessary to hold your own in close--quarters Grappling. You gain the following benefits:');
INSERT INTO feats_desc (feats_index, order_num, "value") VALUES ('grappler', 1, '- You have advantage on Attack Rolls against a creature you are Grappling.');
INSERT INTO feats_desc (feats_index, order_num, "value") VALUES ('grappler', 2, '- You can use your action to try to pin a creature Grappled by you. To do so, make another grapple check. If you succeed, you and the creature are both Restrained until the grapple ends.');
INSERT INTO feats ("index", name, url) VALUES ('grappler', 'Grappler', '/api/2014/feats/grappler');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 0, 'In battle, you fight with primal ferocity. On your turn, you can enter a rage as a bonus action. While raging, you gain the following benefits if you aren''t wearing heavy armor:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 1, '- You have advantage on Strength checks and Strength saving throws.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 2, '- When you make a melee weapon Attack using Strength, you gain a +2 bonus to the damage roll. This bonus increases as you level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 3, '- You have Resistance to bludgeoning, piercing, and slashing damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 4, 'If you are able to cast Spells, you can''t cast them or concentrate on them while raging.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 5, 'Your rage lasts for 1 minute. It ends early if you are knocked Unconscious or if Your Turn ends and you haven''t attacked a hostile creature since your last turn or taken damage since then. You can also end your rage on Your Turn as a Bonus Action.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rage', 6, 'Once you have raged the maximum number of times for your barbarian level, you must finish a Long Rest before you can rage again. You may rage 2 times at 1st level, 3 at 3rd, 4 at 6th, 5 at 12th, and 6 at 17th.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rage', 'barbarian', 'Rage', 1, '/api/2014/features/rage');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-unarmored-defense', 0, 'While you are not wearing any armor, your Armor Class equals 10 + your Dexterity modifier + your Constitution modifier. You can use a shield and still gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-unarmored-defense', 'barbarian', 'Unarmored Defense', 1, '/api/2014/features/barbarian-unarmored-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('reckless-attack', 0, 'Starting at 2nd level, you can throw aside all concern for defense to attack with fierce desperation. When you make your first attack on your turn, you can decide to attack recklessly. Doing so gives you advantage on melee weapon attack rolls using Strength during this turn, but attack rolls against you have advantage until your next turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('reckless-attack', 'barbarian', 'Reckless Attack', 2, '/api/2014/features/reckless-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('danger-sense', 0, 'At 2nd level, you gain an uncanny sense of when things nearby aren''t as they should be, giving you an edge when you dodge away from danger. You have advantage on Dexterity saving throws against effects that you can see, such as traps and spells. To gain this benefit, you can''t be blinded, deafened, or incapacitated.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('danger-sense', 'barbarian', 'Danger Sense', 2, '/api/2014/features/danger-sense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primal-path', 0, 'At 3rd level, you choose a path that shapes the nature of your rage. Choose the Path of the Berserker or the Path of the Totem Warrior, both detailed at the end of the class description. Your choice grants you features at 3rd level and again at 6th, 10th, and 14th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primal-path', 'barbarian', 'Primal Path', 3, '/api/2014/features/primal-path');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('frenzy', 0, 'Starting when you choose this path at 3rd level, you can go into a frenzy when you rage. If you do so, for the duration of your rage you can make a single melee weapon attack as a bonus action on each of your turns after this one. When your rage ends, you suffer one level of exhaustion (as described in appendix A).');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('frenzy', 'barbarian', 'Frenzy', 3, '/api/2014/features/frenzy', 'berserker');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-ability-score-improvement-1', 'barbarian', 'Ability Score Improvement', 4, '/api/2014/features/barbarian-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-extra-attack', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-extra-attack', 'barbarian', 'Extra Attack', 5, '/api/2014/features/barbarian-extra-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fast-movement', 0, 'Starting at 5th level, your speed increases by 10 feet while you aren''t wearing heavy armor.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fast-movement', 'barbarian', 'Fast Movement', 5, '/api/2014/features/fast-movement');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mindless-rage', 0, 'Beginning at 6th level, you can''t be charmed or frightened while raging. If you are charmed or frightened when you enter your rage, the effect is suspended for the duration of the rage.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('mindless-rage', 'barbarian', 'Mindless Rage', 6, '/api/2014/features/mindless-rage', 'berserker');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primal-path-improvement-1', 0, 'At 3rd level, you choose a path that shapes the nature of your rage. Choose the Path of the Berserker or the Path of the Totem Warrior, both detailed at the end of the class description. Your choice grants you features at 3rd level and again at 6th, 10th, and 14th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primal-path-improvement-1', 'barbarian', 'Path feature', 6, '/api/2014/features/primal-path-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('feral-instinct', 0, 'By 7th level, your instincts are so honed that you have advantage on initiative rolls.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('feral-instinct', 1, 'Additionally, if you are surprised at the beginning of combat and aren''t incapacitated, you can act normally on your first turn, but only if you enter your rage before doing anything else on that turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('feral-instinct', 'barbarian', 'Feral Instinct', 7, '/api/2014/features/feral-instinct');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-ability-score-improvement-2', 'barbarian', 'Ability Score Improvement', 8, '/api/2014/features/barbarian-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('brutal-critical-1-die', 0, 'Beginning at 9th level, you can roll one additional weapon damage die when determining the extra damage for a critical hit with a melee attack. This increases to two additional dice at 13th level and three additional dice at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('brutal-critical-1-die', 'barbarian', 'Brutal Critical (1 die)', 9, '/api/2014/features/brutal-critical-1-die');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('intimidating-presence', 0, 'Beginning at 10th level, you can use your action to frighten someone with your menacing presence. When you do so, choose one creature that you can see within 30 feet of you. If the creature can see or hear you, it must succeed on a Wisdom saving throw (DC equal to 8 + your proficiency bonus + your Charisma modifier) or be frightened of you until the end of your next turn. On subsequent turns, you can use your action to extend the duration of this effect on the frightened creature until the end of your next turn. This effect ends if the creature ends its turn out of line of sight or more than 60 feet away from you.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('intimidating-presence', 1, ' If the creature succeeds on its saving throw, you can''t use this feature on that creature again for 24 hours.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('intimidating-presence', 'barbarian', 'Intimidating Presence', 10, '/api/2014/features/intimidating-presence', 'berserker');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primal-path-improvement-2', 0, 'At 3rd level, you choose a path that shapes the nature of your rage. Choose the Path of the Berserker or the Path of the Totem Warrior, both detailed at the end of the class description. Your choice grants you features at 3rd level and again at 6th, 10th, and 14th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primal-path-improvement-2', 'barbarian', 'Path feature', 10, '/api/2014/features/primal-path-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('relentless-rage', 0, 'Starting at 11th level, your rage can keep you fighting despite grievous wounds. If you drop to 0 hit points while you''re raging and don''t die outright, you can make a DC 10 Constitution saving throw. If you succeed, you drop to 1 hit point instead.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('relentless-rage', 1, 'Each time you use this feature after the first, the DC increases by 5. When you finish a short or long rest, the DC resets to 10.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('relentless-rage', 'barbarian', 'Relentless Rage', 11, '/api/2014/features/relentless-rage');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-ability-score-improvement-3', 'barbarian', 'Ability Score Improvement', 12, '/api/2014/features/barbarian-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('brutal-critical-2-dice', 0, 'Beginning at 9th level, you can roll one additional weapon damage die when determining the extra damage for a critical hit with a melee attack. This increases to two additional dice at 13th level and three additional dice at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('brutal-critical-2-dice', 'barbarian', 'Brutal Critical (2 dice)', 13, '/api/2014/features/brutal-critical-2-dice');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('retaliation', 0, 'Starting at 14th level, when you take damage from a creature that is within 5 feet of you, you can use your reaction to make a melee weapon Attack against that creature.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('retaliation', 'barbarian', 'Retaliation', 14, '/api/2014/features/retaliation', 'berserker');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primal-path-improvement-3', 0, 'At 3rd level, you choose a path that shapes the nature of your rage. Choose the Path of the Berserker or the Path of the Totem Warrior, both detailed at the end of the class description. Your choice grants you features at 3rd level and again at 6th, 10th, and 14th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primal-path-improvement-3', 'barbarian', 'Path feature', 14, '/api/2014/features/primal-path-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('persistent-rage', 0, 'Beginning at 15th level, your rage is so fierce that it ends early only if you fall unconscious or if you choose to end it.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('persistent-rage', 'barbarian', 'Persistent Rage', 15, '/api/2014/features/persistent-rage');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-ability-score-improvement-4', 'barbarian', 'Ability Score Improvement', 16, '/api/2014/features/barbarian-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('brutal-critical-3-dice', 0, 'Beginning at 9th level, you can roll one additional weapon damage die when determining the extra damage for a critical hit with a melee attack. This increases to two additional dice at 13th level and three additional dice at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('brutal-critical-3-dice', 'barbarian', 'Brutal Critical (3 dice)', 17, '/api/2014/features/brutal-critical-3-dice');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('indomitable-might', 0, 'Beginning at 18th level, if your total for a Strength check is less than your Strength score, you can use that score in place of the total.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('indomitable-might', 'barbarian', 'Indomitable Might', 18, '/api/2014/features/indomitable-might');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('barbarian-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('barbarian-ability-score-improvement-5', 'barbarian', 'Ability Score Improvement', 19, '/api/2014/features/barbarian-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primal-champion', 0, 'At 20th level, you embody the power of the wilds. Your Strength and Constitution scores increase by 4. Your maximum for those scores is now 24.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primal-champion', 'barbarian', 'Primal Champion', 20, '/api/2014/features/primal-champion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-bard', 0, 'You have learned to untangle and reshape the fabric of reality in harmony with your wishes and music. Your spells are part of your vast repertoire, magic that you can tune to different situations.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-bard', 'bard', 'Spellcasting: Bard', 1, '/api/2014/features/spellcasting-bard', '/api/2014/classes/bard/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d6', 0, 'You can inspire others through stirring words or music. To do so, you use a bonus action on your turn to choose one creature other than yourself within 60 feet of you who can hear you. That creature gains one Bardic Inspiration die, a d6. Once within the next 10 minutes, the creature can roll the die and add the number rolled to one ability check, attack roll, or saving throw it makes. The creature can wait until after it rolls the d20 before deciding to use the Bardic Inspiration die, but must decide before the GM says whether the roll succeeds or fails. Once the Bardic Inspiration die is rolled, it is lost. A creature can have only one Bardic Inspiration die at a time.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d6', 1, 'You can use this feature a number of times equal to your Charisma modifier (a minimum of once). You regain any expended uses when you finish a long rest. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d6', 2, 'Your Bardic Inspiration die changes when you reach certain levels in this class. The die becomes a d8 at 5th level, a d10 at 10th level, and a d12 at 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bardic-inspiration-d6', 'bard', 'Bardic Inspiration (d6)', 1, '/api/2014/features/bardic-inspiration-d6');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('jack-of-all-trades', 0, 'Starting at 2nd level, you can add half your proficiency bonus, rounded down, to any ability check you make that doesn''t already include your proficiency bonus.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('jack-of-all-trades', 'bard', 'Jack of All Trades', 2, '/api/2014/features/jack-of-all-trades');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('song-of-rest-d6', 0, 'Beginning at 2nd level, you can use soothing music or oration to help revitalize your wounded allies during a short rest. If you or any friendly creatures who can hear your performance regain hit points at the end of the short rest by spending one or more Hit Dice, each of those creatures regains an extra 1d6 hit points. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('song-of-rest-d6', 1, 'The extra hit points increase when you reach certain levels in this class: to 1d8 at 9th level, to 1d10 at 13th level, and to 1d12 at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('song-of-rest-d6', 'bard', 'Song of Rest (d6)', 2, '/api/2014/features/song-of-rest-d6');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-college', 0, 'At 3rd level, you delve into the advanced techniques of a bard college of your choice, such as the College of Lore. Your choice grants you features at 3rd level and again at 6th and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-college', 'bard', 'Bard College', 3, '/api/2014/features/bard-college');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bonus-proficiencies', 0, 'When you join the College of Lore at 3rd level, you gain proficiency with three skills of your choice.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('bonus-proficiencies', 'bard', 'Bonus Proficiencies', 3, '/api/2014/features/bonus-proficiencies', 'lore');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cutting-words', 0, 'Also at 3rd level, you learn how to use your wit to distract, confuse, and otherwise sap the confidence and competence of others.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cutting-words', 1, 'When a creature that you can see within 60 feet of you makes an attack roll, an ability check, or a damage roll, you can use your reaction to expend one of your uses of Bardic Inspiration, rolling a Bardic Inspiration die and subtracting the number rolled from the creature''s roll.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cutting-words', 2, 'You can choose to use this feature after the creature makes its roll, but before the GM determines whether the attack roll or ability check succeeds or fails, or before the creature deals its damage. The creature is immune if it can''t hear you or if it''s immune to being charmed.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('cutting-words', 'bard', 'Cutting Words', 3, '/api/2014/features/cutting-words', 'lore');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-expertise-1', 0, 'At 3rd level, choose two of your skill proficiencies. Your proficiency bonus is doubled for any ability check you make that uses either of the chosen proficiencies. At 10th level, you can choose another two skill proficiencies to gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_expertise_options_choose, feature_specific_expertise_options_type, feature_specific_expertise_options_from_option_set_type) VALUES ('bard-expertise-1', 'bard', 'Expertise', 3, '/api/2014/features/bard-expertise-1', 2, 'proficiency', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-ability-score-improvement-1', 'bard', 'Ability Score Improvement', 4, '/api/2014/features/bard-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d8', 0, 'You can inspire others through stirring words or music. To do so, you use a bonus action on your turn to choose one creature other than yourself within 60 feet of you who can hear you. That creature gains one Bardic Inspiration die, a d6. Once within the next 10 minutes, the creature can roll the die and add the number rolled to one ability check, attack roll, or saving throw it makes. The creature can wait until after it rolls the d20 before deciding to use the Bardic Inspiration die, but must decide before the GM says whether the roll succeeds or fails. Once the Bardic Inspiration die is rolled, it is lost. A creature can have only one Bardic Inspiration die at a time.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d8', 1, 'You can use this feature a number of times equal to your Charisma modifier (a minimum of once). You regain any expended uses when you finish a long rest. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d8', 2, 'Your Bardic Inspiration die changes when you reach certain levels in this class. The die becomes a d8 at 5th level, a d10 at 10th level, and a d12 at 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bardic-inspiration-d8', 'bard', 'Bardic Inspiration (d8)', 5, '/api/2014/features/bardic-inspiration-d8');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('font-of-inspiration', 0, 'Beginning when you reach 5th level, you regain all of your expended uses of Bardic Inspiration when you finish a short or long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('font-of-inspiration', 'bard', 'Font of Inspiration', 5, '/api/2014/features/font-of-inspiration');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('countercharm', 0, 'At 6th level, you gain the ability to use musical notes or words of power to disrupt mind-influencing effects. As an action, you can start a performance that lasts until the end of your next turn. During that time, you and any friendly creatures within 30 feet of you have advantage on saving throws against being frightened or charmed. A creature must be able to hear you to gain this benefit. The performance ends early if you are incapacitated or silenced or if you voluntarily end it (no action required).');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('countercharm', 'bard', 'Countercharm', 6, '/api/2014/features/countercharm');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-college-improvement-1', 0, 'At 3rd level, you delve into the advanced techniques of a bard college of your choice, such as the College of Lore. Your choice grants you features at 3rd level and again at 6th and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-college-improvement-1', 'bard', 'Bard College feature', 6, '/api/2014/features/bard-college-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('additional-magical-secrets', 0, 'At 6th level, you learn two spells of your choice from any class. A spell you choose must be of a level you can cast, as shown on the Bard table, or a cantrip. The chosen spells count as bard spells for you but don''t count against the number of bard spells you know.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('additional-magical-secrets', 'bard', 'Additional Magical Secrets', 6, '/api/2014/features/additional-magical-secrets', 'lore');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-ability-score-improvement-2', 'bard', 'Ability Score Improvement', 8, '/api/2014/features/bard-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('song-of-rest-d8', 0, 'Beginning at 2nd level, you can use soothing music or oration to help revitalize your wounded allies during a short rest. If you or any friendly creatures who can hear your performance regain hit points at the end of the short rest by spending one or more Hit Dice, each of those creatures regains an extra 1d6 hit points. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('song-of-rest-d8', 1, 'The extra hit points increase when you reach certain levels in this class: to 1d8 at 9th level, to 1d10 at 13th level, and to 1d12 at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('song-of-rest-d8', 'bard', 'Song of Rest (d8)', 9, '/api/2014/features/song-of-rest-d8');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d10', 0, 'You can inspire others through stirring words or music. To do so, you use a bonus action on your turn to choose one creature other than yourself within 60 feet of you who can hear you. That creature gains one Bardic Inspiration die, a d6. Once within the next 10 minutes, the creature can roll the die and add the number rolled to one ability check, attack roll, or saving throw it makes. The creature can wait until after it rolls the d20 before deciding to use the Bardic Inspiration die, but must decide before the GM says whether the roll succeeds or fails. Once the Bardic Inspiration die is rolled, it is lost. A creature can have only one Bardic Inspiration die at a time.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d10', 1, 'You can use this feature a number of times equal to your Charisma modifier (a minimum of once). You regain any expended uses when you finish a long rest. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d10', 2, 'Your Bardic Inspiration die changes when you reach certain levels in this class. The die becomes a d8 at 5th level, a d10 at 10th level, and a d12 at 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bardic-inspiration-d10', 'bard', 'Bardic Inspiration (d10)', 10, '/api/2014/features/bardic-inspiration-d10');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-expertise-2', 0, 'At 3rd level, choose two of your skill proficiencies. Your proficiency bonus is doubled for any ability check you make that uses either of the chosen proficiencies. At 10th level, you can choose another two skill proficiencies to gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_expertise_options_choose, feature_specific_expertise_options_type, feature_specific_expertise_options_from_option_set_type) VALUES ('bard-expertise-2', 'bard', 'Expertise', 10, '/api/2014/features/bard-expertise-2', 2, 'proficiency', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-1', 0, 'By 10th level, you have plundered magical knowledge from a wide spectrum of disciplines. Choose two spells from any class, including this one. A spell you choose must be of a level you can cast, as shown on the Bard table, or a cantrip. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-1', 1, 'The chosen spells count as bard spells for you and are included in the number in the Spells Known column of the Bard table. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-1', 2, 'You learn two additional spells from any class at 14th level and again at 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('magical-secrets-1', 'bard', 'Magical Secrets', 10, '/api/2014/features/magical-secrets-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-ability-score-improvement-3', 'bard', 'Ability Score Improvement', 12, '/api/2014/features/bard-ability-score-improvement-3');
