INSERT INTO features_desc (features_index, order_num, "value") VALUES ('song-of-rest-d10', 1, 'The extra hit points increase when you reach certain levels in this class: to 1d8 at 9th level, to 1d10 at 13th level, and to 1d12 at 17th level.');
