INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-2', 1, 'The chosen spells count as bard spells for you and are included in the number in the Spells Known column of the Bard table. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-2', 2, 'You learn two additional spells from any class at 14th level and again at 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('magical-secrets-2', 'bard', 'Magical Secrets', 14, '/api/2014/features/magical-secrets-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-college-improvement-2', 0, 'At 3rd level, you delve into the advanced techniques of a bard college of your choice, such as the College of Lore. Your choice grants you features at 3rd level and again at 6th and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-college-improvement-2', 'bard', 'Bard College feature', 14, '/api/2014/features/bard-college-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('peerless-skill', 0, 'Starting at 14th level, when you make an ability check, you can expend one use of Bardic Inspiration. Roll a Bardic Inspiration die and add the number rolled to your ability check. You can choose to do so after you roll the die for the ability check, but before the GM tells you whether you succeed or fail.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('peerless-skill', 'bard', 'Peerless Skill', 14, '/api/2014/features/peerless-skill', 'lore');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bardic-inspiration-d12', 0, 'You can inspire others through stirring words or music. To do so, you use a bonus action on your turn to choose one creature other than yourself within 60 feet of you who can hear you. That creature gains one Bardic Inspiration die, a d6. Once within the next 10 minutes, the creature can roll the die and add the number rolled to one ability check, attack roll, or saving throw it makes. The creature can wait until after it rolls the d20 before deciding to use the Bardic Inspiration die, but must decide before the GM says whether the roll succeeds or fails. Once the Bardic Inspiration die is rolled, it is lost. A creature can have only one Bardic Inspiration die at a time.');
