INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-3', 1, 'The chosen spells count as bard spells for you and are included in the number in the Spells Known column of the Bard table. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('magical-secrets-3', 2, 'You learn two additional spells from any class at 14th level and again at 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('magical-secrets-3', 'bard', 'Magical Secrets', 18, '/api/2014/features/magical-secrets-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bard-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('bard-ability-score-improvement-5', 'bard', 'Ability Score Improvement', 19, '/api/2014/features/bard-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-inspiration', 0, 'At 20th level, when you roll initiative and have no uses of Bardic Inspiration left, you regain one use.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('superior-inspiration', 'bard', 'Superior Inspiration', 20, '/api/2014/features/superior-inspiration');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-cleric', 0, 'As a conduit for divine power, you can cast cleric spells.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-cleric', 'cleric', 'Spellcasting: Cleric', 1, '/api/2014/features/spellcasting-cleric', '/api/2014/classes/cleric/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain', 0, 'Choose one domain related to your deity, such as Knowledge, Life, Light, Nature, Tempest, Trickery, or War. Only the Life domain is detailed in the Open Game Licensed SRD. Additional Domains are described in the official rulebooks or products from other publishers.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain', 1, 'Your domain grants you domain spells and other features when you choose it at 1st level. It also grants you additional ways to use Channel Divinity when you gain that feature at 2nd level, and additional benefits at 6th, 8th, and 17th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-domain', 'cleric', 'Divine Domain', 1, '/api/2014/features/divine-domain');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-1', 0, 'Each domain has a list of spells--its domain spells--that you gain at the cleric levels noted in the domain description. Once you gain a domain spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-1', 1, 'If you have a domain spell that doesn''t appear on the cleric spell list, the spell is nonetheless a cleric spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('domain-spells-1', 'cleric', 'Domain Spells', 1, '/api/2014/features/domain-spells-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bonus-proficiency', 0, 'When you choose this domain at 1st level, you gain proficiency with heavy armor.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('bonus-proficiency', 'cleric', 'Bonus Proficiency', 1, '/api/2014/features/bonus-proficiency', 'life');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('disciple-of-life', 0, 'Also starting at 1st level, your healing spells are more effective. Whenever you use a spell of 1st level or higher to restore hit points to a creature, the creature regains additional hit points equal to 2 + the spell''s level.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('disciple-of-life', 'cleric', 'Disciple of Life', 1, '/api/2014/features/disciple-of-life', 'life');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-1-rest', 0, 'At 2nd level, you gain the ability to channel divine energy directly from your deity, using that energy to fuel magical effects. You start with two such effects: Turn Undead and an effect determined by your domain. Some domains grant you additional effects as you advance in levels, as noted in the domain description.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-1-rest', 1, 'When you use your Channel Divinity, you choose which effect to create. You must then finish a short or long rest to use your Channel Divinity again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-1-rest', 2, 'Some Channel Divinity effects require saving throws. When you use such an effect from this class, the DC equals your cleric spell save DC.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-1-rest', 3, 'Beginning at 6th level, you can use your Channel Divinity twice between rests, and beginning at 18th level, you can use it three times between rests. When you finish a short or long rest, you regain your expended uses.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('channel-divinity-1-rest', 'cleric', 'Channel Divinity (1/rest)', 2, '/api/2014/features/channel-divinity-1-rest');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-turn-undead', 0, 'As an action, you present your holy symbol and speak a prayer censuring the undead. Each undead that can see or hear you within 30 feet of you must make a Wisdom saving throw. If the creature fails its saving throw, it is turned for 1 minute or until it takes any damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-turn-undead', 1, 'A turned creature must spend its turns trying to move as far away from you as it can, and it can''t willingly move to a space within 30 feet of you. It also can''t take reactions. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If there''s nowhere to move, the creature can use the Dodge action.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('channel-divinity-turn-undead', 'cleric', 'Channel Divinity: Turn Undead', 2, '/api/2014/features/channel-divinity-turn-undead');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-1', 0, 'Choose one domain related to your deity, such as Knowledge, Life, Light, Nature, Tempest, Trickery, or War. Only the Life domain is detailed in the Open Game Licensed SRD. Additional Domains are described in the official rulebooks or products from other publishers.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-1', 1, 'Your domain grants you domain spells and other features when you choose it at 1st level. It also grants you additional ways to use Channel Divinity when you gain that feature at 2nd level, and additional benefits at 6th, 8th, and 17th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-domain-improvement-1', 'cleric', 'Divine Domain feature', 2, '/api/2014/features/divine-domain-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-preserve-life', 0, 'Starting at 2nd level, you can use your Channel Divinity to heal the badly injured.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-preserve-life', 1, 'As an action, you present your holy symbol and evoke healing energy that can restore a number of hit points equal to five times your cleric level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-preserve-life', 2, 'Choose any creatures within 30 feet of you, and divide those hit points among them. This feature can restore a creature to no more than half of its hit point maximum. You can''t use this feature on an undead or a construct.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('channel-divinity-preserve-life', 'cleric', 'Channel Divinity: Preserve Life', 2, '/api/2014/features/channel-divinity-preserve-life', 'life');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-2', 0, 'Each domain has a list of spells--its domain spells--that you gain at the cleric levels noted in the domain description. Once you gain a domain spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-2', 1, 'If you have a domain spell that doesn''t appear on the cleric spell list, the spell is nonetheless a cleric spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('domain-spells-2', 'cleric', 'Domain Spells', 3, '/api/2014/features/domain-spells-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleric-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleric-ability-score-improvement-1', 'cleric', 'Ability Score Improvement', 4, '/api/2014/features/cleric-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-3', 0, 'Each domain has a list of spells--its domain spells--that you gain at the cleric levels noted in the domain description. Once you gain a domain spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-3', 1, 'If you have a domain spell that doesn''t appear on the cleric spell list, the spell is nonetheless a cleric spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('domain-spells-3', 'cleric', 'Domain Spells', 5, '/api/2014/features/domain-spells-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('destroy-undead-cr-1-2-or-below', 0, 'Starting at 5th level, when an undead fails its saving throw against your Turn Undead feature, the creature is instantly destroyed if its challenge rating is at or below a certain threshold.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('destroy-undead-cr-1-2-or-below', 'cleric', 'Destroy Undead (CR 1/2 or below)', 5, '/api/2014/features/destroy-undead-cr-1-2-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-2-rest', 0, 'Beginning at 6th level, you can use your Channel Divinity twice between rests, and beginning at 18th level, you can use it three times between rests. When you finish a short or long rest, you regain your expended uses.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('channel-divinity-2-rest', 'cleric', 'Channel Divinity (2/rest)', 6, '/api/2014/features/channel-divinity-2-rest');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-2', 0, 'Choose one domain related to your deity, such as Knowledge, Life, Light, Nature, Tempest, Trickery, or War. Only the Life domain is detailed in the Open Game Licensed SRD. Additional Domains are described in the official rulebooks or products from other publishers.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-2', 1, 'Your domain grants you domain spells and other features when you choose it at 1st level. It also grants you additional ways to use Channel Divinity when you gain that feature at 2nd level, and additional benefits at 6th, 8th, and 17th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-domain-improvement-2', 'cleric', 'Divine Domain feature', 6, '/api/2014/features/divine-domain-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('blessed-healer', 0, 'Beginning at 6th level, the healing spells you cast on others heal you as well. When you cast a spell of 1st level or higher that restores hit points to a creature other than you, you regain hit points equal to 2 + the spell''s level.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('blessed-healer', 'cleric', 'Blessed Healer', 6, '/api/2014/features/blessed-healer', 'life');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-4', 0, 'Each domain has a list of spells--its domain spells--that you gain at the cleric levels noted in the domain description. Once you gain a domain spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-4', 1, 'If you have a domain spell that doesn''t appear on the cleric spell list, the spell is nonetheless a cleric spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('domain-spells-4', 'cleric', 'Domain Spells', 7, '/api/2014/features/domain-spells-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleric-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleric-ability-score-improvement-2', 'cleric', 'Ability Score Improvement', 8, '/api/2014/features/cleric-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('destroy-undead-cr-1-or-below', 0, 'Starting at 5th level, when an undead fails its saving throw against your Turn Undead feature, the creature is instantly destroyed if its challenge rating is at or below a certain threshold.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('destroy-undead-cr-1-or-below', 'cleric', 'Destroy Undead (CR 1 or below)', 8, '/api/2014/features/destroy-undead-cr-1-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-3', 0, 'Choose one domain related to your deity, such as Knowledge, Life, Light, Nature, Tempest, Trickery, or War. Only the Life domain is detailed in the Open Game Licensed SRD. Additional Domains are described in the official rulebooks or products from other publishers.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-3', 1, 'Your domain grants you domain spells and other features when you choose it at 1st level. It also grants you additional ways to use Channel Divinity when you gain that feature at 2nd level, and additional benefits at 6th, 8th, and 17th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-domain-improvement-3', 'cleric', 'Divine Domain feature', 8, '/api/2014/features/divine-domain-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-strike', 0, 'At 8th level, you gain the ability to infuse your weapon strikes with divine energy. Once on each of your turns when you hit a creature with a weapon attack, you can cause the attack to deal an extra 1d8 radiant damage to the target. When you reach 14th level, the extra damage increases to 2d8.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('divine-strike', 'cleric', 'Divine Strike', 8, '/api/2014/features/divine-strike', 'life');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-5', 0, 'Each domain has a list of spells--its domain spells--that you gain at the cleric levels noted in the domain description. Once you gain a domain spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('domain-spells-5', 1, 'If you have a domain spell that doesn''t appear on the cleric spell list, the spell is nonetheless a cleric spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('domain-spells-5', 'cleric', 'Domain Spells', 9, '/api/2014/features/domain-spells-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-intervention', 0, 'Beginning at 10th level, you can call on your deity to intervene on your behalf when your need is great.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-intervention', 1, 'Imploring your deity''s aid requires you to use your action. Describe the assistance you seek, and roll percentile dice. If you roll a number equal to or lower than your cleric level, your deity intervenes. The GM chooses the nature of the intervention; the effect of any cleric spell or cleric domain spell would be appropriate.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-intervention', 2, 'If your deity intervenes, you can''t use this feature again for 7 days. Otherwise, you can use it again after you finish a long rest.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-intervention', 3, 'At 20th level, your call for intervention succeeds automatically, no roll required.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-intervention', 'cleric', 'Divine Intervention', 10, '/api/2014/features/divine-intervention');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('destroy-undead-cr-2-or-below', 0, 'Starting at 5th level, when an undead fails its saving throw against your Turn Undead feature, the creature is instantly destroyed if its challenge rating is at or below a certain threshold.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('destroy-undead-cr-2-or-below', 'cleric', 'Destroy Undead (CR 2 or below)', 11, '/api/2014/features/destroy-undead-cr-2-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleric-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleric-ability-score-improvement-3', 'cleric', 'Ability Score Improvement', 12, '/api/2014/features/cleric-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('destroy-undead-cr-3-or-below', 0, 'Starting at 5th level, when an undead fails its saving throw against your Turn Undead feature, the creature is instantly destroyed if its challenge rating is at or below a certain threshold.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('destroy-undead-cr-3-or-below', 'cleric', 'Destroy Undead (CR 3 or below)', 14, '/api/2014/features/destroy-undead-cr-3-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleric-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleric-ability-score-improvement-4', 'cleric', 'Ability Score Improvement', 16, '/api/2014/features/cleric-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('destroy-undead-cr-4-or-below', 0, 'Starting at 5th level, when an undead fails its saving throw against your Turn Undead feature, the creature is instantly destroyed if its challenge rating is at or below a certain threshold.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('destroy-undead-cr-4-or-below', 'cleric', 'Destroy Undead (CR 4 or below)', 17, '/api/2014/features/destroy-undead-cr-4-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-4', 0, 'Choose one domain related to your deity, such as Knowledge, Life, Light, Nature, Tempest, Trickery, or War. Only the Life domain is detailed in the Open Game Licensed SRD. Additional Domains are described in the official rulebooks or products from other publishers.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-domain-improvement-4', 1, 'Your domain grants you domain spells and other features when you choose it at 1st level. It also grants you additional ways to use Channel Divinity when you gain that feature at 2nd level, and additional benefits at 6th, 8th, and 17th levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-domain-improvement-4', 'cleric', 'Divine Domain feature', 17, '/api/2014/features/divine-domain-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('supreme-healing', 0, 'Starting at 17th level, when you would normally roll one or more dice to restore hit points with a spell, you instead use the highest number possible for each die. For example, instead of restoring 2d6 hit points to a creature, you restore 12.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('supreme-healing', 'cleric', 'Supreme Healing', 17, '/api/2014/features/supreme-healing');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-3-rest', 0, 'Beginning at 6th level, you can use your Channel Divinity twice between rests, and beginning at 18th level, you can use it three times between rests. When you finish a short or long rest, you regain your expended uses.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('channel-divinity-3-rest', 'cleric', 'Channel Divinity (3/rest)', 18, '/api/2014/features/channel-divinity-3-rest');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleric-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleric-ability-score-improvement-5', 'cleric', 'Ability Score Improvement', 19, '/api/2014/features/cleric-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-intervention-improvement', 0, 'At 20th level, your call for intervention succeeds automatically, no roll required.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-intervention-improvement', 'cleric', 'Divine Intervention Improvement', 20, '/api/2014/features/divine-intervention-improvement');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-druid', 0, 'Drawing on the divine essence of nature itself, you can cast spells to shape that essence to your will.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-druid', 'druid', 'Spellcasting: Druid', 1, '/api/2014/features/spellcasting-druid', '/api/2014/classes/druid/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druidic', 0, 'You know Druidic, the secret language of druids. You can speak the language and use it to leave hidden messages. You and others who know this language automatically spot such a message. Others spot the message''s presence with a successful DC 15 Wisdom (Perception) check but can''t decipher it without magic.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druidic', 'druid', 'Druidic', 1, '/api/2014/features/druidic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 0, 'Starting at 2nd level, you can use your action to magically assume the shape of a beast that you have seen before. You can use this feature twice. You regain expended uses when you finish a short or long rest.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 1, 'Your druid level determines the beasts you can transform into, as shown in the Beast Shapes table. At 2nd level, for example, you can transform into any beast that has a challenge rating of 1/4 or lower that doesn''t have a flying or swimming speed.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 2, 'You can stay in a beast shape for a number of hours equal to half your druid level (rounded down). You then revert to your normal form unless you expend another use of this feature. You can revert to your normal form earlier by using a bonus action on your turn. You automatically revert if you fall unconscious, drop to 0 hit points, or die.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 3, 'While you are transformed, the following rules apply:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 4, '- Your game statistics are replaced by the statistics of the beast, but you retain your alignment, personality, and Intelligence, Wisdom, and Charisma scores. You also retain all of your skill and saving throw proficiencies, in addition to gaining those of the creature. If the creature has the same proficiency as you and the bonus in its stat block is higher than yours, use the creature''s bonus instead of yours. If the creature has any legendary or lair actions, you can''t use them.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 5, '- When you transform, you assume the beast''s hit points and Hit Dice. When you revert to your normal form, you return to the number of hit points you had before you transformed. However, if you revert as a result of dropping to 0 hit points, any excess damage carries over to your normal form. For example, if you take 10 damage in animal form and have only 1 hit point left, you revert and take 9 damage. As long as the excess damage doesn''t reduce your normal form to 0 hit points, you aren''t knocked unconscious.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 6, '- You can''t cast spells, and your ability to speak or take any action that requires hands is limited to the capabilities of your beast form. Transforming doesn''t break your concentration on a spell you''ve already cast, however, or prevent you from taking actions that are part of a spell, such as call lightning, that you''ve already cast.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 7, '- You retain the benefit of any features from your class, race, or other source and can use them if the new form is physically capable of doing so. However, you can''t use any of your special senses, such as darkvision, unless your new form also has that sense.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 8, '- You choose whether your equipment falls to the ground in your space, merges into your new form, or is worn by it. Worn equipment functions as normal, but the GM decides whether it is practical for the new form to wear a piece of equipment, based on the creature''s shape and size. Your equipment doesn''t change size or shape to match the new form, and any equipment that the new form can''t wear must either fall to the ground or merge with it. Equipment that merges with the form has no effect until you leave the form.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wild-shape-cr-1-4-or-below-no-flying-or-swim-speed', 'druid', 'Wild Shape (CR 1/4 or below, no flying or swim speed)', 2, '/api/2014/features/wild-shape-cr-1-4-or-below-no-flying-or-swim-speed');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-circle', 0, 'At 2nd level, you choose to identify with a circle of druids, such as the Circle of the Land. Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-circle', 'druid', 'Druid Circle', 2, '/api/2014/features/druid-circle');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-of-the-land', 0, 'The Circle of the Land is made up of mystics and sages who safeguard ancient knowledge and rites through a vast oral tradition. These druids meet within sacred circles of trees or standing stones to whisper primal secrets in Druidic. The circle''s wisest members preside as the chief priests of communities that hold to the Old Faith and serve as advisors to the rulers of those folk. As a member of this circle, your magic is influenced by the land where you were initiated into the circle''s mysterious rites.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('circle-of-the-land', 'druid', 'Circle of the Land', 2, '/api/2014/features/circle-of-the-land', 'land', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-of-the-land-arctic', 0, 'The Circle of the Land is made up of mystics and sages who safeguard ancient knowledge and rites through a vast oral tradition. These druids meet within sacred circles of trees or standing stones to whisper primal secrets in Druidic. The circle''s wisest members preside as the chief priests of communities that hold to the Old Faith and serve as advisors to the rulers of those folk. As a member of this circle, your magic is influenced by the land where you were initiated into the circle''s mysterious rites.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('circle-of-the-land-arctic', 'druid', 'Circle of the Land: Arctic', 2, '/api/2014/features/circle-of-the-land-arctic', 'land', 'circle-of-the-land');
