INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-of-the-land-swamp', 0, 'The Circle of the Land is made up of mystics and sages who safeguard ancient knowledge and rites through a vast oral tradition. These druids meet within sacred circles of trees or standing stones to whisper primal secrets in Druidic. The circle''s wisest members preside as the chief priests of communities that hold to the Old Faith and serve as advisors to the rulers of those folk. As a member of this circle, your magic is influenced by the land where you were initiated into the circle''s mysterious rites.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('circle-of-the-land-swamp', 'druid', 'Circle of the Land: Swamp', 2, '/api/2014/features/circle-of-the-land-swamp', 'land', 'circle-of-the-land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('bonus-cantrip', 0, 'When you choose this circle at 2nd level, you learn one additional druid cantrip of your choice.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('bonus-cantrip', 'druid', 'Bonus Cantrip', 2, '/api/2014/features/bonus-cantrip', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-recovery', 0, 'Starting at 2nd level, you can regain some of your magical energy by sitting in meditation and communing with nature. During a short rest, you choose expended spell slots to recover. The spell slots can have a combined level that is equal to or less than half your druid level (rounded up), and none of the slots can be 6th level or higher. You can''t use this feature again until you finish a long rest.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-recovery', 1, 'For example, when you are a 4th-level druid, you can recover up to two levels worth of spell slots. You can recover either a 2nd-level slot or two 1st-level slots.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('natural-recovery', 'druid', 'Natural Recovery', 2, '/api/2014/features/natural-recovery', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-1', 0, 'Your mystical connection to the land infuses you with the ability to cast certain spells. At 3rd, 5th, 7th, and 9th level you gain access to circle spells connected to the land where you became a druid.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-1', 1, 'Choose that land--arctic, coast, desert, forest, grassland, mountain, or swamp--and consult the associated list of spells.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-1', 2, 'Once you gain access to a circle spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day. If you gain access to a spell that doesn''t appear on the druid spell list, the spell is nonetheless a druid spell for you.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('circle-spells-1', 'druid', 'Circle Spells', 3, '/api/2014/features/circle-spells-1', 'land');
