INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-circle-improvement-1', 0, 'At 2nd level, you choose to identify with a circle of druids, such as the Circle of the Land. Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-circle-improvement-1', 'druid', 'Druid Circle feature', 6, '/api/2014/features/druid-circle-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-lands-stride', 0, 'Starting at 6th level, moving through nonmagical difficult terrain costs you no extra movement. You can also pass through nonmagical plants without being slowed by them and without taking damage from them if they have thorns, spines, or a similar hazard.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-lands-stride', 1, 'In addition, you have advantage on saving throws against plants that are magically created or manipulated to impede movement, such those created by the entangle spell.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('druid-lands-stride', 'druid', 'Land''s Stride', 6, '/api/2014/features/druid-lands-stride', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-3', 0, 'Your mystical connection to the land infuses you with the ability to cast certain spells. At 3rd, 5th, 7th, and 9th level you gain access to circle spells connected to the land where you became a druid.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-3', 1, 'Choose that land--arctic, coast, desert, forest, grassland, mountain, or swamp--and consult the associated list of spells.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-3', 2, 'Once you gain access to a circle spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day. If you gain access to a spell that doesn''t appear on the druid spell list, the spell is nonetheless a druid spell for you.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('circle-spells-3', 'druid', 'Circle Spells', 7, '/api/2014/features/circle-spells-3', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 0, 'Starting at 2nd level, you can use your action to magically assume the shape of a beast that you have seen before. You can use this feature twice. You regain expended uses when you finish a short or long rest.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 1, 'Your druid level determines the beasts you can transform into, as shown in the Beast Shapes table. At 2nd level, for example, you can transform into any beast that has a challenge rating of 1/4 or lower that doesn''t have a flying or swimming speed.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 2, 'You can stay in a beast shape for a number of hours equal to half your druid level (rounded down). You then revert to your normal form unless you expend another use of this feature. You can revert to your normal form earlier by using a bonus action on your turn. You automatically revert if you fall unconscious, drop to 0 hit points, or die.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 3, 'While you are transformed, the following rules apply:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 4, '- Your game statistics are replaced by the statistics of the beast, but you retain your alignment, personality, and Intelligence, Wisdom, and Charisma scores. You also retain all of your skill and saving throw proficiencies, in addition to gaining those of the creature. If the creature has the same proficiency as you and the bonus in its stat block is higher than yours, use the creature''s bonus instead of yours. If the creature has any legendary or lair actions, you can''t use them.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 5, '- When you transform, you assume the beast''s hit points and Hit Dice. When you revert to your normal form, you return to the number of hit points you had before you transformed. However, if you revert as a result of dropping to 0 hit points, any excess damage carries over to your normal form. For example, if you take 10 damage in animal form and have only 1 hit point left, you revert and take 9 damage. As long as the excess damage doesn''t reduce your normal form to 0 hit points, you aren''t knocked unconscious.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 6, '- You can''t cast spells, and your ability to speak or take any action that requires hands is limited to the capabilities of your beast form. Transforming doesn''t break your concentration on a spell you''ve already cast, however, or prevent you from taking actions that are part of a spell, such as call lightning, that you''ve already cast.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 7, '- You retain the benefit of any features from your class, race, or other source and can use them if the new form is physically capable of doing so. However, you can''t use any of your special senses, such as darkvision, unless your new form also has that sense.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wild-shape-cr-1-or-below', 8, '- You choose whether your equipment falls to the ground in your space, merges into your new form, or is worn by it. Worn equipment functions as normal, but the GM decides whether it is practical for the new form to wear a piece of equipment, based on the creature''s shape and size. Your equipment doesn''t change size or shape to match the new form, and any equipment that the new form can''t wear must either fall to the ground or merge with it. Equipment that merges with the form has no effect until you leave the form.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wild-shape-cr-1-or-below', 'druid', 'Wild Shape (CR 1 or below)', 8, '/api/2014/features/wild-shape-cr-1-or-below');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-ability-score-improvement-2', 'druid', 'Ability Score Improvement', 8, '/api/2014/features/druid-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-4', 0, 'Your mystical connection to the land infuses you with the ability to cast certain spells. At 3rd, 5th, 7th, and 9th level you gain access to circle spells connected to the land where you became a druid.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-4', 1, 'Choose that land--arctic, coast, desert, forest, grassland, mountain, or swamp--and consult the associated list of spells.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('circle-spells-4', 2, 'Once you gain access to a circle spell, you always have it prepared, and it doesn''t count against the number of spells you can prepare each day. If you gain access to a spell that doesn''t appear on the druid spell list, the spell is nonetheless a druid spell for you.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('circle-spells-4', 'druid', 'Circle Spells', 9, '/api/2014/features/circle-spells-4', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-circle-improvement-2', 0, 'At 2nd level, you choose to identify with a circle of druids, such as the Circle of the Land. Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-circle-improvement-2', 'druid', 'Druid Circle feature', 10, '/api/2014/features/druid-circle-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natures-ward', 0, 'When you reach 10th level, you can''t be charmed or frightened by elementals or fey, and you are immune to poison and disease.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('natures-ward', 'druid', 'Nature''s Ward', 10, '/api/2014/features/natures-ward', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-ability-score-improvement-3', 'druid', 'Ability Score Improvement', 12, '/api/2014/features/druid-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-circle-improvement-3', 0, 'At 2nd level, you choose to identify with a circle of druids, such as the Circle of the Land. Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-circle-improvement-3', 'druid', 'Druid Circle feature', 14, '/api/2014/features/druid-circle-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natures-sanctuary', 0, 'When you reach 14th level, creatures of the natural world sense your connection to nature and become hesitant to attack you. When a beast or plant creature attacks you, that creature must make a Wisdom saving throw against your druid spell save DC. On a failed save, the creature must choose a different target, or the attack automatically misses. On a successful save, the creature is immune to this effect for 24 hours. The creature is aware of this effect before it makes its attack against you.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('natures-sanctuary', 'druid', 'Nature''s Sanctuary', 14, '/api/2014/features/natures-sanctuary', 'land');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-ability-score-improvement-4', 'druid', 'Ability Score Improvement', 16, '/api/2014/features/druid-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-timeless-body', 0, 'Starting at 18th level, the primal magic that you wield causes you to age more slowly. For every 10 years that pass, your body ages only 1 year.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-timeless-body', 'druid', 'Timeless Body', 18, '/api/2014/features/druid-timeless-body');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('beast-spells', 0, 'Beginning at 18th level, you can cast many of your druid spells in any shape you assume using Wild Shape. You can perform the somatic and verbal components of a druid spell while in a beast shape, but you aren''t able to provide material components.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('beast-spells', 'druid', 'Beast Spells', 18, '/api/2014/features/beast-spells');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('druid-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('druid-ability-score-improvement-5', 'druid', 'Ability Score Improvement', 19, '/api/2014/features/druid-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('archdruid', 0, 'At 20th level, you can use your Wild Shape an unlimited number of times.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('archdruid', 1, 'Additionally, you can ignore the verbal and somatic components of your druid spells, as well as any material components that lack a cost and aren''t consumed by a spell. You gain this benefit in both your normal shape and your beast shape from Wild Shape.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('archdruid', 'druid', 'Archdruid', 20, '/api/2014/features/archdruid');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style', 0, 'You adopt a particular style of fighting as your specialty. Choose one of the following options. You can''t take a Fighting Style option more than once, even if you later get to choose again.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('fighter-fighting-style', 'fighter', 'Fighting Style', 1, '/api/2014/features/fighter-fighting-style', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-archery', 0, 'You gain a +2 bonus to attack rolls you make with ranged weapons.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-archery', 'fighter', 'Fighting Style: Archery', 1, '/api/2014/features/fighter-fighting-style-archery', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-defense', 0, 'While you are wearing armor, you gain a +1 bonus to AC.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-defense', 'fighter', 'Fighting Style: Defense', 1, '/api/2014/features/fighter-fighting-style-defense', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-dueling', 0, 'When you are wielding a melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-dueling', 'fighter', 'Fighting Style: Dueling', 1, '/api/2014/features/fighter-fighting-style-dueling', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-great-weapon-fighting', 0, 'When you roll a 1 or 2 on a damage die for an attack you make with a melee weapon that you are wielding with two hands, you can reroll the die and must use the new roll, even if the new roll is a 1 or a 2. The weapon must have the two-handed or versatile property for you to gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-great-weapon-fighting', 'fighter', 'Fighting Style: Great Weapon Fighting', 1, '/api/2014/features/fighter-fighting-style-great-weapon-fighting', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-protection', 0, 'When a creature you can see attacks a target other than you that is within 5 feet of you, you can use your reaction to impose disadvantage on the attack roll. You must be wielding a shield.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-protection', 'fighter', 'Fighting Style: Protection', 1, '/api/2014/features/fighter-fighting-style-protection', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-fighting-style-two-weapon-fighting', 0, 'When you engage in two-weapon fighting, you can add your ability modifier to the damage of the second attack.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighter-fighting-style-two-weapon-fighting', 'fighter', 'Fighting Style: Two-Weapon Fighting', 1, '/api/2014/features/fighter-fighting-style-two-weapon-fighting', 'fighter-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('second-wind', 0, 'You have a limited well of stamina that you can draw on to protect yourself from harm. On your turn, you can use a bonus action to regain hit points equal to 1d10 + your fighter level. Once you use this feature, you must finish a short or long rest before you can use it again.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('second-wind', 'fighter', 'Second Wind', 1, '/api/2014/features/second-wind');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('action-surge-1-use', 0, 'Starting at 2nd level, you can push yourself beyond your normal limits for a moment. On your turn, you can take one additional action on top of your regular action and a possible bonus action.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('action-surge-1-use', 1, 'Once you use this feature, you must finish a short or long rest before you can use it again. Starting at 17th level, you can use it twice before a rest, but only once on the same turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('action-surge-1-use', 'fighter', 'Action Surge (1 use)', 2, '/api/2014/features/action-surge-1-use');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-archetype', 0, 'At 3rd level, you choose an archetype that you strive to emulate in your combat styles and techniques, such as Champion. The archetype you choose grants you features at 3rd level and again at 7th, 10th, 15th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-archetype', 'fighter', 'Martial Archetype', 3, '/api/2014/features/martial-archetype');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('improved-critical', 0, 'Beginning when you choose this archetype at 3rd level, your weapon attacks score a critical hit on a roll of 19 or 20.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('improved-critical', 'fighter', 'Improved Critical', 3, '/api/2014/features/improved-critical', 'champion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-1', 'fighter', 'Ability Score Improvement', 4, '/api/2014/features/fighter-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('extra-attack-1', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn. The number of attacks increases to three when you reach 11th level in this class and to four when you reach 20th level in this class.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('extra-attack-1', 'fighter', 'Extra Attack', 5, '/api/2014/features/extra-attack-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-2', 'fighter', 'Ability Score Improvement', 6, '/api/2014/features/fighter-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('remarkable-athlete', 0, 'Starting at 7th level, you can add half your proficiency bonus (round up) to any Strength, Dexterity, or Constitution check you make that doesn''t already use your proficiency bonus. In addition, when you make a running long jump, the distance you can cover increases by a number of feet equal to your Strength modifier.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('remarkable-athlete', 'fighter', 'Remarkable Athlete', 7, '/api/2014/features/remarkable-athlete', 'champion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-archetype-improvement-1', 0, 'At 3rd level, you choose an archetype that you strive to emulate in your combat styles and techniques, such as Champion. The archetype you choose grants you features at 3rd level and again at 7th, 10th, 15th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-archetype-improvement-1', 'fighter', 'Martial Archetype feature', 7, '/api/2014/features/martial-archetype-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-3', 'fighter', 'Ability Score Improvement', 8, '/api/2014/features/fighter-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('indomitable-1-use', 0, 'Beginning at 9th level, you can reroll a saving throw that you fail. If you do so, you must use the new roll, and you can''t use this feature again until you finish a long rest. You can use this feature twice between long rests starting at 13th level and three times between long rests starting at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('indomitable-1-use', 'fighter', 'Indomitable (1 use)', 9, '/api/2014/features/indomitable-1-use');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('additional-fighting-style', 0, 'At 10th level, you can choose a second option from the Fighting Style class feature.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('additional-fighting-style', 'fighter', 'Additional Fighting Style', 10, '/api/2014/features/additional-fighting-style', 'champion', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-archetype-improvement-2', 0, 'At 3rd level, you choose an archetype that you strive to emulate in your combat styles and techniques, such as Champion. The archetype you choose grants you features at 3rd level and again at 7th, 10th, 15th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-archetype-improvement-2', 'fighter', 'Martial Archetype feature', 10, '/api/2014/features/martial-archetype-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('extra-attack-2', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn. The number of attacks increases to three when you reach 11th level in this class and to four when you reach 20th level in this class.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('extra-attack-2', 'fighter', 'Extra Attack (2)', 11, '/api/2014/features/extra-attack-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-4', 'fighter', 'Ability Score Improvement', 12, '/api/2014/features/fighter-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('indomitable-2-uses', 0, 'Beginning at 9th level, you can reroll a saving throw that you fail. If you do so, you must use the new roll, and you can''t use this feature again until you finish a long rest. You can use this feature twice between long rests starting at 13th level and three times between long rests starting at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('indomitable-2-uses', 'fighter', 'Indomitable (2 uses)', 13, '/api/2014/features/indomitable-2-uses');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-5', 'fighter', 'Ability Score Improvement', 14, '/api/2014/features/fighter-ability-score-improvement-5');
