INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-archetype-improvement-3', 'fighter', 'Martial Archetype feature', 15, '/api/2014/features/martial-archetype-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-6', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-6', 'fighter', 'Ability Score Improvement', 16, '/api/2014/features/fighter-ability-score-improvement-6');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('action-surge-2-uses', 0, 'Starting at 2nd level, you can push yourself beyond your normal limits for a moment. On your turn, you can take one additional action on top of your regular action and a possible bonus action.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('action-surge-2-uses', 1, 'Once you use this feature, you must finish a short or long rest before you can use it again. Starting at 17th level, you can use it twice before a rest, but only once on the same turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('action-surge-2-uses', 'fighter', 'Action Surge (2 uses)', 17, '/api/2014/features/action-surge-2-uses');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('indomitable-3-uses', 0, 'Beginning at 9th level, you can reroll a saving throw that you fail. If you do so, you must use the new roll, and you can''t use this feature again until you finish a long rest. You can use this feature twice between long rests starting at 13th level and three times between long rests starting at 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('indomitable-3-uses', 'fighter', 'Indomitable (3 uses)', 17, '/api/2014/features/indomitable-3-uses');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-archetype-improvement-4', 0, 'At 3rd level, you choose an archetype that you strive to emulate in your combat styles and techniques, such as Champion. The archetype you choose grants you features at 3rd level and again at 7th, 10th, 15th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-archetype-improvement-4', 'fighter', 'Martial Archetype feature', 18, '/api/2014/features/martial-archetype-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('survivor', 0, 'At 18th level, you attain the pinnacle of resilience in battle. At the start of each of your turns, you regain hit points equal to 5 + your Constitution modifier if you have no more than half of your hit points left. You don''t gain this benefit if you have 0 hit points.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('survivor', 'fighter', 'Survivor', 18, '/api/2014/features/survivor', 'champion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighter-ability-score-improvement-7', 0, 'When you reach 4th level, and again at 6th, 8th, 12th, 14th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('fighter-ability-score-improvement-7', 'fighter', 'Ability Score Improvement', 19, '/api/2014/features/fighter-ability-score-improvement-7');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('extra-attack-3', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn. The number of attacks increases to three when you reach 11th level in this class and to four when you reach 20th level in this class.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('extra-attack-3', 'fighter', 'Extra Attack (3)', 20, '/api/2014/features/extra-attack-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-unarmored-defense', 0, 'Beginning at 1st level, while you are wearing no armor and not wielding a shield, your AC equals 10 + your Dexterity modifier + your Wisdom modifier.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-unarmored-defense', 'monk', 'Unarmored Defense', 1, '/api/2014/features/monk-unarmored-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 0, 'At 1st level, your practice of martial arts gives you mastery of combat styles that use unarmed strikes and monk weapons, which are shortswords and any simple melee weapons that don''t have the two- handed or heavy property.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 1, 'You gain the following benefits while you are unarmed or wielding only monk weapons and you aren''t wearing armor or wielding a shield:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 2, '- You can use Dexterity instead of Strength for the attack and damage rolls of your unarmed strikes and monk weapons.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 3, '- You can roll a d4 in place of the normal damage of your unarmed strike or monk weapon. This die changes as you gain monk levels, as shown in the Martial Arts column of Table: The Monk.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 4, '- When you use the Attack action with an unarmed strike or a monk weapon on your turn, you can make one unarmed strike as a bonus action. For example, if you take the Attack action and attack with a quarterstaff, you can also make an unarmed strike as a bonus action, assuming you haven''t already taken a bonus action this turn.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('martial-arts', 5, 'Certain monasteries use specialized forms of the monk weapons. For example, you might use a club that is two lengths of wood connected by a short chain (called a nunchaku) or a sickle with a shorter, straighter blade (called a kama). Whatever name you use for a monk weapon, you can use the game statistics provided for the weapon.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('martial-arts', 'monk', 'Martial Arts', 1, '/api/2014/features/martial-arts');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki', 0, 'Starting at 2nd level, your training allows you to harness the mystic energy of ki. Your access to this energy is represented by a number of ki points. Your monk level determines the number of points you have, as shown in the Ki Points column of Table: The Monk.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki', 1, 'You can spend these points to fuel various ki features. You start knowing three such features: Flurry of Blows, Patient Defense, and Step of the Wind. You learn more ki features as you gain levels in this class.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki', 2, 'When you spend a ki point, it is unavailable until you finish a short or long rest, at the end of which you draw all of your expended ki back into yourself. You must spend at least 30 minutes of the rest meditating to regain your ki points.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki', 3, 'Some of your ki features require your target to make a saving throw to resist the feature''s effects. The saving throw DC is calculated as follows:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki', 4, 'Ki save DC = 8 + your proficiency bonus + your Wisdom modifier');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ki', 'monk', 'Ki', 2, '/api/2014/features/ki');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('flurry-of-blows', 0, 'Immediately after you take the Attack action on your turn, you can spend 1 ki point to make two unarmed strikes as a bonus action.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('flurry-of-blows', 'monk', 'Flurry of Blows', 2, '/api/2014/features/flurry-of-blows');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('patient-defense', 0, 'You can spend 1 ki point to take the Dodge action as a bonus action on your turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('patient-defense', 'monk', 'Patient Defense', 2, '/api/2014/features/patient-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('step-of-the-wind', 0, 'You can spend 1 ki point to take the Disengage or Dash action as a bonus action on your turn, and your jump distance is doubled for the turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('step-of-the-wind', 'monk', 'Step of the Wind', 2, '/api/2014/features/step-of-the-wind');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('unarmored-movement-1', 0, 'Starting at 2nd level, your speed increases by 10 feet while you are not wearing armor or wielding a shield. This bonus increases when you reach certain monk levels, as shown in Table: The Monk.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('unarmored-movement-1', 1, 'At 9th level, you gain the ability to move along vertical surfaces and across liquids on your turn without falling during the move.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('unarmored-movement-1', 'monk', 'Unarmored Movement', 2, '/api/2014/features/unarmored-movement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monastic-tradition', 0, 'When you reach 3rd level, you commit yourself to a monastic tradition, such as the Way of the Open Hand. Your tradition grants you features at 3rd level and again at 6th, 11th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monastic-tradition', 'monk', 'Monastic Tradition', 3, '/api/2014/features/monastic-tradition');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('deflect-missiles', 0, 'Starting at 3rd level, you can use your reaction to deflect or catch the missile when you are hit by a ranged weapon attack. When you do so, the damage you take from the attack is reduced by 1d10 + your Dexterity modifier + your monk level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('deflect-missiles', 1, 'If you reduce the damage to 0, you can catch the missile if it is small enough for you to hold in one hand and you have at least one hand free. If you catch a missile in this way, you can spend 1 ki point to make a ranged attack with the weapon or piece of ammunition you just caught, as part of the same reaction. You make this attack with proficiency, regardless of your weapon proficiencies, and the missile counts as a monk weapon for the attack, which has a normal range of 20 feet and a long range of 60 feet.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('deflect-missiles', 'monk', 'Deflect Missiles', 3, '/api/2014/features/deflect-missiles');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('open-hand-technique', 0, 'Starting when you choose this tradition at 3rd level, you can manipulate your enemy''s ki when you harness your own. Whenever you hit a creature with one of the attacks granted by your Flurry of Blows, you can impose one of the following effects on that target:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('open-hand-technique', 1, '- It must succeed on a Dexterity saving throw or be knocked prone.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('open-hand-technique', 2, '- It must make a Strength saving throw. If it fails, you can push it up to 15 feet away from you.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('open-hand-technique', 3, '- It can''t take reactions until the end of your next turn.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('open-hand-technique', 'monk', 'Open Hand Technique', 3, '/api/2014/features/open-hand-technique', 'open-hand');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-ability-score-improvement-1', 'monk', 'Ability Score Improvement', 4, '/api/2014/features/monk-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('slow-fall', 0, 'Beginning at 4th level, you can use your reaction when you fall to reduce any falling damage you take by an amount equal to five times your monk level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('slow-fall', 'monk', 'Slow Fall', 4, '/api/2014/features/slow-fall');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-extra-attack', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-extra-attack', 'monk', 'Extra Attack', 5, '/api/2014/features/monk-extra-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('stunning-strike', 0, 'Starting at 5th level, you can interfere with the flow of ki in an opponent''s body. When you hit another creature with a melee weapon attack, you can spend 1 ki point to attempt a stunning strike. The target must succeed on a Constitution saving throw or be stunned until the end of your next turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('stunning-strike', 'monk', 'Stunning Strike', 5, '/api/2014/features/stunning-strike');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ki-empowered-strikes', 0, 'Starting at 6th level, your unarmed strikes count as magical for the purpose of overcoming resistance and immunity to nonmagical attacks and damage.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ki-empowered-strikes', 'monk', 'Ki Empowered Strikes', 6, '/api/2014/features/ki-empowered-strikes');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monastic-tradition-improvement-1', 0, 'When you reach 3rd level, you commit yourself to a monastic tradition, such as the Way of the Open Hand. Your tradition grants you features at 3rd level and again at 6th, 11th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monastic-tradition-improvement-1', 'monk', 'Monastic Tradition feature', 6, '/api/2014/features/monastic-tradition-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wholeness-of-body', 0, 'At 6th level, you gain the ability to heal yourself. As an action, you can regain hit points equal to three times your monk level. You must finish a long rest before you can use this feature again.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('wholeness-of-body', 'monk', 'Wholeness of Body', 6, '/api/2014/features/wholeness-of-body', 'open-hand');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-evasion', 0, 'At 7th level, your instinctive agility lets you dodge out of the way of certain area effects, such as a blue dragon''s lightning breath or a fireball spell. When you are subjected to an effect that allows you to make a Dexterity saving throw to take only half damage, you instead take no damage if you succeed on the saving throw, and only half damage if you fail.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-evasion', 'monk', 'Evasion', 7, '/api/2014/features/monk-evasion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('stillness-of-mind', 0, 'Starting at 7th level, you can use your action to end one effect on yourself that is causing you to be charmed or frightened.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('stillness-of-mind', 'monk', 'Stillness of Mind', 7, '/api/2014/features/stillness-of-mind');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-ability-score-improvement-2', 'monk', 'Ability Score Improvement', 8, '/api/2014/features/monk-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('unarmored-movement-2', 0, 'Starting at 2nd level, your speed increases by 10 feet while you are not wearing armor or wielding a shield. This bonus increases when you reach certain monk levels, as shown in Table: The Monk.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('unarmored-movement-2', 1, 'At 9th level, you gain the ability to move along vertical surfaces and across liquids on your turn without falling during the move.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('unarmored-movement-2', 'monk', 'Unarmored Movement', 9, '/api/2014/features/unarmored-movement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('purity-of-body', 0, 'At 10th level, your mastery of the ki flowing through you makes you immune to disease and poison.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('purity-of-body', 'monk', 'Purity of Body', 10, '/api/2014/features/purity-of-body');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monastic-tradition-improvement-2', 0, 'When you reach 3rd level, you commit yourself to a monastic tradition, such as the Way of the Open Hand. Your tradition grants you features at 3rd level and again at 6th, 11th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monastic-tradition-improvement-2', 'monk', 'Monastic Tradition feature', 11, '/api/2014/features/monastic-tradition-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('tranquility', 0, 'Beginning at 11th level, you can enter a special meditation that surrounds you with an aura of peace. At the end of a long rest, you gain the effect of a sanctuary spell that lasts until the start of your next long rest (the spell can end early as normal). The saving throw DC for the spell equals 8 + your Wisdom modifier + your proficiency bonus.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('tranquility', 'monk', 'Tranquility', 11, '/api/2014/features/tranquility', 'open-hand');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-ability-score-improvement-3', 'monk', 'Ability Score Improvement', 12, '/api/2014/features/monk-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('tongue-of-the-sun-and-moon', 0, 'Starting at 13th level, you learn to touch the ki of other minds so that you understand all spoken languages. Moreover, any creature that can understand a language can understand what you say.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('tongue-of-the-sun-and-moon', 'monk', 'Tongue of the Sun and Moon', 13, '/api/2014/features/tongue-of-the-sun-and-moon');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('diamond-soul', 0, 'Beginning at 14th level, your mastery of ki grants you proficiency in all saving throws.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('diamond-soul', 1, 'Additionally, whenever you make a saving throw and fail, you can spend 1 ki point to reroll it and take the second result.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('diamond-soul', 'monk', 'Diamond Soul', 14, '/api/2014/features/diamond-soul');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-timeless-body', 0, 'At 15th level, your ki sustains you so that you suffer none of the frailty of old age, and you can''t be aged magically. You can still die of old age, however. In addition, you no longer need food or water.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-timeless-body', 'monk', 'Timeless Body', 15, '/api/2014/features/monk-timeless-body');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-ability-score-improvement-4', 'monk', 'Ability Score Improvement', 16, '/api/2014/features/monk-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monastic-tradition-improvement-3', 0, 'When you reach 3rd level, you commit yourself to a monastic tradition, such as the Way of the Open Hand. Your tradition grants you features at 3rd level and again at 6th, 11th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monastic-tradition-improvement-3', 'monk', 'Monastic Tradition feature', 17, '/api/2014/features/monastic-tradition-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('quivering-palm', 0, 'At 17th level, you gain the ability to set up lethal vibrations in someone''s body. When you hit a creature with an unarmed strike, you can spend 3 ki points to start these imperceptible vibrations, which last for a number of days equal to your monk level. The vibrations are harmless unless you use your action to end them. To do so, you and the target must be on the same plane of existence. When you use this action, the creature must make a Constitution saving throw. If it fails, it is reduced to 0 hit points. If it succeeds, it takes 10d10 necrotic damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('quivering-palm', 1, 'You can have only one creature under the effect of this feature at a time. You can choose to end the vibrations harmlessly without using an action.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('quivering-palm', 'monk', 'Quivering Palm', 17, '/api/2014/features/quivering-palm', 'open-hand');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('empty-body', 0, 'Beginning at 18th level, you can use your action to spend 4 ki points to become invisible for 1 minute. During that time, you also have resistance to all damage but force damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('empty-body', 1, 'Additionally, you can spend 8 ki points to cast the astral projection spell, without needing material components. When you do so, you can''t take any other creatures with you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('empty-body', 'monk', 'Empty Body', 18, '/api/2014/features/empty-body');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('monk-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('monk-ability-score-improvement-5', 'monk', 'Ability Score Improvement', 19, '/api/2014/features/monk-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('perfect-self', 0, 'At 20th level, when you roll for initiative and have no ki points remaining, you regain 4 ki points.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('perfect-self', 'monk', 'Perfect Self', 20, '/api/2014/features/perfect-self');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-sense', 0, 'The presence of strong evil registers on your senses like a noxious odor, and powerful good rings like heavenly music in your ears. As an action, you can open your awareness to detect such forces. Until the end of your next turn, you know the location of any celestial, fiend, or undead within 60 feet of you that is not behind total cover. You know the type (celestial, fiend, or undead) of any being whose presence you sense, but not its identity. Within the same radius, you also detect the presence of any place or object that has been consecrated or desecrated, as with the hallow spell.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-sense', 1, 'You can use this feature a number of times equal to 1 + your Charisma modifier. When you finish a long rest, you regain all expended uses.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-sense', 'paladin', 'Divine Sense', 1, '/api/2014/features/divine-sense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('lay-on-hands', 0, 'Your blessed touch can heal wounds. You have a pool of healing power that replenishes when you take a long rest. With that pool, you can restore a total number of hit points equal to your paladin level x 5.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('lay-on-hands', 1, 'As an action, you can touch a creature and draw power from the pool to restore a number of hit points to that creature, up to the maximum amount remaining in your pool.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('lay-on-hands', 2, 'Alternatively, you can expend 5 hit points from your pool of healing to cure the target of one disease or neutralize one poison affecting it. You can cure multiple diseases and neutralize multiple poisons with a single use of Lay on Hands, expending hit points separately for each one.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('lay-on-hands', 3, 'This feature has no effect on undead and constructs.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('lay-on-hands', 'paladin', 'Lay on Hands', 1, '/api/2014/features/lay-on-hands');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-fighting-style', 0, 'At 2nd level, you adopt a style of fighting as your specialty. Choose one of the following options. You can''t take a Fighting Style option more than once, even if you later get to choose again.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('paladin-fighting-style', 'paladin', 'Fighting Style', 2, '/api/2014/features/paladin-fighting-style', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighting-style-defense', 0, 'While you are wearing armor, you gain a +1 bonus to AC.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighting-style-defense', 'paladin', 'Fighting Style: Defense', 2, '/api/2014/features/fighting-style-defense', 'paladin-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighting-style-dueling', 0, 'When you are wielding a melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighting-style-dueling', 'paladin', 'Fighting Style: Dueling', 2, '/api/2014/features/fighting-style-dueling', 'paladin-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighting-style-great-weapon-fighting', 0, 'When you roll a 1 or 2 on a damage die for an attack you make with a melee weapon that you are wielding with two hands, you can reroll the die and must use the new roll. The weapon must have the two-handed or versatile property for you to gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighting-style-great-weapon-fighting', 'paladin', 'Fighting Style: Great Weapon Fighting', 2, '/api/2014/features/fighting-style-great-weapon-fighting', 'paladin-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fighting-style-protection', 0, 'When a creature you can see attacks a target other than you that is within 5 feet of you, you can use your reaction to impose disadvantage on the attack roll. You must be wielding a shield.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('fighting-style-protection', 'paladin', 'Fighting Style: Protection', 2, '/api/2014/features/fighting-style-protection', 'paladin-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-paladin', 0, 'By 2nd level, you have learned to draw on divine magic through meditation and prayer to cast spells as a cleric does.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-paladin', 'paladin', 'Spellcasting: Paladin', 2, '/api/2014/features/spellcasting-paladin', '/api/2014/classes/paladin/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-smite', 0, 'Starting at 2nd level, when you hit a creature with a melee weapon attack, you can expend one spell slot to deal radiant damage to the target, in addition to the weapon''s damage. The extra damage is 2d8 for a 1st-level spell slot, plus 1d8 for each spell level higher than 1st, to a maximum of 5d8. The damage increases by 1d8 if the target is an undead or a fiend.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-smite', 'paladin', 'Divine Smite', 2, '/api/2014/features/divine-smite');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('divine-health', 0, 'By 3rd level, the divine magic flowing through you makes you immune to disease.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('divine-health', 'paladin', 'Divine Health', 3, '/api/2014/features/divine-health');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath', 0, 'When you reach 3rd level, you swear the oath that binds you as a paladin forever. Up to this time you have been in a preparatory stage, committed to the path but not yet sworn to it. Now you choose an oath, such as the Oath of Devotion.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath', 1, 'Your choice grants you features at 3rd level and again at 7th, 15th, and 20th level. Those features include oath spells and the Channel Divinity feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sacred-oath', 'paladin', 'Sacred Oath', 3, '/api/2014/features/sacred-oath');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('oath-spells', 0, 'Each oath has a list of associated spells. You gain access to these spells at the levels specified in the oath description. Once you gain access to an oath spell, you always have it prepared. Oath spells don''t count against the number of spells you can prepare each day.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('oath-spells', 1, 'If you gain an oath spell that doesn''t appear on the paladin spell list, the spell is nonetheless a paladin spell for you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('oath-spells', 'paladin', 'Oath Spells', 3, '/api/2014/features/oath-spells');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity', 0, 'Your oath allows you to channel divine energy to fuel magical effects. Each Channel Divinity option provided by your oath explains how to use it.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity', 1, 'When you use your Channel Divinity, you choose which option to use. You must then finish a short or long rest to use your Channel Divinity again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity', 2, 'Some Channel Divinity effects require saving throws. When you use such an effect from this class, the DC equals your paladin spell save DC.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('channel-divinity', 'paladin', 'Channel Divinity', 3, '/api/2014/features/channel-divinity');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-sacred-weapon', 0, 'As an action, you can imbue one weapon that you are holding with positive energy, using your Channel Divinity. For 1 minute, you add your Charisma modifier to attack rolls made with that weapon (with a minimum bonus of +1). The weapon also emits bright light in a 20-foot radius and dim light 20 feet beyond that. If the weapon is not already magical, it becomes magical for the duration.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-sacred-weapon', 1, 'You can end this effect on your turn as part of any other action. If you are no longer holding or carrying this weapon, or if you fall unconscious, this effect ends.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('channel-divinity-sacred-weapon', 'paladin', 'Channel Divinity: Sacred Weapon', 3, '/api/2014/features/channel-divinity-sacred-weapon', 'devotion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-turn-the-unholy', 0, 'As an action, you present your holy symbol and speak a prayer censuring fiends and undead, using your Channel Divinity. Each fiend or undead that can see or hear you within 30 feet of you must make a Wisdom saving throw. If the creature fails its saving throw, it is turned for 1 minute or until it takes damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('channel-divinity-turn-the-unholy', 1, 'A turned creature must spend its turns trying to move as far away from you as it can, and it can''t willingly move to a space within 30 feet of you. It also can''t take reactions. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If there''s nowhere to move, the creature can use the Dodge action.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('channel-divinity-turn-the-unholy', 'paladin', 'Channel Divinity: Turn the Unholy', 3, '/api/2014/features/channel-divinity-turn-the-unholy', 'devotion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-ability-score-improvement-1', 'paladin', 'Ability Score Improvement', 4, '/api/2014/features/paladin-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-extra-attack', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-extra-attack', 'paladin', 'Extra Attack', 5, '/api/2014/features/paladin-extra-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-protection', 0, 'Starting at 6th level, whenever you or a friendly creature within 10 feet of you must make a saving throw, the creature gains a bonus to the saving throw equal to your Charisma modifier (with a minimum bonus of +1). You must be conscious to grant this bonus.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-protection', 1, 'At 18th level, the range of this aura increases to 30 feet.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('aura-of-protection', 'paladin', 'Aura of Protection', 6, '/api/2014/features/aura-of-protection');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-1', 0, 'When you reach 3rd level, you swear the oath that binds you as a paladin forever. Up to this time you have been in a preparatory stage, committed to the path but not yet sworn to it. Now you choose an oath, such as the Oath of Devotion.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-1', 1, 'Your choice grants you features at 3rd level and again at 7th, 15th, and 20th level. Those features include oath spells and the Channel Divinity feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sacred-oath-improvement-1', 'paladin', 'Sacred Oath feature', 7, '/api/2014/features/sacred-oath-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-devotion', 0, 'Starting at 7th level, you and friendly creatures within 10 feet of you can''t be charmed while you are conscious.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-devotion', 1, 'At 18th level, the range of this aura increases to 30 feet.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('aura-of-devotion', 'paladin', 'Aura of Devotion', 7, '/api/2014/features/aura-of-devotion', 'devotion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-ability-score-improvement-2', 'paladin', 'Ability Score Improvement', 8, '/api/2014/features/paladin-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-courage', 0, 'Starting at 10th level, you and friendly creatures within 10 feet of you can''t be frightened while you are conscious.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-of-courage', 1, 'At 18th level, the range of this aura increases to 30 feet.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('aura-of-courage', 'paladin', 'Aura of Courage', 10, '/api/2014/features/aura-of-courage');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('improved-divine-smite', 0, 'By 11th level, you are so suffused with righteous might that all your melee weapon strikes carry divine power with them. Whenever you hit a creature with a melee weapon, the creature takes an extra 1d8 radiant damage. If you also use your Divine Smite with an attack, you add this damage to the extra damage of your Divine Smite.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('improved-divine-smite', 'paladin', 'Improved Divine Smite', 11, '/api/2014/features/improved-divine-smite');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-ability-score-improvement-3', 'paladin', 'Ability Score Improvement', 12, '/api/2014/features/paladin-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleansing-touch', 0, 'Beginning at 14th level, you can use your action to end one spell on yourself or on one willing creature that you touch.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cleansing-touch', 1, 'You can use this feature a number of times equal to your Charisma modifier (a minimum of once). You regain expended uses when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cleansing-touch', 'paladin', 'Cleansing Touch', 14, '/api/2014/features/cleansing-touch');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-2', 0, 'When you reach 3rd level, you swear the oath that binds you as a paladin forever. Up to this time you have been in a preparatory stage, committed to the path but not yet sworn to it. Now you choose an oath, such as the Oath of Devotion.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-2', 1, 'Your choice grants you features at 3rd level and again at 7th, 15th, and 20th level. Those features include oath spells and the Channel Divinity feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sacred-oath-improvement-2', 'paladin', 'Sacred Oath feature', 15, '/api/2014/features/sacred-oath-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('purity-of-spirit', 0, 'Beginning at 15th level, you are always under the effects of a protection from evil and good spell.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('purity-of-spirit', 'paladin', 'Purity of Spirit', 15, '/api/2014/features/purity-of-spirit', 'devotion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-ability-score-improvement-4', 'paladin', 'Ability Score Improvement', 16, '/api/2014/features/paladin-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('aura-improvements', 0, 'At 18th level, the range of your auras increase to 30 feet.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('aura-improvements', 'paladin', 'Aura improvements', 18, '/api/2014/features/aura-improvements');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('paladin-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('paladin-ability-score-improvement-5', 'paladin', 'Ability Score Improvement', 19, '/api/2014/features/paladin-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-3', 0, 'When you reach 3rd level, you swear the oath that binds you as a paladin forever. Up to this time you have been in a preparatory stage, committed to the path but not yet sworn to it. Now you choose an oath, such as the Oath of Devotion.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sacred-oath-improvement-3', 1, 'Your choice grants you features at 3rd level and again at 7th, 15th, and 20th level. Those features include oath spells and the Channel Divinity feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sacred-oath-improvement-3', 'paladin', 'Sacred Oath feature', 20, '/api/2014/features/sacred-oath-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('holy-nimbus', 0, 'At 20th level, as an action, you can emanate an aura of sunlight. For 1 minute, bright light shines from you in a 30-foot radius, and dim light shines 30 feet beyond that.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('holy-nimbus', 1, 'Whenever an enemy creature starts its turn in the bright light, the creature takes 10 radiant damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('holy-nimbus', 2, 'In addition, for the duration, you have advantage on saving throws against spells cast by fiends or undead.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('holy-nimbus', 'paladin', 'Holy Nimbus', 20, '/api/2014/features/holy-nimbus', 'devotion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-1-type', 0, 'Beginning at 1st level, you have significant experience studying, tracking, hunting, and even talking to a certain type of enemy.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-1-type', 1, 'Choose a type of favored enemy: aberrations, beasts, celestials, constructs, dragons, elementals, fey, fiends, giants, monstrosities, oozes, plants, or undead. Alternatively, you can select two races of humanoid (such as gnolls and orcs) as favored enemies.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-1-type', 2, 'You have advantage on Wisdom (Survival) checks to track your favored enemies, as well as on Intelligence checks to recall information about them.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-1-type', 3, 'When you gain this feature, you also learn one language of your choice that is spoken by your favored enemies, if they speak one at all.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-1-type', 4, 'You choose one additional favored enemy, as well as an associated language, at 6th and 14th level. As you gain levels, your choices should reflect the types of monsters you have encountered on your adventures.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_enemy_type_options_desc, feature_specific_enemy_type_options_choose, feature_specific_enemy_type_options_type, feature_specific_enemy_type_options_from_option_set_type) VALUES ('favored-enemy-1-type', 'ranger', 'Favored Enemy (1 type)', 1, '/api/2014/features/favored-enemy-1-type', 'one enemy type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 0, 'You are particularly familiar with one type of natural environment and are adept at traveling and surviving in such regions. Choose one type of favored terrain: arctic, coast, desert, forest, grassland, mountain, or swamp. When you make an Intelligence or Wisdom check related to your favored terrain, your proficiency bonus is doubled if you are using a skill that you''re proficient in.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 1, 'While traveling for an hour or more in your favored terrain, you gain the following benefits:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 2, '- Difficult terrain doesn''t slow your group''s travel.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 3, '- Your group can''t become lost except by magical means.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 4, '- Even when you are engaged in another activity while traveling (such as foraging, navigating, or tracking), you remain alert to danger.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 5, '- If you are traveling alone, you can move stealthily at a normal pace.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 6, '- When you forage, you find twice as much food as you normally would.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 7, '- While tracking other creatures, you also learn their exact number, their sizes, and how long ago they passed through the area.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-1-terrain-type', 8, 'You choose additional favored terrain types at 6th and 10th level.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_terrain_type_options_desc, feature_specific_terrain_type_options_choose, feature_specific_terrain_type_options_type, feature_specific_terrain_type_options_from_option_set_type) VALUES ('natural-explorer-1-terrain-type', 'ranger', 'Natural Explorer (1 terrain type)', 1, '/api/2014/features/natural-explorer-1-terrain-type', 'one terrain type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-fighting-style', 0, 'At 2nd level, you adopt a particular style of fighting as your specialty. Choose one of the following options. You can''t take a Fighting Style option more than once, even if you later get to choose again.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('ranger-fighting-style', 'ranger', 'Fighting Style', 2, '/api/2014/features/ranger-fighting-style', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-fighting-style-archery', 0, 'You gain a +2 bonus to attack rolls you make with ranged weapons.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('ranger-fighting-style-archery', 'ranger', 'Fighting Style: Archery', 2, '/api/2014/features/ranger-fighting-style-archery', 'ranger-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-fighting-style-defense', 0, 'While you are wearing armor, you gain a +1 bonus to AC.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('ranger-fighting-style-defense', 'ranger', 'Fighting Style: Defense', 2, '/api/2014/features/ranger-fighting-style-defense', 'ranger-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-fighting-style-dueling', 0, 'When you are wielding a melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('ranger-fighting-style-dueling', 'ranger', 'Fighting Style: Dueling', 2, '/api/2014/features/ranger-fighting-style-dueling', 'ranger-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-fighting-style-two-weapon-fighting', 0, 'When you engage in two-weapon fighting, you can add your ability modifier to the damage of the second attack.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('ranger-fighting-style-two-weapon-fighting', 'ranger', 'Fighting Style: Two-Weapon Fighting', 2, '/api/2014/features/ranger-fighting-style-two-weapon-fighting', 'ranger-fighting-style');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-ranger', 0, 'By the time you reach 2nd level, you have learned to use the magical essence of nature to cast spells, much as a druid does.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-ranger', 'ranger', 'Spellcasting: Ranger', 2, '/api/2014/features/spellcasting-ranger', '/api/2014/classes/ranger/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-archetype', 0, 'At 3rd level, you choose an archetype that you strive to emulate, such as the Hunter. Your choice grants you features at 3rd level and again at 7th, 11th, and 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-archetype', 'ranger', 'Ranger Archetype', 3, '/api/2014/features/ranger-archetype');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey', 0, 'At 3rd level, you gain one of the following features of your choice.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey', 1, 'Colossus Slayer');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey', 2, 'Giant Killer');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey', 3, 'Horde Breaker');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('hunters-prey', 'ranger', 'Hunter''s Prey', 3, '/api/2014/features/hunters-prey', 'hunter', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey-colossus-slayer', 0, 'Your tenacity can wear down the most potent foes. When you hit a creature with a weapon attack, the creature takes an extra 1d8 damage if it''s below its hit point maximum. You can deal this extra damage only once per turn.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('hunters-prey-colossus-slayer', 'ranger', 'Hunter''s Prey: Colossus Slayer', 3, '/api/2014/features/hunters-prey-colossus-slayer', 'hunter', 'hunters-prey');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey-giant-killer', 0, 'When a Large or larger creature within 5 feet of you hits or misses you with an attack, you can use your reaction to attack that creature immediately after its attack, provided that you can see the creature.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('hunters-prey-giant-killer', 'ranger', 'Hunter''s Prey: Giant Killer', 3, '/api/2014/features/hunters-prey-giant-killer', 'hunter', 'hunters-prey');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hunters-prey-horde-breaker', 0, 'Once on each of your turns when you make a weapon attack, you can make another attack with the same weapon against a different creature that is within 5 feet of the original target and within range of your weapon.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('hunters-prey-horde-breaker', 'ranger', 'Hunter''s Prey: Horde Breaker', 3, '/api/2014/features/hunters-prey-horde-breaker', 'hunter', 'hunters-prey');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('primeval-awareness', 0, 'Beginning at 3rd level, you can use your action and expend one ranger spell slot to focus your awareness on the region around you. For 1 minute per level of the spell slot you expend, you can sense whether the following types of creatures are present within 1 mile of you (or within up to 6 miles if you are in your favored terrain): aberrations, celestials, dragons, elementals, fey, fiends, and undead. This feature doesn''t reveal the creatures'' location or number.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('primeval-awareness', 'ranger', 'Primeval Awareness', 3, '/api/2014/features/primeval-awareness');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-ability-score-improvement-1', 'ranger', 'Ability Score Improvement', 4, '/api/2014/features/ranger-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-extra-attack', 0, 'Beginning at 5th level, you can attack twice, instead of once, whenever you take the Attack action on your turn.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-extra-attack', 'ranger', 'Extra Attack', 5, '/api/2014/features/ranger-extra-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-2-types', 0, 'Beginning at 1st level, you have significant experience studying, tracking, hunting, and even talking to a certain type of enemy.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-2-types', 1, 'Choose a type of favored enemy: aberrations, beasts, celestials, constructs, dragons, elementals, fey, fiends, giants, monstrosities, oozes, plants, or undead. Alternatively, you can select two races of humanoid (such as gnolls and orcs) as favored enemies.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-2-types', 2, 'You have advantage on Wisdom (Survival) checks to track your favored enemies, as well as on Intelligence checks to recall information about them.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-2-types', 3, 'When you gain this feature, you also learn one language of your choice that is spoken by your favored enemies, if they speak one at all.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-2-types', 4, 'You choose one additional favored enemy, as well as an associated language, at 6th and 14th level. As you gain levels, your choices should reflect the types of monsters you have encountered on your adventures.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_enemy_type_options_desc, feature_specific_enemy_type_options_choose, feature_specific_enemy_type_options_type, feature_specific_enemy_type_options_from_option_set_type) VALUES ('favored-enemy-2-types', 'ranger', 'Favored Enemy (2 types)', 6, '/api/2014/features/favored-enemy-2-types', 'one enemy type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 0, 'You are particularly familiar with one type of natural environment and are adept at traveling and surviving in such regions. Choose one type of favored terrain: arctic, coast, desert, forest, grassland, mountain, or swamp. When you make an Intelligence or Wisdom check related to your favored terrain, your proficiency bonus is doubled if you are using a skill that you''re proficient in.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 1, 'While traveling for an hour or more in your favored terrain, you gain the following benefits:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 2, '- Difficult terrain doesn''t slow your group''s travel.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 3, '- Your group can''t become lost except by magical means.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 4, '- Even when you are engaged in another activity while traveling (such as foraging, navigating, or tracking), you remain alert to danger.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 5, '- If you are traveling alone, you can move stealthily at a normal pace.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 6, '- When you forage, you find twice as much food as you normally would.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 7, '- While tracking other creatures, you also learn their exact number, their sizes, and how long ago they passed through the area.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-2-terrain-types', 8, 'You choose additional favored terrain types at 6th and 10th level.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_terrain_type_options_desc, feature_specific_terrain_type_options_choose, feature_specific_terrain_type_options_type, feature_specific_terrain_type_options_from_option_set_type) VALUES ('natural-explorer-2-terrain-types', 'ranger', 'Natural Explorer (2 terrain types)', 6, '/api/2014/features/natural-explorer-2-terrain-types', 'one terrain type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-archetype-improvement-1', 0, 'At 3rd level, you choose an archetype that you strive to emulate, such as the Hunter. Your choice grants you features at 3rd level and again at 7th, 11th, and 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-archetype-improvement-1', 'ranger', 'Ranger Archetype feature', 7, '/api/2014/features/ranger-archetype-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics', 0, 'At 7th level, you gain one of the following features of your choice.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics', 1, 'Escape the Horde');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics', 2, 'Multiattack Defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics', 3, 'Steel Will');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('defensive-tactics', 'ranger', 'Defensive Tactics', 7, '/api/2014/features/defensive-tactics', 'hunter', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics-escape-the-horde', 0, 'Opportunity attacks against you are made with disadvantage.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('defensive-tactics-escape-the-horde', 'ranger', 'Defensive Tactics: Escape the Horde', 7, '/api/2014/features/defensive-tactics-escape-the-horde', 'hunter', 'defensive-tactics');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics-multiattack-defense', 0, 'When a creature hits you with an attack, you gain a +4 bonus to AC against all subsequent attacks made by that creature for the rest of the turn.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('defensive-tactics-multiattack-defense', 'ranger', 'Defensive Tactics: Multiattack Defense', 7, '/api/2014/features/defensive-tactics-multiattack-defense', 'hunter', 'defensive-tactics');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('defensive-tactics-steel-will', 0, 'You have advantage on saving throws against being frightened.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('defensive-tactics-steel-will', 'ranger', 'Defensive Tactics: Steel Will', 7, '/api/2014/features/defensive-tactics-steel-will', 'hunter', 'defensive-tactics');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-ability-score-improvement-2', 'ranger', 'Ability Score Improvement', 8, '/api/2014/features/ranger-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-lands-stride', 0, 'Starting at 8th level, moving through nonmagical difficult terrain costs you no extra movement. You can also pass through nonmagical plants without being slowed by them and without taking damage from them if they have thorns, spines, or a similar hazard.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-lands-stride', 1, 'In addition, you have advantage on saving throws against plants that are magically created or manipulated to impede movement, such those created by the entangle spell.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-lands-stride', 'ranger', 'Land''s Stride', 8, '/api/2014/features/ranger-lands-stride');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 0, 'You are particularly familiar with one type of natural environment and are adept at traveling and surviving in such regions. Choose one type of favored terrain: arctic, coast, desert, forest, grassland, mountain, or swamp. When you make an Intelligence or Wisdom check related to your favored terrain, your proficiency bonus is doubled if you are using a skill that you''re proficient in.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 1, 'While traveling for an hour or more in your favored terrain, you gain the following benefits:');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 2, '- Difficult terrain doesn''t slow your group''s travel.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 3, '- Your group can''t become lost except by magical means.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 4, '- Even when you are engaged in another activity while traveling (such as foraging, navigating, or tracking), you remain alert to danger.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 5, '- If you are traveling alone, you can move stealthily at a normal pace.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 6, '- When you forage, you find twice as much food as you normally would.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 7, '- While tracking other creatures, you also learn their exact number, their sizes, and how long ago they passed through the area.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('natural-explorer-3-terrain-types', 8, 'You choose additional favored terrain types at 6th and 10th level.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_terrain_type_options_desc, feature_specific_terrain_type_options_choose, feature_specific_terrain_type_options_type, feature_specific_terrain_type_options_from_option_set_type) VALUES ('natural-explorer-3-terrain-types', 'ranger', 'Natural Explorer (3 terrain types)', 10, '/api/2014/features/natural-explorer-3-terrain-types', 'one terrain type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hide-in-plain-sight', 0, 'Starting at 10th level, you can spend 1 minute creating camouflage for yourself. You must have access to fresh mud, dirt, plants, soot, and other naturally occurring materials with which to create your camouflage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hide-in-plain-sight', 1, 'Once you are camouflaged in this way, you can try to hide by pressing yourself up against a solid surface, such as a tree or wall, that is at least as tall and wide as you are. You gain a +10 bonus to Dexterity (Stealth) checks as long as you remain there without moving or taking actions. Once you move or take an action or a reaction, you must camouflage yourself again to gain this benefit.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('hide-in-plain-sight', 'ranger', 'Hide in Plain Sight', 10, '/api/2014/features/hide-in-plain-sight');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-archetype-improvement-2', 0, 'At 3rd level, you choose an archetype that you strive to emulate, such as the Hunter. Your choice grants you features at 3rd level and again at 7th, 11th, and 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-archetype-improvement-2', 'ranger', 'Ranger Archetype feature', 11, '/api/2014/features/ranger-archetype-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('multiattack', 0, 'At 11th level, you gain one of the following features of your choice.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('multiattack', 1, 'Volley');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('multiattack', 2, 'Whirlwind Attack');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('multiattack', 'ranger', 'Multiattack', 11, '/api/2014/features/multiattack', 'hunter', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('multiattack-volley', 0, 'You can use your action to make a ranged attack against any number of creatures within 10 feet of a point you can see within your weapon''s range. You must have ammunition for each target, as normal, and you make a separate attack roll for each target.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('multiattack-volley', 'ranger', 'Multiattack: Volley', 11, '/api/2014/features/multiattack-volley', 'hunter', 'multiattack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('multiattack-whirlwind-attack', 0, 'You can use your action to make a melee attack against any number of creatures within 5 feet of you, with a separate attack roll for each target.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('multiattack-whirlwind-attack', 'ranger', 'Multiattack: Whirlwind Attack', 11, '/api/2014/features/multiattack-whirlwind-attack', 'hunter', 'multiattack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-ability-score-improvement-3', 'ranger', 'Ability Score Improvement', 12, '/api/2014/features/ranger-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-3-enemies', 0, 'Beginning at 1st level, you have significant experience studying, tracking, hunting, and even talking to a certain type of enemy.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-3-enemies', 1, 'Choose a type of favored enemy: aberrations, beasts, celestials, constructs, dragons, elementals, fey, fiends, giants, monstrosities, oozes, plants, or undead. Alternatively, you can select two races of humanoid (such as gnolls and orcs) as favored enemies.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-3-enemies', 2, 'You have advantage on Wisdom (Survival) checks to track your favored enemies, as well as on Intelligence checks to recall information about them.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-3-enemies', 3, 'When you gain this feature, you also learn one language of your choice that is spoken by your favored enemies, if they speak one at all.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('favored-enemy-3-enemies', 4, 'You choose one additional favored enemy, as well as an associated language, at 6th and 14th level. As you gain levels, your choices should reflect the types of monsters you have encountered on your adventures.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_enemy_type_options_desc, feature_specific_enemy_type_options_choose, feature_specific_enemy_type_options_type, feature_specific_enemy_type_options_from_option_set_type) VALUES ('favored-enemy-3-enemies', 'ranger', 'Favored Enemy (3 enemies)', 14, '/api/2014/features/favored-enemy-3-enemies', 'one enemy type', 1, 'string', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('vanish', 0, 'Starting at 14th level, you can use the Hide action as a bonus action on your turn. Also, you can''t be tracked by nonmagical means, unless you choose to leave a trail.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('vanish', 'ranger', 'Vanish', 14, '/api/2014/features/vanish');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-archetype-improvement-3', 0, 'At 3rd level, you choose an archetype that you strive to emulate, such as the Hunter. Your choice grants you features at 3rd level and again at 7th, 11th, and 15th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-archetype-improvement-3', 'ranger', 'Ranger Archetype feature', 15, '/api/2014/features/ranger-archetype-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense', 0, 'At 15th level, you gain one of the following features of your choice.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense', 1, 'Evasion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense', 2, 'Stand Against the Tide');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense', 3, 'Uncanny Dodge');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('superior-hunters-defense', 'ranger', 'Superior Hunter''s Defense', 15, '/api/2014/features/superior-hunters-defense', 'hunter', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense-evasion', 0, 'When you are subjected to an effect, such as a red dragon''s fiery breath or a lightning bolt spell, that allows you to make a Dexterity saving throw to take only half damage, you instead take no damage if you succeed on the saving throw, and only half damage if you fail.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('superior-hunters-defense-evasion', 'ranger', 'Superior Hunter''s Defense: Evasion', 15, '/api/2014/features/superior-hunters-defense-evasion', 'hunter', 'superior-hunters-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense-stand-against-the-tide', 0, 'When a hostile creature misses you with a melee attack, you can use your reaction to force that creature to repeat the same attack against another creature (other than itself) of your choice.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('superior-hunters-defense-stand-against-the-tide', 'ranger', 'Superior Hunter''s Defense: Stand Against the Tide', 15, '/api/2014/features/superior-hunters-defense-stand-against-the-tide', 'hunter', 'superior-hunters-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('superior-hunters-defense-uncanny-dodge', 0, 'When an attacker that you can see hits you with an attack, you can use your reaction to halve the attack''s damage against you.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('superior-hunters-defense-uncanny-dodge', 'ranger', 'Superior Hunter''s Defense: Uncanny Dodge', 15, '/api/2014/features/superior-hunters-defense-uncanny-dodge', 'hunter', 'superior-hunters-defense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-ability-score-improvement-4', 'ranger', 'Ability Score Improvement', 16, '/api/2014/features/ranger-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('feral-senses', 0, 'At 18th level, you gain preternatural senses that help you fight creatures you can''t see. When you attack a creature you can''t see, your inability to see it doesn''t impose disadvantage on your attack rolls against it.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('feral-senses', 1, 'You are also aware of the location of any invisible creature within 30 feet of you, provided that the creature isn''t hidden from you and you aren''t blinded or deafened.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('feral-senses', 'ranger', 'Feral Senses', 18, '/api/2014/features/feral-senses');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('ranger-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('ranger-ability-score-improvement-5', 'ranger', 'Ability Score Improvement', 19, '/api/2014/features/ranger-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('foe-slayer', 0, 'At 20th level, you become an unparalleled hunter of your enemies. Once on each of your turns, you can add your Wisdom modifier to the attack roll or the damage roll of an attack you make against one of your favored enemies. You can choose to use this feature before or after the roll, but before any effects of the roll are applied.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('foe-slayer', 'ranger', 'Foe Slayer', 20, '/api/2014/features/foe-slayer');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-expertise-1', 0, 'At 1st level, choose two of your skill proficiencies, or one of your skill proficiencies and your proficiency with thieves'' tools. Your proficiency bonus is doubled for any ability check you make that uses either of the chosen proficiencies.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-expertise-1', 1, 'At 6th level, you can choose two more of your proficiencies (in skills or with thieves'' tools) to gain this benefit');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_expertise_options_choose, feature_specific_expertise_options_type, feature_specific_expertise_options_from_option_set_type) VALUES ('rogue-expertise-1', 'rogue', 'Expertise', 1, '/api/2014/features/rogue-expertise-1', 1, 'proficiency', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sneak-attack', 0, 'Beginning at 1st level, you know how to strike subtly and exploit a foe''s distraction. Once per turn, you can deal an extra 1d6 damage to one creature you hit with an attack if you have advantage on the attack roll. The attack must use a finesse or a ranged weapon.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sneak-attack', 1, 'You don''t need advantage on the attack roll if another enemy of the target is within 5 feet of it, that enemy isn''t incapacitated, and you don''t have disadvantage on the attack roll.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sneak-attack', 2, 'The amount of the extra damage increases as you gain levels in this class, as shown in the Sneak Attack column of the Rogue table.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sneak-attack', 'rogue', 'Sneak Attack', 1, '/api/2014/features/sneak-attack');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('thieves-cant', 0, 'During your rogue training you learned thieves'' cant, a secret mix of dialect, jargon, and code that allows you to hide messages in seemingly normal conversation. Only another creature that knows thieves'' cant understands such messages. It takes four times longer to convey such a message than it does to speak the same idea plainly.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('thieves-cant', 1, 'In addition, you understand a set of secret signs and symbols used to convey short, simple messages, such as whether an area is dangerous or the territory of a thieves'' guild, whether loot is nearby, or whether the people in an area are easy marks or will provide a safe house for thieves on the run.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('thieves-cant', 'rogue', 'Thieves'' Cant', 1, '/api/2014/features/thieves-cant');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('cunning-action', 0, 'Starting at 2nd level, your quick thinking and agility allow you to move and act quickly. You can take a bonus action on each of your turns in combat. This action can be used only to take the Dash, Disengage, or Hide action.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('cunning-action', 'rogue', 'Cunning Action', 2, '/api/2014/features/cunning-action');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('roguish-archetype', 0, 'At 3rd level, you choose an archetype that you emulate in the exercise of your rogue abilities, such as Thief. Additional archetypes are available in the original source material. Your archetype choice grants you features at 3rd level and then again at 9th, 13th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('roguish-archetype', 'rogue', 'Roguish Archetype', 3, '/api/2014/features/roguish-archetype');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fast-hands', 0, 'Starting at 3rd level, you can use the bonus action granted by your Cunning Action to make a Dexterity (Sleight of Hand) check, use your thieves'' tools to disarm a trap or open a lock, or take the Use an Object action.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('fast-hands', 'rogue', 'Fast Hands', 3, '/api/2014/features/fast-hands', 'thief');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('second-story-work', 0, 'When you choose this archetype at 3rd level, you gain the ability to climb faster than normal; climbing no longer costs you extra movement.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('second-story-work', 1, 'In addition, when you make a running jump, the distance you cover increases by a number of feet equal to your Dexterity modifier.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('second-story-work', 'rogue', 'Second-Story Work', 3, '/api/2014/features/second-story-work', 'thief');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-1', 'rogue', 'Ability Score Improvement', 4, '/api/2014/features/rogue-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('uncanny-dodge', 0, 'Starting at 5th level, when an attacker that you can see hits you with an attack, you can use your reaction to halve the attack''s damage against you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('uncanny-dodge', 'rogue', 'Uncanny Dodge', 5, '/api/2014/features/uncanny-dodge');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-expertise-2', 0, 'At 1st level, choose two of your skill proficiencies, or one of your skill proficiencies and your proficiency with thieves'' tools. Your proficiency bonus is doubled for any ability check you make that uses either of the chosen proficiencies.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-expertise-2', 1, 'At 6th level, you can choose two more of your proficiencies (in skills or with thieves'' tools) to gain this benefit');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_expertise_options_choose, feature_specific_expertise_options_type, feature_specific_expertise_options_from_option_set_type) VALUES ('rogue-expertise-2', 'rogue', 'Expertise', 6, '/api/2014/features/rogue-expertise-2', 2, 'proficiency', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-evasion', 0, 'Beginning at 7th level, you can nimbly dodge out of the way of certain area effects, such as a red dragon''s fiery breath or an ice storm spell. When you are subjected to an effect that allows you to make a Dexterity saving throw to take only half damage, you instead take no damage if you succeed on the saving throw, and only half damage if you fail.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-evasion', 'rogue', 'Evasion', 7, '/api/2014/features/rogue-evasion');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-2', 'rogue', 'Ability Score Improvement', 8, '/api/2014/features/rogue-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('roguish-archetype-improvement-1', 0, 'At 3rd level, you choose an archetype that you emulate in the exercise of your rogue abilities, such as Thief. Additional archetypes are available in the original source material. Your archetype choice grants you features at 3rd level and then again at 9th, 13th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('roguish-archetype-improvement-1', 'rogue', 'Roguish Archetype feature', 9, '/api/2014/features/roguish-archetype-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('supreme-sneak', 0, 'Starting at 9th level, you have advantage on a Dexterity (Stealth) check if you move no more than half your speed on the same turn.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('supreme-sneak', 'rogue', 'Supreme Sneak', 9, '/api/2014/features/supreme-sneak', 'thief');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-3', 'rogue', 'Ability Score Improvement', 10, '/api/2014/features/rogue-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('reliable-talent', 0, 'By 11th level, you have refined your chosen skills until they approach perfection. Whenever you make an ability check that lets you add your proficiency bonus, you can treat a d20 roll of 9 or lower as a 10.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('reliable-talent', 'rogue', 'Reliable Talent', 11, '/api/2014/features/reliable-talent');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-4', 'rogue', 'Ability Score Improvement', 12, '/api/2014/features/rogue-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('roguish-archetype-improvement-2', 0, 'At 3rd level, you choose an archetype that you emulate in the exercise of your rogue abilities, such as Thief. Additional archetypes are available in the original source material. Your archetype choice grants you features at 3rd level and then again at 9th, 13th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('roguish-archetype-improvement-2', 'rogue', 'Roguish Archetype feature', 13, '/api/2014/features/roguish-archetype-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('use-magic-device', 0, 'By 13th level, you have learned enough about the workings of magic that you can improvise the use of items even when they are not intended for you. You ignore all class, race, and level requirements on the use of magic items.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('use-magic-device', 'rogue', 'Use Magic Device', 13, '/api/2014/features/use-magic-device', 'thief');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('blindsense', 0, 'Starting at 14th level, if you are able to hear, you are aware of the location of any hidden or invisible creature within 10 feet of you.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('blindsense', 'rogue', 'Blindsense', 14, '/api/2014/features/blindsense');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('slippery-mind', 0, 'By 15th level, you have acquired greater mental strength. You gain proficiency in Wisdom saving throws.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('slippery-mind', 'rogue', 'Slippery Mind', 15, '/api/2014/features/slippery-mind');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-5', 'rogue', 'Ability Score Improvement', 16, '/api/2014/features/rogue-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('roguish-archetype-improvement-3', 0, 'At 3rd level, you choose an archetype that you emulate in the exercise of your rogue abilities, such as Thief. Additional archetypes are available in the original source material. Your archetype choice grants you features at 3rd level and then again at 9th, 13th, and 17th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('roguish-archetype-improvement-3', 'rogue', 'Roguish Archetype feature', 17, '/api/2014/features/roguish-archetype-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('thiefs-reflexes', 0, 'When you reach 17th level, you have become adept at laying ambushes and quickly escaping danger. You can take two turns during the first round of any combat. You take your first turn at your normal initiative and your second turn at your initiative minus 10. You can''t use this feature when you are surprised.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('thiefs-reflexes', 'rogue', 'Thief''s Reflexes', 17, '/api/2014/features/thiefs-reflexes', 'thief');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('elusive', 0, 'Beginning at 18th level, you are so evasive that attackers rarely gain the upper hand against you. No attack roll has advantage against you while you aren''t incapacitated.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('elusive', 'rogue', 'Elusive', 18, '/api/2014/features/elusive');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('rogue-ability-score-improvement-6', 0, 'When you reach 4th level, and again at 8th, 10th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('rogue-ability-score-improvement-6', 'rogue', 'Ability Score Improvement', 19, '/api/2014/features/rogue-ability-score-improvement-6');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('stroke-of-luck', 0, 'At 20th level, you have an uncanny knack for succeeding when you need to. If your attack misses a target within range, you can turn the miss into a hit. Alternatively, if you fail an ability check, you can treat the d20 roll as a 20.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('stroke-of-luck', 1, 'Once you use this feature, you can''t use it again until you finish a short or long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('stroke-of-luck', 'rogue', 'Stroke of Luck', 20, '/api/2014/features/stroke-of-luck');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-sorcerer', 0, 'An event in your past, or in the life of a parent or ancestor, left an indelible mark on you, infusing you with arcane magic. This font of magic, whatever its origin, fuels your spells.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-sorcerer', 'sorcerer', 'Spellcasting: Sorcerer', 1, '/api/2014/features/spellcasting-sorcerer', '/api/2014/classes/sorcerer/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin', 0, 'Choose a sorcerous origin, which describes the source of your innate magical power, such as Draconic Bloodline.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin', 1, 'Your choice grants you features when you choose it at 1st level and again at 6th, 14th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerous-origin', 'sorcerer', 'Sorcerous Origin', 1, '/api/2014/features/sorcerous-origin');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dragon-ancestor', 0, 'At 1st level, you choose one type of dragon as your ancestor. The damage type associated with each dragon is used by features you gain later.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dragon-ancestor', 1, 'You can speak, read, and write Draconic. Additionally, whenever you make a Charisma check when interacting with dragons, your proficiency bonus is doubled if it applies to the check.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('dragon-ancestor', 'sorcerer', 'Dragon Ancestor', 1, '/api/2014/features/dragon-ancestor', 'draconic', 1, 'feature', 'options_array');
