INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dragon-ancestor-white---cold-damage', 1, 'You can speak, read, and write Draconic. Additionally, whenever you make a Charisma check when interacting with dragons, your proficiency bonus is doubled if it applies to the check.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, parent_index) VALUES ('dragon-ancestor-white---cold-damage', 'sorcerer', 'Dragon Ancestor: White - Cold Damage', 1, '/api/2014/features/dragon-ancestor-white---cold-damage', 'draconic', 'dragon-ancestor');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('draconic-resilience', 0, 'As magic flows through your body, it causes physical traits of your dragon ancestors to emerge. At 1st level, your hit point maximum increases by 1 and increases by 1 again whenever you gain a level in this class.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('draconic-resilience', 1, 'Additionally, parts of your skin are covered by a thin sheen of dragon-like scales. When you aren''t wearing armor, your AC equals 13 + your Dexterity modifier.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('draconic-resilience', 'sorcerer', 'Draconic Resilience', 1, '/api/2014/features/draconic-resilience', 'draconic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('font-of-magic', 0, 'At 2nd level, you tap into a deep wellspring of magic within yourself. This wellspring is represented by sorcery points, which allow you to create a variety of magical effects.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('font-of-magic', 1, 'Sorcery Points');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('font-of-magic', 2, 'You have 2 sorcery points, and you gain more as you reach higher levels, as shown in the Sorcery Points column of the Sorcerer table. You can never have more sorcery points than shown on the table for your level. You regain all spent sorcery points when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('font-of-magic', 'sorcerer', 'Font of Magic', 2, '/api/2014/features/font-of-magic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('flexible-casting-creating-spell-slots', 0, 'You can transform unexpended sorcery points into one spell slot as a bonus action on your turn. The Creating Spell Slots table shows the cost of creating a spell slot of a given level. You can create spell slots no higher in level than 5th. ');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('flexible-casting-creating-spell-slots', 1, 'Any spell slot you create with this feature vanishes when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('flexible-casting-creating-spell-slots', 'sorcerer', 'Flexible Casting: Creating Spell Slots', 2, '/api/2014/features/flexible-casting-creating-spell-slots');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('flexible-casting-converting-spell-slot', 0, 'As a bonus action on your turn, you can expend one spell slot and gain a number of sorcery points equal to the slot''s level..');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('flexible-casting-converting-spell-slot', 'sorcerer', 'Flexible Casting: Converting Spell Slot', 2, '/api/2014/features/flexible-casting-converting-spell-slot');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-1', 0, 'At 3rd level, you gain the ability to twist your spells to suit your needs. You gain two of the following Metamagic options of your choice. You gain another one at 10th and 17th level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-1', 1, 'You can use only one Metamagic option on a spell when you cast it, unless otherwise noted.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('metamagic-1', 'sorcerer', 'Metamagic', 3, '/api/2014/features/metamagic-1', 2, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-careful-spell', 0, 'When you cast a spell that forces other creatures to make a saving throw, you can protect some of those creatures from the spell''s full force. To do so, you spend 1 sorcery point and choose a number of those creatures up to your Charisma modifier (minimum of one creature). A chosen creature automatically succeeds on its saving throw against the spell.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-careful-spell', 'sorcerer', 'Metamagic: Careful Spell', 3, '/api/2014/features/metamagic-careful-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-distant-spell', 0, 'When you cast a spell that has a range of 5 feet or greater, you can spend 1 sorcery point to double the range of the spell.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-distant-spell', 1, 'When you cast a spell that has a range of touch, you can spend 1 sorcery point to make the range of the spell 30 feet.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-distant-spell', 'sorcerer', 'Metamagic: Distant Spell', 3, '/api/2014/features/metamagic-distant-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-empowered-spell', 0, 'When you roll damage for a spell, you can spend 1 sorcery point to reroll a number of the damage dice up to your Charisma modifier (minimum of one). You must use the new rolls.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-empowered-spell', 1, 'You can use Empowered Spell even if you have already used a different Metamagic option during the casting of the spell.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-empowered-spell', 'sorcerer', 'Metamagic: Empowered Spell', 3, '/api/2014/features/metamagic-empowered-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-extended-spell', 0, 'When you cast a spell that has a duration of 1 minute or longer, you can spend 1 sorcery point to double its duration, to a maximum duration of 24 hours.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-extended-spell', 'sorcerer', 'Metamagic: Extended Spell', 3, '/api/2014/features/metamagic-extended-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-heightened-spell', 0, 'When you cast a spell that forces a creature to make a saving throw to resist its effects, you can spend 3 sorcery points to give one target of the spell disadvantage on its first saving throw made against the spell.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-heightened-spell', 'sorcerer', 'Metamagic: Heightened Spell', 3, '/api/2014/features/metamagic-heightened-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-quickened-spell', 0, 'When you cast a spell that has a casting time of 1 action, you can spend 2 sorcery points to change the casting time to 1 bonus action for this casting.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-quickened-spell', 'sorcerer', 'Metamagic: Quickened Spell', 3, '/api/2014/features/metamagic-quickened-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-subtle-spell', 0, 'When you cast a spell, you can spend 1 sorcery point to cast it without any somatic or verbal components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('metamagic-subtle-spell', 'sorcerer', 'Metamagic: Subtle Spell', 3, '/api/2014/features/metamagic-subtle-spell', 'metamagic-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-twinned-spell', 0, 'When you cast a spell that targets only one creature and doesn''t have a range of self, you can spend a number of sorcery points equal to the spell''s level to target a second creature in range with the same spell (1 sorcery point if the spell is a cantrip).');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-twinned-spell', 1, 'To be eligible, a spell must be incapable of targeting more than one creature at the spell''s current level. For example, magic missile and scorching ray aren''t eligible, but ray of frost is.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('metamagic-twinned-spell', 'sorcerer', 'Metamagic: Twinned Spell', 3, '/api/2014/features/metamagic-twinned-spell');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerer-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerer-ability-score-improvement-1', 'sorcerer', 'Ability Score Improvement', 4, '/api/2014/features/sorcerer-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-1', 0, 'Choose a sorcerous origin, which describes the source of your innate magical power, such as Draconic Bloodline.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-1', 1, 'Your choice grants you features when you choose it at 1st level and again at 6th, 14th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerous-origin-improvement-1', 'sorcerer', 'Sorcerous Origin feature', 6, '/api/2014/features/sorcerous-origin-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('elemental-affinity', 0, 'Starting at 6th level, when you cast a spell that deals damage of the type associated with your draconic ancestry, you can add your Charisma modifier to one damage roll of that spell. At the same time, you can spend 1 sorcery point to gain resistance to that damage type for 1 hour.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index, reference) VALUES ('elemental-affinity', 'sorcerer', 'Elemental Affinity', 6, '/api/2014/features/elemental-affinity', 'draconic', '/api/2014/subclasses/draconic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerer-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerer-ability-score-improvement-2', 'sorcerer', 'Ability Score Improvement', 8, '/api/2014/features/sorcerer-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-2', 0, 'At 3rd level, you gain the ability to twist your spells to suit your needs. You gain two of the following Metamagic options of your choice. You gain another one at 10th and 17th level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-2', 1, 'You can use only one Metamagic option on a spell when you cast it, unless otherwise noted.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('metamagic-2', 'sorcerer', 'Metamagic', 10, '/api/2014/features/metamagic-2', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerer-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerer-ability-score-improvement-3', 'sorcerer', 'Ability Score Improvement', 12, '/api/2014/features/sorcerer-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-2', 0, 'Choose a sorcerous origin, which describes the source of your innate magical power, such as Draconic Bloodline.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-2', 1, 'Your choice grants you features when you choose it at 1st level and again at 6th, 14th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerous-origin-improvement-2', 'sorcerer', 'Sorcerous Origin feature', 14, '/api/2014/features/sorcerous-origin-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dragon-wings', 0, 'At 14th level, you gain the ability to sprout a pair of dragon wings from your back, gaining a flying speed equal to your current speed. You can create these wings as a bonus action on your turn. They last until you dismiss them as a bonus action on your turn.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dragon-wings', 1, 'You can''t manifest your wings while wearing armor unless the armor is made to accommodate them, and clothing not made to accommodate your wings might be destroyed when you manifest them.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('dragon-wings', 'sorcerer', 'Dragon Wings', 14, '/api/2014/features/dragon-wings', 'draconic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerer-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerer-ability-score-improvement-4', 'sorcerer', 'Ability Score Improvement', 16, '/api/2014/features/sorcerer-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-3', 0, 'At 3rd level, you gain the ability to twist your spells to suit your needs. You gain two of the following Metamagic options of your choice. You gain another one at 10th and 17th level.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('metamagic-3', 1, 'You can use only one Metamagic option on a spell when you cast it, unless otherwise noted.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('metamagic-3', 'sorcerer', 'Metamagic', 17, '/api/2014/features/metamagic-3', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-3', 0, 'Choose a sorcerous origin, which describes the source of your innate magical power, such as Draconic Bloodline.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-origin-improvement-3', 1, 'Your choice grants you features when you choose it at 1st level and again at 6th, 14th, and 18th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerous-origin-improvement-3', 'sorcerer', 'Sorcerous Origin feature', 18, '/api/2014/features/sorcerous-origin-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('draconic-presence', 0, 'Beginning at 18th level, you can channel the dread presence of your dragon ancestor, causing those around you to become awestruck or frightened. As an action, you can spend 5 sorcery points to draw on this power and exude an aura of awe or fear (your choice) to a distance of 60 feet. For 1 minute or until you lose your concentration (as if you were casting a concentration spell), each hostile creature that starts its turn in this aura must succeed on a Wisdom saving throw or be charmed (if you chose awe) or frightened (if you chose fear) until the aura ends. A creature that succeeds on this saving throw is immune to your aura for 24 hours.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('draconic-presence', 'sorcerer', 'Draconic Presence', 18, '/api/2014/features/draconic-presence', 'draconic');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerer-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerer-ability-score-improvement-5', 'sorcerer', 'Ability Score Improvement', 19, '/api/2014/features/sorcerer-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sorcerous-restoration', 0, 'At 20th level, you regain 4 expended sorcery points whenever you finish a short rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('sorcerous-restoration', 'sorcerer', 'Sorcerous Restoration', 20, '/api/2014/features/sorcerous-restoration');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('otherworldly-patron', 0, 'At 1st level, you have struck a bargain with an otherworldly being of your choice, such as the Fiend. Your choice grants you features at 1st level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('otherworldly-patron', 'warlock', 'Otherworldly Patron', 1, '/api/2014/features/otherworldly-patron');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dark-ones-blessing', 0, 'Starting at 1st level, when you reduce a hostile creature to 0 hit points, you gain temporary hit points equal to your Charisma modifier + your warlock level (minimum of 1).');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('dark-ones-blessing', 'warlock', 'Dark One''s Blessing', 1, '/api/2014/features/dark-ones-blessing', 'fiend');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-magic', 0, 'Your arcane research and the magic bestowed on you by your patron have given you facility with spells.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('pact-magic', 'warlock', 'Pact Magic', 1, '/api/2014/features/pact-magic', '/api/2014/classes/warlock/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocations', 0, 'In your study of occult lore, you have unearthed eldritch invocations, fragments of forbidden knowledge that imbue you with an abiding magical ability.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocations', 1, 'At 2nd level, you gain two eldritch invocations of your choice. Your invocation options are detailed at the end of the class description. When you gain certain warlock levels, you gain additional invocations of your choice, as shown in the Invocations Known column of the Warlock table.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocations', 2, 'Additionally, when you gain a level in this class, you can choose one of the invocations you know and replace it with another invocation that you could learn at that level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('eldritch-invocations', 'warlock', 'Eldritch Invocations', 2, '/api/2014/features/eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", spell) VALUES ('eldritch-invocation-agonizing-blast', 0, 'spell', '/api/2014/spells/eldritch-blast');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-agonizing-blast', 0, 'When you cast eldritch blast, add your Charisma modifier to the damage it deals on a hit.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-agonizing-blast', 'warlock', 'Eldritch Invocation: Agonizing Blast', 2, '/api/2014/features/eldritch-invocation-agonizing-blast', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-armor-of-shadows', 0, 'You can cast mage armor on yourself at will, without expending a spell slot or material components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-armor-of-shadows', 'warlock', 'Eldritch Invocation: Armor of Shadows', 2, '/api/2014/features/eldritch-invocation-armor-of-shadows', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-beast-speech', 0, 'You can cast speak with animals at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-beast-speech', 'warlock', 'Eldritch Invocation: Beast Speech', 2, '/api/2014/features/eldritch-invocation-beast-speech', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-beguiling-influence', 0, 'You gain proficiency in the Deception and Persuasion skills.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-beguiling-influence', 'warlock', 'Eldritch Invocation: Beguiling Influence', 2, '/api/2014/features/eldritch-invocation-beguiling-influence', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", feature) VALUES ('eldritch-invocation-book-of-ancient-secrets', 0, 'feature', '/api/2014/features/pact-of-the-tome');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-book-of-ancient-secrets', 0, 'You can now inscribe magical rituals in your Book of Shadows. Choose two 1st-level spells that have the ritual tag from any class''s spell list (the two needn''t be from the same list). The spells appear in the book and don''t count against the number of spells you know. With your Book of Shadows in hand, you can cast the chosen spells as rituals. You can''t cast the spells except as rituals, unless you''ve learned them by some other means. You can also cast a warlock spell you know as a ritual if it has the ritual tag.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-book-of-ancient-secrets', 1, 'On your adventures, you can add other ritual spells to your Book of Shadows. When you find such a spell, you can add it to the book if the spell''s level is equal to or less than half your warlock level (rounded up) and if you can spare the time to transcribe the spell. For each level of the spell, the transcription process takes 2 hours and costs 50 gp for the rare inks needed to inscribe it.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-book-of-ancient-secrets', 'warlock', 'Eldritch Invocation: Book of Ancient Secrets', 2, '/api/2014/features/eldritch-invocation-book-of-ancient-secrets', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-devils-sight', 0, 'You can see normally in darkness, both magical and nonmagical, to a distance of 120 feet.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-devils-sight', 'warlock', 'Eldritch Invocation: Devil''s Sight', 2, '/api/2014/features/eldritch-invocation-devils-sight', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-eldritch-sight', 0, 'You can cast detect magic at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-eldritch-sight', 'warlock', 'Eldritch Invocation: Eldritch Sight', 2, '/api/2014/features/eldritch-invocation-eldritch-sight', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", spell) VALUES ('eldritch-invocation-eldritch-spear', 0, 'spell', '/api/2014/spells/eldritch-blast');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-eldritch-spear', 0, 'When you cast eldritch blast, its range is 300 feet.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-eldritch-spear', 'warlock', 'Eldritch Invocation: Eldritch Spear', 2, '/api/2014/features/eldritch-invocation-eldritch-spear', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-eyes-of-the-rune-keeper', 0, 'You can read all writing.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-eyes-of-the-rune-keeper', 'warlock', 'Eldritch Invocation: Eyes of the Rune Keeper', 2, '/api/2014/features/eldritch-invocation-eyes-of-the-rune-keeper', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-fiendish-vigor', 0, 'You can cast false life on yourself at will as a 1st-level spell, without expending a spell slot or material components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-fiendish-vigor', 'warlock', 'Eldritch Invocation: Fiendish Vigor', 2, '/api/2014/features/eldritch-invocation-fiendish-vigor', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-gaze-of-two-minds', 0, 'You can use your action to touch a willing humanoid and perceive through its senses until the end of your next turn. As long as the creature is on the same plane of existence as you, you can use your action on subsequent turns to maintain this connection, extending the duration until the end of your next turn. While perceiving through the other creature''s senses, you benefit from any special senses possessed by that creature, and you are blinded and deafened to your own surroundings.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-gaze-of-two-minds', 'warlock', 'Eldritch Invocation: Gaze of Two Minds', 2, '/api/2014/features/eldritch-invocation-gaze-of-two-minds', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-mask-of-many-faces', 0, 'You can cast disguise self at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-mask-of-many-faces', 'warlock', 'Eldritch Invocation: Mask of Many Faces', 2, '/api/2014/features/eldritch-invocation-mask-of-many-faces', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-misty-visions', 0, 'You can cast silent image at will, without expending a spell slot or material components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-misty-visions', 'warlock', 'Eldritch Invocation: Misty Visions', 2, '/api/2014/features/eldritch-invocation-misty-visions', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", spell) VALUES ('eldritch-invocation-repelling-blast', 0, 'spell', '/api/2014/spells/eldritch-blast');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-repelling-blast', 0, 'When you hit a creature with eldritch blast, you can push the creature up to 10 feet away from you in a straight line.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-repelling-blast', 'warlock', 'Eldritch Invocation: Repelling Blast', 2, '/api/2014/features/eldritch-invocation-repelling-blast', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-thief-of-five-fates', 0, 'You can cast bane once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-thief-of-five-fates', 'warlock', 'Eldritch Invocation: Thief of Five Fates', 2, '/api/2014/features/eldritch-invocation-thief-of-five-fates', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", feature) VALUES ('eldritch-invocation-voice-of-the-chain-master', 0, 'feature', '/api/2014/features/pact-of-the-chain');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-voice-of-the-chain-master', 0, 'You can communicate telepathically with your familiar and perceive through your familiar''s senses as long as you are on the same plane of existence.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-voice-of-the-chain-master', 1, 'Additionally, while perceiving through your familiar''s senses, you can also speak through your familiar in your own voice, even if your familiar is normally incapable of speech.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-voice-of-the-chain-master', 'warlock', 'Eldritch Invocation: Voice of the Chain Master', 2, '/api/2014/features/eldritch-invocation-voice-of-the-chain-master', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-mire-the-mind', 0, 'level', 5);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-mire-the-mind', 0, 'You can cast slow once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-mire-the-mind', 'warlock', 'Eldritch Invocation: Mire the Mind', 5, '/api/2014/features/eldritch-invocation-mire-the-mind', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-one-with-shadows', 0, 'level', 5);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-one-with-shadows', 0, 'When you are in an area of dim light or darkness, you can use your action to become invisible until you move or take an action or a reaction.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-one-with-shadows', 'warlock', 'Eldritch Invocation: One with Shadows', 5, '/api/2014/features/eldritch-invocation-one-with-shadows', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-sign-of-ill-omen', 0, 'level', 5);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-sign-of-ill-omen', 0, 'You can cast bestow curse once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-sign-of-ill-omen', 'warlock', 'Eldritch Invocation: Sign of Ill Omen', 5, '/api/2014/features/eldritch-invocation-sign-of-ill-omen', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-thirsting-blade', 0, 'level', 5);
INSERT INTO features_prerequisites (features_index, order_num, "type", feature) VALUES ('eldritch-invocation-thirsting-blade', 1, 'feature', '/api/2014/features/pact-of-the-blade');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-thirsting-blade', 0, 'You can attack with your pact weapon twice, instead of once, whenever you take the Attack action on your turn.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-thirsting-blade', 'warlock', 'Eldritch Invocation: Thirsting Blade', 5, '/api/2014/features/eldritch-invocation-thirsting-blade', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('otherworldly-patron-improvement-1', 0, 'At 1st level, you have struck a bargain with an otherworldly being of your choice, such as the Fiend. Your choice grants you features at 1st level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('otherworldly-patron-improvement-1', 'warlock', 'Otherworldly Patron feature', 6, '/api/2014/features/otherworldly-patron-improvement-1');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-bewitching-whispers', 0, 'level', 7);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-bewitching-whispers', 0, 'You can cast compulsion once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-bewitching-whispers', 'warlock', 'Eldritch Invocation: Bewitching Whispers', 7, '/api/2014/features/eldritch-invocation-bewitching-whispers', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-dreadful-word', 0, 'level', 7);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-dreadful-word', 0, 'You can cast confusion once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-dreadful-word', 'warlock', 'Eldritch Invocation: Dreadful Word', 7, '/api/2014/features/eldritch-invocation-dreadful-word', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-sculptor-of-flesh', 0, 'level', 7);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-sculptor-of-flesh', 0, 'You can cast polymorph once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-sculptor-of-flesh', 'warlock', 'Eldritch Invocation: Sculptor of Flesh', 7, '/api/2014/features/eldritch-invocation-sculptor-of-flesh', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-ascendant-step', 0, 'level', 9);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-ascendant-step', 0, 'You can cast levitate on yourself at will, without expending a spell slot or material components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-ascendant-step', 'warlock', 'Eldritch Invocation: Ascendant Step', 9, '/api/2014/features/eldritch-invocation-ascendant-step', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-minions-of-chaos', 0, 'level', 9);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-minions-of-chaos', 0, 'You can cast conjure elemental once using a warlock spell slot. You can''t do so again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-minions-of-chaos', 'warlock', 'Eldritch Invocation: Minions of Chaos', 9, '/api/2014/features/eldritch-invocation-minions-of-chaos', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-otherworldly-leap', 0, 'level', 9);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-otherworldly-leap', 0, 'You can cast jump on yourself at will, without expending a spell slot or material components.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-otherworldly-leap', 'warlock', 'Eldritch Invocation: Otherworldly Leap', 9, '/api/2014/features/eldritch-invocation-otherworldly-leap', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-whispers-of-the-grave', 0, 'level', 9);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-whispers-of-the-grave', 0, 'You can cast speak with dead at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-whispers-of-the-grave', 'warlock', 'Eldritch Invocation: Whispers of the Grave', 9, '/api/2014/features/eldritch-invocation-whispers-of-the-grave', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('otherworldly-patron-improvement-2', 0, 'At 1st level, you have struck a bargain with an otherworldly being of your choice, such as the Fiend. Your choice grants you features at 1st level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('otherworldly-patron-improvement-2', 'warlock', 'Otherworldly Patron feature', 10, '/api/2014/features/otherworldly-patron-improvement-2');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-lifedrinker', 0, 'level', 12);
INSERT INTO features_prerequisites (features_index, order_num, "type", feature) VALUES ('eldritch-invocation-lifedrinker', 1, 'feature', '/api/2014/features/pact-of-the-blade');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-lifedrinker', 0, 'When you hit a creature with your pact weapon, the creature takes extra necrotic damage equal to your Charisma modifier (minimum 1).');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-lifedrinker', 'warlock', 'Eldritch Invocation: Lifedrinker', 12, '/api/2014/features/eldritch-invocation-lifedrinker', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('otherworldly-patron-improvement-3', 0, 'At 1st level, you have struck a bargain with an otherworldly being of your choice, such as the Fiend. Your choice grants you features at 1st level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('otherworldly-patron-improvement-3', 'warlock', 'Otherworldly Patron feature', 14, '/api/2014/features/otherworldly-patron-improvement-3');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-chains-of-carceri', 0, 'level', 15);
INSERT INTO features_prerequisites (features_index, order_num, "type", feature) VALUES ('eldritch-invocation-chains-of-carceri', 1, 'feature', '/api/2014/features/pact-of-the-chain');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-chains-of-carceri', 0, 'You can cast hold monster at will--targeting a celestial, fiend, or elemental--without expending a spell slot or material components. You must finish a long rest before you can use this invocation on the same creature again.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-chains-of-carceri', 'warlock', 'Eldritch Invocation: Chains of Carceri', 15, '/api/2014/features/eldritch-invocation-chains-of-carceri', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-master-of-myriad-forms', 0, 'level', 15);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-master-of-myriad-forms', 0, 'You can cast alter self at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-master-of-myriad-forms', 'warlock', 'Eldritch Invocation: Master of Myriad Forms', 15, '/api/2014/features/eldritch-invocation-master-of-myriad-forms', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-visions-of-distant-realms', 0, 'level', 15);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-visions-of-distant-realms', 0, 'You can cast arcane eye at will, without expending a spell slot.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-visions-of-distant-realms', 'warlock', 'Eldritch Invocation: Visions of Distant Realms', 15, '/api/2014/features/eldritch-invocation-visions-of-distant-realms', 'eldritch-invocations');
INSERT INTO features_prerequisites (features_index, order_num, "type", level) VALUES ('eldritch-invocation-witch-sight', 0, 'level', 15);
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-invocation-witch-sight', 0, 'You can see the true form of any shapechanger or creature concealed by illusion or transmutation magic while the creature is within 30 feet of you and within line of sight.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('eldritch-invocation-witch-sight', 'warlock', 'Eldritch Invocation: Witch Sight', 15, '/api/2014/features/eldritch-invocation-witch-sight', 'eldritch-invocations');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-boon', 0, 'At 3rd level, your otherworldly patron bestows a gift upon you for your loyal service. You gain one of the following features of your choice.');
INSERT INTO features ("index", class_index, name, level, url, feature_specific_subfeature_options_choose, feature_specific_subfeature_options_type, feature_specific_subfeature_options_from_option_set_type) VALUES ('pact-boon', 'warlock', 'Pact Boon', 3, '/api/2014/features/pact-boon', 1, 'feature', 'options_array');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-chain', 0, 'You learn the find familiar spell and can cast it as a ritual. The spell doesn''t count against your number of spells known.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-chain', 1, 'When you cast the spell, you can choose one of the normal forms for your familiar or one of the following special forms: imp, pseudodragon, quasit, or sprite.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-chain', 2, 'Additionally, when you take the Attack action, you can forgo one of your own attacks to allow your familiar to make one attack of its own with its reaction.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-chain', 3, 'Your familiar is more cunning than a typical familiar. Its default form can be a reflection of your patron, with imps and quasits tied to the Fiend.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('pact-of-the-chain', 'warlock', 'Pact of the Chain', 3, '/api/2014/features/pact-of-the-chain', 'pact-boon');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-blade', 0, 'You can use your action to create a pact weapon in your empty hand. You can choose the form that this melee weapon takes each time you create it. You are proficient with it while you wield it. This weapon counts as magical for the purpose of overcoming resistance and immunity to nonmagical attacks and damage.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-blade', 1, 'Your pact weapon disappears if it is more than 5 feet away from you for 1 minute or more. It also disappears if you use this feature again, if you dismiss the weapon (no action required), or if you die.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-blade', 2, 'You can transform one magic weapon into your pact weapon by performing a special ritual while you hold the weapon. You perform the ritual over the course of 1 hour, which can be done during a short rest. You can then dismiss the weapon, shunting it into an extradimensional space, and it appears whenever you create your pact weapon thereafter. You can''t affect an artifact or a sentient weapon in this way. The weapon ceases being your pact weapon if you die, if you perform the 1-hour ritual on a different weapon, or if you use a 1-hour ritual to break your bond to it. The weapon appears at your feet if it is in the extradimensional space when the bond breaks.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-blade', 3, 'If you serve the Fiend, your weapon could be an axe made of black metal and adorned with decorative flames.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('pact-of-the-blade', 'warlock', 'Pact of the Blade', 3, '/api/2014/features/pact-of-the-blade', 'pact-boon');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-tome', 0, 'Your patron gives you a grimoire called a Book of Shadows. When you gain this feature, choose three cantrips from any class''s spell list (the three needn''t be from the same list). While the book is on your person, you can cast those cantrips at will. They don''t count against your number of cantrips known. If they don''t appear on the warlock spell list, they are nonetheless warlock spells for you.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-tome', 1, 'If you lose your Book of Shadows, you can perform a 1-hour ceremony to receive a replacement from your patron. This ceremony can be performed during a short or long rest, and it destroys the previous book. The book turns to ash when you die.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('pact-of-the-tome', 2, 'Your Book of Shadows could be a weighty tome bound in demon hide studded with iron, holding spells of conjuration and a wealth of forbidden lore about the sinister regions of the cosmos, a gift of the Fiend.');
INSERT INTO features ("index", class_index, name, level, url, parent_index) VALUES ('pact-of-the-tome', 'warlock', 'Pact of the Tome', 3, '/api/2014/features/pact-of-the-tome', 'pact-boon');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('warlock-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('warlock-ability-score-improvement-1', 'warlock', 'Ability Score Improvement', 4, '/api/2014/features/warlock-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dark-ones-own-luck', 0, 'Starting at 6th level, you can call on your patron to alter fate in your favor. When you make an ability check or a saving throw, you can use this feature to add a d10 to your roll. You can do so after seeing the initial roll but before any of the roll''s effects occur.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('dark-ones-own-luck', 1, 'Once you use this feature, you can''t use it again until you finish a short or long rest.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('dark-ones-own-luck', 'warlock', 'Dark One''s Own Luck', 6, '/api/2014/features/dark-ones-own-luck', 'fiend');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('warlock-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('warlock-ability-score-improvement-2', 'warlock', 'Ability Score Improvement', 8, '/api/2014/features/warlock-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('fiendish-resilience', 0, 'Starting at 10th level, you can choose one damage type when you finish a short or long rest. You gain resistance to that damage type until you choose a different one with this feature. Damage from magical weapons or silver weapons ignores this resistance.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('fiendish-resilience', 'warlock', 'Fiendish Resilience', 10, '/api/2014/features/fiendish-resilience', 'fiend');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-6th-level', 0, 'At 11th level, your patron bestows upon you a magical secret called an arcanum. Choose one 6th- level spell from the warlock spell list as this arcanum.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-6th-level', 1, 'You can cast your arcanum spell once without expending a spell slot. You must finish a long rest before you can do so again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-6th-level', 2, 'At higher levels, you gain more warlock spells of your choice that can be cast in this way: one 7th- level spell at 13th level, one 8th-level spell at 15th level, and one 9th-level spell at 17th level. You regain all uses of your Mystic Arcanum when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('mystic-arcanum-6th-level', 'warlock', 'Mystic Arcanum (6th level)', 11, '/api/2014/features/mystic-arcanum-6th-level');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('warlock-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('warlock-ability-score-improvement-3', 'warlock', 'Ability Score Improvement', 12, '/api/2014/features/warlock-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-7th-level', 0, 'At 11th level, your patron bestows upon you a magical secret called an arcanum. Choose one 6th- level spell from the warlock spell list as this arcanum.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-7th-level', 1, 'You can cast your arcanum spell once without expending a spell slot. You must finish a long rest before you can do so again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-7th-level', 2, 'At higher levels, you gain more warlock spells of your choice that can be cast in this way: one 7th- level spell at 13th level, one 8th-level spell at 15th level, and one 9th-level spell at 17th level. You regain all uses of your Mystic Arcanum when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('mystic-arcanum-7th-level', 'warlock', 'Mystic Arcanum (7th level)', 13, '/api/2014/features/mystic-arcanum-7th-level');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hurl-through-hell', 0, 'Starting at 14th level, when you hit a creature with an attack, you can use this feature to instantly transport the target through the lower planes. The creature disappears and hurtles through a nightmare landscape.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hurl-through-hell', 1, 'At the end of your next turn, the target returns to the space it previously occupied, or the nearest unoccupied space. If the target is not a fiend, it takes 10d10 psychic damage as it reels from its horrific experience.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('hurl-through-hell', 2, 'Once you use this feature, you can''t use it again until you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('hurl-through-hell', 'warlock', 'Hurl Through Hell', 14, '/api/2014/features/hurl-through-hell', 'fiend');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-8th-level', 0, 'At 11th level, your patron bestows upon you a magical secret called an arcanum. Choose one 6th- level spell from the warlock spell list as this arcanum.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-8th-level', 1, 'You can cast your arcanum spell once without expending a spell slot. You must finish a long rest before you can do so again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-8th-level', 2, 'At higher levels, you gain more warlock spells of your choice that can be cast in this way: one 7th- level spell at 13th level, one 8th-level spell at 15th level, and one 9th-level spell at 17th level. You regain all uses of your Mystic Arcanum when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('mystic-arcanum-8th-level', 'warlock', 'Mystic Arcanum (8th level)', 15, '/api/2014/features/mystic-arcanum-8th-level');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('warlock-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('warlock-ability-score-improvement-4', 'warlock', 'Ability Score Improvement', 16, '/api/2014/features/warlock-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-9th-level', 0, 'At 11th level, your patron bestows upon you a magical secret called an arcanum. Choose one 6th- level spell from the warlock spell list as this arcanum.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-9th-level', 1, 'You can cast your arcanum spell once without expending a spell slot. You must finish a long rest before you can do so again.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('mystic-arcanum-9th-level', 2, 'At higher levels, you gain more warlock spells of your choice that can be cast in this way: one 7th- level spell at 13th level, one 8th-level spell at 15th level, and one 9th-level spell at 17th level. You regain all uses of your Mystic Arcanum when you finish a long rest.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('mystic-arcanum-9th-level', 'warlock', 'Mystic Arcanum (9th level)', 17, '/api/2014/features/mystic-arcanum-9th-level');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('warlock-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('warlock-ability-score-improvement-5', 'warlock', 'Ability Score Improvement', 19, '/api/2014/features/warlock-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-master', 0, 'At 20th level, you can draw on your inner reserve of mystical power while entreating your patron to regain expended spell slots. You can spend 1 minute entreating your patron for aid to regain all your expended spell slots from your Pact Magic feature.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('eldritch-master', 1, 'Once you regain spell slots with this feature, you must finish a long rest before you can do so again.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('eldritch-master', 'warlock', 'Eldritch Master', 20, '/api/2014/features/eldritch-master');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spellcasting-wizard', 0, 'As a student of arcane magic, you have a spellbook containing spells that show the first glimmerings of your true power.');
INSERT INTO features ("index", class_index, name, level, url, reference) VALUES ('spellcasting-wizard', 'wizard', 'Spellcasting: Wizard', 1, '/api/2014/features/spellcasting-wizard', '/api/2014/classes/wizard/spellcasting');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-recovery', 0, 'You have learned to regain some of your magical energy by studying your spellbook. Once per day when you finish a short rest, you can choose expended spell slots to recover. The spell slots can have a combined level that is equal to or less than half your wizard level (rounded up), and none of the slots can be 6th level or higher.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-recovery', 1, 'For example, if you''re a 4th-level wizard, you can recover up to two levels worth of spell slots. You can recover either a 2nd-level spell slot or two 1st-level spell slots.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('arcane-recovery', 'wizard', 'Arcane Recovery', 1, '/api/2014/features/arcane-recovery');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition', 0, 'When you reach 2nd level, you choose an arcane tradition, shaping your practice of magic through one of eight schools, such as Evocation.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition', 1, 'Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('arcane-tradition', 'wizard', 'Arcane Tradition', 2, '/api/2014/features/arcane-tradition');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('evocation-savant', 0, 'Beginning when you select this school at 2nd level, the gold and time you must spend to copy an evocation spell into your spellbook is halved.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('evocation-savant', 'wizard', 'Evocation Savant', 2, '/api/2014/features/evocation-savant', 'evocation');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('sculpt-spells', 0, 'Beginning at 2nd level, you can create pockets of relative safety within the effects of your evocation spells. When you cast an evocation spell that affects other creatures that you can see, you can choose a number of them equal to 1 + the spell''s level. The chosen creatures automatically succeed on their saving throws against the spell, and they take no damage if they would normally take half damage on a successful save.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('sculpt-spells', 'wizard', 'Sculpt Spells', 2, '/api/2014/features/sculpt-spells', 'evocation');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wizard-ability-score-improvement-1', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wizard-ability-score-improvement-1', 'wizard', 'Ability Score Improvement', 4, '/api/2014/features/wizard-ability-score-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-1', 0, 'When you reach 2nd level, you choose an arcane tradition, shaping your practice of magic through one of eight schools, such as Evocation.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-1', 1, 'Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('arcane-tradition-improvement-1', 'wizard', 'Arcane Tradition feature', 6, '/api/2014/features/arcane-tradition-improvement-1');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('potent-cantrip', 0, 'Starting at 6th level, your damaging cantrips affect even creatures that avoid the brunt of the effect. When a creature succeeds on a saving throw against your cantrip, the creature takes half the cantrip''s damage (if any) but suffers no additional effect from the cantrip.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('potent-cantrip', 'wizard', 'Potent Cantrip', 6, '/api/2014/features/potent-cantrip', 'evocation');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wizard-ability-score-improvement-2', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wizard-ability-score-improvement-2', 'wizard', 'Ability Score Improvement', 8, '/api/2014/features/wizard-ability-score-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-2', 0, 'When you reach 2nd level, you choose an arcane tradition, shaping your practice of magic through one of eight schools, such as Evocation.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-2', 1, 'Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('arcane-tradition-improvement-2', 'wizard', 'Arcane Tradition feature', 10, '/api/2014/features/arcane-tradition-improvement-2');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('empowered-evocation', 0, 'Beginning at 10th level, you can add your Intelligence modifier to one damage roll of any wizard evocation spell you cast.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('empowered-evocation', 'wizard', 'Empowered Evocation', 10, '/api/2014/features/empowered-evocation', 'evocation');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wizard-ability-score-improvement-3', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wizard-ability-score-improvement-3', 'wizard', 'Ability Score Improvement', 12, '/api/2014/features/wizard-ability-score-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-3', 0, 'When you reach 2nd level, you choose an arcane tradition, shaping your practice of magic through one of eight schools, such as Evocation.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('arcane-tradition-improvement-3', 1, 'Your choice grants you features at 2nd level and again at 6th, 10th, and 14th level.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('arcane-tradition-improvement-3', 'wizard', 'Arcane Tradition feature', 14, '/api/2014/features/arcane-tradition-improvement-3');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('overchannel', 0, 'Starting at 14th level, you can increase the power of your simpler spells. When you cast a wizard spell of 1st through 5th level that deals damage, you can deal maximum damage with that spell.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('overchannel', 1, 'The first time you do so, you suffer no adverse effect. If you use this feature again before you finish a long rest, you take 2d12 necrotic damage for each level of the spell, immediately after you cast it. Each time you use this feature again before finishing a long rest, the necrotic damage per spell level increases by 1d12. This damage ignores resistance and immunity.');
INSERT INTO features ("index", class_index, name, level, url, subclass_index) VALUES ('overchannel', 'wizard', 'Overchannel', 14, '/api/2014/features/overchannel', 'evocation');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wizard-ability-score-improvement-4', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wizard-ability-score-improvement-4', 'wizard', 'Ability Score Improvement', 16, '/api/2014/features/wizard-ability-score-improvement-4');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spell-mastery', 0, 'At 18th level, you have achieved such mastery over certain spells that you can cast them at will. Choose a 1st-level wizard spell and a 2nd-level wizard spell that are in your spellbook. You can cast those spells at their lowest level without expending a spell slot when you have them prepared. If you want to cast either spell at a higher level, you must expend a spell slot as normal.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('spell-mastery', 1, 'By spending 8 hours in study, you can exchange one or both of the spells you chose for different spells of the same levels.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('spell-mastery', 'wizard', 'Spell Mastery', 18, '/api/2014/features/spell-mastery');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('wizard-ability-score-improvement-5', 0, 'When you reach 4th level, and again at 8th, 12th, 16th, and 19th level, you can increase one ability score of your choice by 2, or you can increase two ability scores of your choice by 1. As normal, you can''t increase an ability score above 20 using this feature.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('wizard-ability-score-improvement-5', 'wizard', 'Ability Score Improvement', 19, '/api/2014/features/wizard-ability-score-improvement-5');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('signature-spell', 0, 'When you reach 20th level, you gain mastery over two powerful spells and can cast them with little effort. Choose two 3rd-level wizard spells in your spellbook as your signature spells. You always have these spells prepared, they don''t count against the number of spells you have prepared, and you can cast each of them once at 3rd level without expending a spell slot. When you do so, you can''t do so again until you finish a short or long rest.');
INSERT INTO features_desc (features_index, order_num, "value") VALUES ('signature-spell', 1, 'If you want to cast either spell at a higher level, you must expend a spell slot as normal.');
INSERT INTO features ("index", class_index, name, level, url) VALUES ('signature-spell', 'wizard', 'Signature Spell', 20, '/api/2014/features/signature-spell');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('common', 0, 'Humans');
