INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('dwarvish', 0, 'Dwarves');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('dwarvish', 'Dwarvish', 'Standard', 'Dwarvish', '/api/2014/languages/dwarvish', 'Dwarvish is full of hard consonants and guttural sounds.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('elvish', 0, 'Elves');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('elvish', 'Elvish', 'Standard', 'Elvish', '/api/2014/languages/elvish', 'Elvish is fluid, with subtle intonations and intricate grammar. Elven literature is rich and varied, and their songs and poems are famous among other races. Many bards learn their language so they can add Elvish ballads to their repertoires.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('giant', 0, 'Ogres');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('giant', 1, 'Giants');
INSERT INTO languages ("index", name, "type", script, url) VALUES ('giant', 'Giant', 'Standard', 'Dwarvish', '/api/2014/languages/giant');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('gnomish', 0, 'Gnomes');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('gnomish', 'Gnomish', 'Standard', 'Dwarvish', '/api/2014/languages/gnomish', 'The Gnomish language, which uses the Dwarvish script, is renowned for its technical treatises and its catalogs of knowledge about the natural world.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('goblin', 0, 'Goblinoids');
INSERT INTO languages ("index", name, "type", script, url) VALUES ('goblin', 'Goblin', 'Standard', 'Dwarvish', '/api/2014/languages/goblin');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('halfling', 0, 'Halflings');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('halfling', 'Halfling', 'Standard', 'Common', '/api/2014/languages/halfling', 'The Halfling language isn''t secret, but halflings are loath to share it with others. They write very little, so they don''t have a rich body of literature. Their oral tradition, however, is very strong.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('orc', 0, 'Orcs');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('orc', 'Orc', 'Standard', 'Dwarvish', '/api/2014/languages/orc', 'Orc is a harsh, grating language with hard consonants. It has no script of its own but is written in the Dwarvish script.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('abyssal', 0, 'Demons');
INSERT INTO languages ("index", name, "type", script, url) VALUES ('abyssal', 'Abyssal', 'Exotic', 'Infernal', '/api/2014/languages/abyssal');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('celestial', 0, 'Celestials');
INSERT INTO languages ("index", name, "type", script, url) VALUES ('celestial', 'Celestial', 'Exotic', 'Celestial', '/api/2014/languages/celestial');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('draconic', 0, 'Dragons');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('draconic', 1, 'Dragonborn');
INSERT INTO languages ("index", name, "type", script, url, "desc") VALUES ('draconic', 'Draconic', 'Exotic', 'Draconic', '/api/2014/languages/draconic', 'Draconic is thought to be one of the oldest languages and is often used in the study of magic. The language sounds harsh to most other creatures and includes numerous hard consonants and sibilants.');
INSERT INTO languages_typical_speakers (languages_index, order_num, "value") VALUES ('deep-speech', 0, 'Aboleths');
