INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('adamantine-armor', 1, 'This suit of armor is reinforced with adamantine, one of the hardest substances in existence. While you''re wearing it, any critical hit against you becomes a normal hit.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('adamantine-armor', 'Adamantine Armor', 'armor', 'Uncommon', 0, '/api/images/magic-items/adamantine-armor.png', '/api/2014/magic-items/adamantine-armor');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ammunition-1', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ammunition-2', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ammunition-3', 2);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition', 0, 'Weapon (any ammunition), uncommon (+1), rare (+2), or very rare (+3)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition', 1, 'You have a bonus to attack and damage rolls made with this piece of magic ammunition. The bonus is determined by the rarity of the ammunition. Once it hits a target, the ammunition is no longer magical.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('ammunition', 'Ammunition, +1, +2, or +3', 'ammunition', 'Varies', 0, '/api/images/magic-items/ammunition.png', '/api/2014/magic-items/ammunition');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-1', 0, 'Weapon (any ammunition), uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-1', 1, 'You have a +1 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('ammunition-1', 'Ammunition, +1', 'ammunition', 'Uncommon', 1, '/api/images/magic-items/ammunition.png', '/api/2014/magic-items/ammunition-1');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-2', 0, 'Weapon (any ammunition), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-2', 1, 'You have a +2 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('ammunition-2', 'Ammunition, +2', 'ammunition', 'Rare', 1, '/api/images/magic-items/ammunition.png', '/api/2014/magic-items/ammunition-2');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-3', 0, 'Weapon (any ammunition), very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ammunition-3', 1, 'You have a +3 bonus to attack and damage rolls made with this piece of magic ammunition. Once it hits a target, the ammunition is no longer magical.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('ammunition-3', 'Ammunition, +3', 'ammunition', 'Very Rare', 1, '/api/images/magic-items/ammunition.png', '/api/2014/magic-items/ammunition-3');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-health', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-health', 1, 'Your Constitution score is 19 while you wear this amulet. It has no effect on you if your Constitution is already 19 or higher');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('amulet-of-health', 'Amulet of Health', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/amulet-of-health.png', '/api/2014/magic-items/amulet-of-health');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-proof-against-detection-and-location', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-proof-against-detection-and-location', 1, 'While wearing this amulet, you are hidden from divination magic. You can''t be targeted by such magic or perceived through magical scrying sensors.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('amulet-of-proof-against-detection-and-location', 'Amulet of Proof against Detection and Location', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/amulet-of-proof-against-detection-and-location.png', '/api/2014/magic-items/amulet-of-proof-against-detection-and-location');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-the-planes', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('amulet-of-the-planes', 1, 'While wearing this amulet, you can use an action to name a location that you are familiar with on another plane of existence. Then make a DC 15 Intelligence check. On a successful check, you cast the plane shift spell. On a failure, you and each creature and object within 15 feet of you travel to a random destination. Roll a d100. On a 1-60, you travel to a random location on the plane you named. On a 61-100, you travel to a randomly determined plane of existence.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('amulet-of-the-planes', 'Amulet of the Planes', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/amulet-of-the-planes.png', '/api/2014/magic-items/amulet-of-the-planes');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('animated-shield', 0, 'Armor (shield), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('animated-shield', 1, 'While holding this shield, you can speak its command word as a bonus action to cause it to animate. The shield leaps into the air and hovers in your space to protect you as if you were wielding it, leaving your hands free. The shield remains animated for 1 minute, until you use a bonus action to end this effect, or until you are incapacitated or die, at which point the shield falls to the ground or into your hand if you have one free.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('animated-shield', 'Animated Shield', 'armor', 'Very Rare', 0, '/api/images/magic-items/animated-shield.png', '/api/2014/magic-items/animated-shield');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 1, 'This item first appears to be a Large sealed iron barrel weighing 500 pounds. The barrel has a hidden catch, which can be found with a successful DC 20 Intelligence (Investigation) check. Releasing the catch unlocks a hatch at one end of the barrel, allowing two Medium or smaller creatures to crawl inside. Ten levers are set in a row at the far end, each in a neutral position, able to move either up or down. When certain levers are used, the apparatus transforms to resemble a giant lobster.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 2, 'The apparatus of the Crab is a Large object with the following statistics:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 3, 'Armor Class: 20');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 4, 'Hit Points: 200');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 5, 'Speed: 30 ft., swim 30 ft. (or 0 ft. for both if the legs and tail aren''t extended)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 6, 'Damage Immunities: poison, psychic');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 7, 'To be used as a vehicle, the apparatus requires one pilot. While the apparatus''s hatch is closed, the compartment is airtight and watertight. The compartment holds enough air for 10 hours of breathing, divided by the number of breathing creatures inside.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 8, 'The apparatus floats on water. It can also go underwater to a depth of 900 feet. Below that, the vehicle takes 2d6 bludgeoning damage per minute from pressure.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 9, 'A creature in the compartment can use an action to move as many as two of the apparatus''s levers up or down. After each use, a lever goes back to its neutral position. Each lever, from left to right, functions as shown in the Apparatus of the Crab Levers table.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 10, 'Apparatus of the Crab Levers');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 11, '| Lever | Up | Down |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 12, '|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 13, '| 1 | Legs and tail extend, allowing the apparatus to walk and swim. | Legs and tail retract, reducing the apparatus''s speed to 0 and making it unable to benefit from bonuses to speed. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 14, '| 2 | Forward window shutter opens. | Forward window shutter closes. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 15, '| 3 | Side window shutters open (two per side). | Side window shutters close (two per side). |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 16, '| 4 | Two claws extend from the front sides of the apparatus. | The claws retract. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 17, '| 5 | Each extended claw makes the following melee weapon attack: +8 to hit, reach 5 ft., one target. Hit: 7 (2d6) bludgeoning damage. | Each extended claw makes the following melee weapon attack: +8 to hit, reach 5 ft., one target. Hit: The target is grappled (escape DC 15). |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 18, '| 6 | The apparatus walks or swims forward. | The apparatus walks or swims backward. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 19, '| 7 | The apparatus turns 90 degrees left. | The apparatus turns 90 degrees right. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 20, '| 8 | Eyelike fixtures emit bright light in a 30-foot radius and dim light for an additional 30 feet. | The light turns off. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 21, '| 9 | The apparatus sinks as much as 20 feet in liquid. | The apparatus rises up to 20 feet in liquid. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('apparatus-of-the-crab', 22, '| 10 | The rear hatch unseals and opens. |  The rear hatch closes and seals. |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('apparatus-of-the-crab', 'Apparatus of the Crab', 'wondrous-items', 'Legendary', 0, '/api/images/magic-items/apparatus-of-the-crab.png', '/api/2014/magic-items/apparatus-of-the-crab');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('armor-1', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('armor-2', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('armor-3', 2);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor', 0, 'Armor (light, medium, or heavy), rare (+1), very rare (+2), or legendary (+3)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor', 1, 'You have a bonus to AC while wearing this armor. The bonus is determined by its rarity.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor', 'Armor, +1, +2, or +3', 'armor', 'Varies', 0, '/api/images/magic-items/armor.png', '/api/2014/magic-items/armor');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-1', 0, 'Armor (light, medium, or heavy), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-1', 1, 'You have a +1 bonus to AC while wearing this armor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-1', 'Armor, +1', 'armor', 'Rare', 1, '/api/images/magic-items/armor.png', '/api/2014/magic-items/armor-1');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-2', 0, 'Armor (light, medium, or heavy), very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-2', 1, 'You have a +2 bonus to AC while wearing this armor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-2', 'Armor, +2', 'armor', 'Very Rare', 1, '/api/images/magic-items/armor-2.png', '/api/2014/magic-items/armor-2');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-3', 0, 'Armor (light, medium, or heavy), legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-3', 1, 'You have a +3 bonus to AC while wearing this armor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-3', 'Armor, +3', 'armor', 'Legendary', 1, '/api/images/magic-items/armor-3.png', '/api/2014/magic-items/armor-3');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-invulnerability', 0, 'Armor (plate), legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-invulnerability', 1, 'You have resistance to nonmagical damage while you wear this armor. Additionally, you can use an action to make yourself immune to nonmagical damage for 10 minutes or until you are no longer wearing the armor. Once this special action is used, it can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-of-invulnerability', 'Armor of Invulnerability', 'armor', 'Legendary', 0, '/api/images/magic-items/armor-of-invulnerability.png', '/api/2014/magic-items/armor-of-invulnerability');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 0, 'Armor (light, medium, or heavy), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 1, 'You have resistance to one type of damage while you wear this armor. The GM chooses the type or determines it randomly from the options below.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 2, '| d10 | Damage Type |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 3, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 4, '| 1 | Acid |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 5, '| 2 | Cold |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 6, '| 3 | Fire |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 7, '| 4 | Force |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 8, '| 5 | Lightning |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 9, '| 6 | Necrotic |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 10, '| 7 | Poison |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 11, '| 8 | Psychic |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 12, '| 9 | Radiant |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-resistance', 13, '| 10 | Thunder |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-of-resistance', 'Armor of Resistance', 'armor', 'Rare', 0, '/api/images/magic-items/armor-of-resistance.png', '/api/2014/magic-items/armor-of-resistance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-vulnerability', 0, 'Armor (plate), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-vulnerability', 1, 'While wearing this armor, you have resistance to  one of the following damage types: bludgeoning, piercing, or slashing. The GM chooses the type or determines it randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('armor-of-vulnerability', 2, '***Curse.*** This armor is cursed, a fact that is revealed only when an identify spell is cast on the armor or you attune to it. Attuning to the armor curses you until you are targeted by the remove curse spell or similar magic; removing the armor fails to end the curse. While cursed, you have vulnerability to two of the three damage types associated with the armor (not the one to which it grants resistance).');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('armor-of-vulnerability', 'Armor of Vulnerability', 'armor', 'Rare', 0, '/api/images/magic-items/armor-of-vulnerability.png', '/api/2014/magic-items/armor-of-vulnerability');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-catching-shield', 0, 'Armor (shield), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-catching-shield', 1, 'You gain a +2 bonus to AC against ranged attacks while you wield this shield. This bonus is in addition to the shield''s normal bonus to AC. In addition, whenever an attacker makes a ranged attack against a target within 5 feet of you, you can use your reaction to become the target of the attack instead.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('arrow-catching-shield', 'Arrow-Catching Shield', 'armor', 'Rare', 0, '/api/images/magic-items/arrow-catching-shield.png', '/api/2014/magic-items/arrow-catching-shield');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-of-slaying', 0, 'Weapon (arrow), very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-of-slaying', 1, 'An arrow of slaying is a magic weapon meant to slay a particular kind of creature. Some are more focused than others; for example, there are both arrows of dragon slaying and arrows of blue dragon slaying. If a creature belonging to the type, race, or group associated with an arrow of slaying takes damage from the arrow, the creature must make a DC 17 Constitution saving throw, taking an extra 6d10 piercing damage on a failed save, or half as much extra damage on a successful one.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-of-slaying', 2, 'Once an arrow of slaying deals its extra damage to a creature, it becomes a nonmagical arrow.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('arrow-of-slaying', 3, 'Other types of magic ammunition of this kind exist, such as bolts of slaying meant for a crossbow, though arrows are most common.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('arrow-of-slaying', 'Arrow of Slaying', 'ammunition', 'Very Rare', 0, '/api/images/magic-items/arrow-of-slaying.png', '/api/2014/magic-items/arrow-of-slaying');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 1, 'Inside this heavy cloth bag are 3d4 dry beans. The bag weighs 1/2 pound plus 1/4 pound for each bean it contains.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 2, 'If you dump the bag''s contents out on the ground,  they explode in a 10-foot radius, extending from the beans. Each creature in the area, including you, must  make a DC 15 Dexterity saving throw, taking 5d4 fire  damage on a failed save, or half as much damage on  a successful one. The fire ignites flammable objects  in the area that aren''t being worn or carried.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 3, 'If you remove a bean from the bag, plant it in dirt  or sand, and then water it, the bean produces an  effect 1 minute later from the ground where it was  planted. The GM can choose an effect from the  following table, determine it randomly, or create an  effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 4, '| d100 | Effect |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 5, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 6, '| 01 | 5d4 toadstools sprout. If a creature eats a toadstool, roll any die. On an odd roll, the eater must succeed on a DC 15 Constitution saving throw or take 5d6 poison damage and become poisoned for 1 hour. On an even roll, the eater gains 5d6 temporary hit points for 1 hour. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 7, '| 02-10 | A geyser erupts and spouts water, beer, berry juice, tea, vinegar, wine, or oil (GM''s choice) 30 feet into the air for 1d12 rounds. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 8, '| 11-20 | A treant sprouts. There''s a 50 percent chance that the treant is chaotic evil and attacks. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 9, '| 21-30 | An animate, immobile stone statue in your likeness rises. It makes verbal threats against you. If you leave it and others come near, it describes you as the most heinous of villains and directs the newcomers to find and attack you. If you are on the same plane of existence as the statue, it knows where you are. The statue becomes inanimate after 24 hours. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 10, '| 31-40 | A campfire with blue flames springs forth and burns for 24 hours (or until it is extinguished). |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 11, '| 41-50 | 1d6 + 6 shriekers sprout |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 12, '| 51-60 | 1d4 + 8 bright pink toads crawl forth. Whenever a toad is touched, it transforms into a Large or smaller monster of the GM''s choice. The monster remains for 1 minute, then disappears in a puff of bright pink smoke. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 13, '| 61-70 | A hungry bulette burrows up and attacks. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 14, '| 71-80 | A fruit tree grows. It has 1d10 + 20 fruit, 1d8 of which act as randomly determined magic potions, while one acts as an ingested poison of the GM''s choice. The tree vanishes after 1 hour. Picked fruit remains, retaining any magic for 30 days. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 15, '| 81-90 | A nest of 1d4 + 3 eggs springs up. Any creature that eats an egg must make a DC 20 Constitution saving throw. On a successful save, a creature permanently increases its lowest ability score by 1, randomly choosing among equally low scores. On a failed save, the creature takes 10d6 force damage from an internal magical explosion. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 16, '| 91-99 | A pyramid with a 60-foot-square base bursts upward. Inside is a sarcophagus containing a mummy lord. The pyramid is treated as the mummy lord''s lair, and its sarcophagus contains treasure of the GM''s choice. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-beans', 17, '| 100 | A giant beanstalk sprouts, growing to a height of the GM''s choice. The top leads where the GM chooses, such as to a great view, a cloud giant''s castle, or a different plane of existence. |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bag-of-beans', 'Bag of Beans', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/bag-of-beans.png', '/api/2014/magic-items/bag-of-beans');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-devouring', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-devouring', 1, 'This bag superficially resembles a bag of holding but is a feeding orifice for a gigantic extradimensional creature. Turning the bag inside out closes the orifice.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-devouring', 2, 'The extradimensional creature attached to the bag can sense whatever is placed inside the bag. Animal or vegetable matter placed wholly in the bag is devoured and lost forever. When part of a living creature is placed in the bag, as happens when someone reaches inside it, there is a 50 percent chance that the creature is pulled inside the bag. A creature inside the bag can use its action to try to escape with a successful DC 15 Strength check. Another creature can use its action to reach into the bag to pull a creature out, doing so with a successful DC 20 Strength check (provided it isn''t pulled inside the bag first). Any creature that starts its turn inside the bag is devoured, its body destroyed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-devouring', 3, 'Inanimate objects can be stored in the bag, which can hold a cubic foot of such material. However, once each day, the bag swallows any objects inside it and spits them out into another plane of existence. The GM determines the time and plane.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-devouring', 4, 'If the bag is pierced or torn, it is destroyed, and anything contained within it is transported to a random location on the Astral Plane.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bag-of-devouring', 'Bag of Devouring', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/bag-of-devouring.png', '/api/2014/magic-items/bag-of-devouring');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-holding', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-holding', 1, 'This bag has an interior space considerably larger than its outside dimensions, roughly 2 feet in diameter at the mouth and 4 feet deep. The bag can hold up to 500 pounds, not exceeding a volume of 64 cubic feet. The bag weighs 15 pounds, regardless of its contents. Retrieving an item from the bag requires an action.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-holding', 2, 'If the bag is overloaded, pierced, or torn, it ruptures and is destroyed, and its contents are scattered in the Astral Plane. If the bag is turned inside out, its contents spill forth, unharmed, but the bag must be put right before it can be used again. Breathing creatures inside the bag can survive up to a number of minutes equal to 10 divided by the number of creatures (minimum 1 minute), after which time they begin to suffocate.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-holding', 3, 'Placing a bag of holding inside an extradimensional space created by a Handy Haversack, Portable Hole, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate is sucked through it to a random location on the Astral Plane. The gate then closes. The gate is one-way only and can''t be reopened.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bag-of-holding', 'Bag of Holding', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/bag-of-holding.png', '/api/2014/magic-items/bag-of-holding');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('bag-of-tricks-gray', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('bag-of-tricks-rust', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('bag-of-tricks-tan', 2);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 1, 'This ordinary bag, made from gray, rust, or tan cloth, appears empty. Reaching inside the bag, however, reveals the presence of a small, fuzzy object. The bag weighs 1/2 pound.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 2, 'You can use an action to pull the fuzzy object from the bag and throw it up to 20 feet. When the object lands, it transforms into a creature you determine by rolling a d8 and consulting the table that corresponds to the bag''s color. The creature vanishes at the next dawn or when it is reduced to 0 hit points.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 3, 'The creature is friendly to you and your companions, and it acts on Your Turn. You can use a Bonus Action to Command how the creature moves and what action it takes on its next turn, or to give it general orders, such as to Attack your enemies. In the absence of such orders, the creature acts in a fashion appropriate to its Nature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 4, 'Once three fuzzy Objects have been pulled from the bag, the bag can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bag-of-tricks', 5, 'Gray Bag:');
