INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bead-of-force', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bead-of-force', 1, 'This small black Sphere measures 3/4 of an inch in diameter and weighs an ounce. Typically, 1d4 + 4 beads of force are found together.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bead-of-force', 2, 'You can use an action to throw the bead up to 60 feet. The bead explodes on impact and is destroyed. Each creature within a 10-foot radius of where the bead landed must succeed on a DC 15 Dexterity saving throw or take 5d4 force damage. A Sphere of transparent force then encloses the area for 1 minute. Any creature that failed the save and is completely within the area is trapped inside this Sphere. Creatures that succeeded on the save, or are partially within the area, are pushed away from the center of the Sphere until they are no longer inside it. Only breathable air can pass through the sphere''s wall. No Attack or other Effect can.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bead-of-force', 3, 'An enclosed creature can use its action to push against the sphere''s wall, moving the Sphere up to half the creature''s walking speed. The Sphere can be picked up, and its magic causes it to weigh only 1 pound, regardless of the weight of creatures inside.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bead-of-force', 'Bead of Force', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/bead-of-force.png', '/api/2014/magic-items/bead-of-force');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 0, 'Wondrous Items, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 1, 'While wearing this belt, you gain the following benefits:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 2, 'Your Constitution score increases by 2, to a maximum of 20.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 3, 'You have advantage on Charisma (Persuasion) checks made to interact with Dwarves.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 4, 'In addition, while attuned to the belt, you have a 50 percent chance each day at dawn of growing a full beard if you''re capable of growing one, or a visibly thicker beard if you already have one.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 5, 'If you aren''t a dwarf, you gain the following additional benefits while wearing the belt:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 6, 'You have advantage on Saving Throws against poison, and you have Resistance against poison damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-dwarvenkind', 7, 'You can speak, read, and write Dwarvish.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-dwarvenkind', 'Belt of Dwarvenkind', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/belt-of-dwarvenkind.png', '/api/2014/magic-items/belt-of-dwarvenkind');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-hill', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-stone', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-frost', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-fire', 3);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-cloud', 4);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('belt-of-giant-strength-storm', 5);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 0, 'Wondrous item, rarity varies (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 1, 'While wearing this belt, your Strength score changes to a score granted by the belt. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 2, 'Six varieties of this belt exist, corresponding with and having rarity according to The Six kinds of true Giants. The belt of Stone Giant Strength and the belt of Frost Giant Strength look different, but they have the same Effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 3, '| Type | Strength | Rarity |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 4, '|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 5, '| Hill Giant | 21 | Rare |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 6, '| Stone Giant / Frost Giant | 23 | Very Rare |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 7, '| Fire Giant | 25 | Very Rare |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 8, '| Cloud Giant | 27 | Legendary |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength', 9, '| Storm Giant | 29 | Legendary |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength', 'Belt of Giant Strength', 'wondrous-items', 'Varies', 0, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-hill', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-hill', 1, 'While wearing this belt, your Strength score changes to a 21. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-hill', 'Belt of Hill Giant Strength', 'wondrous-items', 'Rare', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-hill');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-stone', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-stone', 1, 'While wearing this belt, your Strength score changes to a 23. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-stone', 'Belt of Stone Giant Strength', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-stone');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-frost', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-frost', 1, 'While wearing this belt, your Strength score changes to 23. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-frost', 'Belt of Frost Giant Strength', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-frost');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-fire', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-fire', 1, 'While wearing this belt, your Strength score changes to 25. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-fire', 'Belt of Fire Giant Strength', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-fire');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-cloud', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-cloud', 1, 'While wearing this belt, your Strength score changes to 27. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-cloud', 'Belt of Cloud Giant Strength', 'wondrous-items', 'Legendary', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-cloud');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-storm', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('belt-of-giant-strength-storm', 1, 'While wearing this belt, your Strength score changes to 29. If your Strength is already equal to or greater than the belt''s score, the item has no Effect on you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('belt-of-giant-strength-storm', 'Belt of Storm Giant Strength', 'wondrous-items', 'Legendary', 1, '/api/images/magic-items/belt-of-giant-strength.png', '/api/2014/magic-items/belt-of-giant-strength-storm');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('berserker-axe', 0, 'Weapon (any axe), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('berserker-axe', 1, 'You gain a +1 bonus to Attack and Damage Rolls made with this Magic Weapon. In addition, while you are attuned to this weapon, your Hit Points maximum increases by 1 for each level you have attained.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('berserker-axe', 2, '***Curse.*** This axe is Cursed, and becoming attuned to it extends the curse to you. As long as you remain Cursed, you are unwilling to part with the axe, keeping it within reach at all times. You also have disadvantage on Attack rolls with Weapons other than this one, unless no foe is within 60 feet of you that you can see or hear.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('berserker-axe', 3, 'Whenever a Hostile creature damages you while the axe is in your possession, you must succeed on a DC 15 Wisdom saving throw or go berserk. While berserk, you must use your action each round to Attack the creature nearest to you with the axe. If you can make extra attacks as part of the Attack action, you use those extra attacks, moving to Attack the next nearest creature after you fell your current target. If you have multiple possible Targets, you Attack one at random. You are berserk until you start Your Turn with no creatures within 60 feet of you that you can see or hear.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('berserker-axe', 'Berserker Axe', 'weapon', 'Rare', 0, '/api/images/magic-items/berserker-axe.png', '/api/2014/magic-items/berserker-axe');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-elvenkind', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-elvenkind', 1, 'While you wear these boots, your steps make no sound, regardless of the surface you are moving across. You also have advantage on Dexterity (Stealth) checks that rely on moving silently.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('boots-of-elvenkind', 'Boots of Elvenkind', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/boots-of-elvenkind.png', '/api/2014/magic-items/boots-of-elvenkind');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-levitation', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-levitation', 1, 'While you wear these boots, you can use an action to cast the levitate spell on yourself at will.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('boots-of-levitation', 'Boots of Levitation', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/boots-of-levitation.png', '/api/2014/magic-items/boots-of-levitation');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-speed', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-speed', 1, 'While you wear these boots, you can use a bonus action and click the boots'' heels together. If you do, the boots double your walking speed, and any creature that makes an opportunity attack against you has disadvantage on the attack roll. If you click your heels together again, you end the effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-speed', 2, 'When the boots'' property has been used for a total of 10 minutes, the magic ceases to function until you finish a long rest.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('boots-of-speed', 'Boots of Speed', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/boots-of-speed.png', '/api/2014/magic-items/boots-of-speed');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-striding-and-springing', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-striding-and-springing', 1, 'While you wear these boots, your walking speed becomes 30 feet, unless your walking speed is higher, and your speed isn''t reduced if you are encumbered or wearing heavy armor. In addition, you can jump three times the normal distance, though you can''t jump farther than your remaining movement would allow.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('boots-of-striding-and-springing', 'Boots of Striding and Springing', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/boots-of-striding-and-springing.png', '/api/2014/magic-items/boots-of-striding-and-springing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-the-winterlands', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-the-winterlands', 1, 'These furred boots are snug and feel quite warm. While you wear them, you gain the following benefits:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-the-winterlands', 2, '* You have resistance to cold damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-the-winterlands', 3, '* You ignore difficult terrain created by ice or snow.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('boots-of-the-winterlands', 4, '* You can tolerate temperatures as low as -50 degrees Fahrenheit without any additional protection. If you wear heavy clothes, you can tolerate temperatures as low as -100 degrees Fahrenheit.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('boots-of-the-winterlands', 'Boots of the Winterlands', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/boots-of-the-winterlands.png', '/api/2014/magic-items/boots-of-the-winterlands');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bowl-of-commanding-water-elementals', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bowl-of-commanding-water-elementals', 1, 'While this bowl is filled with water, you can use an action to speak the bowl''s command word and summon a water elemental, as if you had cast the conjure elemental spell. The bowl can''t be used this way again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bowl-of-commanding-water-elementals', 2, 'The bowl is about 1 foot in diameter and half as deep. It weighs 3 pounds and holds about 3 gallons.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('bowl-of-commanding-water-elementals', 'Bowl of Commanding Water Elementals', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/bowl-of-commanding-water-elementals');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bracers-of-archery', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bracers-of-archery', 1, 'While wearing these bracers, you have proficiency with the longbow and shortbow, and you gain a +2 bonus to damage rolls on ranged attacks made with such weapons.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bracers-of-archery', 'Bracers of Archery', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/bracers-of-archery.png', '/api/2014/magic-items/bracers-of-archery');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bracers-of-defense', 0, 'Wondous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('bracers-of-defense', 1, 'While wearing these bracers, you gain a +2 bonus to AC if you are wearing no armor and using no shield.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('bracers-of-defense', 'Bracers of Defense', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/bracers-of-defense.png', '/api/2014/magic-items/bracers-of-defense');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('brazier-of-commanding-fire-elementals', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('brazier-of-commanding-fire-elementals', 1, 'While a fire burns in this brass brazier, you can use an action to speak the brazier''s command word and summon a fire elemental, as if you had cast the conjure elemental spell. The brazier can''t be used this way again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('brazier-of-commanding-fire-elementals', 2, 'The brazier weighs 5 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('brazier-of-commanding-fire-elementals', 'Brazier of Commanding Fire Elementals', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/brazier-of-commanding-fire-elementals.png', '/api/2014/magic-items/brazier-of-commanding-fire-elementals');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('brooch-of-shielding', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('brooch-of-shielding', 1, 'While wearing this brooch, you have resistance to force damage, and you have immunity to damage from the magic missile spell.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('brooch-of-shielding', 'Brooch of Shielding', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/brooch-of-shielding.png', '/api/2014/magic-items/brooch-of-shielding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('broom-of-flying', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('broom-of-flying', 1, 'This wooden broom, which weighs 3 pounds, functions like a mundane broom until you stand astride it and speak its command word. It then hovers beneath you and can be ridden in the air. It has a flying speed of 50 feet. It can carry up to 400 pounds, but its flying speed becomes 30 feet while carrying over 200 pounds. The broom stops hovering when you land.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('broom-of-flying', 2, 'You can send the broom to travel alone to a destination within 1 mile of you if you speak the command word, name the location, and are familiar with that place. The broom comes back to you when you speak another command word, provided that the broom is still within 1 mile of you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('broom-of-flying', 'Broom of Flying', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/broom-of-flying.png', '/api/2014/magic-items/broom-of-flying');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 1, 'This slender taper is dedicated to a deity and shares that deity''s alignment. The candle''s alignment can be detected with the detect evil and good spell. The GM chooses the god and associated alignment or determines the alignment randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 2, '| d20 | Alignment |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 3, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 4, '| 1-2 | Chaotic evil |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 5, '| 3-4 | Chaotic neutral |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 6, '| 5-7 | Chaotic good |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 7, '| 8-9 | Neutral evil |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 8, '| 10-11 | Neutral |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 9, '| 12-13 | Neutral good |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 10, '| 14-15 | Lawful evil |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 11, '| 16-17 | Lawful neutral |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 12, '| 18-20 | Lawful good |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 13, 'The candle''s magic is activated when the candle is lit, which requires an action. After burning for 4 hours, the candle is destroyed. You can snuff it out early for use at a later time. Deduct the time it burned in increments of 1 minute from the candle''s total burn time.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 14, 'While lit, the candle sheds dim light in a 30-foot radius. Any creature within that light whose alignment matches that of the candle makes attack rolls, saving throws, and ability checks with advantage. In addition, a cleric or druid in the light whose alignment matches the candle''s can cast 1stlevel spells he or she has prepared without expending spell slots, though the spell''s effect is as if cast with a 1st-level slot.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('candle-of-invocation', 15, 'Alternatively, when you light the candle for the first time, you can cast the gate spell with it. Doing so destroys the candle.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('candle-of-invocation', 'Candle of Invocation', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/candle-of-invocation.png', '/api/2014/magic-items/candle-of-invocation');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cape-of-the-mountebank', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cape-of-the-mountebank', 1, 'This cape smells faintly of brimstone. While wearing it, you can use it to cast the dimension door spell as an action. This property of the cape can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cape-of-the-mountebank', 2, 'When you disappear, you leave behind a cloud of smoke, and you appear in a similar cloud of smoke at your destination. The smoke lightly obscures the space you left and the space you appear in, and it dissipates at the end of your next turn. A light or stronger wind disperses the smoke.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cape-of-the-mountebank', 'Cape of the Mountebank', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/cape-of-the-mountebank.png', '/api/2014/magic-items/cape-of-the-mountebank');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('carpet-of-flying-3x5', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('carpet-of-flying-4x6', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('carpet-of-flying-5x7', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('carpet-of-flying-6x9', 3);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 1, 'You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 2, 'Four sizes of carpet of flying exist. The GM chooses the size of a given carpet or determines it randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 3, '| d100 | Size | Capacity | Flying Speed |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 4, '|---|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 5, '| 01-20 | 3 ft. × 5 ft. | 200 lb. | 80 feet |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 6, '| 21-55 | 4 ft. × 6 ft. | 400 lb. | 60 feet |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 7, '| 56-80 | 5 ft. × 7 ft. | 600 lb. | 40 feet |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 8, '| 81-100 | 6 ft. × 9 ft. | 800 lb. | 30 feet |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying', 9, 'A carpet can carry up to twice the weight shown on the table, but it flies at half speed if it carries more than its normal capacity.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('carpet-of-flying', 'Carpet of Flying', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/carpet-of-flying.png', '/api/2014/magic-items/carpet-of-flying');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-3x5', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-3x5', 1, 'You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-3x5', 2, 'This carpet is 3 feet by 5 feet and has a flying speed of 80 feet. It can carry up to 400 pounds, but its flying speed becomes 40 feet while carrying over 200 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('carpet-of-flying-3x5', 'Carpet of Flying (3 ft. × 5 ft.)', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/carpet-of-flying.png', '/api/2014/magic-items/carpet-of-flying-3x5');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-4x6', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-4x6', 1, 'You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-4x6', 2, 'This carpet is 4 feet by 6 feet and has a flying speed of 60 feet. It can carry up to 800 pounds, but its flying speed becomes 30 feet while carrying over 400 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('carpet-of-flying-4x6', 'Carpet of Flying (4 ft. × 6 ft.)', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/carpet-of-flying.png', '/api/2014/magic-items/carpet-of-flying-4x6');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-5x7', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-5x7', 1, 'You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-5x7', 2, 'This carpet is 5 feet by 7 feet and has a flying speed of 40 feet. It can carry up to 1200 pounds, but its flying speed becomes 20 feet while carrying over 600 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('carpet-of-flying-5x7', 'Carpet of Flying (5 ft. × 7 ft.)', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/carpet-of-flying.png', '/api/2014/magic-items/carpet-of-flying-5x7');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-6x9', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-6x9', 1, 'You can speak the carpet''s command word as an  action to make the carpet hover and fly. It moves according to your spoken directions, provided that you are within 30 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('carpet-of-flying-6x9', 2, 'This carpet is 6 feet by 9 feet and has a flying speed of 30 feet. It can carry up to 1600 pounds, but its flying speed becomes 15 feet while carrying over 800 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('carpet-of-flying-6x9', 'Carpet of Flying (6 ft. × 9 ft.)', 'wondrous-items', 'Very Rare', 1, '/api/images/magic-items/carpet-of-flying.png', '/api/2014/magic-items/carpet-of-flying-6x9');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('censer-of-controlling-air-elementals', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('censer-of-controlling-air-elementals', 1, 'While incense is burning in this censer, you can use an action to speak the censer''s command word and summon an air elemental, as if you had cast the conjure elemental spell. The censer can''t be used this way again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('censer-of-controlling-air-elementals', 2, 'This 6-inch-wide, 1-foot-high vessel resembles a chalice with a decorated lid. It weighs 1 pound.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('censer-of-controlling-air-elementals', 'Censer of Controlling Air Elementals', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/censer-of-controlling-air-elementals.png', '/api/2014/magic-items/censer-of-controlling-air-elementals');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('chime-of-opening', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('chime-of-opening', 1, 'This hollow metal tube measures about 1 foot long and weighs 1 pound. You can strike it as an action, pointing it at an object within 120 feet of you that can be opened, such as a door, lid, or lock. The chime issues a clear tone, and one lock or latch on the object opens unless the sound can''t reach the object. If no locks or latches remain, the object itself opens.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('chime-of-opening', 2, 'The chime can be used ten times. After the tenth time, it cracks and becomes useless.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('chime-of-opening', 'Chime of Opening', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/chime-of-opening.png', '/api/2014/magic-items/chime-of-opening');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('circlet-of-blasting', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('circlet-of-blasting', 1, 'While wearing this circlet, you can use an action to cast the scorching ray spell with it. When you make the spell''s attacks, you do so with an attack bonus of +5. The circlet can''t be used this way again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('circlet-of-blasting', 'Circlet of Blasting', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/circlet-of-blasting.png', '/api/2014/magic-items/circlet-of-blasting');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 1, 'This fine garment is made of black silk interwoven with faint silvery threads. While wearing it, you gain the following benefits:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 2, '* You have resistance to poison damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 3, '* You have a climbing speed equal to your walking speed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 4, '* You can move up, down, and across vertical surfaces and upside down along ceilings, while leaving your hands free.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 5, '* You can''t be caught in webs of any sort and can move through webs as if they were difficult terrain.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-arachnida', 6, '* You can use an action to cast the web spell (save DC 13). The web created by the spell fills twice its normal area. Once used, this property of the cloak can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-arachnida', 'Cloak of Arachnida', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/cloak-of-arachnida.png', '/api/2014/magic-items/cloak-of-arachnida');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-displacement', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-displacement', 1, 'While you wear this cloak, it projects an illusion that makes you appear to be standing in a place near your actual location, causing any creature to have disadvantage on attack rolls against you. If you take damage, the property ceases to function until the start of your next turn. This property is suppressed while you are incapacitated, restrained, or otherwise unable to move.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-displacement', 'Cloak of Displacement', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/cloak-of-displacement.png', '/api/2014/magic-items/cloak-of-displacement');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-elvenkind', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-elvenkind', 1, 'While you wear this cloak with its hood up, Wisdom (Perception) checks made to see you have disadvantage, and you have advantage on Dexterity (Stealth) checks made to hide, as the cloak''s color shifts to camouflage you. Pulling the hood up or down requires an action.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-elvenkind', 'Cloak of Elvenkind', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/cloak-of-elvenkind.png', '/api/2014/magic-items/cloak-of-elvenkind');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-protection', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-protection', 1, 'You gain a +1 bonus to AC and saving throws while you wear this cloak.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-protection', 'Cloak of Protection', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/cloak-of-protection.png', '/api/2014/magic-items/cloak-of-protection');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-the-bat', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-the-bat', 1, 'While wearing this cloak, you have advantage on Dexterity (Stealth) checks. In an area of dim light or darkness, you can grip the edges of the cloak with both hands and use it to fly at a speed of 40 feet. If you ever fail to grip the cloak''s edges while flying in this way, or if you are no longer in dim light or darkness, you lose this flying speed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-the-bat', 2, 'While wearing the cloak in an area of dim light or darkness, you can use your action to cast polymorph on yourself, transforming into a bat. While you are in the form of the bat, you retain your Intelligence, Wisdom, and Charisma scores. The cloak can''t be used this way again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-the-bat', 'Cloak of the Bat', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/cloak-of-the-bat.png', '/api/2014/magic-items/cloak-of-the-bat');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-the-manta-ray', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cloak-of-the-manta-ray', 1, 'While wearing this cloak with its hood up, you can breathe underwater, and you have a swimming speed of 60 feet. Pulling the hood up or down requires an action.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cloak-of-the-manta-ray', 'Cloak of the Manta Ray', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/cloak-of-the-manta-ray.png', '/api/2014/magic-items/cloak-of-the-manta-ray');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('crystal-ball-of-mind-reading', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('crystal-ball-of-telepathy', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('crystal-ball-of-true-seeing', 2);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 0, 'Wondrous item, very rare or legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 1, 'The typical crystal ball, a very rare item, is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 2, 'The following crystal ball variants are legendary items and have additional properties.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 3, '***Crystal Ball of Mind Reading.*** You can use an action to cast the detect thoughts spell (save DC 17) while you are scrying with the crystal ball, targeting creatures you can see within 30 feet of the spell''s sensor. You don''t need to concentrate on this detect thoughts to maintain it during its duration, but it ends if scrying ends.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 4, '***Crystal Ball of Telepathy.*** While scrying with the crystal ball, you can communicate telepathically with creatures you can see within 30 feet of the spell''s sensor. You can also use an action to cast the suggestion spell (save DC 17) through the sensor on one of those creatures. You don''t need to concentrate on this suggestion to maintain it during its duration, but it ends if scrying ends. Once used, the suggestion power of the crystal ball can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball', 5, '***Crystal Ball of True Seeing.*** While scrying with the crystal ball, you have truesight with a radius of 120 feet centered on the spell''s sensor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('crystal-ball', 'Crystal Ball', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/crystal-ball.png', '/api/2014/magic-items/crystal-ball');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-mind-reading', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-mind-reading', 1, 'The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-mind-reading', 2, '***Crystal Ball of Mind Reading.*** You can use an action to cast the detect thoughts spell (save DC 17) while you are scrying with the crystal ball, targeting creatures you can see within 30 feet of the spell''s sensor. You don''t need to concentrate on this detect thoughts to maintain it during its duration, but it ends if scrying ends.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('crystal-ball-of-mind-reading', 'Crystal Ball of Mind Reading', 'wondrous-items', 'Legendary', 1, '/api/images/magic-items/crystal-ball-of-mind-reading.png', '/api/2014/magic-items/crystal-ball-of-mind-reading');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-telepathy', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-telepathy', 1, 'The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-telepathy', 2, '***Crystal Ball of Telepathy.*** While scrying with the crystal ball, you can communicate telepathically with creatures you can see within 30 feet of the spell''s sensor. You can also use an action to cast the suggestion spell (save DC 17) through the sensor on one of those creatures. You don''t need to concentrate on this suggestion to maintain it during its duration, but it ends if scrying ends. Once used, the suggestion power of the crystal ball can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('crystal-ball-of-telepathy', 'Crystal Ball of Telepathy', 'wondrous-items', 'Legendary', 1, '/api/images/magic-items/crystal-ball-of-telepathy.png', '/api/2014/magic-items/crystal-ball-of-telepathy');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-true-seeing', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-true-seeing', 1, 'The crystal ball is about 6 inches in diameter. While touching it, you can cast the scrying spell (save DC 17) with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('crystal-ball-of-true-seeing', 2, '***Crystal Ball of True Seeing.*** While scrying with the crystal ball, you have truesight with a radius of 120 feet centered on the spell''s sensor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('crystal-ball-of-true-seeing', 'Crystal Ball of True Seeing', 'wondrous-items', 'Legendary', 1, '/api/images/magic-items/crystal-ball-of-true-seeing.png', '/api/2014/magic-items/crystal-ball-of-true-seeing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 1, 'This cube is about an inch across. Each face has a distinct marking on it that can be pressed. The cube starts with 36 charges, and it regains 1d20 expended charges daily at dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 2, 'You can use an action to press one of the cube''s faces, expending a number of charges based on the chosen face, as shown in the Cube of Force Faces table. Each face has a different effect. If the cube has insufficient charges remaining, nothing happens. Otherwise, a barrier of invisible force springs into existence, forming a cube 15 feet on a side. The barrier is centered on you, moves with you, and lasts for 1 minute, until you use an action to press the cube''s sixth face, or the cube runs out of charges. You can change the barrier''s effect by pressing a different face of the cube and expending the requisite number of charges, resetting the duration.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 3, 'If your movement causes the barrier to come into contact with a solid object that can''t pass through the cube, you can''t move any closer to that object as long as the barrier remains.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 4, 'Cube of Force Faces');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 5, '| Face | Charges | Effect |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 6, '|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 7, '| 1 | 1 | Gases, wind, and fog can''t pass through the barrier.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 8, '| 2 | 2 | Nonliving matter can''t pass through the barrier. Walls, floors, and ceilings can pass through at your discretion.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 9, '| 3 | 3 | Living matter can''t pass through the barrier.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 10, '| 4 | 4 | Spell effects can''t pass through the barrier.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 11, '| 5 | 5 | Nothing can pass through the barrier. Walls, floors, and ceilings can pass through at your discretion.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 12, '| 6 | 0 | The barrier deactivates.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 13, 'The cube loses charges when the barrier is targeted by certain spells or comes into contact with certain spell or magic item effects, as shown in the table below.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 14, '| Spell or Item | Charges Lost |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 15, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 16, '| Disintegrate | 1d12 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 17, '| Horn of blasting | 1d10 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 18, '| Passwall | 1d6 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 19, '| Prismatic spray | 1d20 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cube-of-force', 20, '| Wall of fire | 1d4 |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cube-of-force', 'Cube of Force', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/cube-of-force.png', '/api/2014/magic-items/cube-of-force');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cubic-gate', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cubic-gate', 1, 'This cube is 3 inches across and radiates palpable magical energy. The six sides of the cube are each keyed to a different plane of existence, one of which is the Material Plane. The other sides are linked to planes determined by the GM.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cubic-gate', 2, 'You can use an action to press one side of the cube to cast the gate spell with it, opening a portal to the plane keyed to that side. Alternatively, if you use an action to press one side twice, you can cast the plane shift spell (save DC 17) with the cube and transport the targets to the plane keyed to that side.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('cubic-gate', 3, 'The cube has 3 charges. Each use of the cube expends 1 charge. The cube regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('cubic-gate', 'Cubic Gate', 'wondrous-items', 'Legendary', 0, '/api/images/magic-items/cubic-gate.png', '/api/2014/magic-items/cubic-gate');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dagger-of-venom', 0, 'Weapon (dagger), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dagger-of-venom', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dagger-of-venom', 2, 'You can use an action to cause thick, black poison to coat the blade. The poison remains for 1 minute or until an attack using this weapon hits a creature. That creature must succeed on a DC 15 Constitution saving throw or take 2d10 poison damage and become poisoned for 1 minute. The dagger can''t be used this way again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dagger-of-venom', 'Dagger of Venom', 'weapon', 'Rare', 0, '/api/images/magic-items/dagger-of-venom.png', '/api/2014/magic-items/dagger-of-venom');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dancing-sword', 0, 'Weapon (any sword), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dancing-sword', 1, 'You can use a bonus action to toss this magic sword into the air and speak the command word. When you do so, the sword begins to hover, flies up to 30 feet, and attacks one creature of your choice within 5 feet of it. The sword uses your attack roll and ability score modifier to damage rolls.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dancing-sword', 2, 'While the sword hovers, you can use a bonus action to cause it to fly up to 30 feet to another spot within 30 feet of you. As part of the same bonus action, you can cause the sword to attack one creature within 5 feet of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dancing-sword', 3, 'After the hovering sword attacks for the fourth time, it flies up to 30 feet and tries to return to your hand. If you have no hand free, it falls to the ground at your feet. If the sword has no unobstructed path to you, it moves as close to you as it can and then falls to the ground. It also ceases to hover if you grasp it or move more than 30 feet away from it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dancing-sword', 'Dancing Sword', 'weapon', 'Very Rare', 0, '/api/images/magic-items/dancing-sword.png', '/api/2014/magic-items/dancing-sword');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 1, 'This stoppered flask sloshes when shaken, as if it contains water. The decanter weighs 2 pounds.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 2, 'You can use an action to remove the stopper and speak one of three command words, whereupon an amount of fresh water or salt water (your choice) pours out of the flask. The water stops pouring out at the start of your next turn. Choose from the following options:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 3, '"Stream" produces 1 gallon of water.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 4, '"Fountain" produces 5 gallons of water.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('decanter-of-endless-water', 5, '"Geyser" produces 30 gallons of water that gushes forth in a geyser 30 feet long and 1 foot wide. As a bonus action while holding the decanter, you can aim the geyser at a creature you can see within 30 feet of you. The target must succeed on a DC 13 Strength saving throw or take 1d4 bludgeoning damage and fall prone. Instead of a creature, you can target an object that isn''t being worn or carried and that weighs no more than 200 pounds. The object is either knocked over or pushed up to 15 feet away from you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('decanter-of-endless-water', 'Decanter of Endless Water', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/decanter-of-endless-water.png', '/api/2014/magic-items/decanter-of-endless-water');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 1, 'This box contains a set of parchment cards. A full deck has 34 cards. A deck found as treasure is usually missing 1d20 - 1 cards.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 2, 'The magic of the deck functions only if cards are drawn at random (you can use an altered deck of playing cards to simulate the deck). You can use an action to draw a card at random from the deck and throw it to the ground at a point within 30 feet of you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 3, 'An illusion of one or more creatures forms over the thrown card and remains until dispelled. An illusory creature appears real, of the appropriate size, and behaves as if it were a real creature except that it can do no harm. While you are within 120 feet of the illusory creature and can see it, you can use an action to move it magically anywhere within 30 feet of its card. Any physical interaction with the illusory creature reveals it to be an illusion, because objects pass through it. Someone who uses an action to visually inspect the creature identifies it as illusory with a successful DC 15 Intelligence (Investigation) check. The creature then appears translucent.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 4, 'The illusion lasts until its card is moved or the illusion is dispelled. When the illusion ends, the image on its card disappears, and that card can''t be used again.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-illusions', 5, '| Playing Card | Illusion |');
