INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 1, 'Usually found in a box or pouch, this deck contains a number of cards made of ivory or vellum. Most (75 percent) of these decks have only thirteen cards, but the rest have twenty-two.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 2, 'Before you draw a card, you must declare how many cards you intend to draw and then draw them randomly (you can use an altered deck of playing cards to simulate the deck). Any cards drawn in excess of this number have no effect. Otherwise, as soon as you draw a card from the deck, its magic takes effect. You must draw each card no more than 1 hour after the previous draw. If you fail to draw the chosen number, the remaining number of cards fly from the deck on their own and take effect all at once.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 3, 'Once a card is drawn, it fades from existence. Unless the card is the Fool or the Jester, the card reappears in the deck, making it possible to draw the same card twice.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 4, '| Playing Card | Card |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 5, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 6, '| Ace of diamonds | Vizier* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 7, '| King of diamonds | Sun |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 8, '| Queen of diamonds | Moon |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 9, '| Jack of diamonds | Star |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 10, '| Two of diamonds | Comet* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 11, '| Ace of hearts | The Fates* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 12, '| King of hearts | Throne |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 13, '| Queen of hearts | Key |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 14, '| Jack of hearts | Knight |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 15, '| Two of hearts | Gem* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 16, '| Ace of clubs | Talons* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 17, '| King of clubs | The Void |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 18, '| Queen of clubs | Flames |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 19, '| Jack of clubs | Skull |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 20, '| Two of clubs | Idiot* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 21, '| Ace of spades | Donjon* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 22, '| King of spades | Ruin |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 23, '| Queen of spades | Euryale |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 24, '| Jack of spades | Rogue |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 25, '| Two of spades | Balance* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 26, '| Joker (with TM) | Fool* |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 27, '| Joker (without TM) | Jester |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 28, '* Found only in a deck with twenty-two cards');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 29, '***Balance.*** Your mind suffers a wrenching alteration, causing your alignment to change. Lawful becomes chaotic, good becomes evil, and vice versa. If you are true neutral or unaligned, this card has no effect on you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 30, '***Comet.*** If you single-handedly defeat the next hostile monster or group of monsters you encounter, you gain experience points enough to gain one level. Otherwise, this card has no effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 31, '***Donjon.*** You disappear and become entombed in a state of suspended animation in an extradimensional sphere. Everything you were wearing and carrying stays behind in the space you occupied when you disappeared. You remain imprisoned until you are found and removed from the sphere. You can''t be located by any divination magic, but a wish spell can reveal the location of your prison. You draw no more cards.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 32, '***Euryale.*** The card''s medusa-like visage curses you. You take a -2 penalty on saving throws while cursed in this way. Only a god or the magic of The Fates card can end this curse.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 33, '**The Fates.** Reality''s fabric unravels and spins anew, allowing you to avoid or erase one event as if it never happened. You can use the card''s magic as soon as you draw the card or at any other time before you die.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 34, '***Flames.*** A powerful devil becomes your enemy. The devil seeks your ruin and plagues your life, savoring your suffering before attempting to slay you. This enmity lasts until either you or the devil dies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 35, '***Fool.*** You lose 10,000 XP, discard this card, and draw from the deck again, counting both draws as one of your declared draws. If losing that much XP would cause you to lose a level, you instead lose an amount that leaves you with just enough XP to keep your level.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 36, '***Gem.*** Twenty-five pieces of jewelry worth 2,000 gp each or fifty gems worth 1,000 gp each appear at your feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 37, '***Idiot.*** Permanently reduce your Intelligence by 1d4 + 1 (to a minimum score of 1). You can draw one additional card beyond your declared draws.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 38, '***Jester.*** You gain 10,000 XP, or you can draw two additional cards beyond your declared draws.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 39, '***Key.*** A rare or rarer magic weapon with which you are proficient appears in your hands. The GM chooses the weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 40, '***Knight.*** You gain the service of a 4th-level fighter who appears in a space you choose within 30 feet of you. The fighter is of the same race as you and serves you loyally until death, believing the fates have drawn him or her to you. You control this character.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 41, '***Moon.*** You are granted the ability to cast the wish spell 1d3 times.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 42, '***Rogue.*** A nonplayer character of the GM''s choice becomes hostile toward you. The identity of your new enemy isn''t known until the NPC or someone else reveals it. Nothing less than a wish spell or divine intervention can end the NPC''s hostility toward you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 43, '***Ruin.*** All forms of wealth that you carry or own, other than magic items, are lost to you. Portable property vanishes. Businesses, buildings, and land you own are lost in a way that alters reality the least. Any documentation that proves you should own something lost to this card also disappears.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('deck-of-many-things', 44, '***Skull.*** You summon an avatar of death-a ghostly humanoid skeleton clad in a tattered black robe and carrying a spectral scythe. It appears in a space of the GM''s choice within 10 feet of you and attacks you, warning all others that you must win the battle alone. The avatar fights until you die or it drops to 0 hit points, whereupon it disappears. If anyone tries to help you, the helper summons its own avatar of death. A creature slain by an avatar of death can''t be restored to life.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('deck-of-many-things', 'Deck of Many Things', 'wondrous-items', 'Legendary', 0, '/api/images/magic-items/deck-of-many-things.png', '/api/2014/magic-items/deck-of-many-things');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('defender', 0, 'Weapon (any sword), legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('defender', 1, 'You gain a +3 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('defender', 2, 'The first time you attack with the sword on each of your turns, you can transfer some or all of the sword''s bonus to your Armor Class, instead of using the bonus on any attacks that turn. For example, you could reduce the bonus to your attack and damage rolls to +1 and gain a +2 bonus to AC. The adjusted bonuses remain in effect until the start of your next turn, although you must hold the sword to gain a bonus to AC from it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('defender', 'Defender', 'weapon', 'Legendary', 0, '/api/images/magic-items/defender.png', '/api/2014/magic-items/defender');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('demon-armor', 0, 'Armor (plate), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('demon-armor', 1, 'While wearing this armor, you gain a +1 bonus to AC, and you can understand and speak Abyssal. In addition, the armor''s clawed gauntlets turn unarmed strikes with your hands into magic weapons that deal slashing damage, with a +1 bonus to attack rolls and damage rolls and a damage die of 1d8.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('demon-armor', 2, '***Curse.*** Once you don this cursed armor, you can''t doff it unless you are targeted by the remove curse spell or similar magic. While wearing the armor, you have disadvantage on attack rolls against demons and on saving throws against their spells and special abilities.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('demon-armor', 'Demon Armor', 'armor', 'Very Rare', 0, '/api/images/magic-items/demon-armor.png', '/api/2014/magic-items/demon-armor');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dimensional-shackles', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dimensional-shackles', 1, 'You can use an action to place these shackles on an incapacitated creature. The shackles adjust to fit a creature of Small to Large size. In addition to serving as mundane manacles, the shackles prevent a creature bound by them from using any method of extradimensional movement, including teleportation or travel to a different plane of existence. They don''t prevent the creature from passing through an interdimensional portal.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dimensional-shackles', 2, 'You and any creature you designate when you use the shackles can use an action to remove them. Once every 30 days, the bound creature can make a DC 30 Strength (Athletics) check. On a success, the creature breaks free and destroys the shackles.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dimensional-shackles', 'Dimensional Shackles', 'wondrous-items', 'Rare', 0, '/api/images/magic-items/dimensional-shackles.png', '/api/2014/magic-items/dimensional-shackles');
