INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-black', 0, 'Armor (scale mail), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-black', 1, 'Dragon scale mail is made of the scales of a black dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-black', 2, 'While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to acid damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-black', 3, 'Additionally, you can focus your senses as an action to magically discern the distance and direction to the closest black dragon within 30 miles of you. This special action can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dragon-scale-mail-black', 'Black Dragon Scale Mail', 'armor', 'Very Rare', 1, '/api/images/magic-items/dragon-scale-mail-black.png', '/api/2014/magic-items/dragon-scale-mail-black');
