INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-brass', 0, 'Armor (scale mail), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-brass', 1, 'Dragon scale mail is made of the scales of a brass dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-brass', 2, 'While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to fire damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-brass', 3, 'Additionally, you can focus your senses as an action to magically discern the distance and direction to the closest brass dragon within 30 miles of you. This special action can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dragon-scale-mail-brass', 'Brass Dragon Scale Mail', 'armor', 'Very Rare', 1, '/api/images/magic-items/dragon-scale-mail-brass.png', '/api/2014/magic-items/dragon-scale-mail-brass');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-bronze', 0, 'Armor (scale mail), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-bronze', 1, 'Dragon scale mail is made of the scales of a bronze dragon. Sometimes dragons collect their cast-off scales and gift them to humanoids. Other times, hunters carefully skin and preserve the hide of a dead dragon. In either case, dragon scale mail is highly valued.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-bronze', 2, 'While wearing this armor, you gain a +1 bonus to AC, you have advantage on saving throws against the Frightful Presence and breath weapons of dragons, and you have resistance to lightning damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-scale-mail-bronze', 3, 'Additionally, you can focus your senses as an action to magically discern the distance and direction to the closest bronze dragon within 30 miles of you. This special action can''t be used again until the next dawn.');
