INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-slayer', 0, 'Weapon (any sword), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-slayer', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dragon-slayer', 2, 'When you hit a dragon with this weapon, the dragon takes an extra 3d6 damage of the weapon''s type. For the purpose of this weapon, "dragon" refers to any creature with the dragon type, including dragon turtles and wyverns.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dragon-slayer', 'Dragon Slayer', 'weapon', 'Rare', 0, '/api/images/magic-items/dragon-slayer.png', '/api/2014/magic-items/dragon-slayer');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-disappearance', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-disappearance', 1, 'Found in a small packet, this powder resembles very fine sand. There is enough of it for one use. When you use an action to throw the dust into the air, you and each creature and object within 10 feet of you become invisible for 2d4 minutes. The duration is the same for all subjects, and the dust is consumed when its magic takes effect. If a creature affected by the dust attacks or casts a spell, the invisibility ends for that creature.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dust-of-disappearance', 'Dust of Disappearance', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/dust-of-disappearance.png', '/api/2014/magic-items/dust-of-disappearance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-dryness', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-dryness', 1, 'This small packet contains 1d6 + 4 pinches of dust. You can use an action to sprinkle a pinch of it over water. The dust turns a cube of water 15 feet on a side into one marble-sized pellet, which floats or rests near where the dust was sprinkled. The pellet''s weight is negligible.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-dryness', 2, 'Someone can use an action to smash the pellet against a hard surface, causing the pellet to shatter and release the water the dust absorbed. Doing so ends that pellet''s magic.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-dryness', 3, 'An elemental composed mostly of water that is exposed to a pinch of the dust must make a DC 13 Constitution saving throw, taking 10d6 necrotic damage on a failed save, or half as much damage on a successful one.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dust-of-dryness', 'Dust of Dryness', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/dust-of-dryness.png', '/api/2014/magic-items/dust-of-dryness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-sneezing-and-choking', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-sneezing-and-choking', 1, 'Found in a small container, this powder resembles very fine sand. It appears to be dust of disappearance, and an identify spell reveals it to be such. There is enough of it for one use.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dust-of-sneezing-and-choking', 2, 'When you use an action to throw a handful of the dust into the air, you and each creature that needs to breathe within 30 feet of you must succeed on a DC 15 Constitution saving throw or become unable to breathe, while sneezing uncontrollably. A creature affected in this way is incapacitated and suffocating. As long as it is conscious, a creature can repeat the saving throw at the end of each of its turns, ending the effect on it on a success. The lesser restoration spell can also end the effect on a creature.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dust-of-sneezing-and-choking', 'Dust of Sneezing and Choking', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/dust-of-sneezing-and-choking.png', '/api/2014/magic-items/dust-of-sneezing-and-choking');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dwarven-plate', 0, 'Armor (plate), very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dwarven-plate', 1, 'While wearing this armor, you gain a +2 bonus to AC. In addition, if an effect moves you against your will along the ground, you can use your reaction to reduce the distance you are moved by up to 10 feet.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dwarven-plate', 'Dwarven Plate', 'armor', 'Very Rare', 0, '/api/images/magic-items/dwarven-plate.png', '/api/2014/magic-items/dwarven-plate');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dwarven-thrower', 0, 'Weapon (warhammer), very rare (requires attunement by a dwarf)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('dwarven-thrower', 1, 'You gain a +3 bonus to attack and damage rolls made with this magic weapon. It has the thrown property with a normal range of 20 feet and a long range of 60 feet. When you hit with a ranged attack using this weapon, it deals an extra 1d8 damage or, if the target is a giant, 2d8 damage. Immediately after the attack, the weapon flies back to your hand.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('dwarven-thrower', 'Dwarven Thrower', 'weapon', 'Very Rare', 0, '/api/images/magic-items/dwarven-thrower.png', '/api/2014/magic-items/dwarven-thrower');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efficient-quiver', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efficient-quiver', 1, 'Each of the quiver''s three compartments connects to an extradimensional space that allows the quiver to hold numerous items while never weighing more than 2 pounds. The shortest compartment can hold up to sixty arrows, bolts, or similar objects. The midsize compartment holds up to eighteen javelins or similar objects. The longest compartment holds up to six long objects, such as bows, quarterstaffs, or spears.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efficient-quiver', 2, 'You can draw any item the quiver contains as if doing so from a regular quiver or scabbard.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('efficient-quiver', 'Efficient Quiver', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/efficient-quiver.png', '/api/2014/magic-items/efficient-quiver');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 1, 'This painted brass bottle weighs 1 pound. When you use an action to remove the stopper, a cloud of thick smoke flows out of the bottle. At the end of your turn, the smoke disappears with a flash of harmless fire, and an efreeti appears in an unoccupied space within 30 feet of you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 2, 'The first time the bottle is opened, the GM rolls to determine what happens.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 3, '| d100 | Effect |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 4, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 5, '| 01-10 | The efreeti attacks you. After fighting for 5 rounds, the efreeti disappears, and the bottle loses its magic. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 6, '| 11-90 | The efreeti serves you for 1 hour, doing as you command. Then the efreeti returns to the bottle, and a new stopper contains it. The stopper can''t be removed for 24 hours. The next two times the bottle is opened, the same effect occurs. If the bottle is opened a fourth time, the efreeti escapes and disappears, and the bottle loses its magic. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('efreeti-bottle', 7, '| 91-100 | The efreeti can cast the wish spell three times for you. It disappears when it grants the final wish or after 1 hour, and the bottle loses its magic. |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('efreeti-bottle', 'Efreeti Bottle', 'wondrous-items', 'Very Rare', 0, '/api/images/magic-items/efreeti-bottle.png', '/api/2014/magic-items/efreeti-bottle');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('elemental-gem-air', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('elemental-gem-earth', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('elemental-gem-fire', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('elemental-gem-water', 3);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 1, 'This gem contains a mote of elemental energy. When you use an action to break the gem, an elemental is summoned as if you had cast the conjure elemental spell, and the gem''s magic is lost. The type of gem determines the elemental summoned by the spell.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 2, '| Gem | Summoned Elemental |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 3, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 4, '| Blue sapphire | Air elemental |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 5, '| Yellow diamond | Earth elemental |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 6, '| Red corundum | Fire elemental |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem', 7, '| Emerald | Water elemental |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('elemental-gem', 'Elemental Gem', 'wondrous-items', 'Uncommon', 0, '/api/images/magic-items/elemental-gem.png', '/api/2014/magic-items/elemental-gem');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-air', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-air', 1, 'This blue sapphire contains a mote of elemental energy. When you use an action to break the gem, an air elemental is summoned as if you had cast the conjure elemental spell, and the gem''s magic is lost.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('elemental-gem-air', 'Air Elemental Gem', 'wondrous-items', 'Uncommon', 1, '/api/images/magic-items/elemental-gem-air.png', '/api/2014/magic-items/elemental-gem-air');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-earth', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-earth', 1, 'This yellow diamond contains a mote of elemental energy. When you use an action to break the gem, an earth elemental is summoned as if you had cast the conjure elemental spell, and the gem''s magic is lost.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('elemental-gem-earth', 'Earth Elemental Gem', 'wondrous-items', 'Uncommon', 1, '/api/images/magic-items/elemental-gem-earth.png', '/api/2014/magic-items/elemental-gem-earth');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-fire', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-fire', 1, 'This red corundum contains a mote of elemental energy. When you use an action to break the gem, a fire elemental is summoned as if you had cast the conjure elemental spell, and the gem''s magic is lost.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('elemental-gem-fire', 'Fire Elemental Gem', 'wondrous-items', 'Uncommon', 1, '/api/images/magic-items/elemental-gem-fire.png', '/api/2014/magic-items/elemental-gem-fire');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-water', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elemental-gem-water', 1, 'This emerald contains a mote of elemental energy. When you use an action to break the gem, a water elemental is summoned as if you had cast the conjure elemental spell, and the gem''s magic is lost.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, image, url) VALUES ('elemental-gem-water', 'Water Elemental Gem', 'wondrous-items', 'Uncommon', 1, '/api/images/magic-items/elemental-gem-water.png', '/api/2014/magic-items/elemental-gem-water');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elven-chain', 0, 'Armor (chain shirt), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('elven-chain', 1, 'You gain a +1 bonus to AC while you wear this armor. You are considered proficient with this armor even if you lack proficiency with medium armor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('elven-chain', 'Elven Chain', 'armor', 'Rare', 0, '/api/2014/magic-items/elven-chain');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eversmoking-bottle', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eversmoking-bottle', 1, 'Smoke leaks from the lead-stoppered mouth of this brass bottle, which weighs 1 pound. When you use an action to remove the stopper, a cloud of thick smoke pours out in a 60-foot radius from the bottle. The cloud''s area is heavily obscured. Each minute the bottle remains open and within the cloud, the radius increases by 10 feet until it reaches its maximum radius of 120 feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eversmoking-bottle', 2, 'The cloud persists as long as the bottle is open. Closing the bottle requires you to speak its command word as an action. Once the bottle is closed, the cloud disperses after 10 minutes. A moderate wind (11 to 20 miles per hour) can also disperse the smoke after 1 minute, and a strong wind (21 or more miles per hour) can do so after 1 round.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('eversmoking-bottle', 'Eversmoking Bottle', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/eversmoking-bottle');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-charming', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-charming', 1, 'These crystal lenses fit over the eyes. They have 3 charges. While wearing them, you can expend 1 charge as an action to cast the charm person spell (save DC 13) on a humanoid within 30 feet of you, provided that you and the target can see each other. The lenses regain all expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('eyes-of-charming', 'Eyes of Charming', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/eyes-of-charming');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-minute-seeing', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-minute-seeing', 1, 'These crystal lenses fit over the eyes. While wearing them, you can see much better than normal out to a range of 1 foot. You have advantage on Intelligence (Investigation) checks that rely on sight while searching an area or studying an object within that range.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('eyes-of-minute-seeing', 'Eyes of Minute Seeing', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/eyes-of-minute-seeing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-the-eagle', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('eyes-of-the-eagle', 1, 'These crystal lenses fit over the eyes. While wearing them, you have advantage on Wisdom (Perception) checks that rely on sight. In conditions of clear visibility, you can make out details of even extremely distant creatures and objects as small as 2 feet across.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('eyes-of-the-eagle', 'Eyes of the Eagle', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/eyes-of-the-eagle');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-anchor', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-bird', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-fan', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-swan-boat', 3);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-tree', 4);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('feather-token-whip', 5);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 1, 'This tiny object looks like a feather. Different types of feather tokens exist, each with a different single use effect. The GM chooses the kind of token or determines it randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 2, '| d100 | Feather Token |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 3, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 4, '| 01-20 | Anchor |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 5, '| 21-35 | Bird |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 6, '| 36-50 | Fan |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 7, '| 51-65 | Swan boat |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 8, '| 66-90 | Tree |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 9, '| 91-100 | Whip |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 10, '***Anchor.*** You can use an action to touch the token to a boat or ship. For the next 24 hours, the vessel can''t be moved by any means. Touching the token to the vessel again ends the effect. When the effect ends, the token disappears.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 11, '***Bird.*** You can use an action to toss the token 5 feet into the air. The token disappears and an enormous, multicolored bird takes its place. The bird has the statistics of a roc, but it obeys your simple commands and can''t attack. It can carry up to 500 pounds while flying at its maximum speed (16 miles an hour for a maximum of 144 miles per day, with a one-hour rest for every 3 hours of flying), or 1,000 pounds at half that speed. The bird disappears after flying its maximum distance for a day or if it drops to 0 hit points. You can dismiss the bird as an action.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 12, '***Fan.*** If you are on a boat or ship, you can use an action to toss the token up to 10 feet in the air. The token disappears, and a giant flapping fan takes its place. The fan floats and creates a wind strong enough to fill the sails of one ship, increasing its speed by 5 miles per hour for 8 hours. You can dismiss the fan as an action.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 13, '***Swan Boat.*** You can use an action to touch the token to a body of water at least 60 feet in diameter. The token disappears, and a 50-foot-long, 20-foot wide boat shaped like a swan takes its place. The boat is self-propelled and moves across water at a speed of 6 miles per hour. You can use an action while on the boat to command it to move or to turn up to 90 degrees. The boat can carry up to thirty-two Medium or smaller creatures. A Large creature counts as four Medium creatures, while a Huge creature counts as nine. The boat remains for 24 hours and then disappears. You can dismiss the boat as an action.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 14, '***Tree.*** You must be outdoors to use this token. You can use an action to touch it to an unoccupied space on the ground. The token disappears, and in its place a nonmagical oak tree springs into existence. The tree is 60 feet tall and has a 5-foot-diameter trunk, and its branches at the top spread out in a 20-foot radius.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 15, '***Whip.*** You can use an action to throw the token to a point within 10 feet of you. The token disappears, and a floating whip takes its place. You can then use a bonus action to make a melee spell attack against a creature within 10 feet of the whip, with an attack bonus of +9. On a hit, the target takes 1d6 + 5 force damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token', 16, 'As a bonus action on your turn, you can direct the whip to fly up to 20 feet and repeat the attack against a creature within 10 feet of it. The whip disappears after 1 hour, when you use an action to dismiss it, or when you are incapacitated or die.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('feather-token', 'Feather Token', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/feather-token');
