INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token-anchor', 1, 'This tiny object looks like a feather.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('feather-token-anchor', 2, 'You can use an action to touch the token to a boat or ship. For the next 24 hours, the vessel can''t be moved by any means. Touching the token to the vessel again ends the effect. When the effect ends, the token disappears.');
