INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 9, 'Speed 30 ft., fly 60 ft.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 10, '| STR | DEX | CON | INT | WIS | CHA |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 11, '|---|---|---|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 12, '| 14 (+2) | 13 (+1) | 13 (+1) | 2 (-4) | 10 (+0) | 3 (-4) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 13, 'Senses darkvision 60 ft., passive Perception 10');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ebony-fly', 14, 'Languages -');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-ebony-fly', 'Ebony Fly Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-ebony-fly');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-golden-lions', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-golden-lions', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-golden-lions', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-golden-lions', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-golden-lions', 4, '***Golden Lions.*** These gold statuettes of lions are always created in pairs. You can use one figurine or both simultaneously. Each can become a lion for up to 1 hour. Once a lion has been used, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-golden-lions', 'Golden Lions Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-golden-lions');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 4, '***Ivory Goats.*** These ivory statuettes of goats are always created in sets of three. Each goat looks unique and functions differently from the others. Their properties are as follows:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 5, 'The goat of traveling can become a Large goat with the same statistics as a riding horse. It has 24 charges, and each hour or portion thereof it spends in beast form costs 1 charge. While it has charges, you can use it as often as you wish. When it runs out of charges, it reverts to a figurine and can''t be used again until 7 days have passed, when it regains all its charges.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 6, 'The goat of travail becomes a giant goat for up to 3 hours. Once it has been used, it can''t be used again until 30 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-ivory-goats', 7, 'The goat of terror becomes a giant goat for up to 3 hours. The goat can''t attack, but you can remove its horns and use them as weapons. One horn becomes a +1 lance, and the other becomes a +2 longsword. Removing a horn requires an action, and the weapons disappear and the horns return when the goat reverts to figurine form. In addition, the goat radiates a 30-foot-radius aura of terror while you are riding it. Any creature hostile to you that starts its turn in the aura must succeed on a DC 15 Wisdom saving throw or be frightened of the goat for 1 minute, or until the goat reverts to figurine form. The frightened creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. Once it successfully saves against the effect, a creature is immune to the goat''s aura for the next 24 hours. Once the figurine has been used, it can''t be used again until 15 days have passed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-ivory-goats', 'Ivory Goats Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-ivory-goats');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-marble-elephant', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-marble-elephant', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-marble-elephant', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-marble-elephant', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-marble-elephant', 4, '***Marble Elephant.*** This marble statuette is about 4 inches high and long. It can become an elephant for up to 24 hours. Once it has been used, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-marble-elephant', 'Marble Elephant Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-marble-elephant');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 4, '***Obsidian Steed.*** This polished obsidian horse can become a nightmare for up to 24 hours. The nightmare fights only to defend itself. Once it has been used, it can''t be used again until 5 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-obsidian-steed', 5, 'If you have a good alignment, the figurine has a 10 percent chance each time you use it to ignore your orders, including a command to revert to figurine form. If you mount the nightmare while it is ignoring your orders, you and the nightmare are instantly transported to a random location on the plane of Hades, where the nightmare reverts to figurine form.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-obsidian-steed', 'Obsidian Steed Figurine of Wondrous Power', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-obsidian-steed');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-onyx-dog', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-onyx-dog', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-onyx-dog', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-onyx-dog', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-onyx-dog', 4, '***Onyx Dog.*** This onyx statuette of a dog can become a mastiff for up to 6 hours. The mastiff has an Intelligence of 8 and can speak Common. It also has darkvision out to a range of 60 feet and can see invisible creatures and objects within that range. Once it has been used, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-onyx-dog', 'Onyx Dog Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-onyx-dog');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-serpentine-owl', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-serpentine-owl', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-serpentine-owl', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-serpentine-owl', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-serpentine-owl', 4, '***Serpentine Owl.*** This serpentine statuette of an owl can become a giant owl for up to 8 hours. Once it has been used, it can''t be used again until 2 days have passed. The owl can telepathically communicate with you at any range if you and it are on the same plane of existence.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-serpentine-owl', 'Serpentine Owl Figurine of Wondrous Power', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/figurine-of-wondrous-power-serpentine-owl');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-silver-raven', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-silver-raven', 1, 'A figurine of wondrous power is a statuette of a beast small enough to fit in a pocket. If you use an action to speak the command word and throw the figurine to a point on the ground within 60 feet of you, the figurine becomes a living creature. If the space where the creature would appear is occupied by other creatures or objects, or if there isn''t enough space for the creature, the figurine doesn''t become a creature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-silver-raven', 2, 'The creature is friendly to you and your companions. It understands your languages and obeys your spoken commands. If you issue no commands, the creature defends itself but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-silver-raven', 3, 'The creature exists for a duration specific to each figurine. At the end of the duration, the creature reverts to its figurine form. It reverts to a figurine early if it drops to 0 hit points or if you use an action to speak the command word again while touching it. When the creature becomes a figurine again, its property can''t be used again until a certain amount of time has passed, as specified in the figurine''s description.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('figurine-of-wondrous-power-silver-raven', 4, '***Silver Raven.*** This silver statuette of a raven can become a raven for up to 12 hours. Once it has been used, it can''t be used again until 2 days have passed. While in raven form, the figurine allows you to cast the animal messenger spell on it at will.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('figurine-of-wondrous-power-silver-raven', 'Silver Raven Figurine of Wondrous Power', 'wondrous-items', 'Uncommon', 1, '/api/2014/magic-items/figurine-of-wondrous-power-silver-raven');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('flame-tongue', 0, 'Weapon (any sword), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('flame-tongue', 1, 'You can use a bonus action to speak this magic sword''s command word, causing flames to erupt from the blade. These flames shed bright light in a 40-foot radius and dim light for an additional 40 feet. While the sword is ablaze, it deals an extra 2d6 fire damage to any target it hits. The flames last until you use a bonus action to speak the command word again or until you drop or sheathe the sword.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('flame-tongue', 'Flame Tongue', 'weapon', 'Rare', 0, '/api/2014/magic-items/flame-tongue');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 1, 'This object appears as a wooden box that measures 12 inches long, 6 inches wide, and 6 inches deep. It weighs 4 pounds and floats. It can be opened to store items inside. This item also has three command words, each requiring you to use an action to speak it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 2, 'One command word causes the box to unfold into a boat 10 feet long, 4 feet wide, and 2 feet deep. The boat has one pair of oars, an anchor, a mast, and a lateen sail. The boat can hold up to four Medium creatures comfortably.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 3, 'The second command word causes the box to unfold into a ship 24 feet long, 8 feet wide, and 6 feet deep. The ship has a deck, rowing seats, five sets of oars, a steering oar, an anchor, a deck cabin, and a mast with a square sail. The ship can hold fifteen Medium creatures comfortably.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 4, 'When the box becomes a vessel, its weight becomes that of a normal vessel its size, and anything that was stored in the box remains in the boat.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('folding-boat', 5, 'The third command word causes the folding boat to fold back into a box, provided that no creatures are aboard. Any objects in the vessel that can''t fit inside the box remain outside the box as it folds. Any objects in the vessel that can fit inside the box do so.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('folding-boat', 'Folding Boat', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/folding-boat');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('frost-brand', 0, 'Weapon (any sword), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('frost-brand', 1, 'When you hit with an attack using this magic sword, the target takes an extra 1d6 cold damage. In addition, while you hold the sword, you have resistance to fire damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('frost-brand', 2, 'In freezing temperatures, the blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('frost-brand', 3, 'When you draw this weapon, you can extinguish all nonmagical flames within 30 feet of you. This property can be used no more than once per hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('frost-brand', 'Frost Brand', 'weapon', 'Very Rare', 0, '/api/2014/magic-items/frost-brand');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gauntlets-of-ogre-power', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gauntlets-of-ogre-power', 1, 'Your Strength score is 19 while you wear these gauntlets. They have no effect on you if your Strength is already 19 or higher.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('gauntlets-of-ogre-power', 'Gauntlets of Ogre Power', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/gauntlets-of-ogre-power');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 1, 'This prism has 50 charges. While you are holding it, you can use an action to speak one of three command words to cause one of the following effects:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 2, 'The first command word causes the gem to shed bright light in a 30-foot radius and dim light for an additional 30 feet. This effect doesn''t expend a charge. It lasts until you use a bonus action to repeat the command word or until you use another function of the gem.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 3, 'The second command word expends 1 charge and causes the gem to fire a brilliant beam of light at one creature you can see within 60 feet of you. The creature must succeed on a DC 15 Constitution saving throw or become blinded for 1 minute. The creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 4, 'The third command word expends 5 charges and causes the gem to flare with blinding light in a 30 foot cone originating from it. Each creature in the cone must make a saving throw as if struck by the beam created with the second command word.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-brightness', 5, 'When all of the gem''s charges are expended, the gem becomes a nonmagical jewel worth 50 gp.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('gem-of-brightness', 'Gem of Brightness', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/gem-of-brightness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-seeing', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-seeing', 1, 'This gem has 3 charges. As an action, you can speak the gem''s command word and expend 1 charge. For the next 10 minutes, you have truesight out to 120 feet when you peer through the gem.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gem-of-seeing', 2, 'The gem regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('gem-of-seeing', 'Gem of Seeing', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/gem-of-seeing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('giant-slayer', 0, 'Weapon (any axe or sword), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('giant-slayer', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('giant-slayer', 2, 'When you hit a giant with it, the giant takes an extra 2d6 damage of the weapon''s type and must succeed on a DC 15 Strength saving throw or fall prone. For the purpose of this weapon, "giant" refers to any creature with the giant type, including ettins and trolls.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('giant-slayer', 'Giant Slayer', 'weapon', 'Rare', 0, '/api/2014/magic-items/giant-slayer');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('glamoured-studded-leather-armor', 0, 'Armor (studded leather), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('glamoured-studded-leather-armor', 1, 'While wearing this armor, you gain a +1 bonus to AC. You can also use a bonus action to speak the armor''s command word and cause the armor to assume the appearance of a normal set of clothing or some other kind of armor. You decide what it looks like, including color, style, and accessories, but the armor retains its normal bulk and weight. The illusory appearance lasts until you use this property again or remove the armor.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('glamoured-studded-leather-armor', 'Glamoured Studded Leather Armor', 'armor', 'Rare', 0, '/api/2014/magic-items/glamoured-studded-leather-armor');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gloves-of-missile-snaring', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gloves-of-missile-snaring', 1, 'These gloves seem to almost meld into your hands when you don them. When a ranged weapon attack hits you while you''re wearing them, you can use your reaction to reduce the damage by 1d10 + your Dexterity modifier, provided that you have a free hand. If you reduce the damage to 0, you can catch the missile if it is small enough for you to hold in that hand.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('gloves-of-missile-snaring', 'Gloves of Missile Snaring', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/gloves-of-missile-snaring');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gloves-of-swimming-and-climbing', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('gloves-of-swimming-and-climbing', 1, 'While wearing these gloves, climbing and swimming don''t cost you extra movement, and you gain a +5 bonus to Strength (Athletics) checks made to climb or swim.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('gloves-of-swimming-and-climbing', 'Gloves of Swimming and Climbing', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/gloves-of-swimming-and-climbing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('goggles-of-night', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('goggles-of-night', 1, 'While wearing these dark lenses, you have darkvision out to a range of 60 feet. If you already have darkvision, wearing the goggles increases its range by 60 feet.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('goggles-of-night', 'Goggles of Night', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/goggles-of-night');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hammer-of-thunderbolts', 0, 'Weapon (maul), legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hammer-of-thunderbolts', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hammer-of-thunderbolts', 2, 'Giant''s Bane (Requires Attunement). You must be wearing a belt of giant strength (any variety) and gauntlets of ogre power to attune to this weapon. The attunement ends if you take off either of those items. While you are attuned to this weapon and holding it, your Strength score increases by 4 and can exceed 20, but not 30. When you roll a 20 on an attack roll made with this weapon against a giant, the giant must succeed on a DC 17 Constitution saving throw or die.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hammer-of-thunderbolts', 3, 'The hammer also has 5 charges. While attuned to it, you can expend 1 charge and make a ranged weapon attack with the hammer, hurling it as if it had the thrown property with a normal range of 20 feet and a long range of 60 feet. If the attack hits, the hammer unleashes a thunderclap audible out to 300 feet. The target and every creature within 30 feet of it must succeed on a DC 17 Constitution saving throw or be stunned until the end of your next turn. The hammer regains 1d4 + 1 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('hammer-of-thunderbolts', 'Hammer of Thunderbolts', 'weapon', 'Legendary', 0, '/api/2014/magic-items/hammer-of-thunderbolts');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('handy-haversack', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('handy-haversack', 1, 'This backpack has a central pouch and two side pouches, each of which is an extradimensional space. Each side pouch can hold up to 20 pounds of material, not exceeding a volume of 2 cubic feet. The large central pouch can hold up to 8 cubic feet or 80 pounds of material. The backpack always weighs 5 pounds, regardless of its contents.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('handy-haversack', 2, 'Placing an object in the haversack follows the normal rules for interacting with objects. Retrieving an item from the haversack requires you to use an action. When you reach into the haversack for a specific item, the item is always magically on top.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('handy-haversack', 3, 'The haversack has a few limitations. If it is overloaded, or if a sharp object pierces it or tears it, the haversack ruptures and is destroyed. If the haversack is destroyed, its contents are lost forever, although an artifact always turns up again somewhere. If the haversack is turned inside out, its contents spill forth, unharmed, and the haversack must be put right before it can be used again. If a breathing creature is placed within the haversack, the creature can survive for up to 10 minutes, after which time it begins to suffocate.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('handy-haversack', 4, 'Placing the haversack inside an extradimensional space created by a bag of holding, portable hole, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate is sucked through it and deposited in a random location on the Astral Plane. The gate then closes. The gate is one-way only and can''t be reopened.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('handy-haversack', 'Handy Haversack', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/handy-haversack');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hat-of-disguise', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('hat-of-disguise', 1, 'While wearing this hat, you can use an action to cast the disguise self spell from it at will. The spell ends if the hat is removed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('hat-of-disguise', 'Hat of Disguise', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/hat-of-disguise');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('headband-of-intellect', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('headband-of-intellect', 1, 'Your Intelligence score is 19 while you wear this headband. It has no effect on you if your Intelligence is already 19 or higher.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('headband-of-intellect', 'Headband of Intellect', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/headband-of-intellect');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 1, 'This dazzling helm is set with 1d10 diamonds, 2d10 rubies, 3d10 fire opals, and 4d10 opals. Any gem pried from the helm crumbles to dust. When all the gems are removed or destroyed, the helm loses its magic.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 2, 'You gain the following benefits while wearing it:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 3, 'You can use an action to cast one of the following spells (save DC 18), using one of the helm''s gems of the specified type as a component: daylight (opal), fireball (fire opal), prismatic spray (diamond), or wall of fire (ruby). The gem is destroyed when the spell is cast and disappears from the helm.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 4, 'As long as it has at least one diamond, the helm emits dim light in a 30-foot radius when at least one undead is within that area. Any undead that starts its turn in that area takes 1d6 radiant damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 5, 'As long as the helm has at least one ruby, you have resistance to fire damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 6, 'As long as the helm has at least one fire opal, you can use an action and speak a command word to cause one weapon you are holding to burst into flames. The flames emit bright light in a 10-foot radius and dim light for an additional 10 feet. The flames are harmless to you and the weapon. When you hit with an attack using the blazing weapon, the target takes an extra 1d6 fire damage. The flames last until you use a bonus action to speak the command word again or until you drop or stow the weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-brilliance', 7, 'Roll a d20 if you are wearing the helm and take fire damage as a result of failing a saving throw against a spell. On a roll of 1, the helm emits beams of light from its remaining gems. Each creature within 60 feet of the helm other than you must succeed on a DC 17 Dexterity saving throw or be struck by a beam, taking radiant damage equal to the number of gems in the helm. The helm and its gems are then destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('helm-of-brilliance', 'Helm of Brilliance', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/helm-of-brilliance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-comprehending-languages', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-comprehending-languages', 1, 'While wearing this helm, you can use an action to cast the comprehend languages spell from it at will.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('helm-of-comprehending-languages', 'Helm of Comprehending Languages', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/helm-of-comprehending-languages');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-telepathy', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-telepathy', 1, 'While wearing this helm, you can use an action to cast the detect thoughts spell (save DC 13) from it. As long as you maintain concentration on the spell, you can use a bonus action to send a telepathic message to a creature you are focused on. It can reply-using a bonus action to do so-while your focus on it continues.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-telepathy', 2, 'While focusing on a creature with detect thoughts, you can use an action to cast the suggestion spell (save DC 13) from the helm on that creature. Once used, the suggestion property can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('helm-of-telepathy', 'Helm of Telepathy', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/helm-of-telepathy');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-teleportation', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-teleportation', 1, 'This helm has 3 charges. While wearing it, you can use an action and expend 1 charge to cast the teleport spell from it. The helm regains 1d3');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('helm-of-teleportation', 2, 'expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('helm-of-teleportation', 'Helm of Teleportation', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/helm-of-teleportation');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('holy-avenger', 0, 'Weapon (any sword), legendary (requires attunement by a paladin)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('holy-avenger', 1, 'You gain a +3 bonus to attack and damage rolls made with this magic weapon. When you hit a fiend or an undead with it, that creature takes an extra 2d10 radiant damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('holy-avenger', 2, 'While you hold the drawn sword, it creates an aura in a 10-foot radius around you. You and all creatures friendly to you in the aura have advantage on saving throws against spells and other magical effects. If you have 17 or more levels in the paladin class, the radius of the aura increases to 30 feet.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('holy-avenger', 'Holy Avenger', 'weapon', 'Legendary', 0, '/api/2014/magic-items/holy-avenger');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-blasting', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-blasting', 1, 'You can use an action to speak the horn''s command word and then blow the horn, which emits a thunderous blast in a 30-foot cone that is audible 600 feet away. Each creature in the cone must make a DC 15 Constitution saving throw. On a failed save, a creature takes 5d6 thunder damage and is deafened for 1 minute. On a successful save, a creature takes half as much damage and isn''t deafened. Creatures and objects made of glass or crystal have disadvantage on the saving throw and take 10d6 thunder damage instead of 5d6.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-blasting', 2, 'Each use of the horn''s magic has a 20 percent chance of causing the horn to explode. The explosion deals 10d6 fire damage to the blower and destroys the horn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-blasting', 'Horn of Blasting', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/horn-of-blasting');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('horn-of-valhalla-silver', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('horn-of-valhalla-brass', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('horn-of-valhalla-bronze', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('horn-of-valhalla-iron', 3);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 0, 'Wondrous item, rare (silver or brass), very rare (bronze) or legendary (iron)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 1, 'You can use an action to blow this horn. In response, warrior spirits from the Valhalla appear within 60 feet of you. They use the statistics of a berserker. They return to Valhalla after 1 hour or when they drop to 0 hit points. Once you use the horn, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 2, 'Four types of horn of Valhalla are known to exist, each made of a different metal. The horn''s type determines how many berserkers answer its summons, as well as the requirement for its use. The GM chooses the horn''s type or determines it randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 3, '| d100 | Horn Type | Berserkers Summoned | Requirement |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 4, '|---|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 5, '| 01-40 | Silver | 2d4 + 2 | None |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 6, '| 41-75 | Brass | 3d4 + 3 | Proficiency with all simple weapons |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 7, '| 76-90 | Bronze | 4d4 + 4 | Proficiency with all medium armor |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 8, '| 91-00 | Iron | 5d4 + 5 | Proficiency with all martial weapons |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla', 9, 'If you blow the horn without meeting its requirement, the summoned berserkers attack you. If you meet the requirement, they are friendly to you and your companions and follow your commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-valhalla', 'Horn of Valhalla', 'wondrous-items', 'Varies', 0, '/api/2014/magic-items/horn-of-valhalla');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-silver', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-silver', 1, 'You can use an action to blow this horn. In response, 2d4 + 2 warrior spirits from the Valhalla appear within 60 feet of you. They use the statistics of a berserker. They return to Valhalla after 1 hour or when they drop to 0 hit points. Once you use the horn, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-silver', 2, 'The summoned berserkers are friendly to you and your companions and follow your commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-valhalla-silver', 'Silver Horn of Valhalla', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/horn-of-valhalla-silver');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-brass', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-brass', 1, 'You can use an action to blow this horn. In response, 3d4 + 3 warrior spirits from the Valhalla appear within 60 feet of you. They use the statistics of a berserker. They return to Valhalla after 1 hour or when they drop to 0 hit points. Once you use the horn, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-brass', 2, 'If you blow the horn without having proficiency with all simple weapons, the summoned berserkers attack you. If you meet the requirement, they are friendly to you and your companions and follow your commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-valhalla-brass', 'Brass Horn of Valhalla', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/horn-of-valhalla-brass');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-bronze', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-bronze', 1, 'You can use an action to blow this horn. In response, 4d4 + 4 warrior spirits from the Valhalla appear within 60 feet of you. They use the statistics of a berserker. They return to Valhalla after 1 hour or when they drop to 0 hit points. Once you use the horn, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-bronze', 2, 'If you blow the horn without having proficiency with all medium armor, the summoned berserkers attack you. If you meet the requirement, they are friendly to you and your companions and follow your commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-valhalla-bronze', 'Bronze Horn of Valhalla', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/horn-of-valhalla-bronze');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-iron', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-iron', 1, 'You can use an action to blow this horn. In response, 5d4 + 5 warrior spirits from the Valhalla appear within 60 feet of you. They use the statistics of a berserker. They return to Valhalla after 1 hour or when they drop to 0 hit points. Once you use the horn, it can''t be used again until 7 days have passed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horn-of-valhalla-iron', 2, 'If you blow the horn without having proficiency with all martial weapons, the summoned berserkers attack you. If you meet the requirement, they are friendly to you and your companions and follow your commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horn-of-valhalla-iron', 'Iron Horn of Valhalla', 'wondrous-items', 'Legendary', 1, '/api/2014/magic-items/horn-of-valhalla-iron');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horseshoes-of-a-zephyr', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horseshoes-of-a-zephyr', 1, 'These iron horseshoes come in a set of four. While all four shoes are affixed to the hooves of a horse or similar creature, they allow the creature to move normally while floating 4 inches above the ground. This effect means the creature can cross or stand above nonsolid or unstable surfaces, such as water or lava. The creature leaves no tracks and ignores difficult terrain. In addition, the creature can move at normal speed for up to 12 hours a day without suffering exhaustion from a forced march.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horseshoes-of-a-zephyr', 'Horseshoes of a Zephyr', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/horseshoes-of-a-zephyr');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horseshoes-of-speed', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('horseshoes-of-speed', 1, 'These iron horseshoes come in a set of four. While all four shoes are affixed to the hooves of a horse or similar creature, they increase the creature''s walking speed by 30 feet.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('horseshoes-of-speed', 'Horseshoes of Speed', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/horseshoes-of-speed');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('immovable-rod', 0, 'Rod, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('immovable-rod', 1, 'This flat iron rod has a button on one end. You can use an action to press the button, which causes the rod to become magically fixed in place. Until you or another creature uses an action to push the button again, the rod doesn''t move, even if it is defying gravity. The rod can hold up to 8,000 pounds of weight. More weight causes the rod to deactivate and fall. A creature can use an action to make a DC 30 Strength check, moving the fixed rod up to 10 feet on a success.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('immovable-rod', 'Immovable Rod', 'rod', 'Uncommon', 0, '/api/2014/magic-items/immovable-rod');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 1, 'You can use an action to place this 1-inch metal cube on the ground and speak its command word. The cube rapidly grows into a fortress that remains until you use an action to speak the command word that dismisses it, which works only if the fortress is empty.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 2, 'The fortress is a square tower, 20 feet on a side and 30 feet high, with arrow slits on all sides and a battlement atop it. Its interior is divided into two floors, with a ladder running along one wall to connect them. The ladder ends at a trapdoor leading to the roof. When activated, the tower has a small door on the side facing you. The door opens only at your command, which you can speak as a bonus action. It is immune to the knock spell and similar magic, such as that of a chime of opening.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 3, 'Each creature in the area where the fortress appears must make a DC 15 Dexterity saving throw, taking 10d10 bludgeoning damage on a failed save, or half as much damage on a successful one. In either case, the creature is pushed to an unoccupied space outside but next to the fortress. Objects in the area that aren''t being worn or carried take this damage and are pushed automatically.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 4, 'The tower is made of adamantine, and its magic prevents it from being tipped over. The roof, the door, and the walls each have 100 hit points,');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('instant-fortress', 5, 'immunity to damage from nonmagical weapons excluding siege weapons, and resistance to all other damage. Only a wish spell can repair the fortress (this use of the spell counts as replicating a spell of 8th level or lower). Each casting of wish causes the roof, the door, or one wall to regain 50 hit points.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('instant-fortress', 'Instant Fortress', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/instant-fortress');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-absorption', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-agility', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-awareness', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-fortitude', 3);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-greater-absorption', 4);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-insight', 5);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ioun-stone-of-intellect', 6);
