INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-reserve', 5, 'Any creature can cast a spell of 1st through 3rd level into the stone by touching it as the spell is cast. The spell has no effect, other than to be stored in the stone. If the stone can''t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-reserve', 6, 'While this stone orbits your head, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster, but is otherwise treated as if you cast the spell. The spell cast from the stone is no longer stored in it, freeing up space.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ioun-stone-of-reserve', 'Ioun Stone of Reserve', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/ioun-stone-of-reserve');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-strength', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-strength', 1, 'An Ioun stone is named after Ioun, a god of knowledge and prophecy revered on some worlds. Many types of Ioun stone exist, each type a distinct combination of shape and color.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-strength', 2, 'When you use an action to toss one of these stones into the air, the stone orbits your head at a distance of 1d3 feet and confers a benefit to you. Thereafter, another creature must use an action to grasp or net the stone to separate it from you, either by making a successful attack roll against AC 24 or a successful DC 24 Dexterity (Acrobatics) check. You can use an action to seize and stow the stone, ending its effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-strength', 3, 'A stone has AC 24, 10 hit points, and resistance to all damage. It is considered to be an object that is being worn while it orbits your head.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-strength', 4, '***Strength.*** Your Strength score increases by 2, to a maximum of 20, while this pale blue rhomboid orbits your head.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ioun-stone-of-strength', 'Ioun Stone of Strength', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/ioun-stone-of-strength');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-sustenance', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-sustenance', 1, 'An Ioun stone is named after Ioun, a god of knowledge and prophecy revered on some worlds. Many types of Ioun stone exist, each type a distinct combination of shape and color.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-sustenance', 2, 'When you use an action to toss one of these stones into the air, the stone orbits your head at a distance of 1d3 feet and confers a benefit to you. Thereafter, another creature must use an action to grasp or net the stone to separate it from you, either by making a successful attack roll against AC 24 or a successful DC 24 Dexterity (Acrobatics) check. You can use an action to seize and stow the stone, ending its effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-sustenance', 3, 'A stone has AC 24, 10 hit points, and resistance to all damage. It is considered to be an object that is being worn while it orbits your head.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ioun-stone-of-sustenance', 4, '***Sustenance.*** You don''t need to eat or drink while this clear spindle orbits your head.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ioun-stone-of-sustenance', 'Ioun Stone of Sustenance', 'wondrous-items', 'Rare', 1, '/api/2014/magic-items/ioun-stone-of-sustenance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-bands-of-binding', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-bands-of-binding', 1, 'This rusty iron sphere measures 3 inches in diameter and weighs 1 pound. You can use an action to speak the command word and throw the sphere at a Huge or smaller creature you can see within 60 feet of you. As the sphere moves through the air, it opens into a tangle of metal bands.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-bands-of-binding', 2, 'Make a ranged attack roll with an attack bonus equal to your Dexterity modifier plus your proficiency bonus. On a hit, the target is restrained until you take a bonus action to speak the command word again to release it. Doing so, or missing with the attack, causes the bands to contract and become a sphere once more.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-bands-of-binding', 3, 'A creature, including the one restrained, can use an action to make a DC 20 Strength check to break the iron bands. On a success, the item is destroyed, and the restrained creature is freed. If the check fails, any further attempts made by that creature automatically fail until 24 hours have elapsed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-bands-of-binding', 4, 'Once the bands are used, they can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('iron-bands-of-binding', 'Iron Bands of Binding', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/iron-bands-of-binding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 1, 'This iron bottle has a brass stopper. You can use an action to speak the flask''s command word, targeting a creature that you can see within 60 feet of you. If the target is native to a plane of existence other than the one you''re on, the target must succeed on a DC 17 Wisdom saving throw or be trapped in the flask. If the target has been trapped by the flask before, it has advantage on the saving throw. Once trapped, a creature remains in the flask until released. The flask can hold only one creature at a time. A creature trapped in the flask doesn''t need to breathe, eat, or drink and doesn''t age.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 2, 'You can use an action to remove the flask''s stopper and release the creature the flask contains. The creature is friendly to you and your companions for 1 hour and obeys your commands for that duration. If you give no commands or give it a command that is likely to result in its death, it defends itself but otherwise takes no actions. At the end of the duration, the creature acts in accordance with its normal disposition and alignment.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 3, 'An identify spell reveals that a creature is inside the flask, but the only way to determine the type of creature is to open the flask. A newly discovered bottle might already contain a creature chosen by the GM or determined randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 4, '| d100 | Contents |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 5, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 6, '| 1-50 | Empty |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 7, '| 51-54 | Demon (type 1) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 8, '| 55-58 | Demon (type 2) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 9, '| 59-62 | Demon (type 3) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 10, '| 63-64 | Demon (type 4) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 11, '| 65 | Demon (type 5) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 12, '| 66 | Demon (type 6) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 13, '| 67 | Deva |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 14, '| 68-69 | Devil (greater) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 15, '| 70-73 | Devil (lesser) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 16, '| 74-75 | Djinni |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 17, '| 76-77 | Efreeti |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 18, '| 78-83 | Elemental (any) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 19, '| 84-86 | Invisible stalker |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 20, '| 87-90 | Night hag |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 21, '| 91 | Planetar |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 22, '| 92-95 | Salamander |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 23, '| 96 | Solar |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 24, '| 97-99 | Succubus/incubus |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('iron-flask', 25, '| 100 | Xorn |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('iron-flask', 'Iron Flask', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/iron-flask');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('javelin-of-lightning', 0, 'Weapon (javelin), uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('javelin-of-lightning', 1, 'This javelin is a magic weapon. When you hurl it and speak its command word, it transforms into a bolt of lightning, forming a line 5 feet wide that extends out from you to a target within 120 feet. Each creature in the line excluding you and the target must make a DC 13 Dexterity saving throw, taking 4d6 lightning damage on a failed save, and half as much damage on a successful one. The lightning bolt turns back into a javelin when it reaches the target. Make a ranged weapon attack against the target. On a hit, the target takes damage from the javelin plus 4d6 lightning damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('javelin-of-lightning', 2, 'The javelin''s property can''t be used again until the next dawn. In the meantime, the javelin can still be used as a magic weapon.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('javelin-of-lightning', 'Javelin of Lightning', 'weapon', 'Uncommon', 0, '/api/2014/magic-items/javelin-of-lightning');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('lantern-of-revealing', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('lantern-of-revealing', 1, 'While lit, this hooded lantern burns for 6 hours on 1 pint of oil, shedding bright light in a 30-foot radius and dim light for an additional 30 feet. Invisible creatures and objects are visible as long as they are in the lantern''s bright light. You can use an action to lower the hood, reducing the light to dim light in a 5 foot radius.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('lantern-of-revealing', 'Lantern of Revealing', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/lantern-of-revealing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('luck-blade', 0, 'Weapon (any sword), legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('luck-blade', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon. While the sword is on your person, you also gain a +1 bonus to saving throws.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('luck-blade', 2, '***Luck.*** If the sword is on your person, you can call on its luck (no action required) to reroll one attack roll, ability check, or saving throw you dislike. You must use the second roll. This property can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('luck-blade', 3, '***Wish.*** The sword has 1d4 - 1 charges. While holding it, you can use an action to expend 1 charge and cast the wish spell from it. This property can''t be used again until the next dawn. The sword loses this property if it has no charges.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('luck-blade', 'Luck Blade', 'weapon', 'Legendary', 0, '/api/2014/magic-items/luck-blade');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-disruption', 0, 'Weapon (mace), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-disruption', 1, 'When you hit a fiend or an undead with this magic weapon, that creature takes an extra 2d6 radiant damage. If the target has 25 hit points or fewer after taking this damage, it must succeed on a DC 15 Wisdom saving throw or be destroyed. On a successful save, the creature becomes frightened of you until the end of your next turn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-disruption', 2, 'While you hold this weapon, it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mace-of-disruption', 'Mace of Disruption', 'weapon', 'Rare', 0, '/api/2014/magic-items/mace-of-disruption');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-smiting', 0, 'Weapon (mace), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-smiting', 1, 'You gain a +1 bonus to attack and damage rolls made with this magic weapon. The bonus increases to +3 when you use the mace to attack a construct.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-smiting', 2, 'When you roll a 20 on an attack roll made with this weapon, the target takes an extra 2d6 bludgeoning damage, or 4d6 bludgeoning damage if it''s a construct. If a construct has 25 hit points or fewer after taking this damage, it is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mace-of-smiting', 'Mace of Smiting', 'weapon', 'Rare', 0, '/api/2014/magic-items/mace-of-smiting');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-terror', 0, 'Weapon (mace), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-terror', 1, 'This magic weapon has 3 charges. While holding it, you can use an action and expend 1 charge to release a wave of terror. Each creature of your choice in a 30-foot radius extending from you must succeed on a DC 15 Wisdom saving throw or become frightened of you for 1 minute. While it is frightened in this way, a creature must spend its turns trying to move as far away from you as it can, and it can''t willingly move to a space within 30 feet of you. It also can''t take reactions. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If it has nowhere it can move, the creature can use the Dodge action. At the end of each of its turns, a creature can repeat the saving throw, ending the effect on itself on a success.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mace-of-terror', 2, 'The mace regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mace-of-terror', 'Mace of Terror', 'weapon', 'Rare', 0, '/api/2014/magic-items/mace-of-terror');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mantle-of-spell-resistance', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mantle-of-spell-resistance', 1, 'You have advantage on saving throws against spells while you wear this cloak.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mantle-of-spell-resistance', 'Mantle of Spell Resistance', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/mantle-of-spell-resistance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-bodily-health', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-bodily-health', 1, 'This book contains health and diet tips, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Constitution score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-bodily-health', 'Manual of Bodily Health', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/manual-of-bodily-health');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-gainful-exercise', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-gainful-exercise', 1, 'This book describes fitness exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Strength score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-gainful-exercise', 'Manual of Gainful Exercise', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/manual-of-gainful-exercise');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('manual-of-golems-clay', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('manual-of-golems-flesh', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('manual-of-golems-iron', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('manual-of-golems-stone', 3);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 1, 'This tome contains information and incantations necessary to make a particular type of golem. The GM chooses the type or determines it randomly. To decipher and use the manual, you must be a spellcaster with at least two 5th-level spell slots. A creature that can''t use a manual of golems and attempts to read it takes 6d6 psychic damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 2, '| d20 | Golem | Time | Cost |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 3, '|---|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 4, '| 1-5 | Clay | 30 days | 65,000 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 5, '| 6-17 | Flesh | 60 days | 50,000 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 6, '| 18 | Iron | 120 days | 100,000 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 7, '| 19-20 | Stone | 90 days | 80,000 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 8, 'To create a golem, you must spend the time shown on the table, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay the specified cost to purchase supplies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems', 9, 'Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. It is under your control, and it understands and obeys your spoken commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-golems', 'Manual of Golems', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/manual-of-golems');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-clay', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-clay', 1, 'This tome contains information and incantations necessary to make a clay golem. To decipher and use the manual, you must be a spellcaster with at least two 5th-level spell slots. A creature that can''t use a manual of golems and attempts to read it takes 6d6 psychic damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-clay', 2, 'To create a golem, you must spend 30 days, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay 65,000 gp to purchase supplies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-clay', 3, 'Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. It is under your control, and it understands and obeys your spoken commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-golems-clay', 'Manual of Clay Golems', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/manual-of-golems-clay');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-flesh', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-flesh', 1, 'This tome contains information and incantations necessary to make a flesh golem. To decipher and use the manual, you must be a spellcaster with at least two 5th-level spell slots. A creature that can''t use a manual of golems and attempts to read it takes 6d6 psychic damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-flesh', 2, 'To create a golem, you must spend 60 days, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay 50,000 gp to purchase supplies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-flesh', 3, 'Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. It is under your control, and it understands and obeys your spoken commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-golems-flesh', 'Manual of Flesh Golems', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/manual-of-golems-flesh');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-iron', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-iron', 1, 'This tome contains information and incantations necessary to make an iron golem. To decipher and use the manual, you must be a spellcaster with at least two 5th-level spell slots. A creature that can''t use a manual of golems and attempts to read it takes 6d6 psychic damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-iron', 2, 'To create a golem, you must spend 120 days, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay 100,000 gp to purchase supplies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-iron', 3, 'Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. It is under your control, and it understands and obeys your spoken commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-golems-iron', 'Manual of Iron Golems', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/manual-of-golems-iron');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-stone', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-stone', 1, 'This tome contains information and incantations necessary to make a stone golem. To decipher and use the manual, you must be a spellcaster with at least two 5th-level spell slots. A creature that can''t use a manual of golems and attempts to read it takes 6d6 psychic damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-stone', 2, 'To create a golem, you must spend 90 days, working without interruption with the manual at hand and resting no more than 8 hours per day. You must also pay 80,000 gp to purchase supplies.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-golems-stone', 3, 'Once you finish creating the golem, the book is consumed in eldritch flames. The golem becomes animate when the ashes of the manual are sprinkled on it. It is under your control, and it understands and obeys your spoken commands.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-golems-stone', 'Manual of Stone Golems', 'wondrous-items', 'Very Rare', 1, '/api/2014/magic-items/manual-of-golems-stone');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-quickness-of-action', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('manual-of-quickness-of-action', 1, 'This book contains coordination and balance exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Dexterity score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('manual-of-quickness-of-action', 'Manual of Quickness of Action', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/manual-of-quickness-of-action');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 1, 'Typically found in 1d4 pots inside a fine wooden box with a brush (weighing 1 pound in total), these pigments allow you to create three-dimensional objects by painting them in two dimensions. The paint flows from the brush to form the desired object as you concentrate on its image.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 2, 'Each pot of paint is sufficient to cover 1,000 square feet of a surface, which lets you create inanimate objects or terrain features-such as a door, a pit, flowers, trees, cells, rooms, or weapons- that are up to 10,000 cubic feet. It takes 10 minutes to cover 100 square feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 3, 'When you complete the painting, the object or terrain feature depicted becomes a real, nonmagical object. Thus, painting a door on a wall creates an actual door that can be opened to whatever is beyond. Painting a pit on a floor creates a real pit, and its depth counts against the total area of objects you create.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 4, 'Nothing created by the pigments can have a value greater than 25 gp. If you paint an object of greater value (such as a diamond or a pile of gold), the object looks authentic, but close inspection reveals it is made from paste, bone, or some other worthless material.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('marvelous-pigments', 5, 'If you paint a form of energy such as fire or lightning, the energy appears but dissipates as soon as you complete the painting, doing no harm to anything.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('marvelous-pigments', 'Marvelous Pigments', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/marvelous-pigments');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('medallion-of-thoughts', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('medallion-of-thoughts', 1, 'The medallion has 3 charges. While wearing it, you can use an action and expend 1 charge to cast the detect thoughts spell (save DC 13) from it. The medallion regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('medallion-of-thoughts', 'Medallion of Thoughts', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/medallion-of-thoughts');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 1, 'When this 4-foot-tall mirror is viewed indirectly, its surface shows faint images of creatures. The mirror weighs 50 pounds, and it has AC 11, 10 hit points, and vulnerability to bludgeoning damage. It shatters and is destroyed when reduced to 0 hit points.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 2, 'If the mirror is hanging on a vertical surface and you are within 5 feet of it, you can use an action to speak its command word and activate it. It remains activated until you use an action to speak the command word again.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 3, 'Any creature other than you that sees its reflection in the activated mirror while within 30 feet of it must succeed on a DC 15 Charisma saving throw or be trapped, along with anything it is wearing or carrying, in one of the mirror''s twelve extradimensional cells. This saving throw is made with advantage if the creature knows the mirror''s nature, and constructs succeed on the saving throw automatically.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 4, 'An extradimensional cell is an infinite expanse filled with thick fog that reduces visibility to 10 feet. Creatures trapped in the mirror''s cells don''t age, and they don''t need to eat, drink, or sleep. A creature trapped within a cell can escape using magic that permits planar travel. Otherwise, the creature is confined to the cell until freed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 5, 'If the mirror traps a creature but its twelve extradimensional cells are already occupied, the mirror frees one trapped creature at random to accommodate the new prisoner. A freed creature appears in an unoccupied space within sight of the mirror but facing away from it. If the mirror is shattered, all creatures it contains are freed and appear in unoccupied spaces near it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 6, 'While within 5 feet of the mirror, you can use an action to speak the name of one creature trapped in it or call out a particular cell by number. The creature named or contained in the named cell appears as an image on the mirror''s surface. You and the creature can then communicate normally.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mirror-of-life-trapping', 7, 'In a similar way, you can use an action to speak a second command word and free one creature trapped in the mirror. The freed creature appears, along with its possessions, in the unoccupied space nearest to the mirror and facing away from it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mirror-of-life-trapping', 'Mirror of Life Trapping', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/mirror-of-life-trapping');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mithral-armor', 0, 'Armor (medium or heavy), uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('mithral-armor', 1, 'Mithral is a light, flexible metal. A mithral chain shirt or breastplate can be worn under normal clothes. If the armor normally imposes disadvantage on Dexterity (Stealth) checks or has a Strength requirement, the mithral version of the armor doesn''t.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('mithral-armor', 'Mithral Armor', 'armor', 'Uncommon', 0, '/api/2014/magic-items/mithral-armor');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-adaptation', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-adaptation', 1, 'While wearing this necklace, you can breathe normally in any environment, and you have advantage on saving throws made against harmful gases and vapors (such as cloudkill and stinking cloud effects, inhaled poisons, and the breath weapons of some dragons).');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('necklace-of-adaptation', 'Necklace of Adaptation', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/necklace-of-adaptation');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-fireballs', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-fireballs', 1, 'This necklace has 1d6 + 3 beads hanging from it. You can use an action to detach a bead and throw it up to 60 feet away. When it reaches the end of its trajectory, the bead detonates as a 3rd-level fireball spell (save DC 15).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-fireballs', 2, 'You can hurl multiple beads, or even the whole necklace, as one action. When you do so, increase the level of the fireball by 1 for each bead beyond the first.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('necklace-of-fireballs', 'Necklace of Fireballs', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/necklace-of-fireballs');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 0, 'Wondrous item, rare (requires attunement by a cleric, druid, or paladin)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 1, 'This necklace has 1d4 + 2 magic beads made from aquamarine, black pearl, or topaz. It also has many nonmagical beads made from stones such as amber, bloodstone, citrine, coral, jade, pearl, or quartz. If a magic bead is removed from the necklace, that bead loses its magic.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 2, 'Six types of magic beads exist. The GM decides the type of each bead on the necklace or determines it randomly. A necklace can have more than one bead of the same type. To use one, you must be wearing the necklace. Each bead contains a spell that you can cast from it as a bonus action (using your spell save DC if a save is necessary). Once a magic bead''s spell is cast, that bead can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 3, '| d20 | Bead of... | Spell |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 4, '|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 5, '| 1-6 | Blessing | Bless |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 6, '| 7-12 | Curing | Cure wounds (2nd level) or lesser restoration |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 7, '| 13-16 | Favor | Greater restoration |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 8, '| 17-18 | Smiting | Branding smite |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 9, '| 19 | Summons | Planar ally |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('necklace-of-prayer-beads', 10, '| 20 | Wind walking | Wind walk |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('necklace-of-prayer-beads', 'Necklace of Prayer Beads', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/necklace-of-prayer-beads');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('nine-lives-stealer', 0, 'Weapon (any sword), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('nine-lives-stealer', 1, 'You gain a +2 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('nine-lives-stealer', 2, 'The sword has 1d8 + 1 charges. If you score a critical hit against a creature that has fewer than 100 hit points, it must succeed on a DC 15 Constitution saving throw or be slain instantly as the sword tears its life force from its body (a construct or an undead is immune). The sword loses 1 charge if the creature is slain. When the sword has no charges remaining, it loses this property.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('nine-lives-stealer', 'Nine Lives Stealer', 'weapon', 'Very Rare', 0, '/api/2014/magic-items/nine-lives-stealer');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oathbow', 0, 'Weapon (longbow), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oathbow', 1, 'When you nock an arrow on this bow, it whispers in Elvish, "Swift defeat to my enemies." When you use this weapon to make a ranged attack, you can, as a command phrase, say, "Swift death to you who have wronged me." The target of your attack becomes your sworn enemy until it dies or until dawn seven days later. You can have only one such sworn enemy at a time. When your sworn enemy dies, you can choose a new one after the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oathbow', 2, 'When you make a ranged attack roll with this weapon against your sworn enemy, you have advantage on the roll. In addition, your target gains no benefit from cover, other than total cover, and you suffer no disadvantage due to long range. If the attack hits, your sworn enemy takes an extra 3d6 piercing damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oathbow', 3, 'While your sworn enemy lives, you have disadvantage on attack rolls with all other weapons.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('oathbow', 'Oathbow', 'weapon', 'Very Rare', 0, '/api/2014/magic-items/oathbow');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-etherealness', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-etherealness', 1, 'Beads of this cloudy gray oil form on the outside of its container and quickly evaporate. The oil can cover a Medium or smaller creature, along with the equipment it''s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of the etherealness spell for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('oil-of-etherealness', 'Oil of Etherealness', 'potion', 'Rare', 0, '/api/2014/magic-items/oil-of-etherealness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-sharpness', 0, 'Potion, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-sharpness', 1, 'This clear, gelatinous oil sparkles with tiny, ultrathin silver shards. The oil can coat one slashing or piercing weapon or up to 5 pieces of slashing or piercing ammunition. Applying the oil takes 1 minute. For 1 hour, the coated item is magical and has a +3 bonus to attack and damage rolls.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('oil-of-sharpness', 'Oil of Sharpness', 'potion', 'Very Rare', 0, '/api/2014/magic-items/oil-of-sharpness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-slipperiness', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-slipperiness', 1, 'This sticky black unguent is thick and heavy in the container, but it flows quickly when poured. The oil can cover a Medium or smaller creature, along with the equipment it''s wearing and carrying (one additional vial is required for each size category above Medium). Applying the oil takes 10 minutes. The affected creature then gains the effect of a freedom of movement spell for 8 hours.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('oil-of-slipperiness', 2, 'Alternatively, the oil can be poured on the ground as an action, where it covers a 10-foot square, duplicating the effect of the grease spell in that area for 8 hours.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('oil-of-slipperiness', 'Oil of Slipperiness', 'potion', 'Uncommon', 0, '/api/2014/magic-items/oil-of-slipperiness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pearl-of-power', 0, 'Wondrous item, uncommon (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pearl-of-power', 1, 'While this pearl is on your person, you can use an action to speak its command word and regain one expended spell slot. If the expended slot was of 4th level or higher, the new slot is 3rd level. Once you use the pearl, it can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('pearl-of-power', 'Pearl of Power', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/pearl-of-power');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-health', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-health', 1, 'You are immune to contracting any disease while you wear this pendant. If you are already infected with a disease, the effects of the disease are suppressed you while you wear the pendant.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('periapt-of-health', 'Periapt of Health', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/periapt-of-health');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-proof-against-poison', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-proof-against-poison', 1, 'This delicate silver chain has a brilliant-cut black gem pendant. While you wear it, poisons have no effect on you. You are immune to the poisoned condition and have immunity to poison damage.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('periapt-of-proof-against-poison', 'Periapt of Proof against Poison', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/periapt-of-proof-against-poison');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-wound-closure', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('periapt-of-wound-closure', 1, 'While you wear this pendant, you stabilize whenever you are dying at the start of your turn. In addition, whenever you roll a Hit Die to regain hit points, double the number of hit points it restores.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('periapt-of-wound-closure', 'Periapt of Wound Closure', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/periapt-of-wound-closure');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('philter-of-love', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('philter-of-love', 1, 'The next time you see a creature within 10 minutes after drinking this philter, you become charmed by that creature for 1 hour. If the creature is of a species and gender you are normally attracted to, you regard it as your true love while you are charmed. This potion''s rose-hued, effervescent liquid contains one easy-to-miss bubble shaped like a heart.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('philter-of-love', 'Philter of Love', 'potion', 'Uncommon', 0, '/api/2014/magic-items/philter-of-love');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-haunting', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-haunting', 1, 'You must be proficient with wind instruments to use these pipes. They have 3 charges. You can use an action to play them and expend 1 charge to create an eerie, spellbinding tune. Each creature within 30 feet of you that hears you play must succeed on a DC 15 Wisdom saving throw or become frightened of you for 1 minute. If you wish, all creatures in the area that aren''t hostile toward you automatically succeed on the saving throw. A creature that fails the saving throw can repeat it at the end of each of its turns, ending the effect on itself on a success. A creature that succeeds on its saving throw is immune to the effect of these pipes for 24 hours. The pipes regain 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('pipes-of-haunting', 'Pipes of Haunting', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/pipes-of-haunting');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-the-sewers', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-the-sewers', 1, 'You must be proficient with wind instruments to use these pipes. While you are attuned to the pipes, ordinary rats and giant rats are indifferent toward you and will not attack you unless you threaten or harm them.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-the-sewers', 2, 'The pipes have 3 charges. If you play the pipes as an action, you can use a bonus action to expend 1 to 3 charges, calling forth one swarm of rats with each expended charge, provided that enough rats are within half a mile of you to be called in this fashion (as determined by the GM). If there aren''t enough rats to form a swarm, the charge is wasted. Called swarms move toward the music by the shortest available route but aren''t under your control otherwise. The pipes regain 1d3 expended charges daily at dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('pipes-of-the-sewers', 3, 'Whenever a swarm of rats that isn''t under another creature''s control comes within 30 feet of you while you are playing the pipes, you can make a Charisma check contested by the swarm''s Wisdom check. If you lose the contest, the swarm behaves as it normally would and can''t be swayed by the pipes'' music for the next 24 hours. If you win the contest, the swarm is swayed by the pipes'' music and becomes friendly to you and your companions for as long as you continue to play the pipes each round as an action. A friendly swarm obeys your commands. If you issue no commands to a friendly swarm, it defends itself but otherwise takes no actions. If a friendly swarm starts its turn and can''t hear the pipes'' music, your control over that swarm ends, and the swarm behaves as it normally would and can''t be swayed by the pipes'' music for the next 24 hours.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('pipes-of-the-sewers', 'Pipes of the Sewers', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/pipes-of-the-sewers');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('plate-armor-of-etherealness', 0, 'Armor (plate), legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('plate-armor-of-etherealness', 1, 'While you''re wearing this armor, you can speak its command word as an action to gain the effect of the etherealness spell, which last for 10 minutes or until you remove the armor or use an action to speak the command word again. This property of the armor can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('plate-armor-of-etherealness', 'Plate Armor of Etherealness', 'armor', 'Legendary', 0, '/api/2014/magic-items/plate-armor-of-etherealness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 1, 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 2, 'You can use an action to unfold a portable hole and place it on or against a solid surface, whereupon the portable hole creates an extradimensional hole 10 feet deep. The cylindrical space within the hole exists on a different plane, so it can''t be used to create open passages. Any creature inside an open portable hole can exit the hole by climbing out of it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 3, 'You can use an action to close a portable hole by taking hold of the edges of the cloth and folding it up. Folding the cloth closes the hole, and any creatures or objects within remain in the extradimensional space. No matter what''s in it, the hole weighs next to nothing.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 4, 'If the hole is folded up, a creature within the hole''s extradimensional space can use an action to make a DC 10 Strength check. On a successful check, the creature forces its way out and appears within 5 feet of the portable hole or the creature carrying it. A breathing creature within a closed portable hole can survive for up to 10 minutes, after which time it begins to suffocate.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('portable-hole', 5, 'Placing a portable hole inside an extradimensional space created by a bag of holding, handy haversack, or similar item instantly destroys both items and opens a gate to the Astral Plane. The gate originates where the one item was placed inside the other. Any creature within 10 feet of the gate is sucked through it and deposited in a random location on the Astral Plane. The gate then closes. The gate is one-way only and can''t be reopened.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('portable-hole', 'Portable Hole', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/portable-hole');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-animal-friendship', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-animal-friendship', 1, 'When you drink this potion, you can cast the animal friendship spell (save DC 13) for 1 hour at will. Agitating this muddy liquid brings little bits into view: a fish scale, a hummingbird tongue, a cat claw, or a squirrel hair.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-animal-friendship', 'Potion of Animal Friendship', 'potion', 'Uncommon', 0, '/api/2014/magic-items/potion-of-animal-friendship');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-clairvoyance', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-clairvoyance', 1, 'When you drink this potion, you gain the effect of the clairvoyance spell. An eyeball bobs in this yellowish liquid but vanishes when the potion is opened.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-clairvoyance', 'Potion of Clairvoyance', 'potion', 'Rare', 0, '/api/2014/magic-items/potion-of-clairvoyance');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-climbing', 0, 'Potion, common');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-climbing', 1, 'When you drink this potion, you gain a climbing speed equal to your walking speed for 1 hour. During this time, you have advantage on Strength (Athletics) checks you make to climb. The potion is separated into brown, silver, and gray layers resembling bands of stone. Shaking the bottle fails to mix the colors.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-climbing', 'Potion of Climbing', 'potion', 'Common', 0, '/api/2014/magic-items/potion-of-climbing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-diminution', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-diminution', 1, 'When you drink this potion, you gain the "reduce" effect of the enlarge/reduce spell for 1d4 hours (no concentration required). The red in the potion''s liquid continuously contracts to a tiny bead and then expands to color the clear liquid around it. Shaking the bottle fails to interrupt this process.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-diminution', 'Potion of Diminution', 'potion', 'Rare', 0, '/api/2014/magic-items/potion-of-diminution');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-flying', 0, 'Potion, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-flying', 1, 'When you drink this potion, you gain a flying speed equal to your walking speed for 1 hour and can hover. If you''re in the air when the potion wears off, you fall unless you have some other means of staying aloft. This potion''s clear liquid floats at the top of its container and has cloudy white impurities drifting in it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-flying', 'Potion of Flying', 'potion', 'Very Rare', 0, '/api/2014/magic-items/potion-of-flying');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-gaseous-form', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-gaseous-form', 1, 'When you drink this potion, you gain the effect of the gaseous form spell for 1 hour (no concentration required) or until you end the effect as a bonus action. This potion''s container seems to hold fog that moves and pours like water.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-gaseous-form', 'Potion of Gaseous Form', 'potion', 'Rare', 0, '/api/2014/magic-items/potion-of-gaseous-form');
