INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-healing', 1, 'You regain hit points when you drink this potion. The number of hit points depends on the potion''s rarity, as shown in the Potions of Healing table. Whatever its potency, the potion''s red liquid glimmers when agitated.');
