INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-heroism', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-heroism', 1, 'For 1 hour after drinking it, you gain 10 temporary hit points that last for 1 hour. For the same duration, you are under the effect of the bless spell (no concentration required). This blue potion bubbles and steams as if boiling.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-heroism', 'Potion of Heroism', 'potion', 'Rare', 0, '/api/2014/magic-items/potion-of-heroism');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-invisibility', 0, 'Potion, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-invisibility', 1, 'This potion''s container looks empty but feels as though it holds liquid. When you drink it, you become invisible for 1 hour. Anything you wear or carry is invisible with you. The effect ends early if you attack or cast a spell.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-invisibility', 'Potion of Invisibility', 'potion', 'Very Rare', 0, '/api/2014/magic-items/potion-of-invisibility');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-mind-reading', 0, 'Potion, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-mind-reading', 1, 'When you drink this potion, you gain the effect of the detect thoughts spell (save DC 13). The potion''s dense, purple liquid has an ovoid cloud of pink floating in it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-mind-reading', 'Potion of Mind Reading', 'potion', 'Rare', 0, '/api/2014/magic-items/potion-of-mind-reading');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-poison', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-poison', 1, 'This concoction looks, smells, and tastes like a potion of healing or other beneficial potion. However, it is actually poison masked by illusion magic. An identify spell reveals its true nature.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-poison', 2, 'If you drink it, you take 3d6 poison damage, and you must succeed on a DC 13 Constitution saving throw or be poisoned. At the start of each of your turns while you are poisoned in this way, you take 3d6 poison damage. At the end of each of your turns, you can repeat the saving throw. On a successful save, the poison damage you take on your subsequent turns decreases by 1d6. The poison ends when the damage decreases to 0.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-poison', 'Potion of Poison', 'potion', 'Uncommon', 0, '/api/2014/magic-items/potion-of-poison');
