INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-lightning', 1, 'When you drink this potion, you gain resistance to lightning damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-lightning', 'Potion of Lightning Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-lightning');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-necrotic', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-necrotic', 1, 'When you drink this potion, you gain resistance to necrotic damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-necrotic', 'Potion of Necrotic Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-necrotic');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-poison', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-poison', 1, 'When you drink this potion, you gain resistance to poison damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-poison', 'Potion of Poison Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-poison');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-psychic', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-psychic', 1, 'When you drink this potion, you gain resistance to psychic damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-psychic', 'Potion of Psychic Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-psychic');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-radiant', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-radiant', 1, 'When you drink this potion, you gain resistance to radiant damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-radiant', 'Potion of Radiant Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-radiant');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-thunder', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-resistance-thunder', 1, 'When you drink this potion, you gain resistance to thunder damage for 1 hour.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-resistance-thunder', 'Potion of Thunder Resistance', 'potion', 'Uncommon', 1, '/api/2014/magic-items/potion-of-resistance-thunder');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-speed', 0, 'Potion, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-speed', 1, 'When you drink this potion, you gain the effect of the haste spell for 1 minute (no concentration required). The potion''s yellow fluid is streaked with black and swirls on its own.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-speed', 'Potion of Speed', 'potion', 'Very Rare', 0, '/api/2014/magic-items/potion-of-speed');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-water-breathing', 0, 'Potion, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('potion-of-water-breathing', 1, 'You can breathe underwater for 1 hour after drinking this potion. Its cloudy green fluid smells of the sea and has a jellyfish-like bubble floating in it.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('potion-of-water-breathing', 'Potion of Water Breathing', 'potion', 'Uncommon', 0, '/api/2014/magic-items/potion-of-water-breathing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('restorative-ointment', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('restorative-ointment', 1, 'This glass jar, 3 inches in diameter, contains 1d4 + 1 doses of a thick mixture that smells faintly of aloe. The jar and its contents weigh 1/2 pound.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('restorative-ointment', 2, 'As an action, one dose of the ointment can be swallowed or applied to the skin. The creature that receives it regains 2d8 + 2 hit points, ceases to be poisoned, and is cured of any disease.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('restorative-ointment', 'Restorative Ointment', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/restorative-ointment');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-animal-influence', 0, 'Ring, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-animal-influence', 1, 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. While wearing the ring, you can use an action to expend 1 of its charges to cast one of the following spells:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-animal-influence', 2, 'Animal friendship (save DC 13)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-animal-influence', 3, 'Fear (save DC 13), targeting only beasts that have an Intelligence of 3 or lower');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-animal-influence', 4, 'Speak with animals');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-animal-influence', 'Ring of Animal Influence', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-animal-influence');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-djinni-summoning', 0, 'Ring, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-djinni-summoning', 1, 'While wearing this ring, you can speak its command word as an action to summon a particular djinni from the Elemental Plane of Air. The djinni appears in an unoccupied space you choose within 120 feet of you. It remains as long as you concentrate (as if concentrating on a spell), to a maximum of 1 hour, or until it drops to 0 hit points. It then returns to its home plane.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-djinni-summoning', 2, 'While summoned, the djinni is friendly to you and your companions. It obeys any commands you give it, no matter what language you use. If you fail to command it, the djinni defends itself against attackers but takes no other actions.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-djinni-summoning', 3, 'After the djinni departs, it can''t be summoned again for 24 hours, and the ring becomes nonmagical if the djinni dies.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-djinni-summoning', 'Ring of Djinni Summoning', 'ring', 'Legendary', 0, '/api/2014/magic-items/ring-of-djinni-summoning');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ring-of-elemental-command-air', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ring-of-elemental-command-earth', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ring-of-elemental-command-fire', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('ring-of-elemental-command-water', 3);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 0, 'Ring, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 1, 'This ring is linked to one of the four Elemental Planes. The GM chooses or randomly determines the linked plane.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 2, 'While wearing this ring, you have advantage on attack rolls against elementals from the linked plane, and they have disadvantage on attack rolls against you. In addition, you have access to properties based on the linked plane.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 3, 'The ring has 5 charges. It regains 1d4 + 1 expended charges daily at dawn. Spells cast from the ring have a save DC of 17.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 4, '***Ring of Air Elemental Command.*** You can expend 2 of the ring''s charges to cast dominate monster on an air elemental. In addition, when you fall, you descend 60 feet per round and take no damage from falling. You can also speak and understand Auran.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 5, 'If you help slay an air elemental while attuned to the ring, you gain access to the following additional properties:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 6, 'You have resistance to lightning damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 7, 'You have a flying speed equal to your walking speed and can hover.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 8, 'You can cast the following spells from the ring, expending the necessary number of charges: chain lightning (3 charges), gust of wind (2 charges), or wind wall (1 charge).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 9, '***Ring of Earth Elemental Command.*** You can expend 2 of the ring''s charges to cast dominate monster on an earth elemental. In addition, you can move in difficult terrain that is composed of rubble, rocks, or dirt as if it were normal terrain. You can also speak and understand Terran.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 10, 'If you help slay an earth elemental while attuned to the ring, you gain access to the following additional properties:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 11, 'You have resistance to acid damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 12, 'You can move through solid earth or rock as if those areas were difficult terrain. If you end your turn there, you are shunted out to the nearest unoccupied space you last occupied.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 13, 'You can cast the following spells from the ring, expending the necessary number of charges: stone shape (2 charges), stoneskin (3 charges), or wall of stone (3 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 14, '***Ring of Fire Elemental Command.*** You can expend 2 of the ring''s charges to cast dominate monster on a fire elemental. In addition, you have resistance to fire damage. You can also speak and understand Ignan.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 15, 'If you help slay a fire elemental while attuned to the ring, you gain access to the following additional properties:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 16, 'You are immune to fire damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 17, 'You can cast the following spells from the ring, expending the necessary number of charges: burning hands (1 charge), fireball (2 charges), and wall of fire (3 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 18, '***Ring of Water Elemental Command.*** You can expend 2 of the ring''s charges to cast dominate monster on a water elemental. In addition, you can stand on and walk across liquid surfaces as if they were solid ground. You can also speak and understand Aquan.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 19, 'If you help slay a water elemental while attuned to the ring, you gain access to the following additional properties:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 20, 'You can breathe underwater and have a swimming speed equal to your walking speed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-elemental-command', 21, 'You can cast the following spells from the ring, expending the necessary number of charges: create or destroy water (1 charge), control water (3 charges), ice storm (2 charges), or wall of ice (3 charges).');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-elemental-command', 'Ring of Elemental Command', 'ring', 'Legendary', 0, '/api/2014/magic-items/ring-of-elemental-command');
