INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-elemental-command-water', 'Ring of Water Elemental Command', 'ring', 'Legendary', 1, '/api/2014/magic-items/ring-of-elemental-command-water');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-evasion', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-evasion', 1, 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. When you fail a Dexterity saving throw while wearing it, you can use your reaction to expend 1 of its charges to succeed on that saving throw instead.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-evasion', 'Ring of Evasion', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-evasion');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-feather-falling', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-feather-falling', 1, 'When you fall while wearing this ring, you descend 60 feet per round and take no damage from falling.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-feather-falling', 'Ring of Feather Falling', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-feather-falling');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-free-action', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-free-action', 1, 'While you wear this ring, difficult terrain doesn''t cost you extra movement. In addition, magic can neither reduce your speed nor cause you to be paralyzed or restrained.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-free-action', 'Ring of Free Action', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-free-action');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-invisibility', 0, 'Ring, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-invisibility', 1, 'While wearing this ring, you can turn invisible as an action. Anything you are wearing or carrying is invisible with you. You remain invisible until the ring is removed, until you attack or cast a spell, or until you use a bonus action to become visible again.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-invisibility', 'Ring of Invisibility', 'ring', 'Legendary', 0, '/api/2014/magic-items/ring-of-invisibility');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-jumping', 0, 'Ring, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-jumping', 1, 'While wearing this ring, you can cast the jump spell from it as a bonus action at will, but can target only yourself when you do so.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-jumping', 'Ring of Jumping', 'ring', 'Uncommon', 0, '/api/2014/magic-items/ring-of-jumping');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-mind-shielding', 0, 'Ring, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-mind-shielding', 1, 'While wearing this ring, you are immune to magic that allows other creatures to read your thoughts, determine whether you are lying, know your alignment, or know your creature type. Creatures can telepathically communicate with you only if you allow it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-mind-shielding', 2, 'You can use an action to cause the ring to become invisible until you use another action to make it visible, until you remove the ring, or until you die.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-mind-shielding', 3, 'If you die while wearing the ring, your soul enters it, unless it already houses a soul. You can remain in the ring or depart for the afterlife. As long as your soul is in the ring, you can telepathically communicate with any creature wearing it. A wearer can''t prevent this telepathic communication.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-mind-shielding', 'Ring of Mind Shielding', 'ring', 'Uncommon', 0, '/api/2014/magic-items/ring-of-mind-shielding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-protection', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-protection', 1, 'You gain a +1 bonus to AC and saving throws while wearing this ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-protection', 'Ring of Protection', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-protection');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-regeneration', 0, 'Ring, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-regeneration', 1, 'While wearing this ring, you regain 1d6 hit points every 10 minutes, provided that you have at least 1 hit point. If you lose a body part, the ring causes the missing part to regrow and return to full functionality after 1d6 + 1 days if you have at least 1 hit point the whole time.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-regeneration', 'Ring of Regeneration', 'ring', 'Very Rare', 0, '/api/2014/magic-items/ring-of-regeneration');
