INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-acid', 1, 'You have resistance to acid damage while wearing this pearl ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-acid', 'Ring of Acid Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-acid');
