INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-cold', 1, 'You have resistance to cold damage while wearing this tourmaline ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-cold', 'Ring of Cold Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-cold');
