INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-fire', 1, 'You have resistance to fire damage while wearing this garnet ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-fire', 'Ring of Fire Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-fire');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-force', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-force', 1, 'You have resistance to force damage while wearing this sapphire ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-force', 'Ring of Force Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-force');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-lightning', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-lightning', 1, 'You have resistance to lightning damage while wearing this citrine ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-lightning', 'Ring of Lightning Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-lightning');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-necrotic', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-necrotic', 1, 'You have resistance to necrotic damage while wearing this jet ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-necrotic', 'Ring of Necrotic Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-necrotic');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-poison', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-poison', 1, 'You have resistance to poison damage while wearing this amethyst ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-poison', 'Ring of Poison Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-poison');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-psychic', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-psychic', 1, 'You have resistance to psychic damage while wearing this jade ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-psychic', 'Ring of Psychic Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-psychic');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-radiant', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-radiant', 1, 'You have resistance to radiant damage while wearing this topaz ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-radiant', 'Ring of Radiant Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-radiant');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-thunder', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-resistance-thunder', 1, 'You have resistance to thunder damage while wearing this spinel ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-resistance-thunder', 'Ring of Thunder Resistance', 'ring', 'Rare', 1, '/api/2014/magic-items/ring-of-resistance-thunder');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 0, 'Ring, very rare (requires attunement outdoors at night)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 1, 'While wearing this ring in dim light or darkness, you can cast dancing lights and light from the ring at will. Casting either spell from the ring requires an action.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 2, 'The ring has 6 charges for the following other properties. The ring regains 1d6 expended charges daily at dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 3, '***Faerie Fire.*** You can expend 1 charge as an action to cast faerie fire from the ring.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 4, '***Ball Lightning.*** You can expend 2 charges as an action to create one to four 3-foot-diameter spheres of lightning. The more spheres you create, the less powerful each sphere is individually.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 5, 'Each sphere appears in an unoccupied space you can see within 120 feet of you. The spheres last as long as you concentrate (as if concentrating on a spell), up to 1 minute. Each sphere sheds dim light in a 30-foot radius.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 6, 'As a bonus action, you can move each sphere up to 30 feet, but no farther than 120 feet away from you. When a creature other than you comes within 5 feet of a sphere, the sphere discharges lightning at that creature and disappears. That creature must make a DC 15 Dexterity saving throw. On a failed save, the creature takes lightning damage based on the number of spheres you created.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 7, '| Spheres | Lightning Damage |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 8, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 9, '| 4 | 2d4 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 10, '| 3 | 2d6 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 11, '| 2 | 5d4 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 12, '| 1 | 4d12 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-shooting-stars', 13, '***Shooting Stars.*** You can expend 1 to 3 charges as an action. For every charge you expend, you launch a glowing mote of light from the ring at a point you can see within 60 feet of you. Each creature within a 15-foot cube originating from that point is showered in sparks and must make a DC 15 Dexterity saving throw, taking 5d4 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-shooting-stars', 'Ring of Shooting Stars', 'ring', 'Very Rare', 0, '/api/2014/magic-items/ring-of-shooting-stars');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-storing', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-storing', 1, 'This ring stores spells cast into it, holding them until the attuned wearer uses them. The ring can store up to 5 levels worth of spells at a time. When found, it contains 1d6 - 1 levels of stored spells chosen by the GM.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-storing', 2, 'Any creature can cast a spell of 1st through 5th level into the ring by touching the ring as the spell is cast. The spell has no effect, other than to be stored in the ring. If the ring can''t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-storing', 3, 'While wearing this ring, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster, but is otherwise treated as if you cast the spell. The spell cast from the ring is no longer stored in it, freeing up space.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-spell-storing', 'Ring of Spell Storing', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-spell-storing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-turning', 0, 'Ring, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-spell-turning', 1, 'While wearing this ring, you have advantage on saving throws against any spell that targets only you (not in an area of effect). In addition, if you roll a 20 for the save and the spell is 7th level or lower, the spell has no effect on you and instead targets the caster, using the slot level, spell save DC, attack bonus, and spellcasting ability of the caster.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-spell-turning', 'Ring of Spell Turning', 'ring', 'Legendary', 0, '/api/2014/magic-items/ring-of-spell-turning');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-swimming', 0, 'Ring, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-swimming', 1, 'You have a swimming speed of 40 feet while wearing this ring.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-swimming', 'Ring of Swimming', 'ring', 'Uncommon', 0, '/api/2014/magic-items/ring-of-swimming');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-telekinesis', 0, 'Ring, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-telekinesis', 1, 'While wearing this ring, you can cast the telekinesis spell at will, but you can target only objects that aren''t being worn or carried.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-telekinesis', 'Ring of Telekinesis', 'ring', 'Very Rare', 0, '/api/2014/magic-items/ring-of-telekinesis');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-the-ram', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-the-ram', 1, 'This ring has 3 charges, and it regains 1d3 expended charges daily at dawn. While wearing the ring, you can use an action to expend 1 to 3 of its charges to attack one creature you can see within 60 feet of you. The ring produces a spectral ram''s head and makes its attack roll with a +7 bonus. On a hit, for each charge you spend, the target takes 2d10 force damage and is pushed 5 feet away from you.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-the-ram', 2, 'Alternatively, you can expend 1 to 3 of the ring''s charges as an action to try to break an object you can see within 60 feet of you that isn''t being worn or carried. The ring makes a Strength check with a +5 bonus for each charge you spend.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-the-ram', 'Ring of the Ram', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-the-ram');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-three-wishes', 0, 'Ring, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-three-wishes', 1, 'While wearing this ring, you can use an action to expend 1 of its 3 charges to cast the wish spell from it. The ring becomes nonmagical when you use the last charge.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-three-wishes', 'Ring of Three Wishes', 'ring', 'Legendary', 0, '/api/2014/magic-items/ring-of-three-wishes');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-warmth', 0, 'Ring, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-warmth', 1, 'While wearing this ring, you have resistance to cold damage. In addition, you and everything you wear and carry are unharmed by temperatures as low as -50 degrees Fahrenheit.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-warmth', 'Ring of Warmth', 'ring', 'Uncommon', 0, '/api/2014/magic-items/ring-of-warmth');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-water-walking', 0, 'Ring, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-water-walking', 1, 'While wearing this ring, you can stand on and move across any liquid surface as if it were solid ground.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-water-walking', 'Ring of Water Walking', 'ring', 'Uncommon', 0, '/api/2014/magic-items/ring-of-water-walking');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-x-ray-vision', 0, 'Ring, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-x-ray-vision', 1, 'While wearing this ring, you can use an action to speak its command word. When you do so, you can see into and through solid matter for 1 minute. This vision has a radius of 30 feet. To you, solid objects within that radius appear transparent and don''t prevent light from passing through them. The vision can penetrate 1 foot of stone, 1 inch of common metal, or up to 3 feet of wood or dirt. Thicker substances block the vision, as does a thin sheet of lead.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('ring-of-x-ray-vision', 2, 'Whenever you use the ring again before taking a long rest, you must succeed on a DC 15 Constitution saving throw or gain one level of exhaustion.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('ring-of-x-ray-vision', 'Ring of X-ray Vision', 'ring', 'Rare', 0, '/api/2014/magic-items/ring-of-x-ray-vision');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 1, 'This robe is adorned with eyelike patterns. While you wear the robe, you gain the following benefits:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 2, 'The robe lets you see in all directions, and you have advantage on Wisdom (Perception) checks that rely on sight.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 3, 'You have darkvision out to a range of 120 feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 4, 'You can see invisible creatures and objects, as well as see into the Ethereal Plane, out to a range of 120 feet.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 5, 'The eyes on the robe can''t be closed or averted. Although you can close or avert your own eyes, you are never considered to be doing so while wearing this robe.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-eyes', 6, 'A light spell cast on the robe or a daylight spell cast within 5 feet of the robe causes you to be blinded for 1 minute. At the end of each of your turns, you can make a Constitution saving throw (DC 11 for light or DC 15 for daylight), ending the blindness on a success.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('robe-of-eyes', 'Robe of Eyes', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/robe-of-eyes');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-scintillating-colors', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-scintillating-colors', 1, 'This robe has 3 charges, and it regains 1d3 expended charges daily at dawn. While you wear it, you can use an action and expend 1 charge to cause the garment to display a shifting pattern of dazzling hues until the end of your next turn. During this time, the robe sheds bright light in a 30-foot radius and dim light for an additional 30 feet. Creatures that can see you have disadvantage on attack rolls against you. In addition, any creature in the bright light that can see you when the robe''s power is activated must succeed on a DC 15 Wisdom saving throw or become stunned until the effect ends.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('robe-of-scintillating-colors', 'Robe of Scintillating Colors', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/robe-of-scintillating-colors');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-stars', 0, 'Wondrous item, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-stars', 1, 'This black or dark blue robe is embroidered with small white or silver stars. You gain a +1 bonus to saving throws while you wear it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-stars', 2, 'Six stars, located on the robe''s upper front portion, are particularly large. While wearing this robe, you can use an action to pull off one of the stars and use it to cast magic missile as a 5th-level spell. Daily at dusk, 1d6 removed stars reappear on the robe.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-stars', 3, 'While you wear the robe, you can use an action to enter the Astral Plane along with everything you are wearing and carrying. You remain there until you use an action to return to the plane you were on. You reappear in the last space you occupied, or if that space is occupied, the nearest unoccupied space.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('robe-of-stars', 'Robe of Stars', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/robe-of-stars');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 0, 'Wondrous item, legendary (requires attunement by a sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 1, 'This elegant garment is made from exquisite cloth of white, gray, or black and adorned with silvery runes. The robe''s color corresponds to the alignment for which the item was created. A white robe was made for good, gray for neutral, and black for evil. You can''t attune to a robe of the archmagi that doesn''t correspond to your alignment.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 2, 'You gain these benefits while wearing the robe:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 3, 'If you aren''t wearing armor, your base Armor Class is 15 + your Dexterity modifier.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 4, 'You have advantage on saving throws against spells and other magical effects.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-the-archmagi', 5, 'Your spell save DC and spell attack bonus each increase by 2.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('robe-of-the-archmagi', 'Robe of the Archmagi', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/robe-of-the-archmagi');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 1, 'This robe has cloth patches of various shapes and colors covering it. While wearing the robe, you can use an action to detach one of the patches, causing it to become the object or creature it represents. Once the last patch is removed, the robe becomes an ordinary garment.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 2, 'The robe has two of each of the following patches:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 3, 'Dagger');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 4, 'Bullseye lantern (filled and lit)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 5, 'Steel mirror');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 6, '10-foot pole');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 7, 'Hempen rope (50 feet, coiled)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 8, 'Sack');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 9, 'In addition, the robe has 4d4 other patches. The GM chooses the patches or determines them randomly.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 10, '| d100 | Patch |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 11, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 12, '| 01-08 | Bag of 100 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 13, '| 09-15 | Silver coffer (1 foot long, 6 inches wide and deep) worth 500 gp |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 14, '| 16-22 | Iron door (up to 10 feet wide and 10 feet high, barred on one side of your choice), which you can place in an opening you can reach; it conforms to fit the opening, attaching and hinging itself |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 15, '| 23-30 | 10 gems worth 100 gp each |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 16, '| 31-44 | Wooden ladder (24 feet long) 45-51 A riding horse with saddle bags |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 17, '| 52-59 | Pit (a cube 10 feet on a side), which you can place on the ground within 10 feet of you |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 18, '| 60-68 | 4 potions of healing |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 19, '| 69-75 | Rowboat (12 feet long) |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 20, '| 76-83 | Spell scroll containing one spell of 1st to 3rd level |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 21, '| 84-90 | 2 mastiffs |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 22, '| 91-96 | Window (2 feet by 4 feet, up to 2 feet deep), which you can place on a vertical surface you can reach |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('robe-of-useful-items', 23, '| 97-100 | Portable ram |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('robe-of-useful-items', 'Robe of Useful Items', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/robe-of-useful-items');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-absorption', 0, 'Rod, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-absorption', 1, 'While holding this rod, you can use your reaction to absorb a spell that is targeting only you and not with an area of effect. The absorbed spell''s effect is canceled, and the spell''s energy-not the spell itself-is stored in the rod. The energy has the same level as the spell when it was cast. The rod can absorb and store up to 50 levels of energy over the course of its existence. Once the rod absorbs 50 levels of energy, it can''t absorb more. If you are targeted by a spell that the rod can''t store, the rod has no effect on that spell.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-absorption', 2, 'When you become attuned to the rod, you know how many levels of energy the rod has absorbed over the course of its existence, and how many levels of spell energy it currently has stored.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-absorption', 3, 'If you are a spellcaster holding the rod, you can convert energy stored in it into spell slots to cast spells you have prepared or know. You can create spell slots only of a level equal to or lower than your own spell slots, up to a maximum of 5th level. You use the stored levels in place of your slots, but otherwise cast the spell as normal. For example, you can use 3 levels stored in the rod as a 3rd-level spell slot.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-absorption', 4, 'A newly found rod has 1d10 levels of spell energy stored in it already. A rod that can no longer absorb spell energy and has no energy remaining becomes nonmagical.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rod-of-absorption', 'Rod of Absorption', 'rod', 'Very Rare', 0, '/api/2014/magic-items/rod-of-absorption');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 0, 'Rod, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 1, 'This rod has a flanged head and the following properties.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 2, '***Alertness.*** While holding the rod, you have advantage on Wisdom (Perception) checks and on rolls for initiative.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 3, '***Spells.*** While holding the rod, you can use an action to cast one of the following spells from it: detect evil and good, detect magic, detect poison and disease, or see invisibility.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 4, '***Protective Aura.*** As an action, you can plant the haft end of the rod in the ground, whereupon the rod''s head sheds bright light in a 60-foot radius and dim light for an additional 60 feet. While in that bright light, you and any creature that is friendly to you gain a +1 bonus to AC and saving throws and can sense the location of any invisible hostile creature that is also in the bright light.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-alertness', 5, 'The rod''s head stops glowing and the effect ends after 10 minutes, or when a creature uses an action to pull the rod from the ground. This property can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rod-of-alertness', 'Rod of Alertness', 'rod', 'Very Rare', 0, '/api/2014/magic-items/rod-of-alertness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 0, 'Rod, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 1, 'This rod has a flanged head, and it functions as a magic mace that grants a +3 bonus to attack and damage rolls made with it. The rod has properties associated with six different buttons that are set in a row along the haft. It has three other properties as well, detailed below.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 2, '***Six Buttons.*** You can press one of the rod''s six buttons as a bonus action. A button''s effect lasts until you push a different button or until you push the same button again, which causes the rod to revert to its normal form.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 3, 'If you press **button 1**, the rod becomes a flame tongue, as a fiery blade sprouts from the end opposite the rod''s flanged head.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 4, 'If you press **button 2**, the rod''s flanged head folds down and two crescent-shaped blades spring out, transforming the rod into a magic battleaxe that grants a +3 bonus to attack and damage rolls made with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 5, 'If you press **button 3**, the rod''s flanged head folds down, a spear point springs from the rod''s tip, and the rod''s handle lengthens into a 6-foot haft, transforming the rod into a magic spear that grants a +3 bonus to attack and damage rolls made with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 6, 'If you press **button 4**, the rod transforms into a climbing pole up to 50 feet long, as you specify. In surfaces as hard as granite, a spike at the bottom and three hooks at the top anchor the pole. Horizontal bars 3 inches long fold out from the sides, 1 foot apart, forming a ladder. The pole can bear up to 4,000 pounds. More weight or lack of solid anchoring causes the rod to revert to its normal form.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 7, 'If you press **button 5**, the rod transforms into a handheld battering ram and grants its user a +10 bonus to Strength checks made to break through doors, barricades, and other barriers.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 8, 'If you press **button 6**, the rod assumes or remains in its normal form and indicates magnetic north. (Nothing happens if this function of the rod is used in a location that has no magnetic north.) The rod also gives you knowledge of your approximate depth beneath the ground or your height above it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 9, '***Drain Life.*** When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Constitution saving throw. On a failure, the target takes an extra 4d6 necrotic damage, and you regain a number of hit points equal to half that necrotic damage. This property can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 10, '***Paralyze.*** When you hit a creature with a melee attack using the rod, you can force the target to make a DC 17 Strength saving throw. On a failure, the target is paralyzed for 1 minute. The target can repeat the saving throw at the end of each of its turns, ending the effect on a success. This property can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-lordly-might', 11, '***Terrify.*** While holding the rod, you can use an action to force each creature you can see within 30 feet of you to make a DC 17 Wisdom saving throw. On a failure, a target is frightened of you for 1 minute. A frightened target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. This property can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rod-of-lordly-might', 'Rod of Lordly Might', 'rod', 'Legendary', 0, '/api/2014/magic-items/rod-of-lordly-might');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-rulership', 0, 'Rod, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-rulership', 1, 'You can use an action to present the rod and command obedience from each creature of your choice that you can see within 120 feet of you. Each target must succeed on a DC 15 Wisdom saving throw or be charmed by you for 8 hours. While charmed in this way, the creature regards you as its trusted leader. If harmed by you or your companions, or commanded to do something contrary to its nature, a target ceases to be charmed in this way. The rod can''t be used again until the next dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rod-of-rulership', 'Rod of Rulership', 'rod', 'Rare', 0, '/api/2014/magic-items/rod-of-rulership');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-security', 0, 'Rod, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-security', 1, 'While holding this rod, you can use an action to activate it. The rod then instantly transports you and up to 199 other willing creatures you can see to a paradise that exists in an extraplanar space. You choose the form that the paradise takes. It could be a tranquil garden, lovely glade, cheery tavern, immense palace, tropical island, fantastic carnival, or whatever else you can imagine. Regardless of its nature, the paradise contains enough water and food to sustain its visitors. Everything else that can be interacted with inside the extraplanar space can exist only there. For example, a flower picked from a garden in the paradise disappears if it is taken outside the extraplanar space.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-security', 2, 'For each hour spent in the paradise, a visitor regains hit points as if it had spent 1 Hit Die. Also, creatures don''t age while in the paradise, although time passes normally. Visitors can remain in the paradise for up to 200 days divided by the number of creatures present (round down).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rod-of-security', 3, 'When the time runs out or you use an action to end it, all visitors reappear in the location they occupied when you activated the rod, or an unoccupied space nearest that location. The rod can''t be used again until ten days have passed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rod-of-security', 'Rod of Security', 'rod', 'Very Rare', 0, '/api/2014/magic-items/rod-of-security');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-climbing', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-climbing', 1, 'This 60-foot length of silk rope weighs 3 pounds and can hold up to 3,000 pounds. If you hold one end of the rope and use an action to speak the command word, the rope animates. As a bonus action, you can command the other end to move toward a destination you choose. That end moves 10 feet on your turn when you first command it and 10 feet on each of your turns until reaching its destination, up to its maximum length away, or until you tell it to stop. You can also tell the rope to fasten itself securely to an object or to unfasten itself, to knot or unknot itself, or to coil itself for carrying.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-climbing', 2, 'If you tell the rope to knot, large knots appear at 1 foot intervals along the rope. While knotted, the rope shortens to a 50-foot length and grants advantage on checks made to climb it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-climbing', 3, 'The rope has AC 20 and 20 hit points. It regains 1 hit point every 5 minutes as long as it has at least 1 hit point. If the rope drops to 0 hit points, it is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rope-of-climbing', 'Rope of Climbing', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/rope-of-climbing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-entanglement', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-entanglement', 1, 'This rope is 30 feet long and weighs 3 pounds. If you hold one end of the rope and use an action to speak its command word, the other end darts forward to entangle a creature you can see within 20 feet of you. The target must succeed on a DC 15 Dexterity saving throw or become restrained.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-entanglement', 2, 'You can release the creature by using a bonus action to speak a second command word. A target restrained by the rope can use an action to make a DC 15 Strength or Dexterity check (target''s choice). On a success, the creature is no longer restrained by the rope.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('rope-of-entanglement', 3, 'The rope has AC 20 and 20 hit points. It regains 1 hit point every 5 minutes as long as it has at least 1 hit point. If the rope drops to 0 hit points, it is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('rope-of-entanglement', 'Rope of Entanglement', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/rope-of-entanglement');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scarab-of-protection', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scarab-of-protection', 1, 'If you hold this beetle-shaped medallion in your hand for 1 round, an inscription appears on its surface revealing its magical nature. It provides two benefits while it is on your person:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scarab-of-protection', 2, 'You have advantage on saving throws against spells.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scarab-of-protection', 3, 'The scarab has 12 charges. If you fail a saving throw against a necromancy spell or a harmful effect originating from an undead creature, you can use your reaction to expend 1 charge and turn the failed save into a successful one. The scarab crumbles into powder and is destroyed when its last charge is expended.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('scarab-of-protection', 'Scarab of Protection', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/scarab-of-protection');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scimitar-of-speed', 0, 'Weapon (scimitar), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('scimitar-of-speed', 1, 'You gain a +2 bonus to attack and damage rolls made with this magic weapon. In addition, you can make one attack with it as a bonus action on each of your turns.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('scimitar-of-speed', 'Scimitar of Speed', 'weapon', 'Very Rare', 0, '/api/2014/magic-items/scimitar-of-speed');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('shield-of-missile-attraction', 0, 'Armor (shield), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('shield-of-missile-attraction', 1, 'While holding this shield, you have resistance to damage from ranged weapon attacks.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('shield-of-missile-attraction', 2, '***Curse.*** This shield is cursed. Attuning to it curses you until you are targeted by the remove curse spell or similar magic. Removing the shield fails to end the curse on you. Whenever a ranged weapon attack is made against a target within 10 feet of you, the curse causes you to become the target instead.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('shield-of-missile-attraction', 'Shield of Missile Attraction', 'armor', 'Rare', 0, '/api/2014/magic-items/shield-of-missile-attraction');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('slippers-of-spider-climbing', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('slippers-of-spider-climbing', 1, 'While you wear these light shoes, you can move up, down, and across vertical surfaces and upside down along ceilings, while leaving your hands free. You have a climbing speed equal to your walking speed. However, the slippers don''t allow you to move this way on a slippery surface, such as one covered by ice or oil.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('slippers-of-spider-climbing', 'Slippers of Spider Climbing', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/slippers-of-spider-climbing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sovereign-glue', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sovereign-glue', 1, 'This viscous, milky-white substance can form a permanent adhesive bond between any two objects. It must be stored in a jar or flask that has been coated inside with oil of slipperiness. When found, a container contains 1d6 + 1 ounces.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sovereign-glue', 2, 'One ounce of the glue can cover a 1-foot square surface. The glue takes 1 minute to set. Once it has done so, the bond it creates can be broken only by the application of universal solvent or oil of etherealness, or with a wish spell.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sovereign-glue', 'Sovereign Glue', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/sovereign-glue');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-cantrip', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-1st', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-2nd', 2);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-3rd', 3);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-4th', 4);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-5th', 5);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-6th', 6);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-7th', 7);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-8th', 8);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('spell-scroll-9th', 9);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 0, 'Scroll, varies');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 1, 'A spell scroll bears the words of a single spell, written in a mystical cipher. If the spell is on your class''s spell list, you can read the scroll and cast its spell without providing any material components. Otherwise, the scroll is unintelligible. Casting the spell by reading the scroll requires the spell''s normal casting time. Once the spell is cast, the words on the scroll fade, and it crumbles to dust. If the casting is uninterrupted, the scroll is not lost.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 2, 'If the spell is on your class''s spell list but of a higher level than you can normally cast, you must make an ability check using your spellcasting ability to determine whether you cast it successfully. The DC equals 10 + the spell''s level. On a failed check, the spell disappears from the scroll with no other effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 3, 'The level of the spell on the scroll determines the spell''s saving throw DC and attack bonus, as well as the scroll''s rarity, as shown in the Spell Scroll table.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 4, 'Spell Scroll (table)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 5, '| Spell Level | Rarity | Save DC | Attack Bonus |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 6, '|---|---|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 7, '| Cantrip | Common | 13 | +5 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 8, '| 1st | Common | 13 | +5 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 9, '| 2nd | Uncommon | 13 | +5 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 10, '| 3rd | Uncommon | 15 | +7 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 11, '| 4th | Rare | 15 | +7 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 12, '| 5th | Rare | 17 | +9 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 13, '| 6th | Very rare | 17 | +9 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 14, '| 7th | Very rare | 18 | +10 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 15, '| 8th | Very rare | 18 | +10 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 16, '| 9th | Legendary | 19 | +11 |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll', 17, 'A wizard spell on a spell scroll can be copied just as spells in spellbooks can be copied. When a spell is copied from a spell scroll, the copier must succeed on an Intelligence (Arcana) check with a DC equal to 10 + the spell''s level. If the check succeeds, the spell is successfully copied. Whether the check succeeds or fails, the spell scroll is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('spell-scroll', 'Spell Scroll', 'scroll', 'Varies', 0, '/api/2014/magic-items/spell-scroll');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll-cantrip', 0, 'Scroll, common');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll-cantrip', 1, 'A spell scroll bears the words of a single spell, written in a mystical cipher. If the spell is on your class''s spell list, you can read the scroll and cast its spell without providing any material components. Otherwise, the scroll is unintelligible. Casting the spell by reading the scroll requires the spell''s normal casting time. Once the spell is cast, the words on the scroll fade, and it crumbles to dust. If the casting is uninterrupted, the scroll is not lost.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll-cantrip', 2, 'If the spell is on your class''s spell list but of a higher level than you can normally cast, you must make an ability check using your spellcasting ability to determine whether you cast it successfully. The DC equals 10 + the spell''s level. On a failed check, the spell disappears from the scroll with no other effect.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spell-scroll-cantrip', 3, 'This scroll contains a cantrip. The spell''s saving throw is 13 and the attack bonus is +5.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('spell-scroll-cantrip', 'Spell Scroll (Cantrip)', 'scroll', 'Common', 1, '/api/2014/magic-items/spell-scroll-cantrip');
