INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spellguard-shield', 0, 'Armor (shield), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('spellguard-shield', 1, 'While holding this shield, you have advantage on saving throws against spells and other magical effects, and spell attacks have disadvantage against you.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('spellguard-shield', 'Spellguard Shield', 'armor', 'Very Rare', 0, '/api/2014/magic-items/spellguard-shield');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 1, 'This 2-foot-diameter black sphere is a hole in the multiverse, hovering in space and stabilized by a magical field surrounding it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 2, 'The sphere obliterates all matter it passes through and all matter that passes through it. Artifacts are the exception. Unless an artifact is susceptible to damage from a sphere of annihilation, it passes through the sphere unscathed. Anything else that touches the sphere but isn''t wholly engulfed and obliterated by it takes 4d10 force damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 3, 'The sphere is stationary until someone controls it. If you are within 60 feet of an uncontrolled sphere, you can use an action to make a DC 25 Intelligence (Arcana) check. On a success, the sphere levitates in one direction of your choice, up to a number of feet equal to 5 × your Intelligence modifier (minimum 5 feet). On a failure, the sphere moves 10 feet toward you. A creature whose space the sphere enters must succeed on a DC 13 Dexterity saving throw or be touched by it, taking 4d10 force damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 4, 'If you attempt to control a sphere that is under another creature''s control, you make an Intelligence (Arcana) check contested by the other creature''s Intelligence (Arcana) check. The winner of the contest gains control of the sphere and can levitate it as normal.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 5, 'If the sphere comes into contact with a planar portal, such as that created by the gate spell, or an extradimensional space, such as that within a portable hole, the GM determines randomly what happens, using the following table.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 6, '| d100 | Result |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 7, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 8, '| 01-50 | The sphere is destroyed. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 9, '| 51-85 | The sphere moves through the portal or into the extradimensional space. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sphere-of-annihilation', 10, '| 86-00 | A spatial rift sends each creature and object within 180 feet of the sphere, including the sphere, to a random plane of existence. |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sphere-of-annihilation', 'Sphere of Annihilation', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/sphere-of-annihilation');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-charming', 0, 'Staff, rare (requires attunement by a bard, cleric, druid, sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-charming', 1, 'While holding this staff, you can use an action to expend 1 of its 10 charges to cast charm person, command, or comprehend languages from it using your spell save DC. The staff can also be used as a magic quarterstaff.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-charming', 2, 'If you are holding the staff and fail a saving throw against an enchantment spell that targets only you, you can turn your failed save into a successful one. You can''t use this property of the staff again until the next dawn. If you succeed on a save against an enchantment spell that targets only you, with or without the staff''s intervention, you can use your reaction to expend 1 charge from the staff and turn the spell back on its caster as if you had cast the spell.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-charming', 3, 'The staff regains 1d8 + 2 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff becomes a nonmagical quarterstaff.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-charming', 'Staff of Charming', 'staff', 'Rare', 0, '/api/2014/magic-items/staff-of-charming');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-fire', 0, 'Staff, very rare (requires attunement by a druid, sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-fire', 1, 'You have resistance to fire damage while you hold this staff.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-fire', 2, 'The staff has 10 charges. While holding it, you can use an action to expend 1 or more of its charges to cast one of the following spells from it, using your spell save DC: burning hands (1 charge), fireball (3 charges), or wall of fire (4 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-fire', 3, 'The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff blackens, crumbles into cinders, and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-fire', 'Staff of Fire', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-fire');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-frost', 0, 'Staff, very rare (requires attunement by a druid, sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-frost', 1, 'You have resistance to cold damage while you hold this staff.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-frost', 2, 'The staff has 10 charges. While holding it, you can use an action to expend 1 or more of its charges to cast one of the following spells from it, using your spell save DC: cone of cold (5 charges), fog cloud (1 charge), ice storm (4 charges), or wall of ice (4 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-frost', 3, 'The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff turns to water and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-frost', 'Staff of Frost', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-frost');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-healing', 0, 'Staff, rare (requires attunement by a bard, cleric, or druid)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-healing', 1, 'This staff has 10 charges. While holding it, you can use an action to expend 1 or more of its charges to cast one of the following spells from it, using your spell save DC and spellcasting ability modifier: cure wounds (1 charge per spell level, up to 4th), lesser restoration (2 charges), or mass cure wounds (5 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-healing', 2, 'The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff vanishes in a flash of light, lost forever.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-healing', 'Staff of Healing', 'staff', 'Rare', 0, '/api/2014/magic-items/staff-of-healing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 0, 'Staff, very rare (requires attunement by a sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 1, 'This staff can be wielded as a magic quarterstaff that grants a +2 bonus to attack and damage rolls made with it. While holding it, you gain a +2 bonus to Armor Class, saving throws, and spell attack rolls.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 2, 'The staff has 20 charges for the following properties. The staff regains 2d8 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff retains its +2 bonus to attack and damage rolls but loses all other properties. On a 20, the staff regains 1d8 + 2 charges.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 3, '***Power Strike.*** When you hit with a melee attack using the staff, you can expend 1 charge to deal an extra 1d6 force damage to the target.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 4, '***Spells.*** While holding this staff, you can use an action to expend 1 or more of its charges to cast one of the following spells from it, using your spell save DC and spell attack bonus: cone of cold (5 charges), fireball (5th-level version, 5 charges), globe of invulnerability (6 charges), hold monster (5 charges), levitate (2 charges), lightning bolt (5th-level version, 5 charges), magic missile (1 charge), ray of enfeeblement (1 charge), or wall of force (5 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 5, '***Retributive Strike.*** You can use an action to break the staff over your knee or against a solid surface, performing a retributive strike. The staff is destroyed and releases its remaining magic in an explosion that expands to fill a 30-foot-radius sphere centered on it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 6, 'You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take force damage equal to 16 × the number of charges in the staff. Every other creature in the area must make a DC 17 Dexterity saving throw. On a failed save, a creature takes an amount of damage based on how far away it is from the point of origin, as shown in the following table. On a successful save, a creature takes half as much damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 7, '| Distance from Origin | Damage |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 8, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 9, '| 10 ft. away or closer | 8 × the number of charges in the staff |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 10, '| 11 to 20 ft. away | 6 × the number of charges in the staff |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-power', 11, '| 21 to 30 ft. away | 4 × the number of charges in the staff |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-power', 'Staff of Power', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-power');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-striking', 0, 'Staff, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-striking', 1, 'This staff can be wielded as a magic quarterstaff that grants a +3 bonus to attack and damage rolls made with it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-striking', 2, 'The staff has 10 charges. When you hit with a melee attack using it, you can expend up to 3 of its charges. For each charge you expend, the target takes an extra 1d6 force damage. The staff regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff becomes a nonmagical quarterstaff.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-striking', 'Staff of Striking', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-striking');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-swarming-insects', 0, 'Staff, very rare (requires attunement by a bard, cleric, druid, sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-swarming-insects', 1, 'This staff has 10 charges and regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, a swarm of insects consumes and destroys the staff, then disperses.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-swarming-insects', 2, '***Spells.*** While holding the staff, you can use an action to expend some of its charges to cast one of the following spells from it, using your spell save DC: giant insect (4 charges) or insect plague (5 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-swarming-insects', 3, '***Insect Cloud.*** While holding the staff, you can use an action and expend 1 charge to cause a swarm of harmless flying insects to spread out in a 30-foot radius from you. The insects remain for 10 minutes, making the area heavily obscured for creatures other than you. The swarm moves with you, remaining centered on you. A wind of at least 10 miles per hour disperses the swarm and ends the effect.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-swarming-insects', 'Staff of Swarming Insects', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-swarming-insects');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 0, 'Staff, legendary (requires attunement by a sorcerer, warlock, or wizard)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 1, 'This staff can be wielded as a magic quarterstaff that grants a +2 bonus to attack and damage rolls made with it. While you hold it, you gain a +2 bonus to spell attack rolls.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 2, 'The staff has 50 charges for the following properties. It regains 4d6 + 2 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 20, the staff regains 1d12 + 1 charges.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 3, '***Spell Absorption.*** While holding the staff, you have advantage on saving throws against spells. In addition, you can use your reaction when another creature casts a spell that targets only you. If you do, the staff absorbs the magic of the spell, canceling its effect and gaining a number of charges equal to the absorbed spell''s level. However, if doing so brings the staff''s total number of charges above 50, the staff explodes as if you activated its retributive strike (see below).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 4, '***Spells.*** While holding the staff, you can use an action to expend some of its charges to cast one of the following spells from it, using your spell save DC and spellcasting ability: conjure elemental (7 charges), dispel magic (3 charges), fireball (7th-level version, 7 charges), flaming sphere (2 charges), ice storm (4 charges), invisibility (2 charges), knock (2 charges), lightning bolt (7th-level version, 7 charges), passwall (5 charges), plane shift (7 charges), telekinesis (5 charges), wall of fire (4 charges), or web (2 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 5, 'You can also use an action to cast one of the following spells from the staff without using any charges: arcane lock, detect magic, enlarge/reduce, light, mage hand, or protection from evil and good.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 6, '***Retributive Strike.*** You can use an action to break the staff over your knee or against a solid surface, performing a retributive strike. The staff is destroyed and releases its remaining magic in an explosion that expands to fill a 30-foot-radius sphere centered on it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 7, 'You have a 50 percent chance to instantly travel to a random plane of existence, avoiding the explosion. If you fail to avoid the effect, you take force damage equal to 16 × the number of charges in the staff. Every other creature in the area must make a DC 17 Dexterity saving throw. On a failed save, a creature takes an amount of damage based on how far away it is from the point of origin, as shown in the following table. On a successful save, a creature takes half as much damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 8, '| Distance from Origin | Damage |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 9, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 10, '| 10 ft. away or closer | 8 × the number of charges in the staff |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 11, '| 11 to 20 ft. away | 6 × the number of charges in the staff |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-magi', 12, '| 21 to 30 ft. away | 4 × the number of charges in the staff |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-the-magi', 'Staff of the Magi', 'staff', 'Legendary', 0, '/api/2014/magic-items/staff-of-the-magi');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-python', 0, 'Staff, very rare (requires attunement by a cleric, druid, or warlock)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-python', 1, 'You can use an action to speak this staff''s command word and throw the staff on the ground within 10 feet of you. The staff becomes a giant constrictor snake under your control and acts on its own initiative count. By using a bonus action to speak the command word again, you return the staff to its normal form in a space formerly occupied by the snake.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-python', 2, 'On your turn, you can mentally command the snake if it is within 60 feet of you and you aren''t incapacitated. You decide what action the snake takes and where it moves during its next turn, or you can issue it a general command, such as to attack your enemies or guard a location.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-python', 3, 'If the snake is reduced to 0 hit points, it dies and reverts to its staff form. The staff then shatters and is destroyed. If the snake reverts to staff form before losing all its hit points, it regains all of them.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-the-python', 'Staff of the Python', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-the-python');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 0, 'Staff, rare (requires attunement by a druid)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 1, 'This staff can be wielded as a magic quarterstaff that grants a +2 bonus to attack and damage rolls made with it. While holding it, you have a +2 bonus to spell attack rolls.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 2, 'The staff has 10 charges for the following properties. It regains 1d6 + 4 expended charges daily at dawn. If you expend the last charge, roll a d20. On a 1, the staff loses its properties and becomes a nonmagical quarterstaff.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 3, '***Spells.*** You can use an action to expend 1 or more of the staff''s charges to cast one of the following spells from it, using your spell save DC: animal friendship (1 charge), awaken (5 charges), barkskin (2 charges), locate animals or plants (2 charges), speak with animals (1 charge), speak with plants (3 charges), or wall of thorns (6 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 4, 'You can also use an action to cast the pass without trace spell from the staff without using any charges. Tree Form. You can use an action to plant one end of the staff in fertile earth and expend 1 charge to transform the staff into a healthy tree. The tree is 60 feet tall and has a 5-foot-diameter trunk, and its branches at the top spread out in a 20-foot radius.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-the-woodlands', 5, 'The tree appears ordinary but radiates a faint aura of transmutation magic if targeted by detect magic. While touching the tree and using another action to speak its command word, you return the staff to its normal form. Any creature in the tree falls when it reverts to a staff.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-the-woodlands', 'Staff of the Woodlands', 'staff', 'Rare', 0, '/api/2014/magic-items/staff-of-the-woodlands');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 0, 'Staff, very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 1, 'This staff can be wielded as a magic quarterstaff that grants a +2 bonus to attack and damage rolls made with it. It also has the following additional properties. When one of these properties is used, it can''t be used again until the next dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 2, '***Lightning.*** When you hit with a melee attack using the staff, you can cause the target to take an extra 2d6 lightning damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 3, '***Thunder.*** When you hit with a melee attack using the staff, you can cause the staff to emit a crack of thunder, audible out to 300 feet. The target you hit must succeed on a DC 17 Constitution saving throw or become stunned until the end of your next turn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 4, '***Lightning Strike.*** You can use an action to cause a bolt of lightning to leap from the staff''s tip in a line that is 5 feet wide and 120 feet long. Each creature in that line must make a DC 17 Dexterity saving throw, taking 9d6 lightning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 5, '***Thunderclap.*** You can use an action to cause the staff to issue a deafening thunderclap, audible out to 600 feet. Each creature within 60 feet of you (not including you) must make a DC 17 Constitution saving throw. On a failed save, a creature takes 2d6 thunder damage and becomes deafened for 1 minute. On a successful save, a creature takes half damage and isn''t deafened.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-thunder-and-lightning', 6, '***Thunder and Lightning.*** You can use an action to use the Lightning Strike and Thunderclap properties at the same time. Doing so doesn''t expend the daily use of those properties, only the use of this one.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-thunder-and-lightning', 'Staff of Thunder and Lightning', 'staff', 'Very Rare', 0, '/api/2014/magic-items/staff-of-thunder-and-lightning');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-withering', 0, 'Staff, rare (requires attunement by a cleric, druid, or warlock)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-withering', 1, 'This staff has 3 charges and regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('staff-of-withering', 2, 'The staff can be wielded as a magic quarterstaff. On a hit, it deals damage as a normal quarterstaff, and you can expend 1 charge to deal an extra 2d10 necrotic damage to the target. In addition, the target must succeed on a DC 15 Constitution saving throw or have disadvantage for 1 hour on any ability check or saving throw that uses Strength or Constitution.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('staff-of-withering', 'Staff of Withering', 'staff', 'Rare', 0, '/api/2014/magic-items/staff-of-withering');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('stone-of-controlling-earth-elementals', 0, 'Wondrous item, rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('stone-of-controlling-earth-elementals', 1, 'If the stone is touching the ground, you can use an action to speak its command word and summon an earth elemental, as if you had cast the conjure elemental spell. The stone can''t be used this way again until the next dawn. The stone weighs 5 pounds.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('stone-of-controlling-earth-elementals', 'Stone of Controlling Earth Elementals', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/stone-of-controlling-earth-elementals');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('stone-of-good-luck-luckstone', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('stone-of-good-luck-luckstone', 1, 'While this polished agate is on your person, you gain a +1 bonus to ability checks and saving throws.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('stone-of-good-luck-luckstone', 'Stone of Good Luck (Luckstone)', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/stone-of-good-luck-luckstone');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sun-blade', 0, 'Weapon (longsword), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sun-blade', 1, 'This item appears to be a longsword hilt. While grasping the hilt, you can use a bonus action to cause a blade of pure radiance to spring into existence, or make the blade disappear. While the blade exists, this magic longsword has the finesse property. If you are proficient with shortswords or longswords, you are proficient with the sun blade.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sun-blade', 2, 'You gain a +2 bonus to attack and damage rolls made with this weapon, which deals radiant damage instead of slashing damage. When you hit an undead with it, that target takes an extra 1d8 radiant damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sun-blade', 3, 'The sword''s luminous blade emits bright light in a 15-foot radius and dim light for an additional 15 feet. The light is sunlight. While the blade persists, you can use an action to expand or reduce its radius of bright and dim light by 5 feet each, to a maximum of 30 feet each or a minimum of 10 feet each.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sun-blade', 'Sun Blade', 'weapon', 'Rare', 0, '/api/2014/magic-items/sun-blade');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-life-stealing', 0, 'Weapon (any sword), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-life-stealing', 1, 'When you attack a creature with this magic weapon and roll a 20 on the attack roll, that target takes an extra 3d6 necrotic damage, provided that the target isn''t a construct or an undead. You gain temporary hit points equal to the extra damage dealt.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sword-of-life-stealing', 'Sword of Life Stealing', 'weapon', 'Rare', 0, '/api/2014/magic-items/sword-of-life-stealing');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-sharpness', 0, 'Weapon (any sword that deals slashing damage), very rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-sharpness', 1, 'When you attack an object with this magic sword and hit, maximize your weapon damage dice against the target.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-sharpness', 2, 'When you attack a creature with this weapon and roll a 20 on the attack roll, that target takes an extra 4d6 slashing damage. Then roll another d20. If you roll a 20, you lop off one of the target''s limbs, with the effect of such loss determined by the GM. If the creature has no limb to sever, you lop off a portion of its body instead.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-sharpness', 3, 'In addition, you can speak the sword''s command word to cause the blade to shed bright light in a 10 foot radius and dim light for an additional 10 feet. Speaking the command word again or sheathing the sword puts out the light.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sword-of-sharpness', 'Sword of Sharpness', 'weapon', 'Very Rare', 0, '/api/2014/magic-items/sword-of-sharpness');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-wounding', 0, 'Weapon (any sword), rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-wounding', 1, 'Hit points lost to this weapon''s damage can be regained only through a short or long rest, rather than by regeneration, magic, or any other means.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('sword-of-wounding', 2, 'Once per turn, when you hit a creature with an attack using this magic weapon, you can wound the target. At the start of each of the wounded creature''s turns, it takes 1d4 necrotic damage for each time you''ve wounded it, and it can then make a DC 15 Constitution saving throw, ending the effect of all such wounds on itself on a success. Alternatively, the wounded creature, or a creature within 5 feet of it, can use an action to make a DC 15 Wisdom (Medicine) check, ending the effect of such wounds on it on a success.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('sword-of-wounding', 'Sword of Wounding', 'weapon', 'Rare', 0, '/api/2014/magic-items/sword-of-wounding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-pure-good', 0, 'Wondrous item, legendary (requires attunement by a creature of good alignment)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-pure-good', 1, 'This talisman is a mighty symbol of goodness. A creature that is neither good nor evil in alignment takes 6d6 radiant damage upon touching the talisman. An evil creature takes 8d6 radiant damage upon touching the talisman. Either sort of creature takes the damage again each time it ends its turn holding or carrying the talisman.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-pure-good', 2, 'If you are a good cleric or paladin, you can use the talisman as a holy symbol, and you gain a +2 bonus to spell attack rolls while you wear or hold it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-pure-good', 3, 'The talisman has 7 charges. If you are wearing or holding it, you can use an action to expend 1 charge from it and choose one creature you can see on the ground within 120 feet of you. If the target is of evil alignment, a flaming fissure opens under it. The target must succeed on a DC 20 Dexterity saving throw or fall into the fissure and be destroyed, leaving no remains. The fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman disperses into motes of golden light and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('talisman-of-pure-good', 'Talisman of Pure Good', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/talisman-of-pure-good');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-the-sphere', 0, 'Wondrous item, legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-the-sphere', 1, 'When you make an Intelligence (Arcana) check to control a sphere of annihilation while you are holding this talisman, you double your proficiency bonus on the check. In addition, when you start your turn with control over a sphere of annihilation, you can use an action to levitate it 10 feet plus a number of additional feet equal to 10 × your Intelligence modifier.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('talisman-of-the-sphere', 'Talisman of the Sphere', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/talisman-of-the-sphere');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-ultimate-evil', 0, 'Wondrous item, legendary (requires attunement by a creature of evil alignment)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-ultimate-evil', 1, 'This item symbolizes unrepentant evil. A creature that is neither good nor evil in alignment takes 6d6 necrotic damage upon touching the talisman. A good creature takes 8d6 necrotic damage upon touching the talisman. Either sort of creature takes the damage again each time it ends its turn holding or carrying the talisman.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-ultimate-evil', 2, 'If you are an evil cleric or paladin, you can use the talisman as a holy symbol, and you gain a +2 bonus to spell attack rolls while you wear or hold it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('talisman-of-ultimate-evil', 3, 'The talisman has 6 charges. If you are wearing or holding it, you can use an action to expend 1 charge from the talisman and choose one creature you can see on the ground within 120 feet of you. If the target is of good alignment, a flaming fissure opens under it. The target must succeed on a DC 20 Dexterity saving throw or fall into the fissure and be destroyed, leaving no remains. The fissure then closes, leaving no trace of its existence. When you expend the last charge, the talisman dissolves into foul-smelling slime and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('talisman-of-ultimate-evil', 'Talisman of Ultimate Evil', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/talisman-of-ultimate-evil');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-clear-thought', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-clear-thought', 1, 'This book contains memory and logic exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Intelligence score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('tome-of-clear-thought', 'Tome of Clear Thought', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/tome-of-clear-thought');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-leadership-and-influence', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-leadership-and-influence', 1, 'This book contains guidelines for influencing and charming others, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Charisma score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('tome-of-leadership-and-influence', 'Tome of Leadership and Influence', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/tome-of-leadership-and-influence');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-understanding', 0, 'Wondrous item, very rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('tome-of-understanding', 1, 'This book contains intuition and insight exercises, and its words are charged with magic. If you spend 48 hours over a period of 6 days or fewer studying the book''s contents and practicing its guidelines, your Wisdom score increases by 2, as does your maximum for that score. The manual then loses its magic, but regains it in a century.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('tome-of-understanding', 'Tome of Understanding', 'wondrous-items', 'Very Rare', 0, '/api/2014/magic-items/tome-of-understanding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('trident-of-fish-command', 0, 'Weapon (trident), uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('trident-of-fish-command', 1, 'This trident is a magic weapon. It has 3 charges. While you carry it, you can use an action and expend 1 charge to cast dominate beast (save DC 15) from it on a beast that has an innate swimming speed. The trident regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('trident-of-fish-command', 'Trident of Fish Command', 'weapon', 'Uncommon', 0, '/api/2014/magic-items/trident-of-fish-command');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('universal-solvent', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('universal-solvent', 1, 'This tube holds milky liquid with a strong alcohol smell. You can use an action to pour the contents of the tube onto a surface within reach. The liquid instantly dissolves up to 1 square foot of adhesive it touches, including sovereign glue.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('universal-solvent', 'Universal Solvent', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/universal-solvent');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('vicious-weapon', 0, 'Weapon (any), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('vicious-weapon', 1, 'When you roll a 20 on your attack roll with this magic weapon, your critical hit deals an extra 2d6 damage of the weapon''s type.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('vicious-weapon', 'Vicious Weapon', 'weapon', 'Rare', 0, '/api/2014/magic-items/vicious-weapon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('vorpal-sword', 0, 'Weapon (any sword that deals slashing damage), legendary (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('vorpal-sword', 1, 'You gain a +3 bonus to attack and damage rolls made with this magic weapon. In addition, the weapon ignores resistance to slashing damage.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('vorpal-sword', 2, 'When you attack a creature that has at least one head with this weapon and roll a 20 on the attack roll, you cut off one of the creature''s heads. The creature dies if it can''t survive without the lost head. A creature is immune to this effect if it is immune to slashing damage, doesn''t have or need a head, has legendary actions, or the GM decides that the creature is too big for its head to be cut off with this weapon. Such a creature instead takes an extra 6d8 slashing damage from the hit.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('vorpal-sword', 'Vorpal Sword', 'weapon', 'Legendary', 0, '/api/2014/magic-items/vorpal-sword');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-binding', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-binding', 1, 'This wand has 7 charges for the following properties. It regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-binding', 2, '***Spells.*** While holding the wand, you can use an action to expend some of its charges to cast one of the following spells (save DC 17): hold monster (5 charges) or hold person (2 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-binding', 3, '***Assisted Escape.*** While holding the wand, you can use your reaction to expend 1 charge and gain advantage on a saving throw you make to avoid being paralyzed or restrained, or you can expend 1 charge and gain advantage on any check you make to escape a grapple.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-binding', 'Wand of Binding', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-binding');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-enemy-detection', 0, 'Wand, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-enemy-detection', 1, 'This wand has 7 charges. While holding it, you can use an action and expend 1 charge to speak its command word. For the next minute, you know the direction of the nearest creature hostile to you within 60 feet, but not its distance from you. The wand can sense the presence of hostile creatures that are ethereal, invisible, disguised, or hidden, as well as those in plain sight. The effect ends if you stop holding the wand.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-enemy-detection', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-enemy-detection', 'Wand of Enemy Detection', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-enemy-detection');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fear', 0, 'Wand, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fear', 1, 'This wand has 7 charges for the following properties. It regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fear', 2, '***Command.*** While holding the wand, you can use an action to expend 1 charge and command another creature to flee or grovel, as with the command spell (save DC 15).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fear', 3, '***Cone of Fear.*** While holding the wand, you can use an action to expend 2 charges, causing the wand''s tip to emit a 60-foot cone of amber light. Each creature in the cone must succeed on a DC 15 Wisdom saving throw or become frightened of you for 1 minute. While it is frightened in this way, a creature must spend its turns trying to move as far away from you as it can, and it can''t willingly move to a space within 30 feet of you. It also can''t take reactions. For its action, it can use only the Dash action or try to escape from an effect that prevents it from moving. If it has nowhere it can move, the creature can use the Dodge action. At the end of each of its turns, a creature can repeat the saving throw, ending the effect on itself on a success.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-fear', 'Wand of Fear', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-fear');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fireballs', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fireballs', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 or more of its charges to cast the fireball spell (save DC 15) from it. For 1 charge, you cast the 3rd-level version of the spell. You can increase the spell slot level by one for each additional charge you expend.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-fireballs', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-fireballs', 'Wand of Fireballs', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-fireballs');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-lightning-bolts', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-lightning-bolts', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 or more of its charges to cast the lightning bolt spell (save DC 15) from it. For 1 charge, you cast the 3rd-level version of the spell. You can increase the spell slot level by one for each additional charge you expend.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-lightning-bolts', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-lightning-bolts', 'Wand of Lightning Bolts', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-lightning-bolts');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-magic-detection', 0, 'Wand, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-magic-detection', 1, 'This wand has 3 charges. While holding it, you can expend 1 charge as an action to cast the detect magic spell from it. The wand regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-magic-detection', 'Wand of Magic Detection', 'wand', 'Uncommon', 0, '/api/2014/magic-items/wand-of-magic-detection');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-magic-missiles', 0, 'Wand, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-magic-missiles', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 or more of its charges to cast the magic missile spell from it. For 1 charge, you cast the 1st-level version of the spell. You can increase the spell slot level by one for each additional charge you expend.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-magic-missiles', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-magic-missiles', 'Wand of Magic Missiles', 'wand', 'Uncommon', 0, '/api/2014/magic-items/wand-of-magic-missiles');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-paralysis', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-paralysis', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 of its charges to cause a thin blue ray to streak from the tip toward a creature you can see within 60 feet of you. The target must succeed on a DC 15 Constitution saving throw or be paralyzed for 1 minute. At the end of each of the target''s turns, it can repeat the saving throw, ending the effect on itself on a success.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-paralysis', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-paralysis', 'Wand of Paralysis', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-paralysis');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-polymorph', 0, 'Wand, very rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-polymorph', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 of its charges to cast the polymorph spell (save DC 15) from it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-polymorph', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-polymorph', 'Wand of Polymorph', 'wand', 'Very Rare', 0, '/api/2014/magic-items/wand-of-polymorph');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-secrets', 0, 'Wand, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-secrets', 1, 'The wand has 3 charges. While holding it, you can use an action to expend 1 of its charges, and if a secret door or trap is within 30 feet of you, the wand pulses and points at the one nearest to you. The wand regains 1d3 expended charges daily at dawn.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-secrets', 'Wand of Secrets', 'wand', 'Uncommon', 0, '/api/2014/magic-items/wand-of-secrets');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('wand-of-the-war-mage-1', 0);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('wand-of-the-war-mage-2', 1);
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('wand-of-the-war-mage-3', 2);
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage', 0, 'Wand, uncommon (+1), rare (+2), or very rare (+3) (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage', 1, 'While holding this wand, you gain a bonus to spell attack rolls determined by the wand''s rarity. In addition, you ignore half cover when making a spell attack.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-the-war-mage', 'Wand of the War Mage, +1, +2, or +3', 'wand', 'Varies', 0, '/api/2014/magic-items/wand-of-the-war-mage');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-1', 0, 'Wand, uncommon (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-1', 1, 'While holding this wand, you gain a +1 bonus to spell attack rolls. In addition, you ignore half cover when making a spell attack.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-the-war-mage-1', 'Wand of the War Mage, +1', 'wand', 'Uncommon', 1, '/api/2014/magic-items/wand-of-the-war-mage-1');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-2', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-2', 1, 'While holding this wand, you gain a +2 bonus to spell attack rolls. In addition, you ignore half cover when making a spell attack.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-the-war-mage-2', 'Wand of the War Mage, +2', 'wand', 'Rare', 1, '/api/2014/magic-items/wand-of-the-war-mage-2');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-3', 0, 'Wand, very rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-the-war-mage-3', 1, 'While holding this wand, you gain a +3 bonus to spell attack rolls. In addition, you ignore half cover when making a spell attack.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-the-war-mage-3', 'Wand of the War Mage, +3', 'wand', 'Very Rare', 1, '/api/2014/magic-items/wand-of-the-war-mage-3');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-web', 0, 'Wand, uncommon (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-web', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 of its charges to cast the web spell (save DC 15) from it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-web', 2, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into ashes and is destroyed.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-web', 'Wand of Web', 'wand', 'Uncommon', 0, '/api/2014/magic-items/wand-of-web');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 0, 'Wand, rare (requires attunement by a spellcaster)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 1, 'This wand has 7 charges. While holding it, you can use an action to expend 1 of its charges and choose a target within 120 feet of you. The target can be a creature, an object, or a point in space. Roll d100 and consult the following table to discover what happens.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 2, 'If the effect causes you to cast a spell from the wand, the spell''s save DC is 15. If the spell normally has a range expressed in feet, its range becomes 120 feet if it isn''t already.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 3, 'If an effect covers an area, you must center the spell on and include the target. If an effect has multiple possible subjects, the GM randomly determines which ones are affected.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 4, 'The wand regains 1d6 + 1 expended charges daily at dawn. If you expend the wand''s last charge, roll a d20. On a 1, the wand crumbles into dust and is destroyed.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 5, '| d100 | Effect |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 6, '|---|---|');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 7, '| 01-05 | You cast slow. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 8, '| 06-10 | You cast faerie fire. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 9, '| 11-15 | You are stunned until the start of your next turn, believing something awesome just happened. 16-20 You cast gust of wind. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 10, '| 21-25 | You cast detect thoughts on the target you chose. If you didn''t target a creature, you instead take 1d6 psychic damage. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 11, '| 26-30 | You cast stinking cloud. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 12, '| 31-33 | Heavy rain falls in a 60-foot radius centered on the target. The area becomes lightly obscured. The rain falls until the start of your next turn. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 13, '| 34-36 | An animal appears in the unoccupied space nearest the target. The animal isn''t under your control and acts as it normally would. Roll a d100 to determine which animal appears. On a 01-25, a rhinoceros appears; on a 26-50, an elephant appears; and on a 51-100, a rat appears. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 14, '| 37-46 | You cast lightning bolt. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 15, '| 47-49 | A cloud of 600 oversized butterflies fills a 30-foot radius centered on the target. The area becomes heavily obscured. The butterflies remain for 10 minutes. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 16, '| 50-53 | You enlarge the target as if you had cast enlarge/reduce. If the target can''t be affected by that spell, or if you didn''t target a creature, you become the target. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 17, '| 54-58 | You cast darkness. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 18, '| 59-62 | Grass grows on the ground in a 60-foot radius centered on the target. If grass is already there, it grows to ten times its normal size and remains overgrown for 1 minute. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 19, '| 63-65 | An object of the GM''s choice disappears into the Ethereal Plane. The object must be neither worn nor carried, within 120 feet of the target, and no larger than 10 feet in any dimension. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 20, '| 66-69 | You shrink yourself as if you had cast enlarge/reduce on yourself. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 21, '| 70-79 | You cast fireball. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 22, '| 80-84 | You cast invisibility on yourself. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 23, '| 85-87 | Leaves grow from the target. If you chose a point in space as the target, leaves sprout from the creature nearest to that point. Unless they are picked off, the leaves turn brown and fall off after 24 hours. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 24, '| 88-90 | A stream of 1d4 × 10 gems, each worth 1 gp, shoots from the wand''s tip in a line 30 feet long and 5 feet wide. Each gem deals 1 bludgeoning damage, and the total damage of the gems is divided equally among all creatures in the line. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 25, '| 91-95 | A burst of colorful shimmering light extends from you in a 30-foot radius. You and each creature in the area that can see must succeed on a DC 15 Constitution saving throw or become blinded for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 26, '| 96-97 | The target''s skin turns bright blue for 1d10 days. If you chose a point in space, the creature nearest to that point is affected. |');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wand-of-wonder', 27, '| 98-100 | If you targeted a creature, it must make a DC 15 Constitution saving throw. If you didn''t target a creature, you become the target and must make the saving throw. If the saving throw fails by 5 or more, the target is instantly petrified. On any other failed save, the target is restrained and begins to turn to stone. While restrained in this way, the target must repeat the saving throw at the end of its next turn, becoming petrified on a failure or ending the effect on a success. The petrification lasts until the target is freed by the greater restoration spell or similar magic. |');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wand-of-wonder', 'Wand of Wonder', 'wand', 'Rare', 0, '/api/2014/magic-items/wand-of-wonder');
INSERT INTO magic_items_variants (magic_items_index, order_num) VALUES ('weapon-1', 0);
