INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('weapon', 1, 'You have a bonus to attack and damage rolls made with this magic weapon. The bonus is determined by the weapon''s rarity.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('weapon', 'Weapon, +1, +2, or +3', 'weapon', 'Varies', 0, '/api/2014/magic-items/weapon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('weapon-1', 0, 'Weapon (any), uncommon');
