INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('weapon-1', 'Weapon, +1', 'weapon', 'Uncommon', 1, '/api/2014/magic-items/weapon-1');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('weapon-2', 0, 'Weapon (any), rare');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('weapon-2', 1, 'You have a +2 bonus to attack and damage rolls made with this magic weapon.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('weapon-2', 'Weapon, +2', 'weapon', 'Rare', 1, '/api/2014/magic-items/weapon-2');
