INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('well-of-many-worlds', 0, 'Wondrous item, legendary');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('well-of-many-worlds', 1, 'This fine black cloth, soft as silk, is folded up to the dimensions of a handkerchief. It unfolds into a circular sheet 6 feet in diameter.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('well-of-many-worlds', 2, 'You can use an action to unfold and place the well of many worlds on a solid surface, whereupon it creates a two-way portal to another world or plane of existence. Each time the item opens a portal, the GM decides where it leads. You can use an action to close an open portal by taking hold of the edges of the cloth and folding it up. Once well of many worlds has opened a portal, it can''t do so again for 1d8 hours.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('well-of-many-worlds', 'Well of Many Worlds', 'wondrous-items', 'Legendary', 0, '/api/2014/magic-items/well-of-many-worlds');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wind-fan', 0, 'Wondrous item, uncommon');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wind-fan', 1, 'While holding this fan, you can use an action to cast the gust of wind spell (save DC 13) from it. Once used, the fan shouldn''t be used again until the next dawn. Each time it is used again before then, it has a cumulative 20 percent chance of not working and tearing into useless, nonmagical tatters.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wind-fan', 'Wind Fan', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/wind-fan');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('winged-boots', 0, 'Wondrous item, uncommon (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('winged-boots', 1, 'While you wear these boots, you have a flying speed equal to your walking speed. You can use the boots to fly for up to 4 hours, all at once or in several shorter flights, each one using a minimum of 1 minute from the duration. If you are flying when the duration expires, you descend at a rate of 30 feet per round until you land.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('winged-boots', 2, 'The boots regain 2 hours of flying capability for every 12 hours they aren''t in use.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('winged-boots', 'Winged Boots', 'wondrous-items', 'Uncommon', 0, '/api/2014/magic-items/winged-boots');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wings-of-flying', 0, 'Wondrous item, rare (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('wings-of-flying', 1, 'While wearing this cloak, you can use an action to speak its command word. This turns the cloak into a pair of bat wings or bird wings on your back for 1 hour or until you repeat the command word as an action. The wings give you a flying speed of 60 feet. When they disappear, you can''t use them again for 1d12 hours.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('wings-of-flying', 'Wings of Flying', 'wondrous-items', 'Rare', 0, '/api/2014/magic-items/wings-of-flying');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 0, 'Wondrous item, artifact (requires attunement)');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 1, 'Ages past, elves and humans waged a terrible war against evil dragons. When the world seemed doomed, powerful wizards came together and worked their greatest magic, forging five Orbs of Dragonkind (or Dragon Orbs) to help them defeat the dragons. One orb was taken to each of the five wizard towers, and there they were used to speed the war toward a victorious end. The wizards used the orbs to lure dragons to them, then destroyed the dragons with powerful magic.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 2, 'As the wizard towers fell in later ages, the orbs were destroyed or faded into legend, and only three are thought to survive. Their magic has been warped and twisted over the centuries, so although their primary purpose of calling dragons still functions, they also allow some measure of control over dragons.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 3, 'Each orb contains the essence of an evil dragon, a presence that resents any attempt to coax magic from it. Those lacking in force of personality might find themselves enslaved to an orb.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 4, 'An orb is an etched crystal globe about 10 inches in diameter. When used, it grows to about 20 inches in diameter, and mist swirls inside it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 5, 'While attuned to an orb, you can use an action to peer into the orb''s depths and speak its command word. You must then make a DC 15 Charisma check. On a successful check, you control the orb for as long as you remain attuned to it. On a failed check, you become charmed by the orb for as long as you remain attuned to it.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 6, 'While you are charmed by the orb, you can''t voluntarily end your attunement to it, and the orb casts suggestion on you at will (save DC 18), urging you to work toward the evil ends it desires. The dragon essence within the orb might want many things: the annihilation of a particular people, freedom from the orb, to spread suffering in the world, to advance the worship of Tiamat, or something else the GM decides.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 7, '***Random Properties.*** An Orb of Dragonkind has the following random properties:');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 8, '2 minor beneficial properties');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 9, '1 minor detrimental property');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 10, '1 major detrimental property');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 11, '***Spells.*** The orb has 7 charges and regains 1d4 + 3 expended charges daily at dawn. If you control the orb, you can use an action and expend 1 or more charges to cast one of the following spells (save DC 18) from it: cure wounds (5th-level version, 3 charges), daylight (1 charge), death ward (2 charges), or scrying (3 charges).');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 12, 'You can also use an action to cast the detect magic spell from the orb without using any charges.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 13, '***Call Dragons.*** While you control the orb, you can use an action to cause the artifact to issue a telepathic call that extends in all directions for 40 miles. Evil dragons in range feel compelled to come to the orb as soon as possible by the most direct route. Dragon deities such as Tiamat are unaffected by this call. Dragons drawn to the orb might be hostile toward you for compelling them against their will. Once you have used this property, it can''t be used again for 1 hour.');
INSERT INTO magic_items_desc (magic_items_index, order_num, "value") VALUES ('orb-of-dragonkind', 14, '***Destroying an Orb.*** An Orb of Dragonkind appears fragile but is impervious to most damage, including the attacks and breath weapons of dragons. A disintegrate spell or one good hit from a +3 magic weapon is sufficient to destroy an orb, however.');
INSERT INTO magic_items ("index", name, equipment_category_index, rarity_name, variant, url) VALUES ('orb-of-dragonkind', 'Orb of Dragonkind', 'wondrous-items', 'Artifact', 0, '/api/2014/magic-items/orb-of-dragonkind');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('abjuration', 'Abjuration', 'Abjuration spells are protective in nature, though some of them have aggressive uses. They create magical barriers, negate harmful effects, harm trespassers, or banish creatures to other planes of existence.', '/api/2014/magic-schools/abjuration');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('conjuration', 'Conjuration', 'Conjuration spells involve the transportation of objects and creatures from one location to another. Some spells summon creatures or objects to the caster''s side, whereas others allow the caster to teleport to another location. Some conjurations create objects or effects out of nothing.', '/api/2014/magic-schools/conjuration');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('divination', 'Divination', 'Divination spells reveal information, whether in the form of secrets long forgotten, glimpses of the future, the locations of hidden things, the truth behind illusions, or visions of distant people or places.', '/api/2014/magic-schools/divination');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('enchantment', 'Enchantment', 'Enchantment spells affect the minds of others, influencing or controlling their behavior. Such spells can make enemies see the caster as a friend, force creatures to take a course of action, or even control another creature like a puppet.', '/api/2014/magic-schools/enchantment');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('evocation', 'Evocation', 'Evocation spells manipulate magical energy to produce a desired effect. Some call up blasts of fire or lightning. Others channel positive energy to heal wounds.', '/api/2014/magic-schools/evocation');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('illusion', 'Illusion', 'Illusion spells deceive the senses or minds of others. They cause people to see things that are not there, to miss things that are there, to hear phantom noises, or to remember things that never happened. Some illusions create phantom images that any creature can see, but the most insidious illusions plant an image directly in the mind of a creature.', '/api/2014/magic-schools/illusion');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('necromancy', 'Necromancy', 'Necromancy spells manipulate the energies of life and death. Such spells can grant an extra reserve of life force, drain the life energy from another creature, create the undead, or even bring the dead back to life.', '/api/2014/magic-schools/necromancy');
INSERT INTO magic_schools ("index", name, "desc", url) VALUES ('transmutation', 'Transmutation', 'Transmutation spells change the properties of a creature, object, or environment. They might turn an enemy into a harmless creature, bolster the strength of an ally, make an object move at the caster''s command, or enhance a creature''s innate healing abilities to rapidly recover from injury.', '/api/2014/magic-schools/transmutation');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('aboleth', 0, 'natural', 17);
