INSERT INTO monsters_proficiencies (monsters_index, order_num, "value", proficiency_index) VALUES ('aboleth', 4, 10, 'skill-perception');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('aboleth', 0, 'Amphibious', 'The aboleth can breathe air and water.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('aboleth', 1, 'Mucous Cloud', 'While underwater, the aboleth is surrounded by transformative mucus. A creature that touches the aboleth or that hits it with a melee attack while within 5 ft. of it must make a DC 14 Constitution saving throw. On a failure, the creature is diseased for 1d4 hours. The diseased creature can breathe only underwater.', 'con', 14, 'none');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('aboleth', 2, 'Probing Telepathy', 'If a creature communicates telepathically with the aboleth, the aboleth learns the creature''s greatest desires if the aboleth can see the creature.');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('aboleth', 0, 'Tentacle', 3, 'melee');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('aboleth', 0, 'Multiattack', 'actions', 'The aboleth makes three tentacle attacks.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('aboleth', 0, 'bludgeoning', '2d6+5');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('aboleth', 1, 'acid', '1d12');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus, dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('aboleth', 1, 'Tentacle', 'Melee Weapon Attack: +9 to hit, reach 10 ft., one target. Hit: 12 (2d6 + 5) bludgeoning damage. If the target is a creature, it must succeed on a DC 14 Constitution saving throw or become diseased. The disease has no effect for 1 minute and can be removed by any magic that cures disease. After 1 minute, the diseased creature''s skin becomes translucent and slimy, the creature can''t regain hit points unless it is underwater, and the disease can be removed only by heal or another disease-curing spell of 6th level or higher. When the creature is outside a body of water, it takes 6 (1d12) acid damage every 10 minutes unless moisture is applied to the skin before 10 minutes have passed.', 9, 'con', 14, 'none');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('aboleth', 0, 'bludgeoning', '3d6+5');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('aboleth', 2, 'Tail', 'Melee Weapon Attack: +9 to hit, reach 10 ft., one target. Hit: 15 (3d6 + 5) bludgeoning damage.', 9);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_times) VALUES ('aboleth', 3, 'Enslave', 'The aboleth targets one creature it can see within 30 ft. of it. The target must succeed on a DC 14 Wisdom saving throw or be magically charmed by the aboleth until the aboleth dies or until it is on a different plane of existence from the target. The charmed target is under the aboleth''s control and can''t take reactions, and the aboleth and the target can communicate telepathically with each other over any distance.
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('aboleth', 0, 'Detect', 'The aboleth makes a Wisdom (Perception) check.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('aboleth', 1, 'Tail Swipe', 'The aboleth makes one tail attack.');
INSERT INTO monsters_legendary_actions_damage (monsters_legendary_actions_index, order_num, damage_type_index, damage_dice) VALUES ('aboleth', 0, 'psychic', '3d6');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('aboleth', 2, 'Psychic Drain (Costs 2 Actions)', 'One creature charmed by the aboleth takes 10 (3d6) psychic damage, and the aboleth regains hit points equal to the damage the creature takes.');
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, speed_swim, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url) VALUES ('aboleth', 'Aboleth', 'Large', 'aberration', 'lawful evil', 135, '18d10', '18d10+36', '10 ft.', '40 ft.', 21, 9, 15, 18, 15, 18, '120 ft.', 20, 'Deep Speech, telepathy 120 ft.', 10, 4, 5900, '/api/images/monsters/aboleth.png', '/api/2014/monsters/aboleth');
