INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('acolyte', 0, 'bludgeoning', '1d4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('acolyte', 0, 'Club', 'Melee Weapon Attack: +2 to hit, reach 5 ft., one target. Hit: 2 (1d4) bludgeoning damage.', 2);
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('acolyte', 'Acolyte', 'Medium', 'humanoid', 'any alignment', 9, '2d8', '2d8', '30 ft.', 10, 10, 10, 10, 14, 11, 12, 'any one language (usually Common)', 0.25, 2, 50, '/api/images/monsters/acolyte.png', '/api/2014/monsters/acolyte', 'Acolytes are junior members of a clergy, usually answerable to a priest. They perform a variety of functions in a temple and are granted minor spellcasting power by their deities.', 'any race');
