INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('adult-black-dragon', 1, 'Bite', 'Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage plus 4 (1d8) acid damage.', 11);
