INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('adult-black-dragon', 2, 'Claw', 'Melee Weapon Attack: +11 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage.', 11);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('adult-black-dragon', 0, 'bludgeoning', '2d8+6');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('adult-black-dragon', 3, 'Tail', 'Melee Weapon Attack: +11 to hit, reach 15 ft., one target. Hit: 15 (2d8 + 6) bludgeoning damage.', 11);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('adult-black-dragon', 4, 'Frightful Presence', 'Each creature of the dragon''s choice that is within 120 feet of the dragon and aware of it must succeed on a DC 16 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours.', 'wis', 16, 'none');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('adult-black-dragon', 0, 'acid', '12d8');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_dice, usage_min_value) VALUES ('adult-black-dragon', 5, 'Acid Breath', 'The dragon exhales acid in a 60-foot line that is 5 feet wide. Each creature in that line must make a DC 18 Dexterity saving throw, taking 54 (12d8) acid damage on a failed save, or half as much damage on a successful one.', 'dex', 18, 'half', 'recharge on roll', '1d6', 5);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('adult-black-dragon', 0, 'Detect', 'The dragon makes a Wisdom (Perception) check.');
