INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('ancient-white-dragon', 0, 'cold', '16d8');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_dice, usage_min_value) VALUES ('ancient-white-dragon', 5, 'Cold Breath', 'The dragon exhales an icy blast in a 90-foot cone. Each creature in that area must make a DC 22 Constitution saving throw, taking 72 (l6d8) cold damage on a failed save, or half as much damage on a successful one.', 'con', 22, 'none', 'recharge on roll', '1d6', 5);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('ancient-white-dragon', 0, 'Detect', 'The dragon makes a Wisdom (Perception) check.');
