INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('behir', 2, 'Constrict', 'Melee Weapon Attack: +10 to hit, reach 5 ft., one Large or smaller creature. Hit: 17 (2d10 + 6) bludgeoning damage plus 17 (2d10 + 6) slashing damage. The target is grappled (escape DC 16) if the behir isn''t already constricting a creature, and the target is restrained until this grapple ends.', 10);
