INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_dice, usage_min_value) VALUES ('behir', 3, 'Lightning Breath', 'The behir exhales a line of lightning that is 20 ft. long and 5 ft. wide. Each creature in that line must make a DC 16 Dexterity saving throw, taking 66 (12d10) lightning damage on a failed save, or half as much damage on a successful one.', 'dex', 16, 'half', 'recharge on roll', '1d6', 5);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('behir', 0, 'acid', '6d6');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('behir', 4, 'Swallow', 'The behir makes one bite attack against a Medium or smaller target it is grappling. If the attack hits, the target is also swallowed, and the grapple ends. While swallowed, the target is blinded and restrained, it has total cover against attacks and other effects outside the behir, and it takes 21 (6d6) acid damage at the start of each of the behir''s turns. A behir can have only one creature swallowed at a time.
