INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('blink-dog', 'Blink Dog', 'Medium', 'fey', 'lawful good', 22, '4d8', '4d8+4', '40 ft.', 12, 17, 12, 10, 13, 11, 10, 'Blink Dog, understands Sylvan but can''t speak it', 0.25, 2, 50, '/api/images/monsters/blink-dog.png', '/api/2014/monsters/blink-dog', 'A blink dog takes its name from its ability to blink in and out of existence, a talent it uses to aid its attacks and to avoid harm.');
