INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('chain-devil', 0, 'Devil''s Sight', 'Magical darkness doesn''t impede the devil''s darkvision.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('chain-devil', 1, 'Magic Resistance', 'The devil has advantage on saving throws against spells and other magical effects.');
