INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('chain-devil', 0, 'Multiattack', 'actions', 'The devil makes two attacks with its chains.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('chain-devil', 0, 'slashing', '2d6+4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('chain-devil', 1, 'Chain', 'Melee Weapon Attack: +8 to hit, reach 10 ft., one target. Hit: 11 (2d6 + 4) slashing damage. The target is grappled (escape DC 14) if the devil isn''t already grappling a creature. Until this grapple ends, the target is restrained and takes 7 (2d6) piercing damage at the start of each of its turns.', 8);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type) VALUES ('chain-devil', 2, 'Animate Chains', 'Up to four chains the devil can see within 60 feet of it magically sprout razor-edged barbs and animate under the devil''s control, provided that the chains aren''t being worn or carried.
INSERT INTO monsters_reactions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('chain-devil', 0, 'Unnerving Mask', 'When a creature the devil can see starts its turn within 30 feet of the devil, the devil can create the illusion that it looks like one of the creature''s departed loved ones or bitter enemies. If the creature can see the devil, it must succeed on a DC 14 Wisdom saving throw or be frightened until the end of its turn.', 'wis', 14, 'none');
