INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('chuul', 1, 'Sense Magic', 'The chuul senses magic within 120 feet of it at will. This trait otherwise works like the detect magic spell but isn''t itself magical.');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc", action_options_choose, action_options_type, action_options_from_option_set_type) VALUES ('chuul', 0, 'Multiattack', 'action_options', 'The chuul makes two pincer attacks. If the chuul is grappling a creature, the chuul can also use its tentacles once.', 1, 'action', 'options_array');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('chuul', 0, 'bludgeoning', '2d6+4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('chuul', 1, 'Pincer', 'Melee Weapon Attack: +6 to hit, reach 10 ft., one target. Hit: 11 (2d6 + 4) bludgeoning damage. The target is grappled (escape DC 14) if it is a Large or smaller creature and the chuul doesn''t have two other creatures grappled.', 6);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('chuul', 2, 'Tentacles', 'One creature grappled by the chuul must succeed on a DC 13 Constitution saving throw or be poisoned for 1 minute. Until this poison ends, the target is paralyzed. The target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.', 'con', 13, 'none');
