INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('clay-golem', 0, 'Acid Absorption', 'Whenever the golem is subjected to acid damage, it takes no damage and instead regains a number of hit points equal to the acid damage dealt.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('clay-golem', 1, 'Berserk', 'Whenever the golem starts its turn with 60 hit points or fewer, roll a d6. On a 6, the golem goes berserk. On each of its turns while berserk, the golem attacks the nearest creature it can see. If no creature is near enough to move to and attack, the golem attacks an object, with preference for an object smaller than itself. Once the golem goes berserk, it continues to do so until it is destroyed or regains all its hit points.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('clay-golem', 2, 'Immutable Form', 'The golem is immune to any spell or effect that would alter its form.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('clay-golem', 3, 'Magic Resistance', 'The golem has advantage on saving throws against spells and other magical effects.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('clay-golem', 4, 'Magic Weapons', 'The golem''s weapon attacks are magical.');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('clay-golem', 0, 'Slam', 2, 'melee');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('clay-golem', 0, 'Multiattack', 'actions', 'The golem makes two slam attacks.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('clay-golem', 0, 'bludgeoning', '2d10+5');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('clay-golem', 1, 'Slam', 'Melee Weapon Attack: +8 to hit, reach 5 ft., one target. Hit: 16 (2d10 + 5) bludgeoning damage. If the target is a creature, it must succeed on a DC 15 Constitution saving throw or have its hit point maximum reduced by an amount equal to the damage taken. The target dies if this attack reduces its hit point maximum to 0. The reduction lasts until removed by the greater restoration spell or other magic.', 8);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_dice, usage_min_value) VALUES ('clay-golem', 2, 'Haste', 'Until the end of its next turn, the golem magically gains a +2 bonus to its AC, has advantage on Dexterity saving throws, and can use its slam attack as a bonus action.', 'recharge on roll', '1d6', 5);
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url) VALUES ('clay-golem', 'Clay Golem', 'Large', 'construct', 'unaligned', 133, '14d10', '14d10+56', '20 ft.', 20, 9, 18, 3, 8, 1, '60 ft.', 9, 'understands the languages of its creator but can''t speak', 9, 4, 5000, '/api/images/monsters/clay-golem.png', '/api/2014/monsters/clay-golem');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('cloaker', 0, 'natural', 14);
INSERT INTO monsters_proficiencies (monsters_index, order_num, "value", proficiency_index) VALUES ('cloaker', 0, 5, 'skill-stealth');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('cloaker', 0, 'Damage Transfer', 'While attached to a creature, the cloaker takes only half the damage dealt to it (rounded down). and that creature takes the other half.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('cloaker', 1, 'False Appearance', 'While the cloaker remains motionless without its underside exposed, it is indistinguishable from a dark leather cloak.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('cloaker', 2, 'Light Sensitivity', 'While in bright light, the cloaker has disadvantage on attack rolls and Wisdom (Perception) checks that rely on sight.');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('cloaker', 0, 'Bite', 1, 'melee');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('cloaker', 1, 'Tail', 1, 'melee');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('cloaker', 0, 'Multiattack', 'actions', 'The cloaker makes two attacks: one with its bite and one with its tail.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('cloaker', 0, 'piercing', '2d6+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('cloaker', 1, 'Bite', 'Melee Weapon Attack: +6 to hit, reach 5 ft., one creature. Hit: 10 (2d6 + 3) piercing damage, and if the target is Large or smaller, the cloaker attaches to it. If the cloaker has advantage against the target, the cloaker attaches to the target''s head, and the target is blinded and unable to breathe while the cloaker is attached. While attached, the cloaker can make this attack only against the target and has advantage on the attack roll. The cloaker can detach itself by spending 5 feet of its movement. A creature, including the target, can take its action to detach the cloaker by succeeding on a DC 16 Strength check.', 6);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('cloaker', 0, 'slashing', '1d8+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('cloaker', 2, 'Tail', 'Melee Weapon Attack: +6 to hit, reach 10 ft., one creature. Hit: 7 (1d8 + 3) slashing damage.', 6);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('cloaker', 3, 'Moan', 'Each creature within 60 feet of the cloaker that can hear its moan and that isn''t an aberration must succeed on a DC 13 Wisdom saving throw or become frightened until the end of the cloaker''s next turn. If a creature''s saving throw is successful, the creature is immune to the cloaker''s moan for the next 24 hours.', 'wis', 13, 'none');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type) VALUES ('cloaker', 4, 'Phantasms', 'The cloaker magically creates three illusory duplicates of itself if it isn''t in bright light. The duplicates move with it and mimic its actions, shifting position so as to make it impossible to track which cloaker is the real one. If the cloaker is ever in an area of bright light, the duplicates disappear.
