INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('couatl', 0, 'Bite', 'Melee Weapon Attack: +8 to hit, reach 5 ft., one creature. Hit: 8 (1d6 + 5) piercing damage, and the target must succeed on a DC 13 Constitution saving throw or be poisoned for 24 hours. Until this poison ends, the target is unconscious. Another creature can use an action to shake the target awake.', 8);
