INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('couatl', 1, 'Constrict', 'Melee Weapon Attack: +6 to hit, reach 10 ft., one Medium or smaller creature. Hit: 10 (2d6 + 3) bludgeoning damage, and the target is grappled (escape DC 15). Until this grapple ends, the target is restrained, and the couatl can''t constrict another target.', 6);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('couatl', 2, 'Change Shape', 'The couatl magically polymorphs into a humanoid or beast that has a challenge rating equal to or less than its own, or back into its true form. It reverts to its true form if it dies. Any equipment it is wearing or carrying is absorbed or borne by the new form (the couatl''s choice).
