INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('cult-fanatic', 'Cult Fanatic', 'Medium', 'humanoid', 'any non-good alignment', 22, '6d8', '6d8-5', '30 ft.', 11, 14, 12, 10, 13, 14, 11, 'any one language (usually Common)', 2, 2, 450, '/api/images/monsters/cult-fanatic.png', '/api/2014/monsters/cult-fanatic', 'Fanatics are often part of a cult’s leadership, using their charisma and dogma to influence and prey on those of weak will. Most are interested in personal power above all else.', 'any race');
