INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('cultist', 'Cultist', 'Medium', 'humanoid', 'any non-good alignment', 9, '2d8', '2d8', '30 ft.', 11, 12, 10, 10, 11, 10, 10, 'any one language (usually Common)', 0.125, 2, 25, '/api/images/monsters/cultist.png', '/api/2014/monsters/cultist', 'Cultists swear allegiance to dark powers such as elemental princes, demon lords, or archdevils. Most conceal their loyalties to avoid being ostracized, imprisoned, or executed for their beliefs. Unlike evil acolytes, cultists often show signs of insanity in their beliefs and practices.', 'any race');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('darkmantle', 0, 'dex', 11);
INSERT INTO monsters_proficiencies (monsters_index, order_num, "value", proficiency_index) VALUES ('darkmantle', 0, 3, 'skill-stealth');
