INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('darkmantle', 1, 'False Appearance', 'While the darkmantle remains motionless, it is indistinguishable from a cave formation such as a stalactite or stalagmite.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('darkmantle', 0, 'bludgeoning', '1d6+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('darkmantle', 0, 'Crush', 'Melee Weapon Attack: +5 to hit, reach 5 ft., one creature. Hit: 6 (1d6 + 3) bludgeoning damage, and the darkmantle attaches to the target. If the target is Medium or smaller and the darkmantle has advantage on the attack roll, it attaches by engulfing the target''s head, and the target is also blinded and unable to breathe while the darkmantle is attached in this way.
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('darkmantle', 1, 'Darkness Aura', 'A 15-foot radius of magical darkness extends out from the darkmantle, moves with it, and spreads around corners. The darkness lasts as long as the darkmantle maintains concentration, up to 10 minutes (as if concentrating on a spell). Darkvision can''t penetrate this darkness, and no natural light can illuminate it. If any of the darkness overlaps with an area of light created by a spell of 2nd level or lower, the spell creating the light is dispelled.', 'per day', 1);
