INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('death-dog', 1, 'Bite', 'Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 5 (1d6 + 2) piercing damage. If the target is a creature, it must succeed on a DC 12 Constitution saving throw against disease or become poisoned until the disease is cured. Every 24 hours that elapse, the creature must repeat the saving throw, reducing its hit point maximum by 5 (1d10) on a failure. This reduction lasts until the disease is cured. The creature dies if the disease reduces its hit point maximum to 0.', 4);
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('death-dog', 'Death Dog', 'Medium', 'monstrosity', 'neutral evil', 39, '6d8', '6d8+12', '40 ft.', 15, 14, 14, 3, 13, 6, '120 ft.', 15, '', 1, 2, 200, '/api/images/monsters/death-dog.png', '/api/2014/monsters/death-dog', 'A death dog is an ugly two-headed hound that roams plains, and deserts. Hate burns in a death dog’s heart, and a taste for humanoid flesh drives it to attack travelers and explorers. Death dog saliva carries a foul disease that causes a victim’s flesh to slowly rot off the bone.');
