INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('deva', 2, 'Healing Touch', 'The deva touches another creature. The target magically regains 20 (4d8 + 2) hit points and is freed from any curse, disease, poison, blindness, or deafness.', 'per day', 3);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('deva', 3, 'Change Shape', 'The deva magically polymorphs into a humanoid or beast that has a challenge rating equal to or less than its own, or back into its true form. It reverts to its true form if it dies. Any equipment it is wearing or carrying is absorbed or borne by the new form (the deva''s choice).
