INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('doppelganger', 0, 'Shapechanger', 'The doppelganger can use its action to polymorph into a Small or Medium humanoid it has seen, or back into its true form. Its statistics, other than its size, are the same in each form. Any equipment it is wearing or carrying isn''t transformed. It reverts to its true form if it dies.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('doppelganger', 1, 'Ambusher', 'In the first round of combat, the doppelganger has advantage on attack rolls against any creature it has surprised.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('doppelganger', 2, 'Surprise Attack', 'If the doppelganger surprises a creature and hits it with an attack during the first round of combat, the target takes an extra 10 (3d6) damage from the attack.');
