INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('druid', 'Druid', 'Medium', 'humanoid', 'any alignment', 27, '5d8', '5d8+5', '30 ft.', 10, 12, 13, 12, 15, 11, 14, 'Druidic plus any two languages', 2, 2, 450, '/api/images/monsters/druid.png', '/api/2014/monsters/druid', '**Druids** dwell in forests and other secluded wilderness locations, where they protect the natural world from monsters and the encroachment of civilization. Some are **tribal shamans** who heal the sick, pray to animal spirits, and provide spiritual guidance.', 'any race');
