INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('dryad', 1, 'Magic Resistance', 'The dryad has advantage on saving throws against spells and other magical effects.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('dryad', 2, 'Speak with Beasts and Plants', 'The dryad can communicate with beasts and plants as if they shared a language.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('dryad', 3, 'Tree Stride', 'Once on her turn, the dryad can use 10 ft. of her movement to step magically into one living tree within her reach and emerge from a second living tree within 60 ft. of the first tree, appearing in an unoccupied space within 5 ft. of the second tree. Both trees must be large or bigger.');
