INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('duergar', 1, 'Sunlight Sensitivity', 'While in sunlight, the duergar has disadvantage on attack rolls, as well as on Wisdom (Perception) checks that rely on sight.');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type) VALUES ('duergar', 0, 'Enlarge', 'For 1 minute, the duergar magically increases in size, along with anything it is wearing or carrying. While enlarged, the duergar is Large, doubles its damage dice on Strength-based weapon attacks (included in the attacks), and makes Strength checks and Strength saving throws with advantage. If the duergar lacks the room to become Large, it attains the maximum size possible in the space available.', 'recharge after rest');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('duergar', 0, 'piercing', '1d8+2');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('duergar', 1, 'War Pick', 'Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 6 (1d8 + 2) piercing damage, or 11 (2d8 + 2) piercing damage while enlarged.', 4);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('duergar', 0, 'bludgeoning', '1d6+2');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('duergar', 2, 'Javelin', 'Melee or Ranged Weapon Attack: +4 to hit, reach 5 ft. or range 30/120 ft., one target. Hit: 5 (1d6 + 2) piercing damage, or 9 (2d6 + 2) piercing damage while enlarged.', 4);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type) VALUES ('duergar', 3, 'Invisibility', 'The duergar magically turns invisible until it attacks, casts a spell, or uses its Enlarge, or until its concentration is broken, up to 1 hour (as if concentrating on a spell). Any equipment the duergar wears or carries is invisible with it.', 'recharge after rest');
