INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus, usage_type, usage_dice, usage_min_value) VALUES ('ettercap', 3, 'Web', 'Ranged Weapon Attack: +4 to hit, range 30/60 ft., one Large or smaller creature. Hit: The creature is restrained by webbing. As an action, the restrained creature can make a DC 11 Strength check, escaping from the webbing on a success. The effect ends if the webbing is destroyed. The webbing has AC 10, 5 hit points, is vulnerable to fire damage and immune to bludgeoning damage.', 4, 'recharge on roll', '1d6', 5);
