INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('fire-elemental', 1, 'Touch', 'Melee Weapon Attack: +6 to hit, reach 5 ft., one target. Hit: 10 (2d6 + 3) fire damage. If the target is a creature or a flammable object, it ignites. Until a creature takes an action to douse the fire, the target takes 5 (1d10) fire damage at the start of each of its turns.', 6);
