INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('ghost', 1, 'Incorporeal Movement', 'The ghost can move through other creatures and objects as if they were difficult terrain. It takes 5 (1d10) force damage if it ends its turn inside an object.');
