INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", speed_fly) VALUES ('giant-eagle', 'Giant Eagle', 'Large', 'beast', 'neutral good', 26, '4d10', '4d10+4', '10 ft.', 16, 17, 13, 8, 14, 10, 14, 'Giant Eagle, understands Common and Auran but can''t speak', 1, 2, 200, '/api/images/monsters/giant-eagle.png', '/api/2014/monsters/giant-eagle', 'A giant eagle is a noble creature that speaks its own language and understands speech in the Common tongue. A mated pair of giant eagles typically has up to four eggs or young in their nest (treat the young as normal eagles).', '80 ft.');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('giant-elk', 0, 'natural', 14);
