INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('giant-elk', 1, 'Hooves', 'Melee Weapon Attack: +6 to hit, reach 5 ft., one prone creature. Hit: 22 (4d8 + 4) bludgeoning damage.', 6);
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('giant-elk', 'Giant Elk', 'Huge', 'beast', 'unaligned', 42, '5d12', '5d12+10', '60 ft.', 19, 16, 14, 7, 14, 10, 14, 'Giant Elk, understands Common, Elvish, and Sylvan but can''t speak', 2, 2, 450, '/api/images/monsters/giant-elk.png', '/api/2014/monsters/giant-elk', 'The majestic giant elk is rare to the point that its appearance is often taken as a foreshadowing of an important event, such as the birth of a king. Legends tell of gods that take the form of giant elk when visiting the Material Plane. Many cultures therefore believe that to hunt these creatures is to invite divine wrath.');
