INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", senses_blindsight) VALUES ('giant-fire-beetle', 'Giant Fire Beetle', 'Small', 'beast', 'unaligned', 4, '1d6', '1d6+1', '30 ft.', 8, 10, 12, 1, 7, 3, 8, '', 0, 2, 10, '/api/images/monsters/giant-fire-beetle.png', '/api/2014/monsters/giant-fire-beetle', 'A giant fire beetle is a nocturnal creature that takes its name from a pair of glowing glands that give off light. Miners and adventurers prize these creatures, for a giant fire beetle’s glands continue to shed light for 1d6 days after the beetle dies. Giant fire beetles are most commonly found underground and in dark forests.', '30 ft.');
