INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('giant-sea-horse', 0, 'natural', 13);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-sea-horse', 0, 'Charge', 'If the sea horse moves at least 20 ft. straight toward a target and then hits it with a ram attack on the same turn, the target takes an extra 7 (2d6) bludgeoning damage. If the target is a creature, it must succeed on a DC 11 Strength saving throw or be knocked prone.');
