INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, speed_swim, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('giant-sea-horse', 'Giant Sea Horse', 'Large', 'beast', 'unaligned', 16, '3d10', '3d10', '0 ft.', '40 ft.', 12, 15, 11, 2, 12, 5, 11, '', 0.5, 2, 100, '/api/images/monsters/giant-sea-horse.png', '/api/2014/monsters/giant-sea-horse', 'Like their smaller kin, giant sea horses are shy, colorful fish with elongated bodies and curled tails. Aquatic elves train them as mounts.');
