INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_swim, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", senses_blindsight) VALUES ('giant-shark', 'Giant Shark', 'Huge', 'beast', 'unaligned', 126, '11d12', '11d12+55', '50 ft.', 23, 11, 21, 1, 10, 5, 13, '', 5, 3, 1800, '/api/images/monsters/giant-shark.png', '/api/2014/monsters/giant-shark', 'A giant shark is 30 feet long and normally found in deep oceans. Utterly fearless, it preys on anything that crosses its path, including whales and ships.', '60 ft.');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('giant-spider', 0, 'natural', 14);
