INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-spider', 0, 'Spider Climb', 'The spider can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-spider', 1, 'Web Sense', 'While in contact with a web, the spider knows the exact location of any other creature in contact with the same web.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-spider', 2, 'Web Walker', 'The spider ignores movement restrictions caused by webbing.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('giant-spider', 0, 'piercing', '1d8+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('giant-spider', 0, 'Bite', 'Melee Weapon Attack: +5 to hit, reach 5 ft., one creature. Hit: 7 (1d8 + 3) piercing damage, and the target must make a DC 11 Constitution saving throw, taking 9 (2d8) poison damage on a failed save, or half as much damage on a successful one. If the poison damage reduces the target to 0 hit points, the target is stable but poisoned for 1 hour, even after regaining hit points, and is paralyzed while poisoned in this way.', 5);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus, usage_type, usage_dice, usage_min_value) VALUES ('giant-spider', 1, 'Web', 'Ranged Weapon Attack: +5 to hit, range 30/60 ft., one creature. Hit: The target is restrained by webbing. As an action, the restrained target can make a DC 12 Strength check, bursting the webbing on a success. The webbing can also be attacked and destroyed (AC 10; hp 5; vulnerability to fire damage; immunity to bludgeoning, poison, and psychic damage).', 5, 'recharge on roll', '1d6', 5);
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", senses_blindsight, speed_climb) VALUES ('giant-spider', 'Giant Spider', 'Large', 'beast', 'unaligned', 26, '4d10', '4d10+4', '30 ft.', 14, 16, 12, 2, 11, 4, '60 ft.', 10, '', 1, 2, 200, '/api/images/monsters/giant-spider.png', '/api/2014/monsters/giant-spider', 'To snare its prey, a giant spider spins elaborate webs or shoots sticky strands of webbing from its abdomen. Giant spiders are most commonly found underground, making their lairs on ceilings or in dark, web-filled crevices. Such lairs are often festooned with web cocoons holding past victims.', '10 ft.', '30 ft.');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('giant-toad', 0, 'dex', 11);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-toad', 0, 'Amphibious', 'The toad can breathe air and water');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('giant-toad', 1, 'Standing Leap', 'The toad''s long jump is up to 20 ft. and its high jump is up to 10 ft., with or without a running start.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('giant-toad', 0, 'piercing', '1d10+2');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('giant-toad', 1, 'poison', '1d10');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('giant-toad', 0, 'Bite', 'Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 7 (1d10 + 2) piercing damage plus 5 (1d10) poison damage, and the target is grappled (escape DC 13). Until this grapple ends, the target is restrained, and the toad can''t bite another target.', 4);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('giant-toad', 1, 'Swallow', 'The toad makes one bite attack against a Medium or smaller target it is grappling. If the attack hits, the target is swallowed, and the grapple ends. The swallowed target is blinded and restrained, it has total cover against attacks and other effects outside the toad, and it takes 10 (3d6) acid damage at the start of each of the toad''s turns. The toad can have only one target swallowed at a time.
