INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", speed_fly) VALUES ('giant-vulture', 'Giant Vulture', 'Large', 'beast', 'neutral evil', 22, '3d10', '3d10+6', '10 ft.', 15, 10, 15, 6, 12, 7, 13, 'understands Common but can''t speak', 1, 2, 200, '/api/images/monsters/giant-vulture.png', '/api/2014/monsters/giant-vulture', 'A giant vulture has advanced intelligence and a malevolent bent. Unlike its smaller kin, it will attack a wounded creature to hasten its end. Giant vultures have been known to haunt a thirsty, starving creature for days to enjoy its suffering.', '60 ft.');
