INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", senses_blindsight, speed_climb) VALUES ('giant-wolf-spider', 'Giant Wolf Spider', 'Medium', 'beast', 'unaligned', 11, '2d8', '2d8+2', '40 ft.', 12, 16, 13, 3, 12, 4, '60 ft.', 13, '', 0.25, 2, 50, '/api/images/monsters/giant-wolf-spider.png', '/api/2014/monsters/giant-wolf-spider', 'Smaller than a giant spider, a giant wolf spider hunts prey across open ground or hides in a burrow or crevice, or in a hidden cavity beneath debris.', '10 ft.', '40 ft.');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('gibbering-mouther', 0, 'dex', 9);
INSERT INTO monsters_condition_immunities (monsters_index, order_num, conditions_index) VALUES ('gibbering-mouther', 0, 'prone');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('gibbering-mouther', 0, 'Aberrant Ground', 'The ground in a 10-foot radius around the mouther is doughlike difficult terrain. Each creature that starts its turn in that area must succeed on a DC 10 Strength saving throw or have its speed reduced to 0 until the start of its next turn.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('gibbering-mouther', 1, 'Gibbering', 'The mouther babbles incoherently while it can see any creature and isn''t incapacitated. Each creature that starts its turn within 20 feet of the mouther and can hear the gibbering must succeed on a DC 10 Wisdom saving throw. On a failure, the creature can''t take reactions until the start of its next turn and rolls a d8 to determine what it does during its turn. On a 1 to 4, the creature does nothing. On a 5 or 6, the creature takes no action or bonus action and uses all its movement to move in a randomly determined direction. On a 7 or 8, the creature makes a melee attack against a randomly determined creature within its reach or does nothing if it can''t make such an attack.', 'wis', 10, 'none');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('gibbering-mouther', 0, 'Bites', 1, 'melee');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('gibbering-mouther', 1, 'Blinding Spittle', 1, 'ranged');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('gibbering-mouther', 0, 'Multiattack', 'actions', 'The gibbering mouther makes one bite attack and, if it can, uses its Blinding Spittle.');
