INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('hydra', 1, 'Multiple Heads', 'The hydra has five heads. While it has more than one head, the hydra has advantage on saving throws against being blinded, charmed, deafened, frightened, stunned, and knocked unconscious.
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('hydra', 2, 'Reactive Heads', 'For each head the hydra has beyond one, it gets an extra reaction that can be used only for opportunity attacks.');
