INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type) VALUES ('knight', 3, 'Leadership', 'For 1 minute, the knight can utter a special command or warning whenever a nonhostile creature that it can see within 30 ft. of it makes an attack roll or a saving throw. The creature can add a d4 to its roll provided it can hear and understand the knight. A creature can benefit from only one Leadership die at a time. This effect ends if the knight is incapacitated.', 'recharge after rest');
INSERT INTO monsters_reactions (monsters_index, order_num, name, "desc") VALUES ('knight', 0, 'Parry', 'The knight adds 2 to its AC against one melee attack that would hit it. To do so, the knight must see the attacker and be wielding a melee weapon.');
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('knight', 'Knight', 'Medium', 'humanoid', 'any alignment', 52, '8d8', '8d8+16', '30 ft.', 16, 11, 14, 11, 11, 15, 10, 'any one language (usually Common)', 3, 2, 700, '/api/images/monsters/knight.png', '/api/2014/monsters/knight', 'Knights are warriors who pledge service to rulers, religious orders, and noble causes. A knight’s alignment determines the extent to which a pledge is honored. Whether undertaking a quest or patrolling a realm, a knight often travels with an entourage that includes squires and hirelings who are commoners.', 'any race');
