INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('mastiff', 'Mastiff', 'Medium', 'beast', 'unaligned', 5, '1d8', '1d8+1', '40 ft.', 13, 14, 12, 3, 12, 7, 13, '', 0.125, 2, 25, '/api/images/monsters/mastiff.png', '/api/2014/monsters/mastiff', 'Mastiffs are impressive hounds prized by humanoids for their loyalty and keen senses. Mastiffs can be trained as guard dogs, hunting dogs, and war dogs. Halflings and other Small humanoids ride them as mounts.');
