INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('medusa', 0, 'Petrifying Gaze', 'When a creature that can see the medusa''s eyes starts its turn within 30 ft. of the medusa, the medusa can force it to make a DC 14 Constitution saving throw if the medusa isn''t incapacitated and can see the creature. If the saving throw fails by 5 or more, the creature is instantly petrified. Otherwise, a creature that fails the save begins to turn to stone and is restrained. The restrained creature must repeat the saving throw at the end of its next turn, becoming petrified on a failure or ending the effect on a success. The petrification lasts until the creature is freed by the greater restoration spell or other magic.
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc", action_options_choose, action_options_type, action_options_from_option_set_type) VALUES ('medusa', 0, 'Multiattack', 'action_options', 'The medusa makes either three melee attacks--one with its snake hair and two with its shortsword--or two ranged attacks with its longbow.', 1, 'action', 'options_array');
