INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('mimic', 0, 'Shapechanger', 'The mimic can use its action to polymorph into an object or back into its true, amorphous form. Its statistics are the same in each form. Any equipment it is wearing or carrying isn ''t transformed. It reverts to its true form if it dies.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('mimic', 1, 'Adhesive (Object Form Only)', 'The mimic adheres to anything that touches it. A Huge or smaller creature adhered to the mimic is also grappled by it (escape DC 13). Ability checks made to escape this grapple have disadvantage.');
