INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('mummy-lord', 0, 'Attack', 'The mummy lord makes one attack with its rotting fist or uses its Dreadful Glare.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('mummy-lord', 1, 'Blinding Dust', 'Blinding dust and sand swirls magically around the mummy lord. Each creature within 5 feet of the mummy lord must succeed on a DC 16 Constitution saving throw or be blinded until the end of the creature''s next turn.', 'con', 16, 'none');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('mummy-lord', 2, 'Blasphemous Word (Costs 2 Actions)', 'The mummy lord utters a blasphemous word. Each non-undead creature within 10 feet of the mummy lord that can hear the magical utterance must succeed on a DC 16 Constitution saving throw or be stunned until the end of the mummy lord''s next turn.', 'con', 16, 'none');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('mummy-lord', 3, 'Channel Negative Energy (Costs 2 Actions)', 'The mummy lord magically unleashes negative energy. Creatures within 60 feet of the mummy lord, including ones behind barriers and around corners, can''t regain hit points until the end of the mummy lord''s next turn.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('mummy-lord', 4, 'Whirlwind of Sand (Costs 2 Actions)', 'The mummy lord magically transforms into a whirlwind of sand, moves up to 60 feet, and reverts to its normal form. While in whirlwind form, the mummy lord is immune to all damage, and it can''t be grappled, petrified, knocked prone, restrained, or stunned. Equipment worn or carried by the mummy lord remain in its possession.');
INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url) VALUES ('mummy-lord', 'Mummy Lord', 'Medium', 'undead', 'lawful evil', 97, '13d8', '13d8+39', '20 ft.', 18, 10, 17, 11, 18, 16, '60 ft.', 14, 'the languages it knew in life', 15, 5, 13000, '/api/images/monsters/mummy-lord.png', '/api/2014/monsters/mummy-lord');
