INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('nalfeshnee', 2, 'Claw', 'Melee Weapon Attack: +10 to hit, reach 10 ft., one target. Hit: 15 (3d6 + 5) slashing damage.', 10);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_dice, usage_min_value) VALUES ('nalfeshnee', 3, 'Horror Nimbus', 'The nalfeshnee magically emits scintillating, multicolored light. Each creature within 15 feet of the nalfeshnee that can see the light must succeed on a DC 15 Wisdom saving throw or be frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the nalfeshnee''s Horror Nimbus for the next 24 hours.', 'wis', 15, 'none', 'recharge on roll', '1d6', 5);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('nalfeshnee', 4, 'Teleport', 'The nalfeshnee magically teleports, along with any equipment it is wearing or carrying, up to 120 feet to an unoccupied space it can see.');
