INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", spellcasting_ability_index, spellcasting_dc, spellcasting_modifier) VALUES ('night-hag', 0, 'Innate Spellcasting', 'The hag''s innate spellcasting ability is Charisma (spell save DC 14, +6 to hit with spell attacks). She can innately cast the following spells, requiring no material components:
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('night-hag', 1, 'Magic Resistance', 'The hag has advantage on saving throws against spells and other magical effects.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('night-hag', 2, 'Night Hag Items', 'A night hag carries two very rare magic items that she must craft for herself If either object is lost, the night hag will go to great lengths to retrieve it, as creating a new tool takes time and effort.
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('night-hag', 0, 'slashing', '2d8+4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('night-hag', 0, 'Claws (Hag Form Only)', 'Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 13 (2d8 + 4) slashing damage.', 7);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('night-hag', 1, 'Change Shape', 'The hag magically polymorphs into a Small or Medium female humanoid, or back into her true form. Her statistics are the same in each form. Any equipment she is wearing or carrying isn''t transformed. She reverts to her true form if she dies.');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('night-hag', 2, 'Etherealness', 'The hag magically enters the Ethereal Plane from the Material Plane, or vice versa. To do so, the hag must have a heartstone in her possession.');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('night-hag', 3, 'Nightmare Haunting', 'While on the Ethereal Plane, the hag magically touches a sleeping humanoid on the Material Plane. A protection from evil and good spell cast on the target prevents this contact, as does a magic circle. As long as the contact persists, the target has dreadful visions. If these visions last for at least 1 hour, the target gains no benefit from its rest, and its hit point maximum is reduced by 5 (1d10). If this effect reduces the target''s hit point maximum to 0, the target dies, and if the target was evil, its soul is trapped in the hag''s soul bag. The reduction to the target''s hit point maximum lasts until removed by the greater restoration spell or similar magic.', 'per day', 1);
