INSERT INTO monsters_reactions (monsters_index, order_num, name, "desc") VALUES ('noble', 0, 'Parry', 'The noble adds 2 to its AC against one melee attack that would hit it. To do so, the noble must see the attacker and be wielding a melee weapon.');
