INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus, usage_type) VALUES ('octopus', 1, 'Ink Cloud', 'A 5-foot-radius cloud of ink extends all around the octopus if it is underwater. The area is heavily obscured for 1 minute, although a significant current can disperse the ink. After releasing the ink, the octopus can use the Dash action as a bonus action.', 0, 'recharge after rest');
