INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('otyugh', 0, 'Limited Telepathy', 'The otyugh can magically transmit simple messages and images to any creature within 120 ft. of it that can understand a language. This form of telepathy doesn''t allow the receiving creature to telepathically respond.');
