INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('priest', 'Priest', 'Medium', 'humanoid', 'any alignment', 27, '5d8', '5d8+5', '25 ft.', 10, 10, 12, 13, 16, 13, 13, 'any two languages', 2, 2, 450, '/api/images/monsters/priest.png', '/api/2014/monsters/priest', 'Priests bring the teachings of their gods to the common folk. They are the spiritual leaders of temples and shrines and often hold positions of influence in their communities. Evil priests might work openly under a tyrant, or they might be the leaders of religious sects hidden in the shadows of good society, overseeing depraved rites.
