INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('quasit', 0, 'Shapechanger', 'The quasit can use its action to polymorph into a beast form that resembles a bat (speed 10 ft. fly 40 ft.), a centipede (40 ft., climb 40 ft.), or a toad (40 ft., swim 40 ft.), or back into its true form . Its statistics are the same in each form, except for the speed changes noted. Any equipment it is wearing or carrying isn''t transformed . It reverts to its true form if it dies.');
