INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('quasit', 0, 'Claw (Bite in Beast Form)', 'Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 5 (1d4 + 3) piercing damage, and the target must succeed on a DC 10 Constitution saving throw or take 5 (2d4) poison damage and become poisoned for 1 minute. The target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.', 4);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type, usage_type, usage_times) VALUES ('quasit', 1, 'Scare', 'One creature of the quasit''s choice within 20 ft. of it must succeed on a DC 10 Wisdom saving throw or be frightened for 1 minute. The target can repeat the saving throw at the end of each of its turns, with disadvantage if the quasit is within line of sight, ending the effect on itself on a success.', 'wis', 10, 'none', 'per day', 1);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('quasit', 2, 'Invisibility', 'The quasit magically turns invisible until it attacks or uses Scare, or until its concentration ends (as if concentrating on a spell). Any equipment the quasit wears or carries is invisible with it.');
