INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('remorhaz', 0, 'Heated Body', 'A creature that touches the remorhaz or hits it with a melee attack while within 5 feet of it takes 10 (3d6) fire damage.');
