INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('remorhaz', 0, 'Bite', 'Melee Weapon Attack: +11 to hit, reach 10 ft., one target. Hit: 40 (6d10 + 7) piercing damage plus 10 (3d6) fire damage. If the target is a creature, it is grappled (escape DC 17). Until this grapple ends, the target is restrained, and the remorhaz can''t bite another target.', 11);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('remorhaz', 1, 'Swallow', 'The remorhaz makes one bite attack against a Medium or smaller creature it is grappling. If the attack hits, that creature takes the bite''s damage and is swallowed, and the grapple ends. While swallowed, the creature is blinded and restrained, it has total cover against attacks and other effects outside the remorhaz, and it takes 21 (6d6) acid damage at the start of each of the remorhaz''s turns.
