INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('roper', 0, 'False Appearance', 'While the roper remains motionless, it is indistinguishable from a normal cave formation, such as a stalagmite.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('roper', 1, 'Grasping Tendrils', 'The roper can have up to six tendrils at a time. Each tendril can be attacked (AC 20; 10 hit points; immunity to poison and psychic damage). Destroying a tendril deals no damage to the roper, which can extrude a replacement tendril on its next turn. A tendril can also be broken if a creature takes an action and succeeds on a DC 15 Strength check against it.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('roper', 2, 'Spider Climb', 'The roper can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('roper', 0, 'Tendril', 4, 'melee');
