INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('roper', 2, 'Tendril', 'Melee Weapon Attack: +7 to hit, reach 50 ft., one creature. Hit: The target is grappled (escape DC 15). Until the grapple ends, the target is restrained and has disadvantage on Strength checks and Strength saving throws, and the roper can''t use the same tendril on another target.', 7);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('roper', 3, 'Reel', 'The roper pulls each creature grappled by it up to 25 ft. straight toward it.');
