INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('rust-monster', 0, 'natural', 14);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('rust-monster', 0, 'Iron Scent', 'The rust monster can pinpoint, by scent, the location of ferrous metal within 30 feet of it.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('rust-monster', 1, 'Rust Metal', 'Any nonmagical weapon made of metal that hits the rust monster corrodes. After dealing damage, the weapon takes a permanent and cumulative -1 penalty to damage rolls. If its penalty drops to -5, the weapon is destroyed. Nonmagical ammunition made of metal that hits the rust monster is destroyed after dealing damage.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('rust-monster', 0, 'piercing', '1d8+1');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('rust-monster', 0, 'Bite', 'Melee Weapon Attack: +3 to hit, reach 5 ft., one target. Hit: 5 (1d8 + 1) piercing damage.', 3);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('rust-monster', 1, 'Antennae', 'The rust monster corrodes a nonmagical ferrous metal object it can see within 5 feet of it. If the object isn''t being worn or carried, the touch destroys a 1-foot cube of it. If the object is being worn or carried by a creature, the creature can make a DC 11 Dexterity saving throw to avoid the rust monster''s touch.
