INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('scout', 'Scout', 'Medium', 'humanoid', 'any alignment', 16, '3d8', '3d8+3', '30 ft.', 11, 14, 12, 11, 13, 11, 15, 'any one language (usually Common)', 0.5, 2, 100, '/api/images/monsters/scout.png', '/api/2014/monsters/scout', 'Scouts are skilled hunters and trackers who offer their services for a fee. Most hunt wild game, but a few work as bounty hunters, serve as guides, or provide military reconnaissance.', 'any race');
INSERT INTO monsters_armor_class (monsters_index, order_num, "type", "value") VALUES ('sea-hag', 0, 'natural', 14);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('sea-hag', 0, 'Amphibious', 'The hag can breathe air and water.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('sea-hag', 1, 'Horrific Appearance', 'Any humanoid that starts its turn within 30 feet of the hag and can see the hag''s true form must make a DC 11 Wisdom saving throw. On a failed save, the creature is frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, with disadvantage if the hag is within line of sight, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the hag''s Horrific Appearance for the next 24 hours.
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('sea-hag', 0, 'slashing', '2d6+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('sea-hag', 0, 'Claws', 'Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 10 (2d6 + 3) slashing damage.', 5);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('sea-hag', 1, 'Death Glare', 'The hag targets one frightened creature she can see within 30 ft. of her. If the target can see the hag, it must succeed on a DC 11 Wisdom saving throw against this magic or drop to 0 hit points.', 'wis', 11, 'none');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('sea-hag', 2, 'Illusory Appearance', 'The hag covers herself and anything she is wearing or carrying with a magical illusion that makes her look like an ugly creature of her general size and humanoid shape. The effect ends if the hag takes a bonus action to end it or if she dies.
