INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('shambling-mound', 0, 'Multiattack', 'actions', 'The shambling mound makes two slam attacks. If both attacks hit a Medium or smaller target, the target is grappled (escape DC 14), and the shambling mound uses its Engulf on it.');
