INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('shambling-mound', 1, 'Slam', 'Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 13 (2d8 + 4) bludgeoning damage.', 7);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('shambling-mound', 2, 'Engulf', 'The shambling mound engulfs a Medium or smaller creature grappled by it. The engulfed target is blinded, restrained, and unable to breathe, and it must succeed on a DC 14 Constitution saving throw at the start of each of the mound''s turns or take 13 (2d8 + 4) bludgeoning damage. If the mound moves, the engulfed target moves with it. The mound can have only one creature engulfed at a time.');
