INSERT INTO monsters_condition_immunities (monsters_index, order_num, conditions_index) VALUES ('shield-guardian', 4, 'poisoned');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('shield-guardian', 0, 'Bound', 'The shield guardian is magically bound to an amulet. As long as the guardian and its amulet are on the same plane of existence, the amulet''s wearer can telepathically call the guardian to travel to it, and the guardian knows the distance and direction to the amulet. If the guardian is within 60 feet of the amulet''s wearer, half of any damage the wearer takes (rounded up) is transferred to the guardian.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('shield-guardian', 1, 'Regeneration', 'The shield guardian regains 10 hit points at the start of its turn if it has at least 1 hit. point.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('shield-guardian', 2, 'Spell Storing', 'A spellcaster who wears the shield guardian''s amulet can cause the guardian to store one spell of 4th level or lower. To do so, the wearer must cast the spell on the guardian. The spell has no effect but is stored within the guardian. When commanded to do so by the wearer or when a situation arises that was predefined by the spellcaster, the guardian casts the stored spell with any parameters set by the original caster, requiring no components. When the spell is cast or a new spell is stored, any previously stored spell is lost.');
INSERT INTO monsters_actions_actions (monsters_actions_index, order_num, action_name, count, "type") VALUES ('shield-guardian', 0, 'Fist', 2, 'melee');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('shield-guardian', 0, 'Multiattack', 'actions', 'The guardian makes two fist attacks.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('shield-guardian', 0, 'bludgeoning', '2d6+4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('shield-guardian', 1, 'Fist', 'Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 11 (2d6 + 4) bludgeoning damage.', 7);
INSERT INTO monsters_reactions (monsters_index, order_num, name, "desc") VALUES ('shield-guardian', 0, 'Shield', 'When a creature makes an attack against the wearer of the guardian''s amulet, the guardian grants a +2 bonus to the wearer''s AC if the guardian is within 5 feet of the wearer.');
