INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('solar', 2, 'Slaying Longbow', 'Ranged Weapon Attack: +13 to hit, range 150/600 ft., one target. Hit: 15 (2d8 + 6) piercing damage plus 27 (6d8) radiant damage. If the target is a creature that has 190 hit points or fewer, it must succeed on a DC 15 Constitution saving throw or die.', 13);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('solar', 3, 'Flying Sword', 'The solar releases its greatsword to hover magically in an unoccupied space within 5 ft. of it. If the solar can see the sword, the solar can mentally command it as a bonus action to fly up to 50 ft. and either make one attack against a target or return to the solar''s hands. If the hovering sword is targeted by any effect, the solar is considered to be holding it. The hovering sword falls if the solar dies.');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('solar', 4, 'Healing Touch', 'The solar touches another creature. The target magically regains 40 (8d8 + 4) hit points and is freed from any curse, disease, poison, blindness, or deafness.', 'per day', 4);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('solar', 0, 'Teleport', 'The solar magically teleports, along with any equipment it is wearing or carrying, up to 120 ft. to an unoccupied space it can see.');
