INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('solar', 1, 'Searing Burst (Costs 2 Actions)', 'The solar emits magical, divine energy. Each creature of its choice in a 10 -foot radius must make a DC 23 Dexterity saving throw, taking 14 (4d6) fire damage plus 14 (4d6) radiant damage on a failed save, or half as much damage on a successful one.', 'dex', 23, 'half');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('solar', 2, 'Blinding Gaze (Costs 3 Actions)', 'The solar targets one creature it can see within 30 ft. of it. If the target can see it, the target must succeed on a DC 15 Constitution saving throw or be blinded until magic such as the lesser restoration spell removes the blindness.', 'con', 15, 'none');
