INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('sprite', 1, 'Shortbow', 'Ranged Weapon Attack: +6 to hit, range 40/160 ft., one target. Hit: 1 piercing damage, and the target must succeed on a DC 10 Constitution saving throw or become poisoned for 1 minute. If its saving throw result is 5 or lower, the poisoned target falls unconscious for the same duration, or until it takes damage or another creature takes an action to shake it awake.', 6);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('sprite', 2, 'Heart Sight', 'The sprite touches a creature and magically knows the creature''s current emotional state. If the target fails a DC 10 Charisma saving throw, the sprite also knows the creature''s alignment. Celestials, fiends, and undead automatically fail the saving throw.', 'cha', 10, 'none');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('sprite', 3, 'Invisibility', 'The sprite magically turns invisible until it attacks or casts a spell, or until its concentration ends (as if concentrating on a spell). Any equipment the sprite wears or carries is invisible with it.');
