INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('spy', 1, 'Sneak Attack (1/Turn)', 'The spy deals an extra 7 (2d6) damage when it hits a target with a weapon attack and has advantage on the attack roll, or when the target is within 5 ft. of an ally of the spy that isn''t incapacitated and the spy doesn''t have disadvantage on the attack roll.');
