INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('succubus-incubus', 0, 'Telepathic Bond', 'The fiend ignores the range restriction on its telepathy when communicating with a creature it has charmed. The two don''t even need to be on the same plane of existence.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('succubus-incubus', 1, 'Shapechanger', 'The fiend can use its action to polymorph into a Small or Medium humanoid, or back into its true form. Without wings, the fiend loses its flying speed. Other than its size and speed, its statistics are the same in each form. Any equipment it is wearing or carrying isn''t transformed. It reverts to its true form if it dies.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('succubus-incubus', 0, 'slashing', '1d6+3');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('succubus-incubus', 0, 'Claw (Fiend Form Only)', 'Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 6 (1d6 + 3) slashing damage.', 5);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('succubus-incubus', 1, 'Charm', 'One humanoid the fiend can see within 30 feet of it must succeed on a DC 15 Wisdom saving throw or be magically charmed for 1 day. The charmed target obeys the fiend''s verbal or telepathic commands. If the target suffers any harm or receives a suicidal command, it can repeat the saving throw, ending the effect on a success. If the target successfully saves against the effect, or if the effect on it ends, the target is immune to this fiend''s Charm for the next 24 hours.
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('succubus-incubus', 0, 'psychic', '5d10+5');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('succubus-incubus', 2, 'Draining Kiss', 'The fiend kisses a creature charmed by it or a willing creature. The target must make a DC 15 Constitution saving throw against this magic, taking 32 (5d10 + 5) psychic damage on a failed save, or half as much damage on a successful one. The target''s hit point maximum is reduced by an amount equal to the damage taken. This reduction lasts until the target finishes a long rest. The target dies if this effect reduces its hit point maximum to 0.');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('succubus-incubus', 3, 'Etherealness', 'The fiend magically enters the Ethereal Plane from the Material Plane, or vice versa.');
