INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('swarm-of-spiders', 0, 'Swarm', 'The swarm can occupy another creature''s space and vice versa, and the swarm can move through any opening large enough for a Tiny insect. The swarm can''t regain hit points or gain temporary hit points.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('swarm-of-spiders', 1, 'Spider Climb', 'The swarm can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('swarm-of-spiders', 2, 'Web Sense', 'While in contact with a web, the swarm knows the exact location of any other creature in contact with the same web.');
