INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('tarrasque', 0, 'Legendary Resistance', 'If the tarrasque fails a saving throw, it can choose to succeed instead.', 'per day', 3);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 1, 'Magic Resistance', 'The tarrasque has advantage on saving throws against spells and other magical effects.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 2, 'Reflective Carapace', 'Any time the tarrasque is targeted by a magic missile spell, a line spell, or a spell that requires a ranged attack roll, roll a d6. On a 1 to 5, the tarrasque is unaffected. On a 6, the tarrasque is unaffected, and the effect is reflected back at the caster as though it originated from the tarrasque, turning the caster into the target.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 3, 'Siege Monster', 'The tarrasque deals double damage to objects and structures.');
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc", action_options_choose, action_options_type, action_options_from_option_set_type) VALUES ('tarrasque', 0, 'Multiattack', 'action_options', 'The tarrasque can use its Frightful Presence. It then makes five attacks: one with its bite, two with its claws, one with its horns, and one with its tail. It can use its Swallow instead of its bite.', 1, 'action', 'options_array');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('tarrasque', 0, 'piercing', '4d12+10');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('tarrasque', 1, 'Bite', 'Melee Weapon Attack: +19 to hit, reach 10 ft., one target. Hit: 36 (4d12 + 10) piercing damage. If the target is a creature, it is grappled (escape DC 20). Until this grapple ends, the target is restrained, and the tarrasque can''t bite another target.', 19);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('tarrasque', 0, 'slashing', '4d8+10');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('tarrasque', 2, 'Claw', 'Melee Weapon Attack: +19 to hit, reach 15 ft., one target. Hit: 28 (4d8 + 10) slashing damage.', 19);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('tarrasque', 0, 'piercing', '4d10+10');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('tarrasque', 3, 'Horns', 'Melee Weapon Attack: +19 to hit, reach 10 ft., one target. Hit: 32 (4d10 + 10) piercing damage.', 19);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('tarrasque', 0, 'bludgeoning', '4d6+10');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('tarrasque', 4, 'Tail', 'Melee Weapon Attack: +19 to hit, reach 20 ft., one target. Hit: 24 (4d6 + 10) bludgeoning damage. If the target is a creature, it must succeed on a DC 20 Strength saving throw or be knocked prone.', 19);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('tarrasque', 5, 'Frightful Presence', 'Each creature of the tarrasque''s choice within 120 feet of it and aware of it must succeed on a DC 17 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, with disadvantage if the tarrasque is within line of sight, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the tarrasque''s Frightful Presence for the next 24 hours.', 'wis', 17, 'none');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 6, 'Swallow', 'The tarrasque makes one bite attack against a Large or smaller creature it is grappling. If the attack hits, the target takes the bite''s damage, the target is swallowed, and the grapple ends. While swallowed, the creature is blinded and restrained, it has total cover against attacks and other effects outside the tarrasque, and it takes 56 (16d6) acid damage at the start of each of the tarrasque''s turns.
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 0, 'Attack', 'The tarrasque makes one claw attack or tail attack.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 1, 'Move', 'The tarrasque moves up to half its speed.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('tarrasque', 2, 'Chomp (Costs 2 Actions)', 'The tarrasque makes one bite attack or uses its Swallow.');
