INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc", subtype) VALUES ('tribal-warrior', 'Tribal Warrior', 'Medium', 'humanoid', 'any alignment', 11, '2d8', '2d8+2', '30 ft.', 13, 11, 12, 8, 11, 8, 10, 'any one language', 0.125, 2, 25, '/api/images/monsters/tribal-warrior.png', '/api/2014/monsters/tribal-warrior', 'Tribal warriors live beyond civilization, most often subsisting on fishing and hunting. Each tribe acts in accordance with the wishes of its chief, who is the greatest or oldest warrior of the tribe or a tribe member blessed by the gods.', 'any race');
