INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc") VALUES ('tyrannosaurus-rex', 0, 'Multiattack', 'actions', 'The tyrannosaurus makes two attacks: one with its bite and one with its tail. It can''t make both attacks against the same target.');
