INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('unicorn', 0, 'Charge', 'If the unicorn moves at least 20 ft. straight toward a target and then hits it with a horn attack on the same turn, the target takes an extra 9 (2d8) piercing damage. If the target is a creature, it must succeed on a DC 15 Strength saving throw or be knocked prone.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", spellcasting_ability_index, spellcasting_dc) VALUES ('unicorn', 1, 'Innate Spellcasting', 'The unicorn''s innate spellcasting ability is Charisma (spell save DC 14). The unicorn can innately cast the following spells, requiring no components:
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('unicorn', 2, 'Magic Resistance', 'The unicorn has advantage on saving throws against spells and other magical effects.');
