INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('unicorn', 3, 'Healing Touch', 'The unicorn touches another creature with its horn. The target magically regains 11 (2d8 + 2) hit points. In addition, the touch removes all diseases and neutralizes all poisons afflicting the target.', 'per day', 3);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('unicorn', 4, 'Teleport', 'The unicorn magically teleports itself and up to three willing creatures it can see within 5 ft. of it, along with any equipment they are wearing or carrying, to a location the unicorn is familiar with, up to 1 mile away.', 'per day', 1);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('unicorn', 0, 'Hooves', 'The unicorn makes one attack with its hooves.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('unicorn', 1, 'Shimmering Shield (Costs 2 Actions)', 'The unicorn creates a shimmering, magical field around itself or another creature it can see within 60 ft. of it. The target gains a +2 bonus to AC until the end of the unicorn''s next turn.');
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc") VALUES ('unicorn', 2, 'Heal Self (Costs 3 Actions)', 'The unicorn magically regains 11 (2d8 + 2) hit points.');
