INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('vampire-vampire', 0, 'Shapechanger', 'If the vampire isn''t in sun light or running water, it can use its action to polymorph into a Tiny bat or a Medium cloud of mist, or back into its true form.
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('vampire-vampire', 1, 'Legendary Resistance', 'If the vampire fails a saving throw, it can choose to succeed instead.', 'per day', 3);
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('vampire-vampire', 2, 'Misty Escape', 'When it drops to 0 hit points outside its resting place, the vampire transforms into a cloud of mist (as in the Shapechanger trait) instead of falling unconscious, provided that it isn''t in sunlight or running water. If it can''t transform, it is destroyed.
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('vampire-vampire', 3, 'Regeneration', 'The vampire regains 20 hit points at the start of its turn if it has at least 1 hit point and isn''t in sunlight or running water. If the vampire takes radiant damage or damage from holy water, this trait doesn''t function at the start of the vampire''s next turn.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('vampire-vampire', 4, 'Spider Climb', 'The vampire can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('vampire-vampire', 5, 'Vampire Weaknesses', 'The vampire has the following flaws:
INSERT INTO monsters_actions (monsters_index, order_num, name, multiattack_type, "desc", action_options_choose, action_options_type, action_options_from_option_set_type) VALUES ('vampire-vampire', 0, 'Multiattack', 'action_options', 'The vampire makes two attacks, only one of which can be a bite attack.', 1, 'action', 'options_array');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('vampire-vampire', 0, 'bludgeoning', '1d8+4');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('vampire-vampire', 1, 'Unarmed Strike', 'Melee Weapon Attack: +9 to hit, reach 5 ft., one creature. Hit: 8 (1d8 + 4) bludgeoning damage. Instead of dealing damage, the vampire can grapple the target (escape DC 18).', 9);
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('vampire-vampire', 0, 'piercing', '1d6+4');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('vampire-vampire', 1, 'necrotic', '3d6');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('vampire-vampire', 2, 'Bite', 'Melee Weapon Attack: +9 to hit, reach 5 ft., one willing creature, or a creature that is grappled by the vampire, incapacitated, or restrained. Hit: 7 (1d6 + 4) piercing damage plus 10 (3d6) necrotic damage. The target''s hit point maximum is reduced by an amount equal to the necrotic damage taken, and the vampire regains hit points equal to that amount. The reduction lasts until the target finishes a long rest. The target dies if this effect reduces its hit point maximum to 0. A humanoid slain in this way and then buried in the ground rises the following night as a vampire spawn under the vampire''s control.', 9);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('vampire-vampire', 3, 'Charm', 'The vampire targets one humanoid it can see within 30 ft. of it. If the target can see the vampire, the target must succeed on a DC 17 Wisdom saving throw against this magic or be charmed by the vampire. The charmed target regards the vampire as a trusted friend to be heeded and protected. Although the target isn''t under the vampire''s control, it takes the vampire''s requests or actions in the most favorable way it can, and it is a willing target for the vampire''s bit attack.
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", usage_type, usage_times) VALUES ('vampire-vampire', 4, 'Children of the Night', 'The vampire magically calls 2d4 swarms of bats or rats, provided that the sun isn''t up. While outdoors, the vampire can call 3d6 wolves instead. The called creatures arrive in 1d4 rounds, acting as allies of the vampire and obeying its spoken commands. The beasts remain for 1 hour, until the vampire dies, or until the vampire dismisses them as a bonus action.', 'per day', 1);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('vampire-vampire', 0, 'Move', 'The vampire moves up to its speed without provoking opportunity attacks.', 0);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('vampire-vampire', 1, 'Unarmed Strike', 'The vampire makes one unarmed strike.', 0);
INSERT INTO monsters_legendary_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('vampire-vampire', 2, 'Bite (Costs 2 Actions)', 'The vampire makes one bite attack.', 0);
