INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('wereboar-boar', 1, 'Charge (Boar or Hybrid Form Only)', 'If the wereboar moves at least 15 feet straight toward a target and then hits it with its tusks on the same turn, the target takes an extra 7 (2d6) slashing damage. If the target is a creature, it must succeed on a DC 13 Strength saving throw or be knocked prone.');
