INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc", dc_dc_type_index, dc_dc_value, dc_success_type) VALUES ('will-o-wisp', 0, 'Consume Life', 'As a bonus action, the will-o''-wisp can target one creature it can see within 5 ft. of it that has 0 hit points and is still alive. The target must succeed on a DC 10 Constitution saving throw against this magic or die. If the target dies, the will-o''-wisp regains 10 (3d6) hit points.', 'con', 10, 'none');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('will-o-wisp', 1, 'Ephemeral', 'The will-o''-wisp can''t wear or carry anything.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('will-o-wisp', 2, 'Incorporeal Movement', 'The will-o''-wisp can move through other creatures and objects as if they were difficult terrain. It takes 5 (1d10) force damage if it ends its turn inside an object.');
INSERT INTO monsters_special_abilities (monsters_index, order_num, name, "desc") VALUES ('will-o-wisp', 3, 'Variable Illumination', 'The will-o''-wisp sheds bright light in a 5- to 20-foot radius and dim light for an additional number of ft. equal to the chosen radius. The will-o''-wisp can alter the radius as a bonus action.');
INSERT INTO monsters_actions_damage (monsters_actions_index, order_num, damage_type_index, damage_dice) VALUES ('will-o-wisp', 0, 'lightning', '2d8');
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc", attack_bonus) VALUES ('will-o-wisp', 0, 'Shock', 'Melee Spell Attack: +4 to hit, reach 5 ft., one creature. Hit: 9 (2d8) lightning damage.', 4);
INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('will-o-wisp', 1, 'Invisibility', 'The will-o''-wisp and its light magically become invisible until it attacks or uses its Consume Life, or until its concentration ends (as if concentrating on a spell).');
