INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('winter-wolf', 'Winter Wolf', 'Large', 'monstrosity', 'neutral evil', 75, '10d10', '10d10+20', '50 ft.', 18, 13, 14, 7, 12, 8, 15, 'Common, Giant, Winter Wolf', 3, 2, 700, '/api/images/monsters/winter-wolf.png', '/api/2014/monsters/winter-wolf', 'The arctic-dwelling winter wolf is as large as a dire wolf but has snow-white fur and pale blue eyes. Frost giants use these evil creatures as guards and hunting companions, putting the wolves’ deadly breath weapon to use against their foes. Winter wolves communicate with one another using growls and barks, but they speak Common and Giant well enough to follow simple conversations.');
