INSERT INTO monsters ("index", name, size, "type", alignment, hit_points, hit_dice, hit_points_roll, speed_walk, strength, dexterity, constitution, intelligence, wisdom, charisma, senses_darkvision, senses_passive_perception, languages, challenge_rating, proficiency_bonus, xp, image, url, "desc") VALUES ('worg', 'Worg', 'Large', 'monstrosity', 'neutral evil', 26, '4d10', '4d10+4', '50 ft.', 16, 13, 13, 7, 11, 8, '60 ft.', 14, 'Goblin, Worg', 0.5, 2, 100, '/api/images/monsters/worg.png', '/api/2014/monsters/worg', 'A worg is an evil predator that delights in hunting and devouring creatures weaker than itself. Cunning and malevolent, worgs roam across the remote wilderness or are raised by goblins and hobgoblins. Those creatures use worgs as mounts, but a worg will turn on its rider if it feels mistreated or malnourished. Worgs speak in their own language and Goblin, and a few learn to speak Common as well.');
