INSERT INTO monsters_actions (monsters_index, order_num, name, "desc") VALUES ('wraith', 1, 'Create Specter', 'The wraith targets a humanoid within 10 feet of it that has been dead for no longer than 1 minute and died violently. The target''s spirit rises as a specter in the space of its corpse or in the nearest unoccupied space. The specter is under the wraith''s control. The wraith can have no more than seven specters under its control at one time.');
