INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('dwarf', 'Dwarf', 25, 'Most dwarves are lawful, believing firmly in the benefits of a well-ordered society. They tend toward good as well, with a strong sense of fair play and a belief that everyone deserves to share in the benefits of a just order.', 'Dwarves mature at the same rate as humans, but they''re considered young until they reach the age of 50. On average, they live about 350 years.', 'Medium', 'Dwarves stand between 4 and 5 feet tall and average about 150 pounds. Your size is Medium.', 'You can speak, read, and write Common and Dwarvish. Dwarvish is full of hard consonants and guttural sounds, and those characteristics spill over into whatever other language a dwarf might speak.', '/api/2014/races/dwarf');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('elf', 0, 'dex', 2);
