INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('elf', 1, 'elvish');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('elf', 0, 'darkvision');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('elf', 1, 'fey-ancestry');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('elf', 2, 'trance');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('elf', 3, 'keen-senses');
INSERT INTO races_subraces (races_index, order_num, subraces_index) VALUES ('elf', 0, 'high-elf');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('elf', 'Elf', 30, 'Elves love freedom, variety, and self-expression, so they lean strongly toward the gentler aspects of chaos. They value and protect others'' freedom as well as their own, and they are more often good than not.', 'Although elves reach physical maturity at about the same age as humans, the elven understanding of adulthood goes beyond physical growth to encompass worldly experience. An elf typically claims adulthood and an adult name around the age of 100 and can live to be 750 years old.', 'Medium', 'Elves range from under 5 to over 6 feet tall and have slender builds. Your size is Medium.', 'You can speak, read, and write Common and Elvish. Elvish is fluid, with subtle intonations and intricate grammar. Elven literature is rich and varied, and their songs and poems are famous among other races. Many bards learn their language so they can add Elvish ballads to their repertoires.', '/api/2014/races/elf');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('halfling', 0, 'dex', 2);
