INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('halfling', 0, 'brave');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('halfling', 1, 'halfling-nimbleness');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('halfling', 2, 'lucky');
INSERT INTO races_subraces (races_index, order_num, subraces_index) VALUES ('halfling', 0, 'lightfoot-halfling');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('halfling', 'Halfling', 25, 'Most halflings are lawful good. As a rule, they are good-hearted and kind, hate to see others in pain, and have no tolerance for oppression. They are also very orderly and traditional, leaning heavily on the support of their community and the comfort of their old ways.', 'A halfling reaches adulthood at the age of 20 and generally lives into the middle of his or her second century.', 'Small', 'Halflings average about 3 feet tall and weigh about 40 pounds. Your size is Small.', 'You can speak, read, and write Common and Halfling. The Halfling language isn''t secret, but halflings are loath to share it with others. They write very little, so they don''t have a rich body of literature. Their oral tradition, however, is very strong. Almost all halflings speak Common to converse with the people in whose lands they dwell or through which they are traveling.', '/api/2014/races/halfling');
