INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url, language_options_choose, language_options_type, language_options_from_option_set_type) VALUES ('human', 'Human', 30, 'Humans tend toward no particular alignment. The best and the worst are found among them.', 'Humans reach adulthood in their late teens and live less than a century.', 'Medium', 'Humans vary widely in height and build, from barely 5 feet to well over 6 feet tall. Regardless of your position in that range, your size is Medium.', 'You can speak, read, and write Common and one extra language of your choice. Humans typically learn the languages of other peoples they deal with, including obscure dialects. They are fond of sprinkling their speech with words borrowed from other tongues: Orc curses, Elvish musical expressions, Dwarvish military phrases, and so on.', '/api/2014/races/human', 1, 'languages', 'options_array');
