INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('dragonborn', 'Dragonborn', 30, 'Dragonborn tend to extremes, making a conscious choice for one side or the other in the cosmic war between good and evil. Most dragonborn are good, but those who side with evil can be terrible villains.', 'Young dragonborn grow quickly. They walk hours after hatching, attain the size and development of a 10-year-old human child by the age of 3, and reach adulthood by 15. They live to be around 80.', 'Medium', 'Dragonborn are taller and heavier than humans, standing well over 6 feet tall and averaging almost 250 pounds. Your size is Medium.', 'You can speak, read, and write Common and Draconic. Draconic is thought to be one of the oldest languages and is often used in the study of magic. The language sounds harsh to most other creatures and includes numerous hard consonants and sibilants.', '/api/2014/races/dragonborn');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('gnome', 0, 'int', 2);
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('gnome', 0, 'common');
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('gnome', 1, 'gnomish');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('gnome', 0, 'darkvision');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('gnome', 1, 'gnome-cunning');
INSERT INTO races_subraces (races_index, order_num, subraces_index) VALUES ('gnome', 0, 'rock-gnome');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('gnome', 'Gnome', 25, 'Gnomes are most often good. Those who tend toward law are sages, engineers, researchers, scholars, investigators, or inventors. Those who tend toward chaos are minstrels, tricksters, wanderers, or fanciful jewelers. Gnomes are good-hearted, and even the tricksters among them are more playful than vicious.', 'Gnomes mature at the same rate humans do, and most are expected to settle down into an adult life by around age 40. They can live 350 to almost 500 years.', 'Small', 'Gnomes are between 3 and 4 feet tall and average about 40 pounds. Your size is Small.', 'You can speak, read, and write Common and Gnomish. The Gnomish language, which uses the Dwarvish script, is renowned for its technical treatises and its catalogs of knowledge about the natural world.', '/api/2014/races/gnome');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('half-elf', 0, 'cha', 2);
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('half-elf', 0, 'common');
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('half-elf', 1, 'elvish');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-elf', 0, 'darkvision');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-elf', 1, 'fey-ancestry');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-elf', 2, 'skill-versatility');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url, language_options_choose, language_options_type, language_options_from_option_set_type, ability_bonus_options_choose, ability_bonus_options_type, ability_bonus_options_from_option_set_type) VALUES ('half-elf', 'Half-Elf', 30, 'Half-elves share the chaotic bent of their elven heritage. They value both personal freedom and creative expression, demonstrating neither love of leaders nor desire for followers. They chafe at rules, resent others'' demands, and sometimes prove unreliable, or at least unpredictable.', 'Half-elves mature at the same rate humans do and reach adulthood around the age of 20. They live much longer than humans, however, often exceeding 180 years.', 'Medium', 'Half-elves are about the same size as humans, ranging from 5 to 6 feet tall. Your size is Medium.', 'You can speak, read, and write Common, Elvish, and one extra language of your choice.', '/api/2014/races/half-elf', 1, 'languages', 'options_array', 2, 'ability_bonuses', 'options_array');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('half-orc', 0, 'str', 2);
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('half-orc', 1, 'con', 1);
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('half-orc', 0, 'common');
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('half-orc', 1, 'orc');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-orc', 0, 'darkvision');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-orc', 1, 'savage-attacks');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-orc', 2, 'relentless-endurance');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('half-orc', 3, 'menacing');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('half-orc', 'Half-Orc', 30, 'Half-orcs inherit a tendency toward chaos from their orc parents and are not strongly inclined toward good. Half-orcs raised among orcs and willing to live out their lives among them are usually evil.', 'Half-orcs mature a little faster than humans, reaching adulthood around age 14. They age noticeably faster and rarely live longer than 75 years.', 'Medium', 'Half-orcs are somewhat larger and bulkier than humans, and they range from 5 to well over 6 feet tall. Your size is Medium.', 'You can speak, read, and write Common and Orc. Orc is a harsh, grating language with hard consonants. It has no script of its own but is written in the Dwarvish script.', '/api/2014/races/half-orc');
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('tiefling', 0, 'int', 1);
INSERT INTO races_ability_bonuses (races_index, order_num, ability_score_index, bonus) VALUES ('tiefling', 1, 'cha', 2);
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('tiefling', 0, 'common');
INSERT INTO races_languages (races_index, order_num, languages_index) VALUES ('tiefling', 1, 'infernal');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('tiefling', 0, 'darkvision');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('tiefling', 1, 'hellish-resistance');
INSERT INTO races_traits (races_index, order_num, traits_index) VALUES ('tiefling', 2, 'infernal-legacy');
INSERT INTO races ("index", name, speed, alignment, age, size, size_description, language_desc, url) VALUES ('tiefling', 'Tiefling', 30, 'Tieflings might not have an innate tendency toward evil, but many of them end up there. Evil or not, an independent nature inclines many tieflings toward a chaotic alignment.', 'Tieflings mature at the same rate as humans but live a few years longer.', 'Medium', 'Tieflings are about the same size and build as humans. Your size is Medium.', 'You can speak, read, and write Common and Infernal.', '/api/2014/races/tiefling');
