INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('acrobatics', 0, 'Your Dexterity (Acrobatics) check covers your attempt to stay on your feet in a tricky situation, such as when you''re trying to run across a sheet of ice, balance on a tightrope, or stay upright on a rocking ship''s deck. The GM might also call for a Dexterity (Acrobatics) check to see if you can perform acrobatic stunts, including dives, rolls, somersaults, and flips.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('acrobatics', 'Acrobatics', 'dex', '/api/2014/skills/acrobatics');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('animal-handling', 0, 'When there is any question whether you can calm down a domesticated animal, keep a mount from getting spooked, or intuit an animal''s intentions, the GM might call for a Wisdom (Animal Handling) check. You also make a Wisdom (Animal Handling) check to control your mount when you attempt a risky maneuver.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('animal-handling', 'Animal Handling', 'wis', '/api/2014/skills/animal-handling');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('arcana', 0, 'Your Intelligence (Arcana) check measures your ability to recall lore about spells, magic items, eldritch symbols, magical traditions, the planes of existence, and the inhabitants of those planes.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('arcana', 'Arcana', 'int', '/api/2014/skills/arcana');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('athletics', 0, 'Your Strength (Athletics) check covers difficult situations you encounter while climbing, jumping, or swimming.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('athletics', 'Athletics', 'str', '/api/2014/skills/athletics');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('deception', 0, 'Your Charisma (Deception) check determines whether you can convincingly hide the truth, either verbally or through your actions. This deception can encompass everything from misleading others through ambiguity to telling outright lies. Typical situations include trying to fast- talk a guard, con a merchant, earn money through gambling, pass yourself off in a disguise, dull someone''s suspicions with false assurances, or maintain a straight face while telling a blatant lie.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('deception', 'Deception', 'cha', '/api/2014/skills/deception');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('history', 0, 'Your Intelligence (History) check measures your ability to recall lore about historical events, legendary people, ancient kingdoms, past disputes, recent wars, and lost civilizations.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('history', 'History', 'int', '/api/2014/skills/history');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('insight', 0, 'Your Wisdom (Insight) check decides whether you can determine the true intentions of a creature, such as when searching out a lie or predicting someone''s next move. Doing so involves gleaning clues from body language, speech habits, and changes in mannerisms.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('insight', 'Insight', 'wis', '/api/2014/skills/insight');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('intimidation', 0, 'When you attempt to influence someone through overt threats, hostile actions, and physical violence, the GM might ask you to make a Charisma (Intimidation) check. Examples include trying to pry information out of a prisoner, convincing street thugs to back down from a confrontation, or using the edge of a broken bottle to convince a sneering vizier to reconsider a decision.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('intimidation', 'Intimidation', 'cha', '/api/2014/skills/intimidation');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('investigation', 0, 'When you look around for clues and make deductions based on those clues, you make an Intelligence (Investigation) check. You might deduce the location of a hidden object, discern from the appearance of a wound what kind of weapon dealt it, or determine the weakest point in a tunnel that could cause it to collapse. Poring through ancient scrolls in search of a hidden fragment of knowledge might also call for an Intelligence (Investigation) check.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('investigation', 'Investigation', 'int', '/api/2014/skills/investigation');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('medicine', 0, 'A Wisdom (Medicine) check lets you try to stabilize a dying companion or diagnose an illness.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('medicine', 'Medicine', 'wis', '/api/2014/skills/medicine');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('nature', 0, 'Your Intelligence (Nature) check measures your ability to recall lore about terrain, plants and animals, the weather, and natural cycles.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('nature', 'Nature', 'int', '/api/2014/skills/nature');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('perception', 0, 'Your Wisdom (Perception) check lets you spot, hear, or otherwise detect the presence of something. It measures your general awareness of your surroundings and the keenness of your senses. For example, you might try to hear a conversation through a closed door, eavesdrop under an open window, or hear monsters moving stealthily in the forest. Or you might try to spot things that are obscured or easy to miss, whether they are orcs lying in ambush on a road, thugs hiding in the shadows of an alley, or candlelight under a closed secret door.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('perception', 'Perception', 'wis', '/api/2014/skills/perception');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('performance', 0, 'Your Charisma (Performance) check determines how well you can delight an audience with music, dance, acting, storytelling, or some other form of entertainment.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('performance', 'Performance', 'cha', '/api/2014/skills/performance');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('persuasion', 0, 'When you attempt to influence someone or a group of people with tact, social graces, or good nature, the GM might ask you to make a Charisma (Persuasion) check. Typically, you use persuasion when acting in good faith, to foster friendships, make cordial requests, or exhibit proper etiquette. Examples of persuading others include convincing a chamberlain to let your party see the king, negotiating peace between warring tribes, or inspiring a crowd of townsfolk.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('persuasion', 'Persuasion', 'cha', '/api/2014/skills/persuasion');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('religion', 0, 'Your Intelligence (Religion) check measures your ability to recall lore about deities, rites and prayers, religious hierarchies, holy symbols, and the practices of secret cults.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('religion', 'Religion', 'int', '/api/2014/skills/religion');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('sleight-of-hand', 0, 'Whenever you attempt an act of legerdemain or manual trickery, such as planting something on someone else or concealing an object on your person, make a Dexterity (Sleight of Hand) check. The GM might also call for a Dexterity (Sleight of Hand) check to determine whether you can lift a coin purse off another person or slip something out of another person''s pocket.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('sleight-of-hand', 'Sleight of Hand', 'dex', '/api/2014/skills/sleight-of-hand');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('stealth', 0, 'Make a Dexterity (Stealth) check when you attempt to conceal yourself from enemies, slink past guards, slip away without being noticed, or sneak up on someone without being seen or heard.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('stealth', 'Stealth', 'dex', '/api/2014/skills/stealth');
INSERT INTO skills_desc (skills_index, order_num, "value") VALUES ('survival', 0, 'The GM might ask you to make a Wisdom (Survival) check to follow tracks, hunt wild game, guide your group through frozen wastelands, identify signs that owlbears live nearby, predict the weather, or avoid quicksand and other natural hazards.');
INSERT INTO skills ("index", name, ability_score_index, url) VALUES ('survival', 'Survival', 'wis', '/api/2014/skills/survival');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('acid-arrow', 0, 'A shimmering green arrow streaks toward a target within range and bursts in a spray of acid. Make a ranged spell attack against the target. On a hit, the target takes 4d4 acid damage immediately and 2d4 acid damage at the end of its next turn. On a miss, the arrow splashes the target with acid for half as much of the initial damage and no damage at the end of its next turn.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('acid-arrow', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the damage (both initial and later) increases by 1d4 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('acid-arrow', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('acid-arrow', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('acid-arrow', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('acid-arrow', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('acid-arrow', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('acid-arrow', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('acid-arrow', 'Acid Arrow', '90 feet', 'Powdered rhubarb leaf and an adder''s stomach.', 0, 'Instantaneous', 0, '1 action', 2, 'ranged', 'acid', 'evocation', '/api/2014/spells/acid-arrow');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('acid-splash', 0, 'You hurl a bubble of acid. Choose one creature within range, or choose two creatures within range that are within 5 feet of each other. A target must succeed on a dexterity saving throw or take 1d6 acid damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('acid-splash', 1, 'This spell''s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('acid-splash', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('acid-splash', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('acid-splash', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('acid-splash', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('acid-splash', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('acid-splash', 'Acid Splash', '60 feet', 0, 'Instantaneous', 0, '1 action', 0, 'acid', 'conjuration', '/api/2014/spells/acid-splash', 'dex', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('aid', 0, 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target''s hit point maximum and current hit points increase by 5 for the duration.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('aid', 0, 'When you cast this spell using a spell slot of 3rd level or higher, a target''s hit points increase by an additional 5 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('aid', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('aid', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('aid', 2, 'M');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 2, '5');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 3, '10');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 4, '15');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 5, '20');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 6, '25');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 7, '30');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 8, '35');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('aid', 9, '40');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('aid', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('aid', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('aid', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('aid', 'Aid', '30 feet', 'A tiny strip of white cloth.', 0, '8 hours', 0, '1 action', 2, 'abjuration', '/api/2014/spells/aid');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alarm', 0, 'You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area. When you cast the spell, you can designate creatures that won''t set off the alarm. You also choose whether the alarm is mental or audible.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alarm', 1, 'A mental alarm alerts you with a ping in your mind if you are within 1 mile of the warded area. This ping awakens you if you are sleeping.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alarm', 2, 'An audible alarm produces the sound of a hand bell for 10 seconds within 60 feet.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('alarm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('alarm', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('alarm', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('alarm', 0, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('alarm', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('alarm', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('alarm', 'Alarm', '30 feet', 'A tiny bell and a piece of fine silver wire.', 1, '8 hours', 0, '1 minute', 1, 'abjuration', '/api/2014/spells/alarm', 'cube', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alter-self', 0, 'You assume a different form. When you cast the spell, choose one of the following options, the effects of which last for the duration of the spell. While the spell lasts, you can end one option as an action to gain the benefits of a different one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alter-self', 1, '***Aquatic Adaptation.*** You adapt your body to an aquatic environment, sprouting gills and growing webbing between your fingers. You can breathe underwater and gain a swimming speed equal to your walking speed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alter-self', 2, '***Change Appearance.*** You transform your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and distinguishing characteristics, if any. You can make yourself appear as a member of another race, though none of your statistics change. You also can''t appear as a creature of a different size than you, and your basic shape stays the same; if you''re bipedal, you can''t use this spell to become quadrupedal, for instance. At any time for the duration of the spell, you can use your action to change your appearance in this way again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('alter-self', 3, '***Natural Weapons.*** You grow claws, fangs, spines, horns, or a different natural weapon of your choice. Your unarmed strikes deal 1d6 bludgeoning, piercing, or slashing damage, as appropriate to the natural weapon you chose, and you are proficient with your unarmed strikes. Finally, the natural weapon is magic and you have a +1 bonus to the attack and damage rolls you make using it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('alter-self', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('alter-self', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('alter-self', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('alter-self', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('alter-self', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('alter-self', 'Alter Self', 'Self', 0, 'Up to 1 hour', 1, '1 action', 2, 'transmutation', '/api/2014/spells/alter-self');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-friendship', 0, 'This spell lets you convince a beast that you mean it no harm. Choose a beast that you can see within range. It must see and hear you. If the beast''s Intelligence is 4 or higher, the spell fails. Otherwise, the beast must succeed on a wisdom saving throw or be charmed by you for the spell''s duration. If you or one of your companions harms the target, the spells ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-friendship', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-friendship', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-friendship', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-friendship', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-friendship', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-friendship', 2, 'ranger');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('animal-friendship', 'Animal Friendship', '30 feet', 'A morsel of food.', 0, '24 hours', 0, '1 action', 1, 'enchantment', '/api/2014/spells/animal-friendship', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-messenger', 0, 'By means of this spell, you use an animal to deliver a message. Choose a Tiny beast you can see within range, such as a squirrel, a blue jay, or a bat. You specify a location, which you must have visited, and a recipient who matches a general description, such as "a man or woman dressed in the uniform of the town guard" or "a red-haired dwarf wearing a pointed hat." You also speak a message of up to twenty-five words. The target beast travels for the duration of the spell toward the specified location, covering about 50 miles per 24 hours for a flying messenger, or 25 miles for other animals.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-messenger', 1, 'When the messenger arrives, it delivers your message to the creature that you described, replicating the sound of your voice. The messenger speaks only to a creature matching the description you gave. If the messenger doesn''t reach its destination before the spell ends, the message is lost, and the beast makes its way back to where you cast this spell.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('animal-messenger', 0, 'If you cast this spell using a spell slot of 3nd level or higher, the duration of the spell increases by 48 hours for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-messenger', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-messenger', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-messenger', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-messenger', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-messenger', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-messenger', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('animal-messenger', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('animal-messenger', 'Animal Messenger', '30 feet', 'A morsel of food.', 1, '24 hours', 0, '1 action', 2, 'enchantment', '/api/2014/spells/animal-messenger');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-shapes', 0, 'Your magic turns others into beasts. Choose any number of willing creatures that you can see within range. You transform each target into the form of a Large or smaller beast with a challenge rating of 4 or lower. On subsequent turns, you can use your action to transform affected creatures into new forms.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-shapes', 1, 'The transformation lasts for the duration for each target, or until the target drops to 0 hit points or dies. You can choose a different form for each target. A target''s game statistics are replaced by the statistics of the chosen beast, though the target retains its alignment and Intelligence, Wisdom, and Charisma scores. The target assumes the hit points of its new form, and when it reverts to its normal form, it returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious. The creature is limited in the actions it can perform by the nature of its new form, and it can''t speak or cast spells.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animal-shapes', 2, 'The target''s gear melds into the new form. The target can''t activate, wield, or otherwise benefit from any of its equipment.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-shapes', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animal-shapes', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animal-shapes', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('animal-shapes', 'Animal Shapes', '30 feet', 0, 'Up to 24 hours', 1, '1 action', 8, 'transmutation', '/api/2014/spells/animal-shapes');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-dead', 0, 'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse (the GM has the creature''s game statistics).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-dead', 1, 'On each of your turns, you can use a bonus action to mentally command any creature you made with this spell if the creature is within 60 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-dead', 2, 'The creature is under your control for 24 hours, after which it stops obeying any command you''ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature again before the current 24-hour period ends. This use of the spell reasserts your control over up to four creatures you have animated with this spell, rather than animating a new one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('animate-dead', 0, 'When you cast this spell using a spell slot of 4th level or higher, you animate or reassert control over two additional undead creatures for each slot level above 3rd. Each of the creatures must come from a different corpse or pile of bones.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animate-dead', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animate-dead', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animate-dead', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animate-dead', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animate-dead', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('animate-dead', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('animate-dead', 'Animate Dead', '10 feet', 'A drop of blood, a piece of flesh, and a pinch of bone dust.', 0, 'Instantaneous', 0, '1 minute', 3, 'necromancy', '/api/2014/spells/animate-dead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 0, 'Objects come to life at your command. Choose up to ten nonmagical objects within range that are not being worn or carried. Medium targets count as two objects, Large targets count as four objects, Huge targets count as eight objects. You can''t animate any object larger than Huge. Each target animates and becomes a creature under your control until the spell ends or until reduced to 0 hit points.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 1, 'As a bonus action, you can mentally command any creature you made with this spell if the creature is within 500 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 2, '##### Animated Object Statistics');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 3, '| Size | HP | AC | Attack | Str | Dex |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 4, '|---|---|---|---|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 5, '| Tiny | 20 | 18 | +8 to hit, 1d4 + 4 damage | 4 | 18 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 6, '| Small | 25 | 16 | +6 to hit, 1d8 + 2 damage | 6 | 14 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 7, '| Medium | 40 | 13 | +5 to hit, 2d6 + 1 damage | 10 | 12 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 8, '| Large | 50 | 10 | +6 to hit, 2d10 + 2 damage | 14 | 10 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 9, '| Huge | 80 | 10 | +8 to hit, 2d12 + 4 damage | 18 | 6 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 10, 'An animated object is a construct with AC, hit points, attacks, Strength, and Dexterity determined by its size. Its Constitution is 10 and its Intelligence and Wisdom are 3, and its Charisma is 1. Its speed is 30 feet; if the object lacks legs or other appendages it can use for locomotion, it instead has a flying speed of 30 feet and can hover. If the object is securely attached to a surface or a larger object, such as a chain bolted to a wall, its speed is 0. It has blindsight with a radius of 30 feet and is blind beyond that distance. When the animated object drops to 0 hit points, it reverts to its original object form, and any remaining damage carries over to its original object form.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('animate-objects', 11, 'If you command an object to attack, it can make a single melee attack against a creature within 5 feet of it. It makes a slam attack with an attack bonus and bludgeoning damage determined by its size. The GM might rule that a specific object inflicts slashing or piercing damage based on its form.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('animate-objects', 0, 'If you cast this spell using a spell slot of 6th level or higher, you can animate two additional objects for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animate-objects', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('animate-objects', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animate-objects', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animate-objects', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('animate-objects', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('animate-objects', 'Animate Objects', '120 feet', 0, 'Up to 1 minute', 1, '1 action', 5, 'transmutation', '/api/2014/spells/animate-objects');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antilife-shell', 0, 'A shimmering barrier extends out from you in a 10-foot radius and moves with you, remaining centered on you and hedging out creatures other than undead and constructs. The barrier lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antilife-shell', 1, 'The barrier prevents an affected creature from passing or reaching through. An affected creature can cast spells or make attacks with ranged or reach weapons through the barrier.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antilife-shell', 2, 'If you move so that an affected creature is forced to pass through the barrier, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antilife-shell', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antilife-shell', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('antilife-shell', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('antilife-shell', 'Antilife Shell', 'Self', 0, 'Up to 1 hour', 1, '1 action', 5, 'abjuration', '/api/2014/spells/antilife-shell', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 0, 'A 10-foot-radius invisible sphere of antimagic surrounds you. This area is divorced from the magical energy that suffuses the multiverse. Within the sphere, spells can''t be cast, summoned creatures disappear, and even magic items become mundane. Until the spell ends, the sphere moves with you, centered on you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 1, 'Spells and other magical effects, except those created by an artifact or a deity, are suppressed in the sphere and can''t protrude into it. A slot expended to cast a suppressed spell is consumed. While an effect is suppressed, it doesn''t function, but the time it spends suppressed counts against its duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 2, '***Targeted Effects.*** Spells and other magical effects, such as magic missile and charm person, that target a creature or an object in the sphere have no effect on that target.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 3, '***Areas of Magic.*** The area of another spell or magical effect, such as fireball, can''t extend into the sphere. If the sphere overlaps an area of magic, the part of the area that is covered by the sphere is suppressed. For example, the flames created by a wall of fire are suppressed within the sphere, creating a gap in the wall if the overlap is large enough.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 4, '***Spells.*** Any active spell or other magical effect on a creature or an object in the sphere is suppressed while the creature or object is in it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 5, '***Magic Items.*** The properties and powers of magic items are suppressed in the sphere. For example, a +1 longsword in the sphere functions as a nonmagical longsword.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 6, 'A magic weapon''s properties and powers are suppressed if it is used against a target in the sphere or wielded by an attacker in the sphere. If a magic weapon or a piece of magic ammunition fully leaves the sphere (for example, if you fire a magic arrow or throw a magic spear at a target outside the sphere), the magic of the item ceases to be suppressed as soon as it exits.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 7, '***Magical Travel.*** Teleportation and planar travel fail to work in the sphere, whether the sphere is the destination or the departure point for such magical travel. A portal to another location, world, or plane of existence, as well as an opening to an extradimensional space such as that created by the rope trick spell, temporarily closes while in the sphere.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 8, '***Creatures and Objects.*** A creature or object summoned or created by magic temporarily winks out of existence in the sphere. Such a creature instantly reappears once the space the creature occupied is no longer within the sphere.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antimagic-field', 9, '***Dispel Magic.*** Spells and magical effects such as dispel magic have no effect on the sphere. Likewise, the spheres created by different antimagic field spells don''t nullify each other.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antimagic-field', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antimagic-field', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antimagic-field', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('antimagic-field', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('antimagic-field', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('antimagic-field', 'Antimagic Field', 'Self', 'A pinch of powdered iron or iron filings.', 0, 'Up to 1 hour', 1, '1 action', 8, 'abjuration', '/api/2014/spells/antimagic-field', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 0, 'This spell attracts or repels creatures of your choice. You target something within range, either a Huge or smaller object or creature or an area that is no larger than a 200-foot cube. Then specify a kind of intelligent creature, such as red dragons, goblins, or vampires. You invest the target with an aura that either attracts or repels the specified creatures for the duration. Choose antipathy or sympathy as the aura''s effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 1, '***Antipathy.*** The enchantment causes creatures of the kind you designated to feel an intense urge to leave the area and avoid the target. When such a creature can see the target or comes within 60 feet of it, the creature must succeed on a wisdom saving throw or become frightened. The creature remains frightened while it can see the target or is within 60 feet of it. While frightened by the target, the creature must use its movement to move to the nearest safe spot from which it can''t see the target. If the creature moves more than 60 feet from the target and can''t see it, the creature is no longer frightened, but the creature becomes frightened again if it regains sight of the target or moves within 60 feet of it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 2, '***Sympathy.*** The enchantment causes the specified creatures to feel an intense urge to approach the target while within 60 feet of it or able to see it. When such a creature can see the target or comes within 60 feet of it, the creature must succeed on a wisdom saving throw or use its movement on each of its turns to enter the area or move within reach of the target. When the creature has done so, it can''t willingly move away from the target.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 3, 'If the target damages or otherwise harms an affected creature, the affected creature can make a wisdom saving throw to end the effect, as described below.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 4, '***Ending the Effect.*** If an affected creature ends its turn while not within 60 feet of the target or able to see it, the creature makes a wisdom saving throw. On a successful save, the creature is no longer affected by the target and recognizes the feeling of repugnance or attraction as magical. In addition, a creature affected by the spell is allowed another wisdom saving throw every 24 hours while the spell persists.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 5, 'A creature that successfully saves against this effect is immune to it for 1 minute, after which time it can be affected again.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('antipathy-sympathy', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('antipathy-sympathy', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('antipathy-sympathy', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('antipathy-sympathy', 'Antipathy/Sympathy', '60 feet', 'Either a lump of alum soaked in vinegar for the antipathy effect or a drop of honey for the sympathy effect.', 0, '10 days', 0, '1 hour', 8, 'enchantment', '/api/2014/spells/antipathy-sympathy', 'cube', 200);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-eye', 0, 'You create an invisible, magical eye within range that hovers in the air for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-eye', 1, 'You mentally receive visual information from the eye, which has normal vision and darkvision out to 30 feet. The eye can look in every direction.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-eye', 2, 'As an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can''t enter another plane of existence. A solid barrier blocks the eye''s movement, but the eye can pass through an opening as small as 1 inch in diameter.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-eye', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-eye', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-eye', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-eye', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-eye', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('arcane-eye', 'Arcane Eye', '30 feet', 'A bit of bat fur.', 0, 'Up to 1 hour', 1, '1 action', 4, 'divination', '/api/2014/spells/arcane-eye', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 0, 'You create a Large hand of shimmering, translucent force in an unoccupied space that you can see within range. The hand lasts for the spell''s duration, and it moves at your command, mimicking the movements of your own hand.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 1, 'The hand is an object that has AC 20 and hit points equal to your hit point maximum. If it drops to 0 hit points, the spell ends. It has a Strength of 26 (+8) and a Dexterity of 10 (+0). The hand doesn''t fill its space.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 2, 'When you cast the spell and as a bonus action on your subsequent turns, you can move the hand up to 60 feet and then cause one of the following effects with it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 3, '***Clenched Fist.*** The hand strikes one creature or object within 5 feet of it. Make a melee spell attack for the hand using your game statistics. On a hit, the target takes 4d8 force damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 4, '***Forceful Hand.*** The hand attempts to push a creature within 5 feet of it in a direction you choose. Make a check with the hand''s Strength contested by the Strength (Athletics) check of the target. If the target is Medium or smaller, you have advantage on the check. If you succeed, the hand pushes the target up to 5 feet plus a number of feet equal to five times your spellcasting ability modifier. The hand moves with the target to remain within 5 feet of it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 5, '***Grasping Hand.*** The hand attempts to grapple a Huge or smaller creature within 5 feet of it. You use the hand''s Strength score to resolve the grapple. If the target is Medium or smaller, you have advantage on the check. While the hand is grappling the target, you can use a bonus action to have the hand crush it. When you do so, the target takes bludgeoning damage equal to 2d6 + your spellcasting ability modifier.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-hand', 6, '***Interposing Hand.*** The hand interposes itself between you and a creature you choose until you give the hand a different command. The hand moves to stay between you and the target, providing you with half cover against the target. The target can''t move through the hand''s space if its Strength score is less than or equal to the hand''s Strength score. If its Strength score is higher than the hand''s Strength score, the target can move toward you through the hand''s space, but that space is difficult terrain for the target.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('arcane-hand', 0, 'When you cast this spell using a spell slot of 6th level or higher, the damage from the clenched fist option increases by 2d8 and the damage from the grasping hand increases by 2d6 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-hand', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-hand', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-hand', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-hand', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('arcane-hand', 'Arcane Hand', '120 feet', 'An eggshell and a snakeskin glove.', 0, 'Up to 1 minute', 1, '1 action', 5, 'evocation', '/api/2014/spells/arcane-hand');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-lock', 0, 'You touch a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and the creatures you designate when you cast this spell can open the object normally. You can also set a password that, when spoken within 5 feet of the object, suppresses this spell for 1 minute. Otherwise, it is impassable until it is broken or the spell is dispelled or suppressed. Casting knock on the object suppresses arcane lock for 10 minutes.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-lock', 1, 'While affected by this spell, the object is more difficult to break or force open; the DC to break it or pick any locks on it increases by 10.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-lock', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-lock', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-lock', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-lock', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('arcane-lock', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('arcane-lock', 'Arcane Lock', 'Touch', 'Gold dust worth at least 25gp, which the spell consumes.', 0, 'Until dispelled', 0, '1 action', 2, 'abjuration', '/api/2014/spells/arcane-lock');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-sword', 0, 'You create a sword-shaped plane of force that hovers within range. It lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcane-sword', 1, 'When the sword appears, you make a melee spell attack against a target of your choice within 5 feet of the sword. On a hit, the target takes 3d10 force damage. Until the spell ends, you can use a bonus action on each of your turns to move the sword up to 20 feet to a spot you can see and repeat this attack against the same target or a different one.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-sword', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-sword', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcane-sword', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-sword', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcane-sword', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('arcane-sword', 'Arcane Sword', '60 feet', 'A miniature platinum sword with a grip and pommel of copper and zinc, worth 250 gp.', 0, 'Up to 1 minute', 1, '1 action', 7, 'melee', 'force', 'evocation', '/api/2014/spells/arcane-sword');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 0, 'You place an illusion on a creature or an object you touch so that divination spells reveal false information about it. The target can be a willing creature or an object that isn''t being carried or worn by another creature.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 1, 'When you cast the spell, choose one or both of the following effects. The effect lasts for the duration. If you cast this spell on the same creature or object every day for 30 days, placing the same effect on it each time, the illusion lasts until it is dispelled.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 2, '***False Aura.*** You change the way the target appears to spells and magical effects, such as detect magic, that detect magical auras. You can make a nonmagical object appear magical, a magical object appear nonmagical, or change the object''s magical aura so that it appears to belong to a specific school of magic that you choose. When you use this effect on an object, you can make the false magic apparent to any creature that handles the item.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 3, '***Mask.*** You change the way the target appears to spells and magical effects that detect creature types, such as a paladin''s Divine Sense or the trigger of a symbol spell. You choose a creature type and other spells and magical effects treat the target as if it were a creature of that type or of that alignment.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('arcanists-magic-aura', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('arcanists-magic-aura', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('arcanists-magic-aura', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('arcanists-magic-aura', 'Arcanist''s Magic Aura', 'Touch', 'A small square of silk.', 0, '24 hours', 0, '1 action', 2, 'illusion', '/api/2014/spells/arcanists-magic-aura');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 0, 'You and up to eight willing creatures within range project your astral bodies into the Astral Plane (the spell fails and the casting is wasted if you are already on that plane). The material body you leave behind is unconscious and in a state of suspended animation; it doesn''t need food or air and doesn''t age.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 1, 'Your astral body resembles your mortal form in almost every way, replicating your game statistics and possessions. The principal difference is the addition of a silvery cord that extends from between your shoulder blades and trails behind you, fading to invisibility after 1 foot. This cord is your tether to your material body. As long as the tether remains intact, you can find your way home. If the cord is cut--something that can happen only when an effect specifically states that it does--your soul and body are separated, killing you instantly.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 2, 'Your astral form can freely travel through the Astral Plane and can pass through portals there leading to any other plane. If you enter a new plane or return to the plane you were on when casting this spell, your body and possessions are transported along the silver cord, allowing you to re-enter your body as you enter the new plane. Your astral form is a separate incarnation. Any damage or other effects that apply to it have no effect on your physical body, nor do they persist when you return to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 3, 'The spell ends for you and your companions when you use your action to dismiss it. When the spell ends, the affected creature returns to its physical body, and it awakens.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 4, 'The spell might also end early for you or one of your companions. A successful dispel magic spell used against an astral or physical body ends the spell for that creature. If a creature''s original body or its astral form drops to 0 hit points, the spell ends for that creature. If the spell ends and the silver cord is intact, the cord pulls the creature''s astral form back to its body, ending its state of suspended animation.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('astral-projection', 5, 'If you are returned to your body prematurely, your companions remain in their astral forms and must find their own way back to their bodies, usually by dropping to 0 hit points.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('astral-projection', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('astral-projection', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('astral-projection', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('astral-projection', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('astral-projection', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('astral-projection', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('astral-projection', 'Astral Projection', '10 feet', 'For each creature you affect with this spell, you must provide one jacinth worth at least 1,000gp and one ornately carved bar of silver worth at least 100gp, all of which the spell consumes.', 0, 'Special', 0, '1 hour', 9, 'necromancy', '/api/2014/spells/astral-projection');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 0, 'By casting gem-inlaid sticks, rolling dragon bones, laying out ornate cards, or employing some other divining tool, you receive an omen from an otherworldly entity about the results of a specific course of action that you plan to take within the next 30 minutes. The GM chooses from the following possible omens:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 1, '- Weal, for good results');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 2, '- Woe, for bad results');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 3, '- Weal and woe, for both good and bad results');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 4, '- Nothing, for results that aren''t especially good or bad');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 5, 'The spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('augury', 6, 'If you cast the spell two or more times before completing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('augury', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('augury', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('augury', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('augury', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('augury', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('augury', 'Augury', 'Self', 'Specially marked sticks, bones, or similar tokens worth at least 25gp.', 1, 'Instantaneous', 0, '1 minute', 2, 'divination', '/api/2014/spells/augury');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('awaken', 0, 'After spending the casting time tracing magical pathways within a precious gemstone, you touch a Huge or smaller beast or plant. The target must have either no Intelligence score or an Intelligence of 3 or less. The target gains an Intelligence of 10. The target also gains the ability to speak one language you know. If the target is a plant, it gains the ability to move its limbs, roots, vines, creepers, and so forth, and it gains senses similar to a human''s. Your GM chooses statistics appropriate for the awakened plant, such as the statistics for the awakened shrub or the awakened tree.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('awaken', 1, 'The awakened beast or plant is charmed by you for 30 days or until you or your companions do anything harmful to it. When the charmed condition ends, the awakened creature chooses whether to remain friendly to you, based on how you treated it while it was charmed.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('awaken', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('awaken', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('awaken', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('awaken', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('awaken', 1, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('awaken', 'Awaken', 'Touch', 'An agate worth at least 1,000 gp, which the spell consumes.', 0, 'Instantaneous', 0, '8 hours', 5, 'transmutation', '/api/2014/spells/awaken');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bane', 0, 'Up to three creatures of your choice that you can see within range must make charisma saving throws. Whenever a target that fails this saving throw makes an attack roll or a saving throw before the spell ends, the target must roll a d4 and subtract the number rolled from the attack roll or saving throw.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('bane', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bane', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bane', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bane', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bane', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bane', 1, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('bane', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('bane', 'Bane', '30 feet', 'A drop of blood.', 0, 'Up to 1 minute', 1, '1 action', 1, 'enchantment', '/api/2014/spells/bane', 'cha', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('banishment', 0, 'You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a charisma saving throw or be banished.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('banishment', 1, 'If the target is native to the plane of existence you''re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('banishment', 2, 'If the target is native to a different plane of existence than the one you''re on, the target is banished with a faint popping noise, returning to its home plane. If the spell ends before 1 minute has passed, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied. Otherwise, the target doesn''t return.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('banishment', 0, 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('banishment', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('banishment', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('banishment', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('banishment', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('banishment', 1, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('banishment', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('banishment', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('banishment', 4, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('banishment', 'Banishment', '60 feet', 'An item distasteful to the target.', 0, 'Up to 1 minute', 1, '1 action', 4, 'abjuration', '/api/2014/spells/banishment', 'cha', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('barkskin', 0, 'You touch a willing creature. Until the spell ends, the target''s skin has a rough, bark-like appearance, and the target''s AC can''t be less than 16, regardless of what kind of armor it is wearing.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('barkskin', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('barkskin', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('barkskin', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('barkskin', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('barkskin', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('barkskin', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('barkskin', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('barkskin', 'Barkskin', 'Touch', 'A handful of oak bark.', 0, 'Up to 1 hour', 1, '1 action', 2, 'transmutation', '/api/2014/spells/barkskin');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('beacon-of-hope', 0, 'This spell bestows hope and vitality. Choose any number of creatures within range. For the duration, each target has advantage on wisdom saving throws and death saving throws, and regains the maximum number of hit points possible from any healing.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('beacon-of-hope', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('beacon-of-hope', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('beacon-of-hope', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('beacon-of-hope', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('beacon-of-hope', 1, 'life');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('beacon-of-hope', 2, 'devotion');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('beacon-of-hope', 'Beacon of Hope', '30 feet', 0, 'Up to 1 minute', 1, '1 action', 3, 'abjuration', '/api/2014/spells/beacon-of-hope');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 0, 'You touch a creature, and that creature must succeed on a wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 1, '- Choose one ability score. While cursed, the target has disadvantage on ability checks and saving throws made with that ability score.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 2, '- While cursed, the target has disadvantage on attack rolls against you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 3, '- While cursed, the target must make a wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 4, '- While the target is cursed, your attacks and spells deal an extra 1d8 necrotic damage to the target.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bestow-curse', 5, 'A remove curse spell ends this effect. At the GM''s option, you may choose an alternative curse effect, but it should be no more powerful than those described above. The GM has final say on such a curse''s effect.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('bestow-curse', 0, 'If you cast this spell using a spell slot of 4th level or higher, the duration is concentration, up to 10 minutes. If you use a spell slot of 5th level or higher, the duration is 8 hours. If you use a spell slot of 7th level or higher, the duration is 24 hours. If you use a 9th level spell slot, the spell lasts until it is dispelled. Using a spell slot of 5th level or higher grants a duration that doesn''t require concentration.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bestow-curse', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bestow-curse', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bestow-curse', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bestow-curse', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bestow-curse', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('bestow-curse', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('bestow-curse', 'Bestow Curse', 'Touch', 0, 'Up to 1 minute', 1, '1 action', 3, 'necromancy', '/api/2014/spells/bestow-curse', 'wis', 'none', 'On fail, become cursed for the duration of the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('black-tentacles', 0, 'Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('black-tentacles', 1, 'When a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends. A creature that starts its turn in the area and is already restrained by the tentacles takes 3d6 bludgeoning damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('black-tentacles', 2, 'A creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('black-tentacles', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('black-tentacles', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('black-tentacles', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('black-tentacles', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('black-tentacles', 'Black Tentacles', '90 feet', 'A piece of tentacle from a giant octopus or a giant squid', 0, 'Up to 1 minute', 1, '1 action', 4, 'bludgeoning', 'conjuration', '/api/2014/spells/black-tentacles', 'dex', 'none', 'cube', 20, 'A creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blade-barrier', 0, 'You create a vertical wall of whirling, razor-sharp blades made of magical energy. The wall appears within range and lasts for the duration. You can make a straight wall up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter, 20 feet high, and 5 feet thick. The wall provides three-quarters cover to creatures behind it, and its space is difficult terrain.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blade-barrier', 1, 'When a creature enters the wall''s area for the first time on a turn or starts its turn there, the creature must make a dexterity saving throw. On a failed save, the creature takes 6d10 slashing damage. On a successful save, the creature takes half as much damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blade-barrier', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blade-barrier', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blade-barrier', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('blade-barrier', 'Blade Barrier', '90 feet', 0, 'Up to 10 minutes', 1, '1 action', 6, 'slashing', 'evocation', '/api/2014/spells/blade-barrier', 'dex', 'half', 'line', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('bless', 0, 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('bless', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bless', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bless', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('bless', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bless', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('bless', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('bless', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('bless', 1, 'life');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('bless', 'Bless', '30 feet', 'A sprinkling of holy water.', 0, 'Up to 1 minute', 1, '1 action', 1, 'enchantment', '/api/2014/spells/bless');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blight', 0, 'Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a constitution saving throw. The target takes 8d8 necrotic damage on a failed save, or half as much damage on a successful one. The spell has no effect on undead or constructs.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blight', 1, 'If you target a plant creature or a magical plant, it makes the saving throw with disadvantage, and the spell deals maximum damage to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blight', 2, 'If you target a nonmagical plant that isn''t a creature, such as a tree or shrub, it doesn''t make a saving throw; it simply withers and dies.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('blight', 0, 'When you cast this spell using a spell slot of 5th level of higher, the damage increases by 1d8 for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blight', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blight', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blight', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blight', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blight', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blight', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blight', 0, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('blight', 'Blight', '30 feet', 0, 'Instantaneous', 0, '1 action', 4, 'necrotic', 'necromancy', '/api/2014/spells/blight', 'con', 'half');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blindness-deafness', 0, 'You can blind or deafen a foe. Choose one creature that you can see within range to make a constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a constitution saving throw. On a success, the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('blindness-deafness', 0, 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blindness-deafness', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blindness-deafness', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blindness-deafness', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blindness-deafness', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blindness-deafness', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blindness-deafness', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blindness-deafness', 1, 'fiend');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('blindness-deafness', 'Blindness/Deafness', '30 feet', 0, '1 minute', 0, '1 action', 2, 'necromancy', '/api/2014/spells/blindness-deafness', 'con', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blink', 0, 'Roll a d20 at the end of each of your turns for the duration of the spell. On a roll of 11 or higher, you vanish from your current plane of existence and appear in the Ethereal Plane (the spell fails and the casting is wasted if you were already on that plane). At the start of your next turn, and when the spell ends if you are on the Ethereal Plane, you return to an unoccupied space of your choice that you can see within 10 feet of the space you vanished from. If no unoccupied space is available within that range, you appear in the nearest unoccupied space (chosen at random if more than one space is equally near). You can dismiss this spell as an action.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blink', 1, 'While on the Ethereal Plane, you can see and hear the plane you originated from, which is cast in shades of gray, and you can''t see anything there more than 60 feet away. You can only affect and be affected by other creatures on the Ethereal Plane. Creatures that aren''t there can''t perceive you or interact with you, unless they have the ability to do so.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blink', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blink', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blink', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blink', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blink', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('blink', 'Blink', 'Self', 0, '1 minute', 0, '1 action', 3, 'transmutation', '/api/2014/spells/blink');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('blur', 0, 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn''t rely on sight, as with blindsight, or can see through illusions, as with truesight.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('blur', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blur', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('blur', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blur', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('blur', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('blur', 'Blur', 'Self', 0, 'Up to 1 minute', 1, '1 action', 2, 'illusion', '/api/2014/spells/blur');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('branding-smite', 0, 'The next time you hit a creature with a weapon attack before this spell ends, the weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target, which becomes visible if it''s invisible, and the target sheds dim light in a 5-foot radius and can''t become invisible until the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('branding-smite', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the extra damage increases by 1d6 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('branding-smite', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('branding-smite', 0, 'paladin');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('branding-smite', 'Branding Smite', 'Self', 0, 'Up to 1 minute', 1, '1 bonus action', 2, 'radiant', 'evocation', '/api/2014/spells/branding-smite');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('burning-hands', 0, 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('burning-hands', 1, 'The fire ignites any flammable objects in the area that aren''t being worn or carried.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('burning-hands', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('burning-hands', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('burning-hands', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('burning-hands', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('burning-hands', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('burning-hands', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('burning-hands', 1, 'fiend');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('burning-hands', 'Burning Hands', 'Self', 0, 'Instantaneous', 0, '1 action', 1, 'fire', 'evocation', '/api/2014/spells/burning-hands', 'dex', 'half', 'cone', 15);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('call-lightning', 0, 'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can''t see a point in the air where the storm cloud could appear (for example, if you are in a room that can''t accommodate the cloud).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('call-lightning', 1, 'When you cast the spell, choose a point you can see within range. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one. On each of your turns until the spell ends, you can use your action to call down lightning in this way again, targeting the same point or a different one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('call-lightning', 2, 'If you are outdoors in stormy conditions when you cast this spell, the spell gives you control over the existing storm instead of creating a new one. Under such conditions, the spell''s damage increases by 1d10.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('call-lightning', 0, 'When you cast this spell using a spell slot of 4th or higher level, the damage increases by 1d10 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('call-lightning', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('call-lightning', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('call-lightning', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('call-lightning', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('call-lightning', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('call-lightning', 'Call Lightning', '120 feet', 0, 'Up to 10 minutes', 1, '1 action', 3, 'lightning', 'conjuration', '/api/2014/spells/call-lightning', 'sphere', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('calm-emotions', 0, 'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a charisma saving throw; a creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of the following two effects. You can suppress any effect causing a target to be charmed or frightened. When this spell ends, any suppressed effect resumes, provided that its duration has not expired in the meantime.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('calm-emotions', 1, 'Alternatively, you can make a target indifferent about creatures of your choice that it is hostile toward. This indifference ends if the target is attacked or harmed by a spell or if it witnesses any of its friends being harmed. When the spell ends, the creature becomes hostile again, unless the GM rules otherwise.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('calm-emotions', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('calm-emotions', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('calm-emotions', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('calm-emotions', 1, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('calm-emotions', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('calm-emotions', 'Calm Emotions', '60 feet', 0, 'Up to 1 minute', 1, '1 action', 2, 'enchantment', '/api/2014/spells/calm-emotions', 'cha', 'none', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('chain-lightning', 0, 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('chain-lightning', 1, 'A target must make a dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('chain-lightning', 0, 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('chain-lightning', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('chain-lightning', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('chain-lightning', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('chain-lightning', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('chain-lightning', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('chain-lightning', 'Chain Lightning', '150 feet', 'A bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins.', 0, 'Instantaneous', 0, '1 action', 6, 'lightning', 'evocation', '/api/2014/spells/chain-lightning', 'dex', 'half');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('charm-person', 0, 'You attempt to charm a humanoid you can see within range. It must make a wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('charm-person', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('charm-person', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('charm-person', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('charm-person', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('charm-person', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('charm-person', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('charm-person', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('charm-person', 4, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('charm-person', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('charm-person', 'Charm Person', '30 feet', 0, '1 hour', 0, '1 action', 1, 'enchantment', '/api/2014/spells/charm-person', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('chill-touch', 0, 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can''t regain hit points until the start of your next turn. Until then, the hand clings to the target.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('chill-touch', 1, 'If you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('chill-touch', 2, 'This spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('chill-touch', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('chill-touch', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('chill-touch', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('chill-touch', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('chill-touch', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('chill-touch', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('chill-touch', 'Chill Touch', '120 feet', 0, '1 round', 0, '1 action', 0, 'ranged', 'necrotic', 'necromancy', '/api/2014/spells/chill-touch');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('circle-of-death', 0, 'A sphere of negative energy ripples out in a 60-foot radius sphere from a point within range. Each creature in that area must make a constitution saving throw. A target takes 8d6 necrotic damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('circle-of-death', 0, 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d6 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('circle-of-death', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('circle-of-death', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('circle-of-death', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('circle-of-death', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('circle-of-death', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('circle-of-death', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('circle-of-death', 'Circle of Death', '150 feet', 'The powder of a crushed black pearl worth at least 500 gp.', 0, 'Instantaneous', 0, '1 action', 6, 'necrotic', 'necromancy', '/api/2014/spells/circle-of-death', 'con', 'half', 'sphere', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('clairvoyance', 0, 'You create an invisible sensor within range in a location familiar to you (a place you have visited or seen before) or in an obvious location that is unfamiliar to you (such as behind a door, around a corner, or in a grove of trees). The sensor remains in place for the duration, and it can''t be attacked or otherwise interacted with.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('clairvoyance', 1, 'When you cast the spell, you choose seeing or hearing. You can use the chosen sense through the sensor as if you were in its space. As your action, you can switch between seeing and hearing.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('clairvoyance', 2, 'A creature that can see the sensor (such as a creature benefiting from see invisibility or truesight) sees a luminous, intangible orb about the size of your fist.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clairvoyance', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clairvoyance', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clairvoyance', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('clairvoyance', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('clairvoyance', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('clairvoyance', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('clairvoyance', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('clairvoyance', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('clairvoyance', 'Clairvoyance', '1 mile', 'A focus worth at least 100gp, either a jeweled horn for hearing or a glass eye for seeing.', 0, 'Up to 10 minutes', 1, '10 minutes', 3, 'divination', '/api/2014/spells/clairvoyance');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('clone', 0, 'This spell grows an inert duplicate of a living creature as a safeguard against death. This clone forms inside a sealed vessel and grows to full size and maturity after 120 days; you can also choose to have the clone be a younger version of the same creature. It remains inert and endures indefinitely, as long as its vessel remains undisturbed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('clone', 1, 'At any time after the clone matures, if the original creature dies, its soul transfers to the clone, provided that the soul is free and willing to return. The clone is physically identical to the original and has the same personality, memories, and abilities, but none of the original''s equipment. The original creature''s physical remains, if they still exist, become inert and can''t thereafter be restored to life, since the creature''s soul is elsewhere.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clone', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clone', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('clone', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('clone', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('clone', 'Clone', 'Touch', 'A diamond worth at least 1,000 gp and at least 1 cubic inch of flesh of the creature that is to be cloned, which the spell consumes, and a vessel worth at least 2,000 gp that has a sealable lid and is large enough to hold a Medium creature, such as a huge urn, coffin, mud-filled cyst in the ground, or crystal container filled with salt water.', 0, 'Instantaneous', 0, '1 hour', 8, 'necromancy', '/api/2014/spells/clone');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cloudkill', 0, 'You create a 20-foot-radius sphere of poisonous, yellow-green fog centered on a point you choose within range. The fog spreads around corners. It lasts for the duration or until strong wind disperses the fog, ending the spell. Its area is heavily obscured.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cloudkill', 1, 'When a creature enters the spell''s area for the first time on a turn or starts its turn there, that creature must make a constitution saving throw. The creature takes 5d8 poison damage on a failed save, or half as much damage on a successful one. Creatures are affected even if they hold their breath or don''t need to breathe.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cloudkill', 2, 'The fog moves 10 feet away from you at the start of each of your turns, rolling along the surface of the ground. The vapors, being heavier than air, sink to the lowest level of the land, even pouring down openings.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('cloudkill', 0, 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('cloudkill', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('cloudkill', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('cloudkill', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('cloudkill', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('cloudkill', 0, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('cloudkill', 'Cloudkill', '120 feet', 0, 'Up to 10 minutes', 1, '1 action', 5, 'poison', 'conjuration', '/api/2014/spells/cloudkill', 'con', 'half', 'sphere', 20, 'Creatures are affected even if they hold their breath or don''t need to breathe.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('color-spray', 0, 'A dazzling array of flashing, colored light springs from your hand. Roll 6d10; the total is how many hit points of creatures this spell can effect. Creatures in a 15-foot cone originating from you are affected in ascending order of their current hit points (ignoring unconscious creatures and creatures that can''t see).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('color-spray', 1, 'Starting with the creature that has the lowest current hit points, each creature affected by this spell is blinded until the spell ends. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('color-spray', 0, 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d10 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('color-spray', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('color-spray', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('color-spray', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('color-spray', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('color-spray', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('color-spray', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('color-spray', 'Color Spray', 'Self', 'A pinch of powder or sand that is colored red, yellow, and blue.', 0, '1 round', 0, '1 action', 1, 'illusion', '/api/2014/spells/color-spray', 'cone', 15);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 0, 'You speak a one-word command to a creature you can see within range. The target must succeed on a wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn''t understand your language, or if your command is directly harmful to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 1, 'Some typical commands and their effects follow. You might issue a command other than one described here. If you do so, the GM determines how the target behaves. If the target can''t follow your command, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 2, '***Approach.*** The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 3, '***Drop.*** The target drops whatever it is holding and then ends its turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 4, '***Flee.*** The target spends its turn moving away from you by the fastest available means.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 5, '***Grovel.*** The target falls prone and then ends its turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('command', 6, '***Halt.*** The target doesn''t move and takes no actions. A flying creature stays aloft, provided that it is able to do so. If it must move to stay aloft, it flies the minimum distance needed to remain in the air.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('command', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('command', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('command', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('command', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('command', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('command', 1, 'fiend');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('command', 'Command', '60 feet', 0, '1 round', 0, '1 action', 1, 'enchantment', '/api/2014/spells/command', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune', 0, 'You contact your deity or a divine proxy and ask up to three questions that can be answered with a yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune', 1, 'Divine beings aren''t necessarily omniscient, so you might receive "unclear" as an answer if a question pertains to information that lies beyond the deity''s knowledge. In a case where a one-word answer could be misleading or contrary to the deity''s interests, the GM might offer a short phrase as an answer instead.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune', 2, 'If you cast the spell two or more times before finishing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer. The GM makes this roll in secret.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('commune', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('commune', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('commune', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('commune', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('commune', 0, 'devotion');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('commune', 'Commune', 'Self', 'Incense and a vial of holy or unholy water.', 1, '1 minute', 0, '1 minute', 5, 'divination', '/api/2014/spells/commune');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 0, 'You briefly become one with nature and gain knowledge of the surrounding territory. In the outdoors, the spell gives you knowledge of the land within 3 miles of you. In caves and other natural underground settings, the radius is limited to 300 feet. The spell doesn''t function where nature has been replaced by construction, such as in dungeons and towns.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 1, 'You instantly gain knowledge of up to three facts of your choice about any of the following subjects as they relate to the area:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 2, '- terrain and bodies of water');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 3, '- prevalent plants, minerals, animals, or peoples');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 4, '- powerful celestials, fey, fiends, elementals, or undead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 5, '- influence from other planes of existence');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 6, '- buildings');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('commune-with-nature', 7, 'For example, you could determine the location of powerful undead in the area, the location of major sources of safe drinking water, and the location of any nearby towns.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('commune-with-nature', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('commune-with-nature', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('commune-with-nature', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('commune-with-nature', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('commune-with-nature', 0, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('commune-with-nature', 'Commune With Nature', 'Self', 1, 'Instantaneous', 0, '1 minute', 5, 'divination', '/api/2014/spells/commune-with-nature');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('comprehend-languages', 0, 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('comprehend-languages', 1, 'This spell doesn''t decode secret messages in a text or a glyph, such as an arcane sigil, that isn''t part of a written language.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('comprehend-languages', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('comprehend-languages', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('comprehend-languages', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('comprehend-languages', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('comprehend-languages', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('comprehend-languages', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('comprehend-languages', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('comprehend-languages', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('comprehend-languages', 'Comprehend Languages', 'Self', 'A pinch of soot and salt.', 1, '1 hour', 0, '1 action', 1, 'divination', '/api/2014/spells/comprehend-languages');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('compulsion', 0, 'Creatures of your choice that you can see within range and that can hear you must make a wisdom saving throw. A target automatically succeeds on this saving throw if it can''t be charmed. On a failed save, a target is affected by this spell. Until the spell ends, you can use a bonus action on each of your turns to designate a direction that is horizontal to you. Each affected target must use as much of its movement as possible to move in that direction on its next turn. It can take any action before it moves. After moving in this way, it can make another Wisdom save to try to end the effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('compulsion', 1, 'A target isn''t compelled to move into an obviously deadly hazard, such as a fire or a pit, but it will provoke opportunity attacks to move in the designated direction.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('compulsion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('compulsion', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('compulsion', 0, 'bard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('compulsion', 'Compulsion', '30 feet', 0, 'Up to 1 minute', 1, '1 action', 4, 'enchantment', '/api/2014/spells/compulsion', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cone-of-cold', 0, 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cone-of-cold', 1, 'A creature killed by this spell becomes a frozen statue until it thaws.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('cone-of-cold', 0, 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('cone-of-cold', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('cone-of-cold', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('cone-of-cold', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('cone-of-cold', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('cone-of-cold', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('cone-of-cold', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('cone-of-cold', 'Cone of Cold', 'Self', 'A small crystal or glass cone.', 0, 'Instantaneous', 0, '1 action', 5, 'cold', 'evocation', '/api/2014/spells/cone-of-cold', 'con', 'half', 'cone', 60, 'A creature killed by this spell becomes a frozen statue until it thaws.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 0, 'This spell assaults and twists creatures'' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a Wisdom saving throw when you cast this spell or be affected by it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 1, 'An affected target can''t take reactions and must roll a d10 at the start of each of its turns to determine its behavior for that turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 2, '| d10 | Behavior |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 3, '|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 4, '| 1 | The creature uses all its movement to move in a random direction. To determine the direction, roll a d8 and assign a direction to each die face. The creature doesn''t take an action this turn. |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 5, '| 2-6 | The creature doesn''t move or take actions this turn. |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 6, '| 7-8 | The creature uses its action to make a melee attack against a randomly determined creature within its reach. If there is no creature within its reach, the creature does nothing this turn. |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 7, '| 9-10 | The creature can act and move normally. |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('confusion', 8, 'At the end of each of its turns, an affected target can make a Wisdom saving throw. If it succeeds, this effect ends for that target.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('confusion', 0, 'When you cast this spell using a spell slot of 5th level or higher, the radius of the sphere increases by 5 feet for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('confusion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('confusion', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('confusion', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('confusion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('confusion', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('confusion', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('confusion', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('confusion', 'Confusion', '90 feet', 'Three walnut shells.', 0, 'Up to 1 minute', 1, '1 action', 4, 'enchantment', '/api/2014/spells/confusion', 'wis', 'none', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 0, 'You summon fey spirits that take the form of beasts and appear in unoccupied spaces that you can see within range. Choose one of the following options for what appears:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 1, '- One beast of challenge rating 2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 2, '- Two beasts of challenge rating 1 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 3, '- Four beasts of challenge rating 1/2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 4, '- Eight beasts of challenge rating 1/4 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 5, '- Each beast is also considered fey, and it disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 6, 'The summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-animals', 7, 'The GM has the creatures'' statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-animals', 0, 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 5th-level slot, three times as many with a 7th-level.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-animals', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-animals', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-animals', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-animals', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('conjure-animals', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('conjure-animals', 'Conjure Animals', '60 feet', 0, 'Up to 1 hour', 1, '1 action', 3, 'conjuration', '/api/2014/spells/conjure-animals');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-celestial', 0, 'You summon a celestial of challenge rating 4 or lower, which appears in an unoccupied space that you can see within range. The celestial disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-celestial', 1, 'The celestial is friendly to you and your companions for the duration. Roll initiative for the celestial, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you), as long as they don''t violate its alignment. If you don''t issue any commands to the celestial, it defends itself from hostile creatures but otherwise takes no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-celestial', 2, 'The GM has the celestial''s statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-celestial', 0, 'When you cast this spell using a 9th-level spell slot, you summon a celestial of challenge rating 5 or lower.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-celestial', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-celestial', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-celestial', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('conjure-celestial', 'Conjure Celestial', '90 feet', 0, 'Up to 1 hour', 1, '1 minute', 7, 'conjuration', '/api/2014/spells/conjure-celestial');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-elemental', 0, 'You call forth an elemental servant. Choose an area of air, earth, fire, or water that fills a 10-foot cube within range. An elemental of challenge rating 5 or lower appropriate to the area you chose appears in an unoccupied space within 10 feet of it. For example, a fire elemental emerges from a bonfire, and an earth elemental rises up from the ground. The elemental disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-elemental', 1, 'The elemental is friendly to you and your companions for the duration. Roll initiative for the elemental, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you). If you don''t issue any commands to the elemental, it defends itself from hostile creatures but otherwise takes no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-elemental', 2, 'If your concentration is broken, the elemental doesn''t disappear. Instead, you lose control of the elemental, it becomes hostile toward you and your companions, and it might attack. An uncontrolled elemental can''t be dismissed by you, and it disappears 1 hour after you summoned it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-elemental', 3, 'The GM has the elemental''s statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-elemental', 0, 'When you cast this spell using a spell slot of 6th level or higher, the challenge rating increases by 1 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-elemental', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-elemental', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-elemental', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-elemental', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-elemental', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('conjure-elemental', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('conjure-elemental', 'Conjure Elemental', '90 feet', 'Burning incense for air, soft clay for earth, sulfur and phosphorus for fire, or water and sand for water.', 0, 'Up to 1 hour', 1, '1 minute', 5, 'conjuration', '/api/2014/spells/conjure-elemental', 'cube', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-fey', 0, 'You summon a fey creature of challenge rating 6 or lower, or a fey spirit that takes the form of a beast of challenge rating 6 or lower. It appears in an unoccupied space that you can see within range. The fey creature disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-fey', 1, 'The fey creature is friendly to you and your companions for the duration. Roll initiative for the creature, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you), as long as they don''t violate its alignment. If you don''t issue any commands to the fey creature, it defends itself from hostile creatures but otherwise takes no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-fey', 2, 'If your concentration is broken, the fey creature doesn''t disappear. Instead, you lose control of the fey creature, it becomes hostile toward you and your companions, and it might attack. An uncontrolled fey creature can''t be dismissed by you, and it disappears 1 hour after you summoned it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-fey', 3, 'The GM has the fey creature''s statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-fey', 0, 'When you cast this spell using a spell slot of 7th level or higher, the challenge rating increases by 1 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-fey', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-fey', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-fey', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-fey', 1, 'warlock');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('conjure-fey', 'Conjure Fey', '90 feet', 0, 'Up to 1 hour', 1, '1 minute', 6, 'conjuration', '/api/2014/spells/conjure-fey');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 0, 'You summon elementals that appear in unoccupied spaces that you can see within range. You choose one the following options for what appears:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 1, '- One elemental of challenge rating 2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 2, '- Two elementals of challenge rating 1 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 3, '- Four elementals of challenge rating 1/2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 4, '- Eight elementals of challenge rating 1/4 or lower.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 5, 'An elemental summoned by this spell disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 6, 'The summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 7, 'The GM has the creatures'' statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 0, 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 6th-level slot and three times as many with an 8th-level slot.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-minor-elementals', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-minor-elementals', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-minor-elementals', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('conjure-minor-elementals', 'Conjure Minor Elementals', '90 feet', 0, 'Up to 1 hour', 1, '1 minute', 4, 'conjuration', '/api/2014/spells/conjure-minor-elementals');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 0, 'You summon fey creatures that appear in unoccupied spaces that you can see within range. Choose one of the following options for what appears:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 1, '- One fey creature of challenge rating 2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 2, '- Two fey creatures of challenge rating 1 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 3, '- Four fey creatures of challenge rating 1/2 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 4, '- Eight fey creatures of challenge rating 1/4 or lower');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 5, 'A summoned creature disappears when it drops to 0 hit points or when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 6, 'The summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which have their own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 7, 'The GM has the creatures'' statistics.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 0, 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 6th-level slot and three times as many with an 8th-level slot.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('conjure-woodland-beings', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-woodland-beings', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('conjure-woodland-beings', 1, 'ranger');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('conjure-woodland-beings', 'Conjure Woodland Beings', '60 feet', 'One holly berry per creature summoned.', 0, 'Up to 1 hour', 1, '1 action', 4, 'conjuration', '/api/2014/spells/conjure-woodland-beings');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contact-other-plane', 0, 'You mentally contact a demigod, the spirit of a long-dead sage, or some other mysterious entity from another plane. Contacting this extraplanar intelligence can strain or even break your mind. When you cast this spell, make a DC 15 intelligence saving throw. On a failure, you take 6d6 psychic damage and are insane until you finish a long rest. While insane, you can''t take actions, can''t understand what other creatures say, can''t read, and speak only in gibberish. A greater restoration spell cast on you ends this effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contact-other-plane', 1, 'On a successful save, you can ask the entity up to five questions. You must ask your questions before the spell ends. The GM answers each question with one word, such as "yes," "no," "maybe," "never," "irrelevant," or "unclear" (if the entity doesn''t know the answer to the question). If a one-word answer would be misleading, the GM might instead offer a short phrase as an answer.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contact-other-plane', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('contact-other-plane', 0, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('contact-other-plane', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('contact-other-plane', 'Contact Other Plane', 'Self', 1, '1 minute', 0, '1 minute', 5, 'divination', '/api/2014/spells/contact-other-plane', 'int', 'other', 'On a failure, you take 6d6 psychic damage and are insane until you finish a long rest.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 0, 'Your touch inflicts disease. Make a melee spell attack against a creature within your reach. On a hit, you afflict the creature with a disease of your choice from any of the ones described below.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 1, 'At the end of each of the target''s turns, it must make a constitution saving throw. After failing three of these saving throws, the disease''s effects last for the duration, and the creature stops making these saves. After succeeding on three of these saving throws, the creature recovers from the disease, and the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 2, 'Since this spell induces a natural disease in its target, any effect that removes a disease or otherwise ameliorates a disease''s effects apply to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 3, '***Blinding Sickness.*** Pain grips the creature''s mind, and its eyes turn milky white. The creature has disadvantage on wisdom checks and wisdom saving throws and is blinded.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 4, '***Filth Fever.*** A raging fever sweeps through the creature''s body. The creature has disadvantage on strength checks, strength saving throws, and attack rolls that use Strength.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 5, '***Flesh Rot.*** The creature''s flesh decays. The creature has disadvantage on Charisma checks and vulnerability to all damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 6, '***Mindfire.*** The creature''s mind becomes feverish. The creature has disadvantage on intelligence checks and intelligence saving throws, and the creature behaves as if under the effects of the confusion spell during combat.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 7, '***Seizure.*** The creature is overcome with shaking. The creature has disadvantage on dexterity checks, dexterity saving throws, and attack rolls that use Dexterity.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contagion', 8, '***Slimy Doom.*** The creature begins to bleed uncontrollably. The creature has disadvantage on constitution checks and constitution saving throws. In addition, whenever the creature takes damage, it is stunned until the end of its next turn.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contagion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contagion', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('contagion', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('contagion', 1, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('contagion', 'Contagion', 'Touch', 0, '7 days', 0, '1 action', 5, 'melee', 'necromancy', '/api/2014/spells/contagion', 'con', 'other', 'After succeeding on three of these saving throws, the creature recovers from the disease, and the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contingency', 0, 'Choose a spell of 5th level or lower that you can cast, that has a casting time of 1 action, and that can target you. You cast that spell--called the contingent spell--as part of casting contingency, expending spell slots for both, but the contingent spell doesn''t come into effect. Instead, it takes effect when a certain circumstance occurs. You describe that circumstance when you cast the two spells. For example, a contingency cast with water breathing might stipulate that water breathing comes into effect when you are engulfed in water or a similar liquid.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contingency', 1, 'The contingent spell takes effect immediately after the circumstance is met for the first time, whether or not you want it to. and then contingency ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('contingency', 2, 'The contingent spell takes effect only on you, even if it can normally target others. You can use only one contingency spell at a time. If you cast this spell again, the effect of another contingency spell on you ends. Also, contingency ends on you if its material component is ever not on your person.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contingency', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contingency', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('contingency', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('contingency', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('contingency', 'Contingency', 'Self', 'A statuette of yourself carved from ivory and decorated with gems worth at least 1,500 gp.', 0, '10 days', 0, '10 minutes', 6, 'evocation', '/api/2014/spells/contingency');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('continual-flame', 0, 'A flame, equivalent in brightness to a torch, springs forth from an object that you touch. The effect looks like a regular flame, but it creates no heat and doesn''t use oxygen. A continual flame can be covered or hidden but not smothered or quenched.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('continual-flame', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('continual-flame', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('continual-flame', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('continual-flame', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('continual-flame', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('continual-flame', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('continual-flame', 'Continual Flame', 'Touch', 'Ruby dust worth 50 gp, which the spell consumes.', 0, 'Until dispelled', 0, '1 action', 2, 'evocation', '/api/2014/spells/continual-flame');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 0, 'Until the spell ends, you control any freestanding water inside an area you choose that is a cube up to 100 feet on a side. You can choose from any of the following effects when you cast this spell. As an action on your turn, you can repeat the same effect or choose a different one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 1, '***Flood.*** You cause the water level of all standing water in the area to rise by as much as 20 feet. If the area includes a shore, the flooding water spills over onto dry land.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 2, 'If you choose an area in a large body of water, you instead create a 20-foot tall wave that travels from one side of the area to the other and then crashes down. Any Huge or smaller vehicles in the wave''s path are carried with it to the other side. Any Huge or smaller vehicles struck by the wave have a 25 percent chance of capsizing.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 3, 'The water level remains elevated until the spell ends or you choose a different effect. If this effect produced a wave, the wave repeats on the start of your next turn while the flood effect lasts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 4, '***Part Water.*** You cause water in the area to move apart and create a trench. The trench extends across the spell''s area, and the separated water forms a wall to either side. The trench remains until the spell ends or you choose a different effect. The water then slowly fills in the trench over the course of the next round until the normal water level is restored.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 5, '***Redirect Flow.*** You cause flowing water in the area to move in a direction you choose, even if the water has to flow over obstacles, up walls, or in other unlikely directions. The water in the area moves as you direct it, but once it moves beyond the spell''s area, it resumes its flow based on the terrain conditions. The water continues to move in the direction you chose until the spell ends or you choose a different effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 6, '***Whirlpool.*** This effect requires a body of water at least 50 feet square and 25 feet deep. You cause a whirlpool to form in the center of the area. The whirlpool forms a vortex that is 5 feet wide at the base, up to 50 feet wide at the top, and 25 feet tall. Any creature or object in the water and within 25 feet of the vortex is pulled 10 feet toward it. A creature can swim away from the vortex by making a Strength (Athletics) check against your spell save DC.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 7, 'When a creature enters the vortex for the first time on a turn or starts its turn there, it must make a strength saving throw. On a failed save, the creature takes 2d8 bludgeoning damage and is caught in the vortex until the spell ends. On a successful save, the creature takes half damage, and isn''t caught in the vortex. A creature caught in the vortex can use its action to try to swim away from the vortex as described above, but has disadvantage on the Strength (Athletics) check to do so.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-water', 8, 'The first time each turn that an object enters the vortex, the object takes 2d8 bludgeoning damage; this damage occurs each round it remains in the vortex.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('control-water', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('control-water', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('control-water', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('control-water', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('control-water', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('control-water', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('control-water', 'Control Water', '300 feet', 'A drop of water and a pinch of dust.', 0, 'Up to 10 minutes', 1, '1 action', 4, 'bludgeoning', 'transmutation', '/api/2014/spells/control-water', 'str', 'half', 'cube', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-weather', 0, 'You take control of the weather within 5 miles of you for the duration. You must be outdoors to cast this spell. Moving to a place where you don''t have a clear path to the sky ends the spell early.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-weather', 1, 'When you cast the spell, you change the current weather conditions, which are determined by the GM based on the climate and season. You can change precipitation, temperature, and wind. It takes 1d4 x 10 minutes for the new conditions to take effect. Once they do so, you can change the conditions again. When the spell ends, the weather gradually returns to normal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-weather', 2, 'When you change the weather conditions, find a current condition on the following tables and change its stage by one, up or down. When changing the wind, you can change its direction.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('control-weather', 3, '##### Precipitation');
