INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('control-weather', 'Control Weather', 'Self', 'Burning incense and bits of earth and wood mixed in water.', 0, 'Up to 8 hours', 1, '10 minutes', 8, 'transmutation', '/api/2014/spells/control-weather');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('counterspell', 0, 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a success, the creature''s spell fails and has no effect.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('counterspell', 0, 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('counterspell', 0, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('counterspell', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('counterspell', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('counterspell', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('counterspell', 'Counterspell', '60 feet', 0, 'Instantaneous', 0, '1 reaction', 3, 'abjuration', '/api/2014/spells/counterspell');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-food-and-water', 0, 'You create 45 pounds of food and 30 gallons of water on the ground or in containers within range, enough to sustain up to fifteen humanoids or five steeds for 24 hours. The food is bland but nourishing, and spoils if uneaten after 24 hours. The water is clean and doesn''t go bad.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-food-and-water', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-food-and-water', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-food-and-water', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-food-and-water', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-food-and-water', 2, 'paladin');
