INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('create-food-and-water', 'Create Food and Water', '30 feet', 0, 'Instantaneous', 0, '1 action', 3, 'conjuration', '/api/2014/spells/create-food-and-water');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-undead', 0, 'You can cast this spell only at night. Choose up to three corpses of Medium or Small humanoids within range. Each corpse becomes a ghoul under your control. (The GM has game statistics for these creatures.)');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-undead', 1, 'As a bonus action on each of your turns, you can mentally command any creature you animated with this spell if the creature is within 120 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-undead', 2, 'The creature is under your control for 24 hours, after which it stops obeying any command you have given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature before the current 24-hour period ends. This use of the spell reasserts your control over up to three creatures you have animated with this spell, rather than animating new ones.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('create-undead', 0, 'When you cast this spell using a 7th-level spell slot, you can animate or reassert control over four ghouls. When you cast this spell using an 8th-level spell slot, you can animate or reassert control over five ghouls or two ghasts or wights. When you cast this spell using a 9th-level spell slot, you can animate or reassert control over six ghouls, three ghasts or wights, or two mummies.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-undead', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-undead', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-undead', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-undead', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-undead', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-undead', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('create-undead', 'Create Undead', '10 feet', 'One clay pot filled with grave dirt, one clay pot filled with brackish water, and one 150 gp black onyx stone for each corpse.', 0, 'Instantaneous', 0, '1 minute', 6, 'necromancy', '/api/2014/spells/create-undead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 0, 'You either create or destroy water.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 1, '***Create Water.*** You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot cube within range.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 2, '***Destroy Water.*** You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot cube within range.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you create or destroy 10 additional gallons of water, or the size of the cube increases by 5 feet, for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('create-or-destroy-water', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-or-destroy-water', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('create-or-destroy-water', 1, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('create-or-destroy-water', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('create-or-destroy-water', 'Create or Destroy Water', '30 feet', 'A drop of water if creating water, or a few grains of sand if destroying it.', 0, 'Instantaneous', 0, '1 action', 1, 'transmutation', '/api/2014/spells/create-or-destroy-water', 'cube', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 0, 'You pull wisps of shadow material from the Shadowfell to create a nonliving object of vegetable matter within range: soft goods, rope, wood, or something similar. You can also use this spell to create mineral objects such as stone, crystal, or metal. The object created must be no larger than a 5-foot cube, and the object must be of a form and material that you have seen before.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 1, 'The duration depends on the object''s material. If the object is composed of multiple materials, use the shortest duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 2, '| Material | Duration |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 3, '|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 4, '| Vegetable matter | 1 day |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 5, '| Stone or crystal | 12 hours |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 6, '| Precious metals | 1 hour |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 7, '| Gems | 10 minutes |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 8, '| Adamantine or mithral | 1 minute |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('creation', 9, 'Using any material created by this spell as another spell''s material component causes that spell to fail.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('creation', 0, 'When you cast this spell using a spell slot of 6th level or higher, the cube increases by 5 feet for each slot level above 5th.');
