INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('creation', 'Creation', '30 feet', 'A tiny piece of matter of the same type of the item you plan to create.', 0, 'Special', 0, '1 minute', 5, 'illusion', '/api/2014/spells/creation', 'cube', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('cure-wounds', 0, 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('cure-wounds', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.');
