INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dancing-lights', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('dancing-lights', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('dancing-lights', 'Dancing Lights', '120 feet', 'A bit of phosphorus or wychwood, or a glowworm.', 0, 'Up to 1 minute', 1, '1 action', 0, 'evocation', '/api/2014/spells/dancing-lights');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('darkness', 0, 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can''t see through this darkness, and nonmagical light can''t illuminate it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('darkness', 1, 'If the point you choose is on an object you are holding or one that isn''t being worn or carried, the darkness emanates from the object and moves with it. Completely covering the source of the darkness with an opaque object, such as a bowl or a helm, blocks the darkness.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('darkness', 2, 'If any of this spell''s area overlaps with an area of light created by a spell of 2nd level or lower, the spell that created the light is dispelled.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('darkness', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('darkness', 1, 'M');
