INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('darkness', 'Darkness', '60 feet', 'Bat fur and a drop of pitch or piece of coal.', 0, 'Up to 10 minutes', 1, '1 action', 2, 'evocation', '/api/2014/spells/darkness', 'sphere', 15);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('darkvision', 0, 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.');
