INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('darkvision', 'Darkvision', 'Touch', 'Either a pinch of dried carrot or an agate.', 0, '8 hours', 0, '1 action', 2, 'transmutation', '/api/2014/spells/darkvision');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('daylight', 0, 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('daylight', 1, 'If you chose a point on an object you are holding or one that isn''t being worn or carried, the light shines from the object and moves with it. Completely covering the affected object with an opaque object, such as a bowl or a helm, blocks the light.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('daylight', 2, 'If any of this spell''s area overlaps with an area of darkness created by a spell of 3rd level or lower, the spell that created the darkness is dispelled.');
