INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('death-ward', 0, 'You touch a creature and grant it a measure of protection from death.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('death-ward', 1, 'The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('death-ward', 2, 'If the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('death-ward', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('death-ward', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('death-ward', 0, 'cleric');
