INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('death-ward', 0, 'life');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('death-ward', 'Death Ward', 'Touch', 0, '8 hours', 0, '1 action', 4, 'abjuration', '/api/2014/spells/death-ward');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 0, 'A beam of yellow light flashes from your pointing finger, then condenses to linger at a chosen point within range as a glowing bead for the duration. When the spell ends, either because your concentration is broken or because you decide to end it, the bead blossoms with a low roar into an explosion of flame that spreads around corners. Each creature in a 20-foot-radius sphere centered on that point must make a dexterity saving throw. A creature takes fire damage equal to the total accumulated damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 1, 'The spell''s base damage is 12d6. If at the end of your turn the bead has not yet detonated, the damage increases by 1d6.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 2, 'If the glowing bead is touched before the interval has expired, the creature touching it must make a dexterity saving throw. On a failed save, the spell ends immediately, causing the bead to erupt in flame. On a successful save, the creature can throw the bead up to 40 feet. When it strikes a creature or a solid object, the spell ends, and the bead explodes.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 3, 'The fire damages objects in the area and ignites flammable objects that aren''t being worn or carried.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 0, 'When you cast this spell using a spell slot of 8th level or higher, the base damage increases by 1d6 for each slot level above 7th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('delayed-blast-fireball', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('delayed-blast-fireball', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('delayed-blast-fireball', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('delayed-blast-fireball', 'Delayed Blast Fireball', '150 feet', 'A tiny ball of bat guano and sulfur.', 0, 'Up to 1 minute', 1, '1 action', 7, 'fire', 'evocation', '/api/2014/spells/delayed-blast-fireball', 'dex', 'half', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('demiplane', 0, 'You create a shadowy door on a flat solid surface that you can see within range. The door is large enough to allow Medium creatures to pass through unhindered. When opened, the door leads to a demiplane that appears to be an empty room 30 feet in each dimension, made of wood or stone. When the spell ends, the door disappears, and any creatures or objects inside the demiplane remain trapped there, as the door also disappears from the other side.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('demiplane', 1, 'Each time you cast this spell, you can create a new demiplane, or have the shadowy door connect to a demiplane you created with a previous casting of this spell. Additionally, if you know the nature and contents of a demiplane created by a casting of this spell by another creature, you can have the shadowy door connect to its demiplane instead.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('demiplane', 0, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('demiplane', 0, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('demiplane', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('demiplane', 'Demiplane', '60 feet', 0, '1 hour', 0, '1 action', 8, 'conjuration', '/api/2014/spells/demiplane');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-evil-and-good', 0, 'For the duration, you know if there is an aberration, celestial, elemental, fey, fiend, or undead within 30 feet of you, as well as where the creature is located. Similarly, you know if there is a place or object within 30 feet of you that has been magically consecrated or desecrated.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-evil-and-good', 1, 'The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-evil-and-good', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-evil-and-good', 1, 'S');
