INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('detect-evil-and-good', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('detect-evil-and-good', 'Detect Evil and Good', 'Self', 0, 'Up to 10 minutes', 1, '1 action', 1, 'divination', '/api/2014/spells/detect-evil-and-good', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-magic', 0, 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-magic', 1, 'The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-magic', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-magic', 1, 'S');
