INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('detect-magic', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('detect-magic', 'Detect Magic', 'Self', 1, 'Up to 10 minutes', 1, '1 action', 1, 'divination', '/api/2014/spells/detect-magic', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-poison-and-disease', 0, 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you. You also identify the kind of poison, poisonous creature, or disease in each case.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-poison-and-disease', 1, 'The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-poison-and-disease', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-poison-and-disease', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-poison-and-disease', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-poison-and-disease', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-poison-and-disease', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-poison-and-disease', 2, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-poison-and-disease', 3, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('detect-poison-and-disease', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('detect-poison-and-disease', 'Detect Poison and Disease', 'Self', 'A yew leaf.', 1, 'Up to 10 minutes', 1, '1 action', 1, 'divination', '/api/2014/spells/detect-poison-and-disease', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-thoughts', 0, 'For the duration, you can read the thoughts of certain creatures. When you cast the spell and as your action on each turn until the spell ends, you can focus your mind on any one creature that you can see within 30 feet of you. If the creature you choose has an Intelligence of 3 or lower or doesn''t speak any language, the creature is unaffected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-thoughts', 1, 'You initially learn the surface thoughts of the creature - what is most on its mind in that moment. As an action, you can either shift your attention to another creature''s thoughts or attempt to probe deeper into the same creature''s mind. If you probe deeper, the target must make a Wisdom saving throw. If it fails, you gain insight into its reasoning (if any), its emotional state, and something that looms large in its mind (such as something it worries over, loves, or hates). If it succeeds, the spell ends. Either way, the target knows that you are probing into its mind, and unless you shift your attention to another creature''s thoughts, the creature can use its action on its turn to make an Intelligence check contested by your Intelligence check; if it succeeds, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-thoughts', 2, 'Questions verbally directed at the target creature naturally shape the course of its thoughts, so this spell is particularly effective as part of an interrogation.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-thoughts', 3, 'You can also use this spell to detect the presence of thinking creatures you can''t see. When you cast the spell or as your action during the duration, you can search for thoughts within 30 feet of you. The spell can penetrate barriers, but 2 feet of rock, 2 inches of any metal other than lead, or a thin sheet of lead blocks you. You can''t detect a creature with an Intelligence of 3 or lower or one that doesn''t speak any language.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('detect-thoughts', 4, 'Once you detect the presence of a creature in this way, you can read its thoughts for the rest of the duration as described above, even if you can''t see it, but it must still be within range.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-thoughts', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-thoughts', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('detect-thoughts', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-thoughts', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-thoughts', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('detect-thoughts', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('detect-thoughts', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('detect-thoughts', 'Detect Thoughts', 'Self', 'A copper coin.', 0, 'Up to 1 minute', 1, '1 action', 2, 'divination', '/api/2014/spells/detect-thoughts');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dimension-door', 0, 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dimension-door', 1, 'You can bring along objects as long as their weight doesn''t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity. The creature must be within 5 feet of you when you cast this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dimension-door', 2, 'If you would arrive in a place already occupied by an object or a creature, you and any creature traveling with you each take 4d6 force damage, and the spell fails to teleport you.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dimension-door', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dimension-door', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dimension-door', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dimension-door', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dimension-door', 3, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('dimension-door', 'Dimension Door', '500 feet', 0, 'Instantaneous', 0, '1 action', 4, 'force', 'conjuration', '/api/2014/spells/dimension-door');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disguise-self', 0, 'You make yourself--including your clothing, armor, weapons, and other belongings on your person--look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can''t change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disguise-self', 1, 'The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel your head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disguise-self', 2, 'To discern that you are disguised, a creature can use its action to inspect your appearance and must succeed on an Intelligence (Investigation) check against your spell save DC.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('disguise-self', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('disguise-self', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('disguise-self', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('disguise-self', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('disguise-self', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('disguise-self', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('disguise-self', 'Disguise Self', 'Self', 0, '1 hour', 0, '1 action', 1, 'illusion', '/api/2014/spells/disguise-self');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disintegrate', 0, 'A thin green ray springs from your pointing finger to a target that you can see within range. The target can be a creature, an object, or a creation of magical force, such as the wall created by wall of force.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disintegrate', 1, 'A creature targeted by this spell must make a dexterity saving throw. On a failed save, the target takes 10d6 + 40 force damage. If this damage reduces the target to 0 hit points, it is disintegrated.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disintegrate', 2, 'A disintegrated creature and everything it is wearing and carrying, except magic items, are reduced to a pile of fine gray dust. The creature can be restored to life only by means of a true resurrection or a wish spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('disintegrate', 3, 'This spell automatically disintegrates a Large or smaller nonmagical object or a creation of magical force. If the target is a Huge or larger object or creation of force, this spell disintegrates a 10-foot-cube portion of it. A magic item is unaffected by this spell.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('disintegrate', 0, 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 3d6 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('disintegrate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('disintegrate', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('disintegrate', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('disintegrate', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('disintegrate', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('disintegrate', 'Disintegrate', '60 feet', 'A lodestone and a pinch of dust.', 0, 'Instantaneous', 0, '1 action', 6, 'force', 'transmutation', '/api/2014/spells/disintegrate', 'dex', 'none', 'cube', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 0, 'Shimmering energy surrounds and protects you from fey, undead, and creatures originating from beyond the Material Plane. For the duration, celestials, elementals, fey, fiends, and undead have disadvantage on attack rolls against you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 1, 'You can end the spell early by using either of the following special functions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 2, '***Break Enchantment.*** As your action, you touch a creature you can reach that is charmed, frightened, or possessed by a celestial, an elemental, a fey, a fiend, or an undead. The creature you touch is no longer charmed, frightened, or possessed by such creatures.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 3, '***Dismissal.*** As your action, make a melee spell attack against a celestial, an elemental, a fey, a fiend, or an undead you can reach. On a hit, you attempt to drive the creature back to its home plane. The creature must succeed on a charisma saving throw or be sent back to its home plane (if it isn''t there already). If they aren''t on their home plane, undead are sent to the Shadowfell, and fey are sent to the Feywild.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dispel-evil-and-good', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-evil-and-good', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-evil-and-good', 1, 'paladin');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('dispel-evil-and-good', 'Dispel Evil and Good', 'Self', 'Holy water or powdered silver and iron.', 0, 'Up to 1 minute', 1, '1 action', 5, 'abjuration', '/api/2014/spells/dispel-evil-and-good', 'cha', 'other', 'The creature must succeed on a charisma saving throw or be sent back to its home plane (if it isn''t there already)');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dispel-magic', 0, 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a successful check, the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('dispel-magic', 0, 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell''s level is equal to or less than the level of the spell slot you used.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dispel-magic', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dispel-magic', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 3, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 4, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 5, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dispel-magic', 6, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('dispel-magic', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('dispel-magic', 1, 'devotion');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('dispel-magic', 'Dispel Magic', '120 feet', 0, 'Instantaneous', 0, '1 action', 3, 'abjuration', '/api/2014/spells/dispel-magic');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divination', 0, 'Your magic and an offering put you in contact with a god or a god''s servants. You ask a single question concerning a specific goal, event, or activity to occur within 7 days. The GM offers a truthful reply. The reply might be a short phrase, a cryptic rhyme, or an omen.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divination', 1, 'The spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divination', 2, 'If you cast the spell two or more times before finishing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divination', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divination', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divination', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('divination', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('divination', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('divination', 'Divination', 'Self', 'Incense and a sacrificial offering appropriate to your religion, together worth at least 25gp, which the spell consumes.', 1, 'Instantaneous', 0, '1 action', 4, 'divination', '/api/2014/spells/divination');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-favor', 0, 'Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divine-favor', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divine-favor', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('divine-favor', 0, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('divine-favor', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('divine-favor', 'Divine Favor', 'Self', 0, 'Up to 1 minute', 1, '1 bonus action', 1, 'radiant', 'evocation', '/api/2014/spells/divine-favor');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 0, 'You utter a divine word, imbued with the power that shaped the world at the dawn of creation. Choose any number of creatures you can see within range. Each creature that can hear you must make a Charisma saving throw. On a failed save, a creature suffers an effect based on its current hit points:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 1, '- 50 hit points or fewer: deafened for 1 minute');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 2, '- 40 hit points or fewer: deafened and blinded for 10 minutes');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 3, '- 30 hit points or fewer: blinded, deafened, and stunned for 1 hour');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 4, '- 20 hit points or fewer: killed instantly');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('divine-word', 5, 'Regardless of its current hit points, a celestial, an elemental, a fey, or a fiend that fails its save is forced back to its plane of origin (if it isn''t there already) and can''t return to your current plane for 24 hours by any means short of a wish spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('divine-word', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('divine-word', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('divine-word', 'Divine Word', '30 feet', 0, 'Instantaneous', 0, '1 bonus action', 7, 'evocation', '/api/2014/spells/divine-word', 'cha', 'none', 'On a failed save, a creature suffers an effect based on its current hit points.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-beast', 0, 'You attempt to beguile a creature that you can see within range. It must succeed on a wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-beast', 1, 'While the creature is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as "Attack that creature," "Run over there," or "Fetch that object." If the creature completes the order and doesn''t receive further direction from you, it defends and preserves itself to the best of its ability.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-beast', 2, 'You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn''t do anything that you don''t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well. Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('dominate-beast', 0, 'When you cast this spell with a 9th level spell slot, the duration is concentration, up to 8 hours.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dominate-beast', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dominate-beast', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dominate-beast', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dominate-beast', 1, 'sorcerer');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('dominate-beast', 'Dominate Beast', '60 feet', 0, 'Up to 1 minute', 1, '1 action', 4, 'enchantment', '/api/2014/spells/dominate-beast', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-monster', 0, 'You attempt to beguile a creature that you can see within range. It must succeed on a wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-monster', 1, 'While the creature is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as "Attack that creature," "Run over there," or "Fetch that object." If the creature completes the order and doesn''t receive further direction from you, it defends and preserves itself to the best of its ability.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-monster', 2, 'You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn''t do anything that you don''t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dominate-monster', 3, 'Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('dominate-monster', 0, 'When you cast this spell with a 9th-level spell slot, the duration is concentration, up to 8 hours.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dominate-monster', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dominate-monster', 1, 'S');
