INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dominate-person', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dominate-person', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('dominate-person', 'Dominate Person', '60 feet', 0, 'Up to 1 minute', 1, '1 action', 5, 'enchantment', '/api/2014/spells/dominate-person', 'wis', 'other', 'Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dream', 0, 'This spell shapes a creature''s dreams. Choose a creature known to you as the target of this spell. The target must be on the same plane of existence as you. Creatures that don''t sleep, such as elves, can''t be contacted by this spell. You, or a willing creature you touch, enters a trance state, acting as a messenger.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dream', 1, 'While in the trance, the messenger is aware of his or her surroundings, but can''t take actions or move.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dream', 2, 'If the target is asleep, the messenger appears in the target''s dreams and can converse with the target as long as it remains asleep, through the duration of the spell. The messenger can also shape the environment of the dream, creating landscapes, objects, and other images. The messenger can emerge from the trance at any time, ending the effect of the spell early. The target recalls the dream perfectly upon waking. If the target is awake when you cast the spell, the messenger knows it, and can either end the trance (and the spell) or wait for the target to fall asleep, at which point the messenger appears in the target''s dreams.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dream', 3, 'You can make the messenger appear monstrous and terrifying to the target. If you do, the messenger can deliver a message of no more than ten words and then the target must make a wisdom saving throw. On a failed save, echoes of the phantasmal monstrosity spawn a nightmare that lasts the duration of the target''s sleep and prevents the target from gaining any benefit from that rest. In addition, when the target wakes up, it takes 3d6 psychic damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('dream', 4, 'If you have a body part, lock of hair, clipping from a nail, or similar portion of the target''s body, the target makes its saving throw with disadvantage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dream', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dream', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('dream', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dream', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dream', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('dream', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('dream', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('dream', 'Dream', 'Special', 'A handful of sand, a dab of ink, and a writing quill plucked from a sleeping bird.', 0, '8 hours', 0, '1 minute', 5, 'psychic', 'illusion', '/api/2014/spells/dream', 'wis', 'none', 'On a failed save, echoes of the phantasmal monstrosity spawn a nightmare that lasts the duration of the target''s sleep and prevents the target from gaining any benefit from that rest.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('druidcraft', 0, 'Whispering to the spirits of nature, you create one of the following effects within ''range'':');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('druidcraft', 1, '- You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('druidcraft', 2, '- You instantly make a flower bloom, a seed pod open, or a leaf bud bloom.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('druidcraft', 3, '- You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint order of skunk. The effect must fit in a 5-foot cube.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('druidcraft', 4, '- You instantly light or snuff out a candle, a torch, or a small campfire.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('druidcraft', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('druidcraft', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('druidcraft', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('druidcraft', 'Druidcraft', '30 feet', 0, 'Instantaneous', 0, '1 action', 0, 'transmutation', '/api/2014/spells/druidcraft');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 0, 'You create a seismic disturbance at a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point and shakes creatures and structures in contact with the ground in that area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 1, 'The ground in the area becomes difficult terrain. Each creature on the ground that is concentrating must make a constitution saving throw. On a failed save, the creature''s concentration is broken.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 2, 'When you cast this spell and at the end of each turn you spend concentrating on it, each creature on the ground in the area must make a dexterity saving throw. On a failed save, the creature is knocked prone.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 3, 'This spell can have additional effects depending on the terrain in the area, as determined by the GM.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 4, 'Fissures. Fissures open throughout the spell''s area at the start of your next turn after you cast the spell. A total of 1d6 such fissures open in locations chosen by the GM. Each is 1d10 x 10 feet deep, 10 feet wide, and extends from one edge of the spell''s area to the opposite side. A creature standing on a spot where a fissure opens must succeed on a dexterity saving throw or fall in. A creature that successfully saves moves with the fissure''s edge as it opens.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 5, 'A fissure that opens beneath a structure causes it to automatically collapse (see below).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('earthquake', 6, 'Structures. The tremor deals 50 bludgeoning damage to any structure in contact with the ground in the area when you cast the spell and at the start of each of your turns until the spell ends. If a structure drops to 0 hit points, it collapses and potentially damages nearby creatures. A creature within half the distance of a structure''s height must make a dexterity saving throw. On a failed save, the creature takes 5d6 bludgeoning damage, is knocked prone, and is buried in the rubble, requiring a DC 20 Strength (Athletics) check as an action to escape. The GM can adjust the DC higher or lower, depending on the nature of the rubble. On a successful save, the creature takes half as much damage and doesn''t fall prone or become buried.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('earthquake', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('earthquake', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('earthquake', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('earthquake', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('earthquake', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('earthquake', 2, 'sorcerer');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('earthquake', 'Earthquake', '500 feet', 'A pinch of dirt, a piece of rock, and a lump of clay.', 0, 'Up to 1 minute', 1, '1 action', 8, 'evocation', '/api/2014/spells/earthquake', 'sphere', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('eldritch-blast', 0, 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage. The spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('eldritch-blast', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('eldritch-blast', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('eldritch-blast', 0, 'warlock');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('eldritch-blast', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('eldritch-blast', 'Eldritch Blast', '120 feet', 0, 'Instantaneous', 0, '1 action', 0, 'ranged', 'force', 'evocation', '/api/2014/spells/eldritch-blast');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 0, 'You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 1, '***Bear''s Endurance.*** The target has advantage on constitution checks. It also gains 2d6 temporary hit points, which are lost when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 2, '***Bull''s Strength.*** The target has advantage on strength checks, and his or her carrying capacity doubles.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 3, '***Cat''s Grace.*** The target has advantage on dexterity checks. It also doesn''t take damage from falling 20 feet or less if it isn''t incapacitated.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 4, '***Eagle''s Splendor.*** The target has advantage on Charisma checks.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 5, '***Fox''s Cunning.*** The target has advantage on intelligence checks.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enhance-ability', 6, '***Owl''s Wisdom.*** The target has advantage on wisdom checks.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('enhance-ability', 0, 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enhance-ability', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enhance-ability', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enhance-ability', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enhance-ability', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enhance-ability', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enhance-ability', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enhance-ability', 3, 'sorcerer');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('enhance-ability', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('enhance-ability', 'Enhance Ability', 'Touch', 'Fur or a feather from a beast.', 0, 'Up to 1 hour', 1, '1 action', 2, 'transmutation', '/api/2014/spells/enhance-ability');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enlarge-reduce', 0, 'You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or an object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enlarge-reduce', 1, 'If the target is a creature, everything it is wearing and carrying changes size with it. Any item dropped by an affected creature returns to normal size at once.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enlarge-reduce', 2, '***Enlarge.*** The target''s size doubles in all dimensions, and its weight is multiplied by eight. This growth increases its size by one category-from Medium to Large, for example. If there isn''t enough room for the target to double its size, the creature or object attains the maximum possible size in the space available. Until the spell ends, the target also has advantage on Strength checks and Strength saving throws. The target''s weapons also grow to match its new size. While these weapons are enlarged, the target''s attacks with them deal 1d4 extra damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enlarge-reduce', 3, '***Reduce.*** The target''s size is halved in all dimensions, and its weight is reduced to one-eighth of normal. This reduction decreases its size by one category-from Medium to Small, for example. Until the spell ends, the target also has disadvantage on Strength checks and Strength saving throws. The target''s weapons also shrink to match its new size. While these weapons are reduced, the target''s attacks with them deal 1d4 less damage (this can''t reduce the damage below 1).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enlarge-reduce', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enlarge-reduce', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enlarge-reduce', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enlarge-reduce', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enlarge-reduce', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('enlarge-reduce', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('enlarge-reduce', 'Enlarge/Reduce', '30 feet', 'A pinch iron powder.', 0, 'Up to 1 minute', 1, '1 action', 2, 'transmutation', '/api/2014/spells/enlarge-reduce', 'con', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('entangle', 0, 'Grasping weeds and vines sprout from the ground in a 20-foot square starting form a point within range. For the duration, these plants turn the ground in the area into difficult terrain.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('entangle', 1, 'A creature in the area when you cast the spell must succeed on a strength saving throw or be restrained by the entangling plants until the spell ends. A creature restrained by the plants can use its action to make a Strength check against your spell save DC. On a success, it frees itself.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('entangle', 2, 'When the spell ends, the conjured plants wilt away.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('entangle', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('entangle', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('entangle', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('entangle', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('entangle', 'Entangle', '90 feet', 0, 'Up to 1 minute', 1, '1 action', 1, 'conjuration', '/api/2014/spells/entangle', 'str', 'none', 'cube', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('enthrall', 0, 'You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a wisdom saving throw. Any creature that can''t be charmed succeeds on this saving throw automatically, and if you or your companions are fighting a creature, it has advantage on the save. On a failed save, the target has disadvantage on Wisdom (Perception) checks made to perceive any creature other than you until the spell ends or until the target can no longer hear you. The spell ends if you are incapacitated or can no longer speak.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enthrall', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('enthrall', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enthrall', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('enthrall', 1, 'warlock');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('enthrall', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('enthrall', 'Enthrall', '60 feet', 0, '1 minute', 0, '1 action', 2, 'enchantment', '/api/2014/spells/enthrall', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('etherealness', 0, 'You step into the border regions of the Ethereal Plane, in the area where it overlaps with your current plane. You remain in the Border Ethereal for the duration or until you use your action to dismiss the spell. During this time, you can move in any direction. If you move up or down, every foot of movement costs an extra foot. You can see and hear the plane you originated from, but everything there looks gray, and you can''t see anything more than 60 feet away.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('etherealness', 1, 'While on the Ethereal Plane, you can only affect and be affected by other creatures on that plane. Creatures that aren''t on the Ethereal Plane can''t perceive you and can''t interact with you, unless a special ability or magic has given them the ability to do so.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('etherealness', 2, 'You ignore all objects and effects that aren''t on the Ethereal Plane, allowing you to move through objects you perceive on the plane you originated from.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('etherealness', 3, 'When the spell ends, you immediately return to the plane you originated from in the spot you currently occupy. If you occupy the same spot as a solid object or creature when this happens, you are immediately shunted to the nearest unoccupied space that you can occupy and take force damage equal to twice the number of feet you are moved.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('etherealness', 4, 'This spell has no effect if you cast it while you are on the Ethereal Plane or a plane that doesn''t border it, such as one of the Outer Planes.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('etherealness', 0, 'When you cast this spell using a spell slot of 8th level or higher, you can target up to three willing creatures (including you) for each slot level above 7th. The creatures must be within 10 feet of you when you cast the spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('etherealness', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('etherealness', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('etherealness', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('etherealness', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('etherealness', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('etherealness', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('etherealness', 4, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('etherealness', 'Etherealness', 'Self', 0, '8 hours', 0, '1 action', 7, 'transmutation', '/api/2014/spells/etherealness');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('expeditious-retreat', 0, 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('expeditious-retreat', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('expeditious-retreat', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('expeditious-retreat', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('expeditious-retreat', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('expeditious-retreat', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('expeditious-retreat', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('expeditious-retreat', 'Expeditious Retreat', 'Self', 0, 'Up to 10 minutes', 1, '1 bonus action', 1, 'transmutation', '/api/2014/spells/expeditious-retreat');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('eyebite', 0, 'For the spell''s duration, your eyes become an inky void imbued with dread power. One creature of your choice within 60 feet of you that you can see must succeed on a wisdom saving throw or be affected by one of the following effects of your choice for the duration. On each of your turns until the spell ends, you can use your action to target another creature but can''t target a creature again if it has succeeded on a saving throw against this casting of eyebite.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('eyebite', 1, '***Asleep.*** The target falls unconscious. It wakes up if it takes any damage or if another creature uses its action to shake the sleeper awake.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('eyebite', 2, '***Panicked.*** The target is frightened of you. On each of its turns, the frightened creature must take the Dash action and move away from you by the safest and shortest available route, unless there is nowhere to move. If the target moves to a place at least 60 feet away from you where it can no longer see you, this effect ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('eyebite', 3, '***Sickened.*** The target has disadvantage on attack rolls and ability checks. At the end of each of its turns, it can make another wisdom saving throw. If it succeeds, the effect ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('eyebite', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('eyebite', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('eyebite', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('eyebite', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('eyebite', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('eyebite', 3, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('eyebite', 'Eyebite', 'Self', 0, 'Up to 1 minute', 1, '1 action', 6, 'necromancy', '/api/2014/spells/eyebite', 'wis', 'none', 'On failure, the target can be affected by one of the following effects of your choice for the duration. [Asleep. The target falls unconscious. It wakes up if it takes any damage or if another creature uses its action to shake the sleeper awake.] [Panicked. The target is frightened of you. On each of its turns, the frightened creature must take the Dash action and move away from you by the safest and shortest available route, unless there is nowhere to move. If the target moves to a place at least 60 feet away from you where it can no longer see you, this effect ends.] [Sickened. The target has disadvantage on attack rolls and ability checks. At the end of each of its turns, it can make another wisdom saving throw. If it succeeds, the effect ends.]');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fabricate', 0, 'You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, and clothes from flax or wool.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fabricate', 1, 'Choose raw materials that you can see within range. You can fabricate a Large or smaller object (contained within a 10-foot cube, or eight connected 5-foot cubes), given a sufficient quantity of raw material. If you are working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than Medium (contained within a single 5-foot cube). The quality of objects made by the spell is commensurate with the quality of the raw materials.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fabricate', 2, 'Creatures or magic items can''t be created or transmuted by this spell. You also can''t use it to create items that ordinarily require a high degree of craftsmanship, such as jewelry, weapons, glass, or armor, unless you have proficiency with the type of artisan''s tools used to craft such objects.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fabricate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fabricate', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fabricate', 0, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('fabricate', 'Fabricate', '120 feet', 0, 'Instantaneous', 0, '10 minutes', 4, 'transmutation', '/api/2014/spells/fabricate');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('faerie-fire', 0, 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('faerie-fire', 1, 'Any attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can''t benefit from being invisible.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('faerie-fire', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('faerie-fire', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('faerie-fire', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('faerie-fire', 'Faerie Fire', '60 feet', 0, 'Up to 1 minute', 1, '1 action', 1, 'evocation', '/api/2014/spells/faerie-fire', 'dex', 'none', 'cube', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('faithful-hound', 0, 'You conjure a phantom watchdog in an unoccupied space that you can see within range, where it remains for the duration, until you dismiss it as an action, or until you move more than 100 feet away from it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('faithful-hound', 1, 'The hound is invisible to all creatures except you and can''t be harmed. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound sees invisible creatures and can see into the Ethereal Plane. It ignores illusions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('faithful-hound', 2, 'At the start of each of your turns, the hound attempts to bite one creature within 5 feet of it that is hostile to you. The hound''s attack bonus is equal to your spellcasting ability modifier + your proficiency bonus. On a hit, it deals 4d8 piercing damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('faithful-hound', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('faithful-hound', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('faithful-hound', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('faithful-hound', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('faithful-hound', 'Faithful Hound', '30 feet', 'A tiny silver whistle, a piece of bone, and a thread', 0, '8 hours', 0, '1 action', 4, 'melee', 'piercing', 'conjuration', '/api/2014/spells/faithful-hound');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('false-life', 0, 'Bolstering yourself with a necromantic facsimile of life, you gain 1d4 + 4 temporary hit points for the duration.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('false-life', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you gain 5 additional temporary hit points for each slot level above 1st.');
