INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('false-life', 'False Life', 'Self', 'A small amount of alcohol or distilled spirits.', 0, '1 hour', 0, '1 action', 1, 'necromancy', '/api/2014/spells/false-life');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fear', 0, 'You project a phantasmal image of a creature''s worst fears. Each creature in a 30-foot cone must succeed on a wisdom saving throw or drop whatever it is holding and become frightened for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fear', 1, 'While frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns, unless there is nowhere to move. If the creature ends its turn in a location where it doesn''t have line of sight to you, the creature can make a wisdom saving throw. On a successful save, the spell ends for that creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fear', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fear', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fear', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fear', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fear', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fear', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fear', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fear', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('fear', 'Fear', 'Self', 'A white feather or the heart of a hen.', 0, 'Up to 1 minute', 1, '1 action', 3, 'illusion', '/api/2014/spells/fear', 'wis', 'none', 'cone', 30, 'On fail, A creature drop whatever it is holding and become frightened for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('feather-fall', 0, 'Choose up to five falling creatures within range. A falling creature''s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('feather-fall', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('feather-fall', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feather-fall', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feather-fall', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feather-fall', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('feather-fall', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('feather-fall', 'Feather Fall', '60 feet', 'A small feather or a piece of down.', 0, '1 minute', 0, '1 reaction', 1, 'transmutation', '/api/2014/spells/feather-fall');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('feeblemind', 0, 'You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 4d6 psychic damage and must make an intelligence saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('feeblemind', 1, 'On a failed save, the creature''s Intelligence and Charisma scores become 1. The creature can''t cast spells, activate magic items, understand language, or communicate in any intelligible way. The creature can, however, identify its friends, follow them, and even protect them.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('feeblemind', 2, 'At the end of every 30 days, the creature can repeat its saving throw against this spell. If it succeeds on its saving throw, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('feeblemind', 3, 'The spell can also be ended by greater restoration, heal, or wish.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('feeblemind', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('feeblemind', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('feeblemind', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feeblemind', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feeblemind', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feeblemind', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('feeblemind', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('feeblemind', 'Feeblemind', '150 feet', 'A handful of clay, crystal, glass, or mineral spheres.', 0, 'Instantaneous', 0, '1 action', 8, 'psychic', 'enchantment', '/api/2014/spells/feeblemind', 'int', 'other', 'The target always takes the damage. On a failed save, the creature''s Intelligence and Charisma scores become 1.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 0, 'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 1, 'Your familiar acts independently of you, but it always obeys your commands. In combat, it rolls its own initiative and acts on its own turn. A familiar can''t attack, but it can take other actions as normal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 2, 'When the familiar drops to 0 hit points, it disappears, leaving behind no physical form. It reappears after you cast this spell again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 3, 'While your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as an action, you can see through your familiar''s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses that the familiar has. During this time, you are deaf and blind with regard to your own senses.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 4, 'As an action, you can temporarily dismiss your familiar. It disappears into a pocket dimension where it awaits your summons. Alternatively, you can dismiss it forever. As an action while it is temporarily dismissed, you can cause it to reappear in any unoccupied space within 30 feet of you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 5, 'You can''t have more than one familiar at a time. If you cast this spell while you already have a familiar, you instead cause it to adopt a new form. Choose one of the forms from the above list. Your familiar transforms into the chosen creature.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-familiar', 6, 'Finally, when you cast a spell with a range of touch, your familiar can deliver the spell as if it had cast the spell. Your familiar must be within 100 feet of you, and it must use its reaction to deliver the spell when you cast it. If the spell requires an attack roll, you use your action modifier for the roll.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-familiar', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-familiar', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-familiar', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-familiar', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('find-familiar', 'Find Familiar', '10 feet', '10gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier.', 1, 'Instantaneous', 0, '1 hour', 1, 'conjuration', '/api/2014/spells/find-familiar');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-steed', 0, 'You summon a spirit that assumes the form of an unusually intelligent, strong, and loyal steed, creating a long-lasting bond with it. Appearing in an unoccupied space within range, the steed takes on a form that you choose, such as a warhorse, a pony, a camel, an elk, or a mastiff. (Your GM might allow other animals to be summoned as steeds.) The steed has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of its normal type. Additionally, if your steed has an Intelligence of 5 or less, its Intelligence becomes 6, and it gains the ability to understand one language of your choice that you speak.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-steed', 1, 'Your steed serves you as a mount, both in combat and out, and you have an instinctive bond with it that allows you to fight as a seamless unit. While mounted on your steed, you can make any spell you cast that targets only you also target your steed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-steed', 2, 'When the steed drops to 0 hit points, it disappears, leaving behind no physical form. You can also dismiss your steed at any time as an action, causing it to disappear. In either case, casting this spell again summons the same steed, restored to its hit point maximum.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-steed', 3, 'While your steed is within 1 mile of you, you can communicate with it telepathically.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-steed', 4, 'You can''t have more than one steed bonded by this spell at a time. As an action, you can release the steed from its bond at any time, causing it to disappear.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-steed', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-steed', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-steed', 0, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('find-steed', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('find-steed', 'Find Steed', '30 feet', 0, 'Instantaneous', 0, '10 minutes', 2, 'conjuration', '/api/2014/spells/find-steed');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-traps', 0, 'You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator. Thus, the spell would sense an area affected by the alarm spell, a glyph of warding, or a mechanical pit trap, but it would not reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-traps', 1, 'This spell merely reveals that a trap is present. You don''t learn the location of each trap, but you do learn the general nature of the danger posed by a trap you sense.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-traps', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-traps', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-traps', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-traps', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-traps', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('find-traps', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('find-traps', 'Find Traps', '120 feet', 0, 'Instantaneous', 0, '1 action', 2, 'divination', '/api/2014/spells/find-traps');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-the-path', 0, 'This spell allows you to find the shortest, most direct physical route to a specific fixed location that you are familiar with on the same plane of existence. If you name a destination on another plane of existence, a destination that moves (such as a mobile fortress), or a destination that isn''t specific (such as "a green dragon''s lair"), the spell fails.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('find-the-path', 1, 'For the duration, as long as you are on the same plane of existence as the destination, you know how far it is and in what direction it lies. While you are traveling there, whenever you are presented with a choice of paths along the way, you automatically determine which path is the shortest and most direct route (but not necessarily the safest route) to the destination.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-the-path', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-the-path', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('find-the-path', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-the-path', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-the-path', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('find-the-path', 2, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('find-the-path', 'Find the Path', 'Self', 'A set of divinatory tools--such as bones, ivory sticks, cards, teeth, or carved runes--worth 100gp and an object from the location you wish to find.', 0, 'Up to 24 hours', 1, '1 minute', 6, 'divination', '/api/2014/spells/find-the-path');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('finger-of-death', 0, 'You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('finger-of-death', 1, 'A humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command, following your verbal orders to the best of its ability.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('finger-of-death', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('finger-of-death', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('finger-of-death', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('finger-of-death', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('finger-of-death', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('finger-of-death', 'Finger of Death', '60 feet', 0, 'Instantaneous', 0, '1 action', 7, 'necrotic', 'necromancy', '/api/2014/spells/finger-of-death', 'con', 'half');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-bolt', 0, 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn''t being worn or carried.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-bolt', 1, 'This spell''s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-bolt', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-bolt', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-bolt', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-bolt', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('fire-bolt', 'Fire Bolt', '120 feet', 0, 'Instantaneous', 0, '1 action', 0, 'ranged', 'fire', 'evocation', '/api/2014/spells/fire-bolt');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-shield', 0, 'Thin and vaporous flame surround your body for the duration of the spell, radiating a bright light bright light in a 10-foot radius and dim light for an additional 10 feet. You can end the spell using an action to make it disappear.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-shield', 1, 'The flames are around you a heat shield or cold, your choice. The heat shield gives you cold damage resistance and the cold resistance to fire damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-shield', 2, 'In addition, whenever a creature within 5 feet of you hits you with a melee attack, flames spring from the shield. The attacker then suffers 2d8 points of fire damage or cold, depending on the model.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-shield', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-shield', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-shield', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-shield', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fire-shield', 0, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('fire-shield', 'Fire Shield', 'Self', 'A little phosphorus or a firefly.', 0, '10 minutes', 0, '1 action', 4, 'fire', 'evocation', '/api/2014/spells/fire-shield', 'sphere', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-storm', 0, 'A storm made up of sheets of roaring flame appears in a location you choose within range. The area of the storm consists of up to ten 10-foot cubes, which you can arrange as you wish. Each cube must have at least one face adjacent to the face of another cube. Each creature in the area must make a dexterity saving throw. It takes 7d10 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fire-storm', 1, 'The fire damages objects in the area and ignites flammable objects that aren''t being worn or carried. If you choose, plant life in the area is unaffected by this spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-storm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fire-storm', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-storm', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-storm', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fire-storm', 2, 'sorcerer');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('fire-storm', 'Fire Storm', '150 feet', 0, 'Instantaneous', 0, '1 action', 7, 'fire', 'evocation', '/api/2014/spells/fire-storm', 'dex', 'half', 'cube', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fireball', 0, 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fireball', 1, 'The fire spreads around corners. It ignites flammable objects in the area that aren''t being worn or carried.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('fireball', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fireball', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fireball', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fireball', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fireball', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fireball', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fireball', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fireball', 1, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('fireball', 'Fireball', '150 feet', 'A tiny ball of bat guano and sulfur.', 0, 'Instantaneous', 0, '1 action', 3, 'fire', 'evocation', '/api/2014/spells/fireball', 'dex', 'half', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flame-blade', 0, 'You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke the blade again as a bonus action.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flame-blade', 1, 'You can use your action to make a melee spell attack with the fiery blade. On a hit, the target takes 3d6 fire damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flame-blade', 2, 'The flaming blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('flame-blade', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for every two slot levels above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-blade', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-blade', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-blade', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flame-blade', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('flame-blade', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('flame-blade', 'Flame Blade', 'Self', 'Leaf of sumac.', 0, 'Up to 10 minutes', 1, '1 bonus action', 2, 'fire', 'evocation', '/api/2014/spells/flame-blade');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flame-strike', 0, 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('flame-strike', 0, 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-strike', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-strike', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flame-strike', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flame-strike', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('flame-strike', 0, 'devotion');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('flame-strike', 1, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('flame-strike', 'Flame Strike', '60 feet', 'Pinch of sulfur.', 0, 'Instantaneous', 0, '1 action', 5, 'fire', 'evocation', '/api/2014/spells/flame-strike', 'dex', 'half', 'cylinder', 40);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flaming-sphere', 0, 'A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a dexterity saving throw. The creature takes 2d6 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flaming-sphere', 1, 'As a bonus action, you can move the sphere up to 30 feet. If you ram the sphere into a creature, that creature must make the saving throw against the sphere''s damage, and the sphere stops moving this turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flaming-sphere', 2, 'When you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. The sphere ignites flammable objects not being worn or carried, and it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('flaming-sphere', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d6 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flaming-sphere', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flaming-sphere', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flaming-sphere', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flaming-sphere', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flaming-sphere', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('flaming-sphere', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('flaming-sphere', 'Flaming Sphere', '60 feet', 'A bit of tallow, a pinch of brimstone, and a dusting of powdered iron.', 0, 'Up to 1 minute', 1, '1 action', 2, 'fire', 'conjuration', '/api/2014/spells/flaming-sphere');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flesh-to-stone', 0, 'You attempt to turn one creature that you can see within range into stone. If the target''s body is made of flesh, the creature must make a constitution saving throw. On a failed save, it is restrained as its flesh begins to harden. On a successful save, the creature isn''t affected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flesh-to-stone', 1, 'A creature restrained by this spell must make another constitution saving throw at the end of each of its turns. If it successfully saves against this spell three times, the spell ends. If it fails its saves three times, it is turned to stone and subjected to the petrified condition for the duration. The successes and failures don''t need to be consecutive; keep track of both until the target collects three of a kind.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flesh-to-stone', 2, 'If the creature is physically broken while petrified, it suffers from similar deformities if it reverts to its original state.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('flesh-to-stone', 3, 'If you maintain your concentration on this spell for the entire possible duration, the creature is turned to stone until the effect is removed.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flesh-to-stone', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flesh-to-stone', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('flesh-to-stone', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flesh-to-stone', 0, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('flesh-to-stone', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('flesh-to-stone', 'Flesh to Stone', '60 feet', 'A pinch of lime, water, and earth.', 0, 'Up to 1 minute', 1, '1 action', 6, 'transmutation', '/api/2014/spells/flesh-to-stone', 'con', 'none', 'On a failed save, the target is restrained as its flesh begins to harden.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('floating-disk', 0, 'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk remains for the duration, and can hold up to 500 pounds. If more weight is placed on it, the spell ends, and everything on the disk falls to the ground.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('floating-disk', 1, 'The disk is immobile while you are within 20 feet of it. If you move more than 20 feet away from it, the disk follows you so that it remains within 20 feet of you. If can move across uneven terrain, up or down stairs, slopes and the like, but it can''t cross an elevation change of 10 feet or more. For example, the disk can''t move across a 10-foot-deep pit, nor could it leave such a pit if it was created at the bottom.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('floating-disk', 2, 'If you move more than 100 feet away from the disk (typically because it can''t move around an obstacle to follow you), the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('floating-disk', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('floating-disk', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('floating-disk', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('floating-disk', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('floating-disk', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('floating-disk', 'Floating Disk', '30 feet', 'A drop of mercury.', 1, '1 hour', 0, '1 action', 1, 'conjuration', '/api/2014/spells/floating-disk');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fly', 0, 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('fly', 0, 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fly', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fly', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fly', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fly', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fly', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fly', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fly', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('fly', 'Fly', 'Touch', 'A wing feather from any bird.', 0, 'Up to 10 minutes', 1, '1 action', 3, 'transmutation', '/api/2014/spells/fly');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('fog-cloud', 0, 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('fog-cloud', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the radius of the fog increases by 20 feet for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fog-cloud', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('fog-cloud', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fog-cloud', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fog-cloud', 1, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fog-cloud', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('fog-cloud', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('fog-cloud', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('fog-cloud', 'Fog Cloud', '120 feet', 0, 'Up to 1 hour', 1, '1 action', 1, 'conjuration', '/api/2014/spells/fog-cloud', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forbiddance', 0, 'You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet above the floor. For the duration, creatures can''t teleport into the area or use portals, such as those created by the gate spell, to enter the area. The spell proofs the area against planar travel, and therefore prevents creatures from accessing the area by way of the Astral Plane, Ethereal Plane, Feywild, Shadowfell, or the plane shift spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forbiddance', 1, 'In addition, the spell damages types of creatures that you choose when you cast it. Choose one or more of the following: celestials, elementals, fey, fiends, and undead. When a chosen creature enters the spell''s area for the first time on a turn or starts its turn there, the creature takes 5d10 radiant or necrotic damage (your choice when you cast this spell).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forbiddance', 2, 'When you cast this spell, you can designate a password. A creature that speaks the password as it enters the area takes no damage from the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forbiddance', 3, 'The spell''s area can''t overlap with the area of another forbiddance spell. If you cast forbiddance every day for 30 days in the same location, the spell lasts until it is dispelled, and the material components are consumed on the last casting.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forbiddance', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forbiddance', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forbiddance', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('forbiddance', 0, 'cleric');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('forbiddance', 'Forbiddance', 'Touch', 'A sprinkling of holy water, rare incense, and powdered ruby worth at least 1,000 gp.', 1, '24 hours', 0, '10 minutes', 6, 'abjuration', '/api/2014/spells/forbiddance', 'cube', 40000);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 0, 'An immobile, invisible, cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 1, 'A prison in the shape of a cage can be up to 20 feet on a side and is made from 1/2-inch diameter bars spaced 1/2 inch apart.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 2, 'A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier that prevents any matter from passing through it and blocking any spells cast into or out from the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 3, 'When you cast the spell, any creature that is completely inside the cage''s area is trapped. Creatures only partially within the area, or those too large to fit inside the area, are pushed away from the center of the area until they are completely outside the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 4, 'A creature inside the cage can''t leave it by nonmagical means. If the creature tries to use teleportation or interplanar travel to leave the cage, it must first make a charisma saving throw. On a success, the creature can use that magic to exit the cage. On a failure, the creature can''t exit the cage and wastes the use of the spell or effect. The cage also extends into the Ethereal Plane, blocking ethereal travel.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('forcecage', 5, 'This spell can''t be dispelled by dispel magic.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forcecage', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forcecage', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('forcecage', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('forcecage', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('forcecage', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('forcecage', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('forcecage', 'Forcecage', '100 feet', 'Ruby dust worth 1,500 gp.', 0, '1 hour', 0, '1 action', 7, 'evocation', '/api/2014/spells/forcecage', 'cube', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('foresight', 0, 'You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can''t be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('foresight', 1, 'This spell immediately ends if you cast it again before its duration ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('foresight', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('foresight', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('foresight', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('foresight', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('foresight', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('foresight', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('foresight', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('foresight', 'Foresight', 'Touch', 'A hummingbird feather.', 0, '8 hours', 0, '1 minute', 9, 'divination', '/api/2014/spells/foresight');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('freedom-of-movement', 0, 'You touch a willing creature. For the duration, the target''s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target''s speed nor cause the target to be paralyzed or restrained.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('freedom-of-movement', 1, 'The target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled. Finally, being underwater imposes no penalties on the target''s movement or attacks.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freedom-of-movement', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freedom-of-movement', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freedom-of-movement', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('freedom-of-movement', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('freedom-of-movement', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('freedom-of-movement', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('freedom-of-movement', 3, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('freedom-of-movement', 0, 'land');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('freedom-of-movement', 1, 'devotion');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('freedom-of-movement', 'Freedom of Movement', 'Touch', 'A leather strap, bound around the arm or a similar appendage.', 0, '1 hour', 0, '1 action', 4, 'abjuration', '/api/2014/spells/freedom-of-movement');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('freezing-sphere', 0, 'A frigid globe of cold energy streaks from your fingertips to a point of your choice within range, where it explodes in a 60-foot-radius sphere. Each creature within the area must make a constitution saving throw. On a failed save, a creature takes 10d6 cold damage. On a successful save, it takes half as much damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('freezing-sphere', 1, 'If the globe strikes a body of water or a liquid that is principally water (not including water-based creatures), it freezes the liquid to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice. A trapped creature can use an action to make a Strength check against your spell save DC to break free.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('freezing-sphere', 2, 'You can refrain from firing the globe after completing the spell, if you wish. A small globe about the size of a sling stone, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling''s normal range). It shatters on impact, with the same effect as the normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn''t already shattered, it explodes.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('freezing-sphere', 0, 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 1d6 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freezing-sphere', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freezing-sphere', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('freezing-sphere', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('freezing-sphere', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('freezing-sphere', 'Freezing Sphere', '300 feet', 'A small crystal sphere.', 0, 'Instantaneous', 0, '1 action', 6, 'cold', 'evocation', '/api/2014/spells/freezing-sphere', 'con', 'half', 'sphere', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gaseous-form', 0, 'You transform a willing creature you touch, along with everything it''s wearing and carrying, into a misty cloud for the duration. The spell ends if the creature drops to 0 hit points. An incorporeal creature isn''t affected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gaseous-form', 1, 'While in this form, the target''s only method of movement is a flying speed of 10 feet. The target can enter and occupy the space of another creature. The target has resistance to nonmagical damage, and it has advantage on Strength, Dexterity, and constitution saving throws. The target can pass through small holes, narrow openings, and even mere cracks, though it treats liquids as though they were solid surfaces. The target can''t fall and remains hovering in the air even when stunned or otherwise incapacitated.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gaseous-form', 2, 'While in the form of a misty cloud, the target can''t talk or manipulate objects, and any objects it was carrying or holding can''t be dropped, used, or otherwise interacted with. The target can''t attack or cast spells.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gaseous-form', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gaseous-form', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gaseous-form', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gaseous-form', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gaseous-form', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gaseous-form', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('gaseous-form', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('gaseous-form', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('gaseous-form', 'Gaseous Form', 'Touch', 'A bit of gauze and a wisp of smoke.', 0, 'Up to 1 hour', 1, '1 action', 3, 'transmutation', '/api/2014/spells/gaseous-form');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gate', 0, 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gate', 1, 'The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gate', 2, 'Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gate', 3, 'When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn''t work). If that creature is on a plane other than the one you are on, the portal opens in the named creature''s immediate vicinity and draws the creature through it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the GM deems appropriate. It might leave, attack you, or help you.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gate', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gate', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gate', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gate', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gate', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('gate', 'Gate', '60 feet', 'A diamond worth at least 5,000gp.', 0, 'Up to 1 minute', 1, '1 action', 9, 'conjuration', '/api/2014/spells/gate');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('geas', 0, 'You place a magical command on a creature that you can see within range, forcing it to carry out some service or refrain from some action or course of activity as you decide. If the creature can understand you, it must succeed on a wisdom saving throw or become charmed by you for the duration. While the creature is charmed by you, it takes 5d10 psychic damage each time it acts in a manner directly counter to your instructions, but no more than once each day. A creature that can''t understand you is unaffected by the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('geas', 1, 'You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('geas', 2, 'You can end the spell early by using an action to dismiss it. A remove curse, greater restoration, or wish spell also ends it.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('geas', 0, 'When you cast this spell using a spell slot of 7th or 8th level, the duration is 1 year. When you cast this spell using a spell slot of 9th level, the spell lasts until it is ended by one of the spells mentioned above.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('geas', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('geas', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('geas', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('geas', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('geas', 3, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('geas', 4, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('geas', 'Geas', '60 feet', 0, '30 days', 0, '1 minute', 5, 'enchantment', '/api/2014/spells/geas', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gentle-repose', 0, 'You touch a corpse or other remains. For the duration, the target is protected from decay and can''t become undead.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gentle-repose', 1, 'The spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don''t count against the time limit of spells such as raise dead.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gentle-repose', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gentle-repose', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gentle-repose', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gentle-repose', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gentle-repose', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('gentle-repose', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('gentle-repose', 'Gentle Repose', 'Touch', 'A pinch of salt and one copper piece placed on each of the corpse''s eyes, which must remain there for the duration.', 1, '10 days', 0, '1 action', 2, 'necromancy', '/api/2014/spells/gentle-repose');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('giant-insect', 0, 'You transform up to ten centipedes, three spiders, five wasps, or one scorpion within range into giant versions of their natural forms for the duration. A centipede becomes a giant centipede, a spider becomes a giant spider, a wasp becomes a giant wasp, and a scorpion becomes a giant scorpion.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('giant-insect', 1, 'Each creature obeys your verbal commands, and in combat, they act on your turn each round. The GM has the statistics for these creatures and resolves their actions and movement.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('giant-insect', 2, 'A creature remains in its giant size for the duration, until it drops to 0 hit points, or until you use an action to dismiss the effect on it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('giant-insect', 3, 'The GM might allow you to choose different targets. For example, if you transform a bee, its giant version might have the same statistics as a giant wasp.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('giant-insect', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('giant-insect', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('giant-insect', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('giant-insect', 'Giant Insect', '30 feet', 0, 'Up to 10 minutes', 1, '1 action', 4, 'transmutation', '/api/2014/spells/giant-insect');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glibness', 0, 'Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('glibness', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('glibness', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('glibness', 1, 'warlock');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('glibness', 'Glibness', 'Self', 0, '1 hour', 0, '1 action', 8, 'transmutation', '/api/2014/spells/glibness');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 0, 'An immobile, faintly shimmering barrier springs into existence in a 10-foot radius around you and remains for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 1, 'Any spell of 5th level or lower cast from outside the barrier can''t affect creatures or objects within it, even if the spell is cast using a higher level spell slot. Such a spell can target creatures and objects within the barrier, but the spell has no effect on them. Similarly, the area within the barrier is excluded from the areas affected by such spells.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 0, 'When you cast this spell using a spell slot of 7th level or higher, the barrier blocks spells of one level higher for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('globe-of-invulnerability', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('globe-of-invulnerability', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('globe-of-invulnerability', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('globe-of-invulnerability', 'Globe of Invulnerability', 'Self', 'A glass or crystal bead that shatters when the spell ends.', 0, 'Up to 1 minute', 1, '1 action', 6, 'abjuration', '/api/2014/spells/globe-of-invulnerability', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 0, 'When you cast this spell, you inscribe a glyph that harms other creatures, either upon a surface (such as a table or a section of floor or wall) or within an object that can be closed (such as a book, a scroll, or a treasure chest) to conceal the glyph. If you choose a surface, the glyph can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 1, 'The glyph is nearly invisible and requires a successful Intelligence (Investigation) check against your spell save DC to be found.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 2, 'You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, the most typical triggers include touching or standing on the glyph, removing another object covering the glyph, approaching within a certain distance of the glyph, or manipulating the object on which the glyph is inscribed. For glyphs inscribed within an object, the most common triggers include opening that object, approaching within a certain distance of the object, or seeing or reading the glyph. Once a glyph is triggered, this spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 3, 'You can further refine the trigger so the spell activates only under certain circumstances or according to physical characteristics (such as height or weight), creature kind (for example, the ward could be set to affect aberrations or drow), or alignment. You can also set conditions for creatures that don''t trigger the glyph, such as those who say a certain password.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 4, 'When you inscribe the glyph, choose *explosive runes* or a *spell glyph*.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 5, '***Explosive Runes.*** When triggered, the glyph erupts with magical energy in a 20-foot-radius sphere centered on the glyph. The sphere spreads around corners. Each creature in the area must make a Dexterity saving throw. A creature takes 5d8 acid, cold, fire, lightning, or thunder damage on a failed saving throw (your choice when you create the glyph), or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('glyph-of-warding', 6, '***Spell Glyph.*** You can store a prepared spell of 3rd level or lower in the glyph by casting it as part of creating the glyph. The spell must target a single creature or an area. The spell being stored has no immediate effect when cast in this way. When the glyph is triggered, the stored spell is cast. If the spell has a target, it targets the creature that triggered the glyph. If the spell affects an area, the area is centered on that creature. If the spell summons hostile creatures or creates harmful objects or traps, they appear as close as possible to the intruder and attack it. If the spell requires concentration, it lasts until the end of its full duration.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('glyph-of-warding', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage of an explosive runes glyph increases by 1d8 for each slot level above 3rd. If you create a spell glyph, you can store any spell of up to the same level as the slot you use for the glyph of warding.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('glyph-of-warding', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('glyph-of-warding', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('glyph-of-warding', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('glyph-of-warding', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('glyph-of-warding', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('glyph-of-warding', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('glyph-of-warding', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('glyph-of-warding', 'Glyph of Warding', 'Touch', 'Incense and powdered diamond worth at least 200 gp, which the spell consumes.', 0, 'Until dispelled', 0, '1 hour', 3, 'abjuration', '/api/2014/spells/glyph-of-warding');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('goodberry', 0, 'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for a day.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('goodberry', 1, 'The berries lose their potency if they have not been consumed within 24 hours of the casting of this spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('goodberry', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('goodberry', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('goodberry', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('goodberry', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('goodberry', 1, 'ranger');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('goodberry', 'Goodberry', 'Touch', 'A sprig of mistletoe.', 0, 'Instantaneous', 0, '1 action', 1, 'transmutation', '/api/2014/spells/goodberry');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('grease', 0, 'Slick grease covers the ground in a 10-foot square centered on a point within range and turns it into difficult terrain for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('grease', 1, 'When the grease appears, each creature standing in its area must succeed on a dexterity saving throw or fall prone. A creature that enters the area or ends its turn there must also succeed on a dexterity saving throw or fall prone.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('grease', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('grease', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('grease', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('grease', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('grease', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('grease', 'Grease', '60 feet', 'A bit of pork rind or butter.', 0, '1 minute', 0, '1 action', 1, 'conjuration', '/api/2014/spells/grease', 'dex', 'none', 'cube', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-invisibility', 0, 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target''s person.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('greater-invisibility', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('greater-invisibility', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-invisibility', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-invisibility', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-invisibility', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('greater-invisibility', 0, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('greater-invisibility', 'Greater Invisibility', 'Touch', 0, 'Up to 1 minute', 1, '1 action', 4, 'illusion', '/api/2014/spells/greater-invisibility');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-restoration', 0, 'You imbue a creature you touch with positive energy to undo a debilitating effect. You can reduce the target''s exhaustion level by one, or end one of the following effects on the target:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-restoration', 1, '- One effect that charmed or petrified the target');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-restoration', 2, '- One curse, including the target''s attunement to a cursed magic item');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-restoration', 3, '- Any reduction to one of the target''s ability scores');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('greater-restoration', 4, '- One effect reducing the target''s hit point maximum');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('greater-restoration', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('greater-restoration', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('greater-restoration', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-restoration', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-restoration', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('greater-restoration', 2, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('greater-restoration', 'Greater Restoration', 'Touch', 'Diamond dust worth at least 100gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 action', 5, 'abjuration', '/api/2014/spells/greater-restoration');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guardian-of-faith', 0, 'A Large spectral guardian appears and hovers for the duration in an unoccupied space of your choice that you can see within range. The guardian occupies that space and is indistinct except for a gleaming sword and shield emblazoned with the symbol of your deity.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guardian-of-faith', 1, 'Any creature hostile to you that moves to a space within 10 feet of the guardian for the first time on a turn must succeed on a dexterity saving throw. The creature takes 20 radiant damage on a failed save, or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guardian-of-faith', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guardian-of-faith', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('guardian-of-faith', 'Guardian of Faith', '30 feet', 0, '8 hours', 0, '1 action', 4, 'radiant', 'conjuration', '/api/2014/spells/guardian-of-faith', 'dex', 'half', 'cylinder', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 0, 'You create a ward that protects up to 2,500 square feet of floor space (an area 50 feet square, or one hundred 5-foot squares or twenty-five 10-foot squares). The warded area can be up to 20 feet tall, and shaped as you desire. You can ward several stories of a stronghold by dividing the area among them, as long as you can walk into each contiguous area while you are casting the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 1, 'When you cast this spell, you can specify individuals that are unaffected by any or all of the effects that you choose. You can also specify a password that, when spoken aloud, makes the speaker immune to these effects.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 2, 'Guards and wards creates the following effects within the warded area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 3, '***Corridors.*** Fog fills all the warded corridors, making them heavily obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you will believe it is going in the opposite direction from the one it chooses.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 4, '***Doors.*** All doors in the warded area are magically locked, as if sealed by an arcane lock spell. In addition, you can cover up to ten doors with an illusion (equivalent to the illusory object function of the minor illusion spell) to make them appear as plain sections of wall.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 5, '***Stairs.*** Webs fill all stairs in the warded area from top to bottom, as the web spell. These strands regrow in 10 minutes if they are burned or torn away while guards and wards lasts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 6, '***Other Spell Effect.*** You can place your choice of one of the following magical effects within the warded area of the stronghold.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 7, '- Place dancing lights in four corridors. You can designate a simple program that the lights repeat as long as guards and wards lasts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 8, '- Place magic mouth in two locations.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 9, '- Place stinking cloud in two locations. The vapors appear in the places you designate; they return within 10 minutes if dispersed by wind while guards and wards lasts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 10, '- Place a constant gust of wind in one corridor or room.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 11, '- Place a suggestion in one location. You select an area of up to 5 feet square, and any creature that enters or passes through the area receives the suggestion mentally.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 12, 'The whole warded area radiates magic. A dispel magic cast on a specific effect, if successful, removes only that effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guards-and-wards', 13, 'You can create a permanently guarded and warded structure by casting this spell there every day for one year.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guards-and-wards', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guards-and-wards', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guards-and-wards', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guards-and-wards', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guards-and-wards', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('guards-and-wards', 'Guards and Wards', 'Touch', 'Burning incense, a small measure of brimstone and oil, a knotted string, a small amount of umber hulk blood, and a small silver rod worth at least 10 gp.', 0, '24 hours', 0, '10 minutes', 6, 'abjuration', '/api/2014/spells/guards-and-wards', 'cube', 2500);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guidance', 0, 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guidance', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guidance', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guidance', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guidance', 1, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('guidance', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('guidance', 'Guidance', 'Touch', 0, 'Up to 1 minute', 1, '1 action', 0, 'divination', '/api/2014/spells/guidance');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('guiding-bolt', 0, 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('guiding-bolt', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guiding-bolt', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('guiding-bolt', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('guiding-bolt', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('guiding-bolt', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('guiding-bolt', 'Guiding Bolt', '120 feet', 0, '1 round', 0, '1 action', 1, 'ranged', 'radiant', 'evocation', '/api/2014/spells/guiding-bolt');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gust-of-wind', 0, 'A line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the spell''s duration. Each creature that starts its turn in the line must succeed on a strength saving throw or be pushed 15 feet away from you in a direction following the line.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gust-of-wind', 1, 'Any creature in the line must spend 2 feet of movement for every 1 foot it moves when moving closer to you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gust-of-wind', 2, 'The gust disperses gas or vapor, and it extinguishes candles, torches, and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('gust-of-wind', 3, 'As a bonus action on each of your turns before the spell ends, you can change the direction in which the line blasts from you.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gust-of-wind', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gust-of-wind', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('gust-of-wind', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gust-of-wind', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gust-of-wind', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('gust-of-wind', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('gust-of-wind', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('gust-of-wind', 'Gust of Wind', 'Self', 'A legume seed.', 0, 'Up to 1 minute', 1, '1 action', 2, 'evocation', '/api/2014/spells/gust-of-wind', 'str', 'none', 'line', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 0, 'You touch a point and infuse an area around it with holy (or unholy) power. The area can have a radius up to 60 feet, and the spell fails if the radius includes an area already under the effect a hallow spell. The affected area is subject to the following effects.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 1, 'First, celestials, elementals, fey, fiends, and undead can''t enter the area, nor can such creatures charm, frighten, or possess creatures within it. Any creature charmed, frightened, or possessed by such a creature is no longer charmed, frightened, or possessed upon entering the area. You can exclude one or more of those types of creatures from this effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 2, 'Second, you can bind an extra effect to the area. Choose the effect from the following list, or choose an effect offered by the GM. Some of these effects apply to creatures in the area; you can designate whether the effect applies to all creatures, creatures that follow a specific deity or leader, or creatures of a specific sort, such as ores or trolls. When a creature that would be affected enters the spell''s area for the first time on a turn or starts its turn there, it can make a charisma saving throw. On a success, the creature ignores the extra effect until it leaves the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 3, '***Courage.*** Affected creatures can''t be frightened while in the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 4, '***Darkness.*** Darkness fills the area. Normal light, as well as magical light created by spells of a lower level than the slot you used to cast this spell, can''t illuminate the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 5, '***Daylight.*** Bright light fills the area. Magical darkness created by spells of a lower level than the slot you used to cast this spell can''t extinguish the light.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 6, '***Energy Protection.*** Affected creatures in the area have resistance to one damage type of your choice, except for bludgeoning, piercing, or slashing.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 7, '***Energy Vulnerability.*** Affected creatures in the area have vulnerability to one damage type of your choice, except for bludgeoning, piercing, or slashing.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 8, '***Everlasting Rest.*** Dead bodies interred in the area can''t be turned into undead.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 9, '***Extradimensional Interference.*** Affected creatures can''t move or travel using teleportation or by extradimensional or interplanar means.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 10, '***Fear.*** Affected creatures are frightened while in the area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 11, '***Silence.*** No sound can emanate from within the area, and no sound can reach into it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallow', 12, '***Tongues.*** Affected creatures can communicate with any other creature in the area, even if they don''t share a common language.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallow', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallow', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallow', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hallow', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hallow', 0, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('hallow', 'Hallow', 'Touch', 'Herbs, oils, and incense worth at least 1,000 gp, which the spell consumes.', 0, 'Until dispelled', 0, '24 hours', 5, 'evocation', '/api/2014/spells/hallow', 'cha', 'none', 'sphere', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallucinatory-terrain', 0, 'You make natural terrain in a 150-foot cube in range look, sound, and smell like some other sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Manufactured structures, equipment, and creatures within the area aren''t changed in appearance.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hallucinatory-terrain', 1, 'The tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to see through the illusion. If the difference isn''t obvious by touch, a creature carefully examining the illusion can attempt an Intelligence (Investigation) check against your spell save DC to disbelieve it. A creature who discerns the illusion for what it is, sees it as a vague image superimposed on the terrain.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallucinatory-terrain', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallucinatory-terrain', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hallucinatory-terrain', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hallucinatory-terrain', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hallucinatory-terrain', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hallucinatory-terrain', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hallucinatory-terrain', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hallucinatory-terrain', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('hallucinatory-terrain', 'Hallucinatory Terrain', '300 feet', 'A stone, a twig, and a bit of green plant.', 0, '24 hours', 0, '10 minutes', 4, 'illusion', '/api/2014/spells/hallucinatory-terrain', 'cube', 150);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('harm', 0, 'You unleash a virulent disease on a creature that you can see within range. The target must make a constitution saving throw. On a failed save, it takes 14d6 necrotic damage, or half as much damage on a successful save. The damage can''t reduce the target''s hit points below 1. If the target fails the saving throw, its hit point maximum is reduced for 1 hour by an amount equal to the necrotic damage it took. Any effect that removes a disease allows a creature''s hit point maximum to return to normal before that time passes.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('harm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('harm', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('harm', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('harm', 'Harm', '60 feet', 0, 'Instantaneous', 0, '1 action', 6, 'necrotic', 'necromancy', '/api/2014/spells/harm', 'con', 'half');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('haste', 0, 'Choose a willing creature that you can see within range. Until the spell ends, the target''s speed is doubled, it gains a +2 bonus to AC, it has advantage on dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('haste', 1, 'When the spell ends, the target can''t move or take actions until after its next turn, as a wave of lethargy sweeps over it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('haste', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('haste', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('haste', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('haste', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('haste', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('haste', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('haste', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('haste', 'Haste', '30 feet', 'A shaving of licorice root.', 0, 'Up to 1 minute', 1, '1 action', 3, 'transmutation', '/api/2014/spells/haste');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('heal', 0, 'Choose a creature that you can see within range. A surge of positive energy washes through the creature, causing it to regain 70 hit points. This spell also ends blindness, deafness, and any diseases affecting the target. This spell has no effect on constructs or undead.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('heal', 0, 'When you cast this spell using a spell slot of 7th level or higher, the amount of healing increases by 10 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heal', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heal', 1, 'S');
