INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('healing-word', 0, 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('healing-word', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.');
