INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('heat-metal', 1, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('heat-metal', 0, 'lore');
