INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hellish-rebuke', 0, 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a dexterity saving throw. It takes 2d10 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('hellish-rebuke', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hellish-rebuke', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hellish-rebuke', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hellish-rebuke', 0, 'warlock');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('hellish-rebuke', 'Hellish Rebuke', '60 feet', 0, 'Instantaneous', 0, '1 reaction', 1, 'fire', 'evocation', '/api/2014/spells/hellish-rebuke', 'dex', 'half');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('heroes-feast', 0, 'You bring forth a great feast, including magnificent food and drink. The feast takes 1 hour to consume and disappears at the end of that time, and the beneficial effects don''t set in until this hour is over. Up to twelve other creatures can partake of the feast.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('heroes-feast', 1, 'A creature that partakes of the feast gains several benefits. The creature is cured of all diseases and poison, becomes immune to poison and being frightened, and makes all wisdom saving throws with advantage. Its hit point maximum also increases by 2d10, and it gains the same number of hit points. These benefits last for 24 hours.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heroes-feast', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heroes-feast', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heroes-feast', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('heroes-feast', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('heroes-feast', 1, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('heroes-feast', 'Heroes'' Feast', '30 feet', 'A gem-encrusted bowl worth at least 1,000gp, which the spell consumes.', 0, 'Instantaneous', 0, '10 minutes', 6, 'conjuration', '/api/2014/spells/heroes-feast');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('heroism', 0, 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns. When the spell ends, the target loses any remaining temporary hit points from this spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heroism', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('heroism', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('heroism', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('heroism', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('heroism', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('heroism', 'Heroism', 'Touch', 0, 'Up to 1 minute', 1, '1 action', 1, 'enchantment', '/api/2014/spells/heroism');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hideous-laughter', 0, 'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn''t affected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hideous-laughter', 1, 'At the end of each of its turns, and each time it takes damage, the target can make another wisdom saving throw. The target had advantage on the saving throw if it''s triggered by damage. On a success, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hideous-laughter', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hideous-laughter', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hideous-laughter', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hideous-laughter', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hideous-laughter', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hideous-laughter', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('hideous-laughter', 'Hideous Laughter', '30 feet', 'Tiny tarts and a feather that is waved in the air.', 0, 'Up to 1 minute', 1, '1 action', 1, 'enchantment', '/api/2014/spells/hideous-laughter', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hold-monster', 0, 'Choose a creature you can see and reach. The target must make a saving throw of Wisdom or be paralyzed for the duration of the spell. This spell has no effect against the undead. At the end of each round, the target can make a new saving throw of Wisdom. If successful, the spell ends for the creature.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('hold-monster', 0, 'When you cast this spell using a level 6 or higher location, you can target an additional creature for each level of location beyond the fifth. The creatures must be within 30 feet o f each other when you target them.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hold-monster', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hold-monster', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hold-monster', 2, 'M');
