INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hold-monster', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hold-monster', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('hold-monster', 'Hold Monster', '90 feet', 'A small piece of iron.', 0, 'Up to 1 minute', 1, '1 action', 5, 'enchantment', '/api/2014/spells/hold-monster', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hold-person', 0, 'Choose a humanoid that you can see within range. The target must succeed on a wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another wisdom saving throw. On a success, the spell ends on the target.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('hold-person', 0, 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd. The humanoids must be within 30 feet of each other when you target them.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hold-person', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hold-person', 1, 'S');
