INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hold-person', 4, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hold-person', 5, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hold-person', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hold-person', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('hold-person', 'Hold Person', '60 feet', 'A small, straight piece of iron.', 0, 'Up to 1 minute', 1, '1 action', 2, 'enchantment', '/api/2014/spells/hold-person', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('holy-aura', 0, 'Divine light washes out from you and coalesces in a soft radiance in a 30-foot radius around you. Creatures of your choice in that radius when you cast this spell shed dim light in a 5-foot radius and have advantage on all saving throws, and other creatures have disadvantage on attack rolls against them until the spell ends. In addition, when a fiend or an undead hits an affected creature with a melee attack, the aura flashes with brilliant light. The attacker must succeed on a constitution saving throw or be blinded until the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('holy-aura', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('holy-aura', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('holy-aura', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('holy-aura', 0, 'cleric');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('holy-aura', 'Holy Aura', 'Self', 'A tiny reliquary worth at least 1,000gp containing a sacred relic, such as a scrap of cloth from a saint''s robe or a piece of parchment from a religious text.', 0, 'Up to 1 minute', 1, '1 action', 8, 'abjuration', '/api/2014/spells/holy-aura', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hunters-mark', 0, 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('hunters-mark', 0, 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hunters-mark', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hunters-mark', 0, 'ranger');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('hunters-mark', 'Hunter''s Mark', '90 feet', 0, 'Up to 1 hour', 1, '1 bonus action', 1, 'divination', '/api/2014/spells/hunters-mark');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hypnotic-pattern', 0, 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('hypnotic-pattern', 1, 'The spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hypnotic-pattern', 0, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('hypnotic-pattern', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hypnotic-pattern', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hypnotic-pattern', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hypnotic-pattern', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('hypnotic-pattern', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('hypnotic-pattern', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('hypnotic-pattern', 'Hypnotic Pattern', '120 feet', 'A glowing stick of incense or a crystal vial filled with phosphorescent material.', 0, 'Up to 1 minute', 1, '1 action', 3, 'illusion', '/api/2014/spells/hypnotic-pattern', 'wis', 'none', 'On a failed save, the creature becomes charmed for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ice-storm', 0, 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ice-storm', 1, 'Hailstones turn the storm''s area of effect into difficult terrain until the end of your next turn.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('ice-storm', 0, 'When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ice-storm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ice-storm', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ice-storm', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ice-storm', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ice-storm', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ice-storm', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('ice-storm', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('ice-storm', 'Ice Storm', '300 feet', 'A pinch of dust and a few drops of water.', 0, 'Instantaneous', 0, '1 action', 4, 'bludgeoning', 'evocation', '/api/2014/spells/ice-storm', 'dex', 'half', 'cylinder', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('identify', 0, 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('identify', 1, 'If you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('identify', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('identify', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('identify', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('identify', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('identify', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('identify', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('identify', 'Identify', 'Touch', 'A pearl worth at least 100gp and an owl feather.', 1, 'Instantaneous', 0, '1 minute', 1, 'divination', '/api/2014/spells/identify');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('illusory-script', 0, 'You write on parchment, paper, or some other suitable writing material and imbue it with a potent illusion that lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('illusory-script', 1, 'To you and any creatures you designate when you cast the spell, the writing appears normal, written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, you can cause the writing to appear to be an entirely different message, written in a different hand and language, though the language must be one you know.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('illusory-script', 2, 'Should the spell be dispelled, the original script and the illusion both disappear.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('illusory-script', 3, 'A creature with truesight can read the hidden message.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('illusory-script', 0, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('illusory-script', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('illusory-script', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('illusory-script', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('illusory-script', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('illusory-script', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('illusory-script', 'Illusory Script', 'Touch', 'A lead-based ink worth at least 10gp, which this spell consumes.', 1, '10 days', 0, '1 minute', 1, 'illusion', '/api/2014/spells/illusory-script');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 0, 'You create a magical restraint to hold a creature that you can see within range. The target must succeed on a wisdom saving throw or be bound by the spell; if it succeeds, it is immune to this spell if you cast it again. While affected by this spell, the creature doesn''t need to breathe, eat, or drink, and it doesn''t age. Divination spells can''t locate or perceive the target.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 1, 'When you cast the spell, you choose one of the following forms of imprisonment.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 2, '***Burial.*** The target is entombed far beneath the earth in a sphere of magical force that is just large enough to contain the target. Nothing can pass through the sphere, nor can any creature teleport or use planar travel to get into or out of it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 3, 'The special component for this version of the spell is a small mithral orb.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 4, '***Chaining.*** Heavy chains, firmly rooted in the ground, hold the target in place. The target is restrained until the spell ends, and it can''t move or be moved by any means until then.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 5, 'The special component for this version of the spell is a fine chain of precious metal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 6, '***Hedged Prison.*** The spell transports the target into a tiny demiplane that is warded against teleportation and planar travel. The demiplane can be a labyrinth, a cage, a tower, or any similar confined structure or area of your choice.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 7, 'The special component for this version of the spell is a miniature representation of the prison made from jade.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 8, '***Minimus Containment.*** The target shrinks to a height of 1 inch and is imprisoned inside a gemstone or similar object. Light can pass through the gemstone normally (allowing the target to see out and other creatures to see in), but nothing else can pass through, even by means of teleportation or planar travel. The gemstone can''t be cut or broken while the spell remains in effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 9, 'The special component for this version of the spell is a large, transparent gemstone, such as a corundum, diamond, or ruby.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 10, '***Slumber.*** The target falls asleep and can''t be awoken.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 11, 'The special component for this version of the spell consists of rare soporific herbs.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 12, '***Ending the Spell.*** During the casting of the spell, in any of its versions, you can specify a condition that will cause the spell to end and release the target. The condition can be as specific or as elaborate as you choose, but the GM must agree that the condition is reasonable and has a likelihood of coming to pass. The conditions can be based on a creature''s name, identity, or deity but otherwise must be based on observable actions or qualities and not based on intangibles such as level, class, or hit points.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 13, 'A dispel magic spell can end the spell only if it is cast as a 9th-level spell, targeting either the prison or the special component used to create it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('imprisonment', 14, 'You can use a particular special component to create only one prison at a time. If you cast the spell again using the same component, the target of the first casting is immediately freed from its binding.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('imprisonment', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('imprisonment', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('imprisonment', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('imprisonment', 0, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('imprisonment', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('imprisonment', 'Imprisonment', '30 feet', 'A vellum depiction or a carved statuette in the likeness of the target, and a special component that varies according to the version of the spell you choose, worth at least 500gp per Hit Die of the target.', 0, 'Until dispelled', 0, '1 minute', 9, 'abjuration', '/api/2014/spells/imprisonment', 'wis', 'none', 'If the creature succeeds, it is immune to this spell if you cast it again');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('incendiary-cloud', 0, 'A swirling cloud of smoke shot through with white-hot embers appears in a 20-foot-radius sphere centered on a point within range. The cloud spreads around corners and is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('incendiary-cloud', 1, 'When the cloud appears, each creature in it must make a dexterity saving throw. A creature takes 10d8 fire damage on a failed save, or half as much damage on a successful one. A creature must also make this saving throw when it enters the spell''s area for the first time on a turn or ends its turn there.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('incendiary-cloud', 2, 'The cloud moves 10 feet directly away from you in a direction that you choose at the start of each of your turns.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('incendiary-cloud', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('incendiary-cloud', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('incendiary-cloud', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('incendiary-cloud', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('incendiary-cloud', 'Incendiary Cloud', '150 feet', 0, 'Up to 1 minute', 1, '1 action', 8, 'fire', 'conjuration', '/api/2014/spells/incendiary-cloud', 'dex', 'half', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('inflict-wounds', 0, 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('inflict-wounds', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('inflict-wounds', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('inflict-wounds', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('inflict-wounds', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('inflict-wounds', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('inflict-wounds', 'Inflict Wounds', 'Touch', 0, 'Instantaneous', 0, '1 action', 1, 'melee', 'necrotic', 'necromancy', '/api/2014/spells/inflict-wounds');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('insect-plague', 0, 'Swarming, biting locusts fill a 20-foot-radius sphere centered on a point you choose within range. The sphere spreads around corners. The sphere remains for the duration, and its area is lightly obscured. The sphere''s area is difficult terrain.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('insect-plague', 1, 'When the area appears, each creature in it must make a constitution saving throw. A creature takes 4d10 piercing damage on a failed save, or half as much damage on a successful one. A creature must also make this saving throw when it enters the spell''s area for the first time on a turn or ends its turn there.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('insect-plague', 0, 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d10 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('insect-plague', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('insect-plague', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('insect-plague', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('insect-plague', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('insect-plague', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('insect-plague', 2, 'sorcerer');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('insect-plague', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('insect-plague', 'Insect Plague', '300 feet', 'A few grains of sugar, some kernels of grain, and a smear of fat.', 0, 'Up to 10 minutes', 1, '1 action', 5, 'piercing', 'conjuration', '/api/2014/spells/insect-plague', 'con', 'half', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('instant-summons', 0, 'You touch an object weighing 10 pounds or less whose longest dimension is 6 feet or less. The spell leaves an invisible mark on its surface and invisibly inscribes the name of the item on the sapphire you use as the material component. Each time you cast this spell, you must use a different sapphire.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('instant-summons', 1, 'At any time thereafter, you can use your action to speak the item''s name and crush the sapphire. The item instantly appears in your hand regardless of physical or planar distances, and the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('instant-summons', 2, 'If another creature is holding or carrying the item, crushing the sapphire doesn''t transport the item to you, but instead you learn who the creature possessing the object is and roughly where that creature is located at that moment.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('instant-summons', 3, 'Dispel magic or a similar effect successfully applied to the sapphire ends this spell''s effect.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('instant-summons', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('instant-summons', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('instant-summons', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('instant-summons', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('instant-summons', 'Instant Summons', 'Touch', 'A sapphire worth 1,000 gp.', 1, 'Until dispelled', 0, '1 minute', 6, 'conjuration', '/api/2014/spells/instant-summons');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('invisibility', 0, 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target''s person. The spell ends for a target that attacks or casts a spell.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('invisibility', 0, 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('invisibility', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('invisibility', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('invisibility', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('invisibility', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('invisibility', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('invisibility', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('invisibility', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('invisibility', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('invisibility', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('invisibility', 'Invisibility', 'Touch', 'An eyelash encased in gum arabic.', 0, 'Up to 1 hour', 1, '1 action', 2, 'illusion', '/api/2014/spells/invisibility');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('irresistible-dance', 0, 'Choose one creature that you can see within range. The target begins a comic dance in place: shuffling, tapping its feet, and capering for the duration. Creatures that can''t be charmed are immune to this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('irresistible-dance', 1, 'A dancing creature must use all its movement to dance without leaving its space and has disadvantage on dexterity saving throws and attack rolls. While the target is affected by this spell, other creatures have advantage on attack rolls against it. As an action, a dancing creature makes a wisdom saving throw to regain control of itself. On a successful save, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('irresistible-dance', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('irresistible-dance', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('irresistible-dance', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('irresistible-dance', 'Irresistible Dance', '30 feet', 0, 'Up to 1 minute', 1, '1 action', 6, 'enchantment', '/api/2014/spells/irresistible-dance');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('jump', 0, 'You touch a creature. The creature''s jump distance is tripled until the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('jump', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('jump', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('jump', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('jump', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('jump', 1, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('jump', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('jump', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('jump', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('jump', 'Jump', 'Touch', 'A grasshopper''s hind leg.', 0, '1 minute', 0, '1 action', 1, 'transmutation', '/api/2014/spells/jump');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('knock', 0, 'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('knock', 1, 'A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred. If the object has multiple locks, only one of them is unlocked.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('knock', 2, 'If you choose a target that is held shut with arcane lock, that spell is suppressed for 10 minutes, during which time the target can be opened and shut normally.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('knock', 3, 'When you cast the spell, a loud knock, audible from as far away as 300 feet, emanates from the target object.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('knock', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('knock', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('knock', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('knock', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('knock', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('knock', 'Knock', '60 feet', 0, 'Instantaneous', 0, '1 action', 2, 'transmutation', '/api/2014/spells/knock');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('legend-lore', 0, 'Name or describe a person, place, or object. The spell brings to your mind a brief summary of the significant lore about the thing you named. The lore might consist of current tales, forgotten stories, or even secret lore that has never been widely known. If the thing you named isn''t of legendary importance, you gain no information. The more information you already have about the thing, the more precise and detailed the information you receive is.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('legend-lore', 1, 'The information you learn is accurate but might be couched in figurative language. For example, if you have a mysterious magic axe on hand the spell might yield this information: "Woe to the evildoer whose hand touches the axe, for even the haft slices the hand of the evil ones. Only a true Child of Stone, lover and beloved of Moradin, may awaken the true powers of the axe, and only with the sacred word *Rudnogg* on the lips."');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('legend-lore', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('legend-lore', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('legend-lore', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('legend-lore', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('legend-lore', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('legend-lore', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('legend-lore', 'Legend Lore', 'Self', 'Incense worth at least 250 gp, which the spell consumes, and four ivory strips worth at least 50 gp each.', 0, 'Instantaneous', 0, '10 minutes', 5, 'divination', '/api/2014/spells/legend-lore');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('lesser-restoration', 0, 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.');
