INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('lesser-restoration', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lesser-restoration', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lesser-restoration', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lesser-restoration', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lesser-restoration', 3, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lesser-restoration', 4, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('lesser-restoration', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('lesser-restoration', 1, 'life');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('lesser-restoration', 2, 'devotion');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('lesser-restoration', 'Lesser Restoration', 'Touch', 0, 'Instantaneous', 0, '1 action', 2, 'abjuration', '/api/2014/spells/lesser-restoration');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('levitate', 0, 'One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds. An unwilling creature that succeeds on a constitution saving throw is unaffected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('levitate', 1, 'The target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target''s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can use your action to move the target, which must remain within the spell''s range.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('levitate', 2, 'When the spell ends, the target floats gently to the ground if it is still aloft.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('levitate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('levitate', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('levitate', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('levitate', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('levitate', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('levitate', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('levitate', 'Levitate', '60 feet', 'Either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end.', 0, 'Up to 10 minutes', 1, '1 action', 2, 'transmutation', '/api/2014/spells/levitate');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('light', 0, 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('light', 1, 'If you target an object held or worn by a hostile creature, that creature must succeed on a dexterity saving throw to avoid the spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('light', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('light', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('light', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('light', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('light', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('light', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('light', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('light', 'Light', 'Touch', 'A firefly or phosphorescent moss.', 0, '1 hour', 0, '1 action', 0, 'evocation', '/api/2014/spells/light', 'dex', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('lightning-bolt', 0, 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('lightning-bolt', 1, 'The lightning ignites flammable objects in the area that aren''t being worn or carried.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('lightning-bolt', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('lightning-bolt', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('lightning-bolt', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('lightning-bolt', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lightning-bolt', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('lightning-bolt', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('lightning-bolt', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('lightning-bolt', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('lightning-bolt', 'Lightning Bolt', 'Self', 'A bit of fur and a rod of amber, crystal, or glass.', 0, 'Instantaneous', 0, '1 action', 3, 'lightning', 'evocation', '/api/2014/spells/lightning-bolt', 'dex', 'half', 'line', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-animals-or-plants', 0, 'Describe or name a specific kind of beast or plant. Concentrating on the voice of nature in your surroundings, you learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-animals-or-plants', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-animals-or-plants', 1, 'S');
