INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-animals-or-plants', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-animals-or-plants', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('locate-animals-or-plants', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('locate-animals-or-plants', 'Locate Animals or Plants', 'Self', 'A bit of fur from a bloodhound.', 1, 'Instantaneous', 0, '1 action', 2, 'divination', '/api/2014/spells/locate-animals-or-plants');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-creature', 0, 'Describe or name a creature that is familiar to you. You sense the direction to the creature''s location, as long as that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-creature', 1, 'The spell can locate a specific creature known to you, or the nearest creature of a specific kind (such as a human or a unicorn), so long as you have seen such a creature up close--within 30 feet--at least once. If the creature you described or named is in a different form, such as being under the effects of a polymorph spell, this spell doesn''t locate the creature.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-creature', 2, 'This spell can''t locate a creature if running water at least 10 feet wide blocks a direct path between you and the creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-creature', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-creature', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-creature', 2, 'M');
