INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-creature', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-creature', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-creature', 3, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-creature', 4, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-creature', 5, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('locate-creature', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('locate-creature', 'Locate Creature', 'Self', 'A bit of fur from a bloodhound.', 0, 'Up to 1 hour', 1, '1 action', 4, 'divination', '/api/2014/spells/locate-creature');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-object', 0, 'Describe or name an object that is familiar to you. You sense the direction to the object''s location, as long as that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-object', 1, 'The spell can locate a specific object known to you, as long as you have seen it up close--within 30 feet--at least once. Alternatively, the spell can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('locate-object', 2, 'This spell can''t locate an object if any thickness of lead, even a thin sheet, blocks a direct path between you and the object.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-object', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-object', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('locate-object', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 3, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 4, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('locate-object', 5, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('locate-object', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('locate-object', 'Locate Object', 'Self', 'A forked twig.', 0, 'Up to 10 minutes', 1, '1 action', 2, 'divination', '/api/2014/spells/locate-object');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('longstrider', 0, 'You touch a creature. The target''s speed increases by 10 feet until the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('longstrider', 0, 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each spell slot above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('longstrider', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('longstrider', 1, 'S');
