INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('longstrider', 'Longstrider', 'Touch', 'A pinch of dirt.', 0, '1 hour', 0, '1 action', 1, 'transmutation', '/api/2014/spells/longstrider');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mage-armor', 0, 'You touch a willing creature who isn''t wearing armor, and a protective magical force surrounds it until the spell ends. The target''s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mage-armor', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mage-armor', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mage-armor', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-armor', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-armor', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mage-armor', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mage-armor', 'Mage Armor', 'Touch', 'A piece of cured leather.', 0, '8 hours', 0, '1 action', 1, 'abjuration', '/api/2014/spells/mage-armor');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mage-hand', 0, 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mage-hand', 1, 'You can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mage-hand', 2, 'The hand can''t attack, activate magic items, or carry more than 10 pounds.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mage-hand', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mage-hand', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-hand', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-hand', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-hand', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mage-hand', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mage-hand', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mage-hand', 'Mage Hand', '30 feet', 0, '1 minute', 0, '1 action', 0, 'conjuration', '/api/2014/spells/mage-hand');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 0, 'You create a 10-foot radius, 20-foot-tall cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear whenever the cylinder intersects with the floor or other surface.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 1, 'Choose one or more of the following types of creatures: celestials, elementals, fey, fiends, or undead. The circle affects a creature of the chosen type in the following ways:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 2, '- The creature can''t willingly enter the cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a charisma saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 3, '- The creature has disadvantage on attack rolls against targets within the cylinder.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 4, '- Targets within the cylinder can''t be charmed, frightened, or possessed by the creature.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-circle', 5, 'When you cast this spell, you can elect to cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the cylinder and protecting targets outside it.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('magic-circle', 0, 'When you cast this spell using a spell slot of 4th level or higher, the duration increases by 1 hour for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-circle', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-circle', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-circle', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-circle', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-circle', 1, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-circle', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-circle', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('magic-circle', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('magic-circle', 'Magic Circle', '10 feet', 'Holy water or powdered silver and iron worth at least 100 gp, which the spell consumes.', 0, '1 hour', 0, '1 minute', 3, 'abjuration', '/api/2014/spells/magic-circle', 'cha', 'other', 'cylinder', 10, 'If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a Charisma saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 0, 'Your body falls into a catatonic state as your soul leaves it and enters the container you used for the spell''s material component. While your soul inhabits the container, you are aware of your surroundings as if you were in the container''s space. You can''t move or use reactions. The only action you can take is to project your soul up to 100 feet out of the container, either returning to your living body (and ending the spell) or attempting to possess a humanoids body.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 1, 'You can attempt to possess any humanoid within 100 feet of you that you can see (creatures warded by a protection from evil and good or magic circle spell can''t be possessed). The target must make a charisma saving throw. On a failure, your soul moves into the target''s body, and the target''s soul becomes trapped in the container. On a success, the target resists your efforts to possess it, and you can''t attempt to possess it again for 24 hours.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 2, 'Once you possess a creature''s body, you control it. Your game statistics are replaced by the statistics of the creature, though you retain your alignment and your Intelligence, Wisdom, and Charisma scores. You retain the benefit of your own class features. If the target has any class levels, you can''t use any of its class features.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 3, 'Meanwhile, the possessed creature''s soul can perceive from the container using its own senses, but it can''t move or take actions at all.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 4, 'While possessing a body, you can use your action to return from the host body to the container if it is within 100 feet of you, returning the host creature''s soul to its body. If the host body dies while you''re in it, the creature dies, and you must make a charisma saving throw against your own spellcasting DC. On a success, you return to the container if it is within 100 feet of you. Otherwise, you die.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 5, 'If the container is destroyed or the spell ends, your soul immediately returns to your body. If your body is more than 100 feet away from you or if your body is dead when you attempt to return to it, you die. If another creature''s soul is in the container when it is destroyed, the creature''s soul returns to its body if the body is alive and within 100 feet. Otherwise, that creature dies.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-jar', 6, 'When the spell ends, the container is destroyed.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-jar', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-jar', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-jar', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-jar', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('magic-jar', 'Magic Jar', 'Self', 'A gem, crystal, reliquary, or some other ornamental container worth at least 500 gp.', 0, 'Until dispelled', 0, '1 minute', 6, 'necromancy', '/api/2014/spells/magic-jar', 'cha', 'other', 'On a failure, your soul moves into the target''s body, and the target''s soul becomes trapped in the container. On a success, the target resists your efforts to possess it, and you can''t attempt to possess it again for 24 hours.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-missile', 0, 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('magic-missile', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-missile', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-missile', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-missile', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-missile', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('magic-missile', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('magic-missile', 'Magic Missile', '120 feet', 0, 'Instantaneous', 0, '1 action', 1, 'force', 'evocation', '/api/2014/spells/magic-missile');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-mouth', 0, 'You plant a message to an object in the range of the spell. The message is verbalized when the trigger conditions are met. Choose an object that you see, and that is not worn or carried by another creature. Then say the message, which should not exceed 25 words but listening can take up to 10 minutes. Finally, establish the circumstances that trigger the spell to deliver your message.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-mouth', 1, 'When these conditions are satisfied, a magical mouth appears on the object and it articulates the message imitating your voice, the same tone used during implantation of the message. If the selected object has a mouth or something that approaches such as the mouth of a statue, the magic mouth come alive at this point, giving the illusion that the words come from the mouth of the object.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-mouth', 2, 'When you cast this spell, you may decide that the spell ends when the message is delivered or it can persist and repeat the message whenever circumstances occur.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-mouth', 3, 'The triggering circumstance can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the mouth to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-mouth', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-mouth', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-mouth', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-mouth', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-mouth', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('magic-mouth', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('magic-mouth', 'Magic Mouth', '30 feet', 'A honeycomb and jade dust of at least 10 inches, the spell consumes.', 1, 'Until dispelled', 0, '1 minute', 2, 'illusion', '/api/2014/spells/magic-mouth');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magic-weapon', 0, 'You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('magic-weapon', 0, 'When you cast this spell using a spell slot of 4th level or higher, the bonus increases to +2. When you use a spell slot of 6th level or higher, the bonus increases to +3.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-weapon', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magic-weapon', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-weapon', 0, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magic-weapon', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('magic-weapon', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('magic-weapon', 'Magic Weapon', 'Touch', 0, 'Up to 1 hour', 1, '1 bonus action', 2, 'transmutation', '/api/2014/spells/magic-weapon');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magnificent-mansion', 0, 'You conjure an extradimensional dwelling in range that lasts for the duration. You choose where its one entrance is located. The entrance shimmers faintly and is 5 feet wide and 10 feet tall. You and any creature you designate when you cast the spell can enter the extradimensional dwelling as long as the portal remains open. You can open or close the portal if you are within 30 feet of it. While closed, the portal is invisible.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magnificent-mansion', 1, 'Beyond the portal is a magnificent foyer with numerous chambers beyond. The atmosphere is clean, fresh, and warm.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('magnificent-mansion', 2, 'You can create any floor plan you like, but the space can''t exceed 50 cubes, each cube being 10 feet on each side. The place is furnished and decorated as you choose. It contains sufficient food to serve a nine course banquet for up to 100 people. A staff of 100 near-transparent servants attends all who enter. You decide the visual appearance of these servants and their attire. They are completely obedient to your orders. Each servant can perform any task a normal human servant could perform, but they can''t attack or take any action that would directly harm another creature. Thus the servants can fetch things, clean, mend, fold clothes, light fires, serve food, pour wine, and so on. The servants can go anywhere in the mansion but can''t leave it. Furnishings and other objects created by this spell dissipate into smoke if removed from the mansion. When the spell ends, any creatures inside the extradimensional space are expelled into the open spaces nearest to the entrance.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magnificent-mansion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magnificent-mansion', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('magnificent-mansion', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magnificent-mansion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('magnificent-mansion', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('magnificent-mansion', 'Magnificent Mansion', '300 feet', 'A miniature portal carved from ivory, a small piece of polished marble, and a tiny silver spoon, each item worth at least 5 gp.', 0, '24 hours', 0, '1 minute', 7, 'conjuration', '/api/2014/spells/magnificent-mansion', 'cube', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('major-image', 0, 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot cube. The image appears at a spot that you can see within range and lasts for the duration. It seems completely real, including sounds, smells, and temperature appropriate to the thing depicted. You can''t create sufficient heat or cold to cause damage, a sound loud enough to deal thunder damage or deafen a creature, or a smell that might sicken a creature (like a troglodyte''s stench).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('major-image', 1, 'As long as you are within range of the illusion, you can use your action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('major-image', 2, 'Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('major-image', 0, 'When you cast this spell using a spell slot of 6th level or higher, the spell lasts until dispelled, without requiring your concentration.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('major-image', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('major-image', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('major-image', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('major-image', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('major-image', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('major-image', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('major-image', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('major-image', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('major-image', 'Major Image', '120 feet', 'A bit of fleece.', 0, 'Up to 10 minutes', 1, '1 action', 3, 'illusion', '/api/2014/spells/major-image');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-cure-wounds', 0, 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('mass-cure-wounds', 0, 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-cure-wounds', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-cure-wounds', 1, 'S');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-cure-wounds', 5, '3d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-cure-wounds', 6, '4d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-cure-wounds', 7, '5d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-cure-wounds', 8, '6d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-cure-wounds', 9, '7d8 + MOD');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-cure-wounds', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-cure-wounds', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-cure-wounds', 2, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mass-cure-wounds', 0, 'life');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('mass-cure-wounds', 'Mass Cure Wounds', '60 feet', 0, 'Instantaneous', 0, '1 action', 5, 'conjuration', '/api/2014/spells/mass-cure-wounds', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-heal', 0, 'A flood of healing energy flows from you into injured creatures around you. You restore up to 700 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell are also cured of all diseases and any effect making them blinded or deafened. This spell has no effect on undead or constructs.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-heal', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-heal', 1, 'S');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-heal', 9, '700');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-heal', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mass-heal', 'Mass Heal', '60 feet', 0, 'Instantaneous', 0, '1 action', 9, 'conjuration', '/api/2014/spells/mass-heal');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-healing-word', 0, 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('mass-healing-word', 0, 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-healing-word', 0, 'V');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 3, '1d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 4, '2d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 5, '3d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 6, '4d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 7, '5d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 8, '6d4 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('mass-healing-word', 9, '7d4 + MOD');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-healing-word', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mass-healing-word', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mass-healing-word', 'Mass Healing Word', '60 feet', 0, 'Instantaneous', 0, '1 bonus action', 3, 'evocation', '/api/2014/spells/mass-healing-word');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-suggestion', 0, 'You suggest a course of activity (limited to a sentence or two) and magically influence up to twelve creatures of your choice that you can see within range and that can hear and understand you. Creatures that can''t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act automatically negates the effect of the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-suggestion', 1, 'Each target must make a wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-suggestion', 2, 'You can also specify conditions that will trigger a special activity during the duration. For example, you might suggest that a group of soldiers give all their money to the first beggar they meet. If the condition isn''t met before the spell ends, the activity isn''t performed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mass-suggestion', 3, 'If you or any of your companions damage a creature affected by this spell, the spell ends for that creature.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('mass-suggestion', 0, 'When you cast this spell using a 7th-level spell slot, the duration is 10 days. When you use an 8th-level spell slot, the duration is 30 days. When you use a 9th-level spell slot, the duration is a year and a day.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-suggestion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mass-suggestion', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-suggestion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-suggestion', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-suggestion', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mass-suggestion', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('mass-suggestion', 'Mass Suggestion', '60 feet', 'A snake''s tongue and either a bit of honeycomb or a drop of sweet oil.', 0, '24 hours', 0, '1 action', 6, 'enchantment', '/api/2014/spells/mass-suggestion', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('maze', 0, 'You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('maze', 1, 'The target can use its action to attempt to escape. When it does so, it makes a DC 20 Intelligence check. If it succeeds, it escapes, and the spell ends (a minotaur or goristro demon automatically succeeds).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('maze', 2, 'When the spell ends, the target reappears in the space it left or, if that space is occupied, in the nearest unoccupied space.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('maze', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('maze', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('maze', 0, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('maze', 'Maze', '60 feet', 0, 'Up to 10 minutes', 1, '1 action', 8, 'conjuration', '/api/2014/spells/maze');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('meld-into-stone', 0, 'You step into a stone object or surface large enough to fully contain your body, melding yourself and all the equipment you carry with the stone for the duration. Using your movement, you step into the stone at a point you can touch. Nothing of your presence remains visible or otherwise detectable by nonmagical senses.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('meld-into-stone', 1, 'While merged with the stone, you can''t see what occurs outside it, and any Wisdom (Perception) checks you make to hear sounds outside it are made with disadvantage. You remain aware of the passage of time and can cast spells on yourself while merged in the stone. You can use your movement to leave the stone where you entered it, which ends the spell. You otherwise can''t move.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('meld-into-stone', 2, 'Minor physical damage to the stone doesn''t harm you, but its partial destruction or a change in its shape (to the extent that you no longer fit within it) expels you and deals 6d6 bludgeoning damage to you. The stone''s complete destruction (or transmutation into a different substance) expels you and deals 50 bludgeoning damage to you. If expelled, you fall prone in an unoccupied space closest to where you first entered.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('meld-into-stone', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('meld-into-stone', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('meld-into-stone', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('meld-into-stone', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('meld-into-stone', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('meld-into-stone', 'Meld Into Stone', 'Touch', 1, '8 hours', 0, '1 action', 3, 'transmutation', '/api/2014/spells/meld-into-stone');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mending', 0, 'This spell repairs a single break or tear in an object you touch, such as a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no longer than 1 foot in any dimension, you mend it, leaving no trace of the former damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mending', 1, 'This spell can physically repair a magic item or construct, but the spell can''t restore magic to such an object.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mending', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mending', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mending', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mending', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mending', 1, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mending', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mending', 3, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mending', 4, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mending', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mending', 'Mending', 'Touch', 'Two lodestones.', 0, 'Instantaneous', 0, '1 minute', 0, 'transmutation', '/api/2014/spells/mending');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('message', 0, 'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('message', 1, 'You can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn''t have to follow a straight line and can travel freely around corners or through openings.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('message', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('message', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('message', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('message', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('message', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('message', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('message', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('message', 'Message', '120 feet', 'A short piece of copper wire.', 0, '1 round', 0, '1 action', 0, 'transmutation', '/api/2014/spells/message');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('meteor-swarm', 0, 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('meteor-swarm', 1, 'The spell damages objects in the area and ignites flammable objects that aren''t being worn or carried.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('meteor-swarm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('meteor-swarm', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('meteor-swarm', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('meteor-swarm', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('meteor-swarm', 'Meteor Swarm', '1 mile', 0, 'Instantaneous', 0, '1 action', 9, 'fire', 'evocation', '/api/2014/spells/meteor-swarm', 'dex', 'half', 'sphere', 40);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mind-blank', 0, 'Until the spell ends, one willing creature you touch is immune to psychic damage, any effect that would sense its emotions or read its thoughts, divination spells, and the charmed condition. The spell even foils wish spells and spells or effects of similar power used to affect the target''s mind or to gain information about the target.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mind-blank', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mind-blank', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mind-blank', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mind-blank', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mind-blank', 'Mind Blank', 'Touch', 0, '24 hours', 0, '1 action', 8, 'abjuration', '/api/2014/spells/mind-blank');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('minor-illusion', 0, 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('minor-illusion', 1, 'If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else''s voice, a lion''s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('minor-illusion', 2, 'If you create an image of an object--such as a chair, muddy footprints, or a small chest--it must be no larger than a 5-foot cube. The image can''t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, because things can pass through it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('minor-illusion', 3, 'If a creature uses its action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('minor-illusion', 0, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('minor-illusion', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('minor-illusion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('minor-illusion', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('minor-illusion', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('minor-illusion', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('minor-illusion', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('minor-illusion', 'Minor Illusion', '30 feet', 'A bit of fleece.', 0, '1 minute', 0, '1 action', 0, 'illusion', '/api/2014/spells/minor-illusion');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirage-arcane', 0, 'You make terrain in an area up to 1 mile square look, sound, smell, and even feel like some other sort of terrain. The terrain''s general shape remains the same, however. Open fields or a road could be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirage-arcane', 1, 'Similarly, you can alter the appearance of structures, or add them where none are present. The spell doesn''t disguise, conceal, or add creatures.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirage-arcane', 2, 'The illusion includes audible, visual, tactile, and olfactory elements, so it can turn clear ground into difficult terrain (or vice versa) or otherwise impede movement through the area. Any piece of the illusory terrain (such as a rock or stick) that is removed from the spell''s area disappears immediately.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirage-arcane', 3, 'Creatures with truesight can see through the illusion to the terrain''s true form; however, all other elements of the illusion remain, so while the creature is aware of the illusion''s presence, the creature can still physically interact with the illusion.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mirage-arcane', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mirage-arcane', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirage-arcane', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirage-arcane', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirage-arcane', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('mirage-arcane', 'Mirage Arcane', 'Sight', 0, '10 days', 0, '10 minutes', 7, 'illusion', '/api/2014/spells/mirage-arcane', 'cube', 5280);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirror-image', 0, 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it''s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirror-image', 1, 'Each time a creature targets you with an attack during the spell''s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirror-image', 2, 'If you have three duplicates, you must roll a 6 or higher to change the attack''s target to a duplicate. With two duplicates, you must roll an 8 or higher. With one duplicate, you must roll an 11 or higher.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirror-image', 3, 'A duplicate''s AC equals 10 + your Dexterity modifier. If an attack hits a duplicate, the duplicate is destroyed. A duplicate can be destroyed only by an attack that hits it. It ignores all other damage and effects. The spell ends when all three duplicates are destroyed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mirror-image', 4, 'A creature is unaffected by this spell if it can''t see, if it relies on senses other than sight, such as blindsight, or if it can perceive illusions as false, as with truesight.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mirror-image', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mirror-image', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirror-image', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirror-image', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mirror-image', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mirror-image', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('mirror-image', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mirror-image', 'Mirror Image', 'Self', 0, '1 minute', 0, '1 action', 2, 'illusion', '/api/2014/spells/mirror-image');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mislead', 0, 'You become invisible at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends if you attack or cast a spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mislead', 1, 'You can use your action to move your illusory double up to twice your speed and make it gesture, speak, and behave in whatever way you choose.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('mislead', 2, 'You can see through its eyes and hear through its ears as if you were located where it is. On each of your turns as a bonus action, you can switch from using its senses to using your own, or back again. While you are using its senses, you are blinded and deafened in regard to your own surroundings.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('mislead', 0, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mislead', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('mislead', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('mislead', 'Mislead', 'Self', 0, 'Up to 1 hour', 1, '1 action', 5, 'illusion', '/api/2014/spells/mislead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('misty-step', 0, 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('misty-step', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('misty-step', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('misty-step', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('misty-step', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('misty-step', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('misty-step', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('misty-step', 'Misty Step', 'Self', 0, 'Instantaneous', 0, '1 bonus action', 2, 'conjuration', '/api/2014/spells/misty-step');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('modify-memory', 0, 'You attempt to reshape another creature''s memories. One creature that you can see must make a wisdom saving throw. If you are fighting the creature, it has advantage on the saving throw. On a failed save, the target becomes charmed by you for the duration. The charmed target is incapacitated and unaware of its surroundings, though it can still hear you. If it takes any damage or is targeted by another spell, this spell ends, and none of the target''s memories are modified.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('modify-memory', 1, 'While this charm lasts, you can affect the target''s memory of an event that it experienced within the last 24 hours and that lasted no more than 10 minutes. You can permanently eliminate all memory of the event, allow the target to recall the event with perfect clarity and exacting detail, change its memory of the details of the event, or create a memory of some other event.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('modify-memory', 2, 'You must speak to the target to describe how its memories are affected, and it must be able to understand your language for the modified memories to take root. Its mind fills in any gaps in the details of your description. If the spell ends before you have finished describing the modified memories, the creature''s memory isn''t altered. Otherwise, the modified memories take hold when the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('modify-memory', 3, 'A modified memory doesn''t necessarily affect how a creature behaves, particularly if the memory contradicts the creature''s natural inclinations, alignment, or beliefs. An illogical modified memory, such as implanting a memory of how much the creature enjoyed dousing itself in acid, is dismissed, perhaps as a bad dream. The GM might deem a modified memory too nonsensical to affect a creature in a significant manner.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('modify-memory', 4, 'A remove curse or greater restoration spell cast on the target restores the creature''s true memory.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('modify-memory', 0, 'If you cast this spell using a spell slot of 6th level or higher, you can alter the target''s memories of an event that took place up to 7 days ago (6th level), 30 days ago (7th level), 1 year ago (8th level), or any time in the creature''s past (9th level).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('modify-memory', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('modify-memory', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('modify-memory', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('modify-memory', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('modify-memory', 'Modify Memory', '30 feet', 0, 'Up to 1 minute', 1, '1 action', 5, 'enchantment', '/api/2014/spells/modify-memory', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('moonbeam', 0, 'A silvery beam of pale light shines down in a 5-foot radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('moonbeam', 1, 'When a creature enters the spell''s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('moonbeam', 2, 'A shapechanger makes its saving throw with disadvantage. If it fails, it also instantly reverts to its original form and can''t assume a different form until it leaves the spell''s light.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('moonbeam', 3, 'On each of your turns after you cast this spell, you can use an action to move the beam 60 feet in any direction.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('moonbeam', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1dl0 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('moonbeam', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('moonbeam', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('moonbeam', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('moonbeam', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('moonbeam', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('moonbeam', 'Moonbeam', '120 feet', 'Several seeds of any moonseed plant and a piece of opalescent feldspar.', 0, 'Up to 1 minute', 1, '1 action', 2, 'radiant', 'evocation', '/api/2014/spells/moonbeam', 'con', 'half', 'cylinder', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('move-earth', 0, 'Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You can raise or lower the area''s elevation, create or fill in a trench, erect or flatten a wall, or form a pillar. The extent of any such changes can''t exceed half the area''s largest dimension. So, if you affect a 40-foot square, you can create a pillar up to 20 feet high, raise or lower the square''s elevation by up to 20 feet, dig a trench up to 20 feet deep, and so on. It takes 10 minutes for these changes to complete.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('move-earth', 1, 'At the end of every 10 minutes you spend concentrating on the spell, you can choose a new area of terrain to affect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('move-earth', 2, 'Because the terrain''s transformation occurs slowly, creatures in the area can''t usually be trapped or injured by the ground''s movement.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('move-earth', 3, 'This spell can''t manipulate natural stone or stone construction. Rocks and structures shift to accommodate the new terrain. If the way you shape the terrain would make a structure unstable, it might collapse.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('move-earth', 4, 'Similarly, this spell doesn''t directly affect plant growth. The moved earth carries any plants along with it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('move-earth', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('move-earth', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('move-earth', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('move-earth', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('move-earth', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('move-earth', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('move-earth', 'Move Earth', '120 feet', 'An iron blade and a small bag containing a mixture of soils--clay, loam, and sand.', 0, 'Up to 2 hours', 1, '1 action', 6, 'transmutation', '/api/2014/spells/move-earth', 'cone', 40);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('nondetection', 0, 'For the duration, you hide a target that you touch from divination magic. The target can be a willing creature or a place or an object no larger than 10 feet in any dimension. The target can''t be targeted by any divination magic or perceived through magical scrying sensors.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('nondetection', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('nondetection', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('nondetection', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('nondetection', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('nondetection', 1, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('nondetection', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('nondetection', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('nondetection', 'Nondetection', 'Touch', 'A pinch of diamond dust worth 25 gp sprinkled over the target, which the spell consumes.', 0, '8 hours', 0, '1 action', 3, 'abjuration', '/api/2014/spells/nondetection');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('pass-without-trace', 0, 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can''t be tracked except by magical means. A creature that receives this bonus leaves behind no tracks or other traces of its passage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('pass-without-trace', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('pass-without-trace', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('pass-without-trace', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('pass-without-trace', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('pass-without-trace', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('pass-without-trace', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('pass-without-trace', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('pass-without-trace', 'Pass Without Trace', 'Self', 'Ashes from a burned leaf of mistletoe and a sprig of spruce.', 0, 'Up to 1 hour', 1, '1 action', 2, 'abjuration', '/api/2014/spells/pass-without-trace');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('passwall', 0, 'A passage appears at a point of your choice that you can see on a wooden, plaster, or stone surface (such as a wall, a ceiling, or a floor) within range, and lasts for the duration. You choose the opening''s dimensions: up to 5 feet wide, 8 feet tall, and 20 feet deep. The passage creates no instability in a structure surrounding it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('passwall', 1, 'When the opening disappears, any creatures or objects still in the passage created by the spell are safely ejected to an unoccupied space nearest to the surface on which you cast the spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('passwall', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('passwall', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('passwall', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('passwall', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('passwall', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('passwall', 'Passwall', '30 feet', 'A pinch of sesame seeds.', 0, '1 hour', 0, '1 action', 5, 'transmutation', '/api/2014/spells/passwall');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('phantasmal-killer', 0, 'You tap into the nightmares of a creature you can see within range and create an illusory manifestation of its deepest fears, visible only to that creature. The target must make a wisdom saving throw. On a failed save, the target becomes frightened for the duration. At the start of each of the target''s turns before the spell ends, the target must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('phantasmal-killer', 0, 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d10 for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('phantasmal-killer', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('phantasmal-killer', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('phantasmal-killer', 0, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('phantasmal-killer', 'Phantasmal Killer', '120 feet', 0, 'Up to 1 minute', 1, '1 action', 4, 'psychic', 'illusion', '/api/2014/spells/phantasmal-killer', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('phantom-steed', 0, 'A Large quasi-real, horselike creature appears on the ground in an unoccupied space of your choice within range. You decide the creature''s appearance, but it is equipped with a saddle, bit, and bridle. Any of the equipment created by the spell vanishes in a puff of smoke if it is carried more than 10 feet away from the steed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('phantom-steed', 1, 'For the duration, you or a creature you choose can ride the steed. The creature uses the statistics for a riding horse, except it has a speed of 100 feet and can travel 10 miles in an hour, or 13 miles at a fast pace. When the spell ends, the steed gradually fades, giving the rider 1 minute to dismount. The spell ends if you use an action to dismiss it or if the steed takes any damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('phantom-steed', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('phantom-steed', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('phantom-steed', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('phantom-steed', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('phantom-steed', 'Phantom Steed', '30 feet', 1, '1 hour', 0, '1 minute', 3, 'illusion', '/api/2014/spells/phantom-steed');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 0, 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a primordial, a demon prince, or some other being of cosmic power. That entity sends a celestial, an elemental, or a fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature''s name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (GM''s choice).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 1, 'When the creature appears, it is under no compulsion to behave in any particular way. You can ask the creature to perform a service in exchange for payment, but it isn''t obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 2, 'Payment can take a variety of forms. A celestial might require a sizable donation of gold or magic items to an allied temple, while a fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 3, 'As a rule of thumb, a task that can be measured in minutes requires a payment worth 100 gp per minute. A task measured in hours requires 1,000 gp per hour. And a task measured in days (up to 10 days) requires 10,000 gp per day. The GM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature''s ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 4, 'After the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you, if appropriate to the task and if possible. If you are unable to agree on a price for the creature''s service, the creature immediately returns to its home plane.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-ally', 5, 'A creature enlisted to join your group counts as a member of it, receiving a full share of experience points awarded.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('planar-ally', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('planar-ally', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('planar-ally', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('planar-ally', 'Planar Ally', '60 feet', 0, 'Instantaneous', 0, '10 minutes', 6, 'conjuration', '/api/2014/spells/planar-ally');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-binding', 0, 'With this spell, you attempt to bind a celestial, an elemental, a fey, or a fiend to your service. The creature must be within range for the entire casting of the spell. (Typically, the creature is first summoned into the center of an inverted magic circle in order to keep it trapped while this spell is cast.) At the completion of the casting, the target must make a charisma saving throw. On a failed save, it is bound to serve you for the duration. If the creature was summoned or created by another spell, that spell''s duration is extended to match the duration of this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('planar-binding', 1, 'A bound creature must follow your instructions to the best of its ability. You might command the creature to accompany you on an adventure, to guard a location, or to deliver a message. The creature obeys the letter of your instructions, but if the creature is hostile to you, it strives to twist your words to achieve its own objectives. If the creature carries out your instructions completely before the spell ends, it travels to you to report this fact if you are on the same plane of existence. If you are on a different plane of existence, it returns to the place where you bound it and remains there until the spell ends.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('planar-binding', 0, 'When you cast this spell using a spell slot of a higher level, the duration increases to 10 days with a 6th-level slot, to 30 days with a 7th-level slot, to 180 days with an 8th-level slot, and to a year and a day with a 9th-level spell slot.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('planar-binding', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('planar-binding', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('planar-binding', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('planar-binding', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('planar-binding', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('planar-binding', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('planar-binding', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('planar-binding', 'Planar Binding', '60 feet', 'A jewel worth at least 1,000 gp, which the spell consumes.', 0, '24 hours', 0, '1 hour', 5, 'abjuration', '/api/2014/spells/planar-binding', 'cha', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plane-shift', 0, 'You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as the City of Brass on the Elemental Plane of Fire or the palace of Dispater on the second level of the Nine Hells, and you appear in or near that destination. If you are trying to reach the City of Brass, for example, you might arrive in its Street of Steel, before its Gate of Ashes, or looking at the city from across the Sea of Fire, at the GM''s discretion.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plane-shift', 1, 'Alternatively, if you know the sigil sequence of a teleportation circle on another plane of existence, this spell can take you to that circle. If the teleportation circle is too small to hold all the creatures you transported, they appear in the closest unoccupied spaces next to the circle.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plane-shift', 2, 'You can use this spell to banish an unwilling creature to another plane. Choose a creature within your reach and make a melee spell attack against it. On a hit, the creature must make a charisma saving throw. If the creature fails this save, it is transported to a random location on the plane of existence you specify. A creature so transported must find its own way back to your current plane of existence.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('plane-shift', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('plane-shift', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('plane-shift', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plane-shift', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plane-shift', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plane-shift', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plane-shift', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plane-shift', 4, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, attack_type, school_index, url, dc_dc_type_index, dc_dc_success, dc_desc) VALUES ('plane-shift', 'Plane Shift', 'Touch', 'A forked, metal rod worth at least 250 gp, attuned to a particular plane of existence.', 0, 'Instantaneous', 0, '1 action', 7, 'melee', 'conjuration', '/api/2014/spells/plane-shift', 'cha', 'none', 'If the creature fails this save, it is transported to a random location on the plane of existence you specify. A creature so transported must find its own way back to your current plane of existence.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plant-growth', 0, 'This spell channels vitality into plants within a specific area. There are two possible uses for the spell, granting either immediate or long-term benefits.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plant-growth', 1, 'If you cast this spell using 1 action, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plant-growth', 2, 'You can exclude one or more areas of any size within the spell''s area from being affected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('plant-growth', 3, 'If you cast this spell over 8 hours, you enrich the land. All plants in a half-mile radius centered on a point within range become enriched for 1 year. The plants yield twice the normal amount of food when harvested.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('plant-growth', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('plant-growth', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plant-growth', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plant-growth', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('plant-growth', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('plant-growth', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('plant-growth', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('plant-growth', 'Plant Growth', '150 feet', 0, 'Instantaneous', 0, '1 action', 3, 'transmutation', '/api/2014/spells/plant-growth');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('poison-spray', 0, 'You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a constitution saving throw or take 1d12 poison damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('poison-spray', 1, 'This spell''s damage increases by 1d12 when you reach 5th level (2d12), 11th level (3d12), and 17th level (4d12).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('poison-spray', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('poison-spray', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('poison-spray', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('poison-spray', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('poison-spray', 2, 'wizard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('poison-spray', 3, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('poison-spray', 'Poison Spray', '10 feet', 0, 'Instantaneous', 0, '1 action', 0, 'poison', 'conjuration', '/api/2014/spells/poison-spray', 'con', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('polymorph', 0, 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a wisdom saving throw to avoid the effect. A shapechanger automatically succeeds on this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('polymorph', 1, 'The transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target''s (or the target''s level, if it doesn''t have a challenge rating). The target''s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast. It retains its alignment and personality.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('polymorph', 2, 'The target assumes the hit points of its new form. When it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('polymorph', 3, 'The creature is limited in the actions it can perform by the nature of its new form, and it can''t speak, cast spells, or take any other action that requires hands or speech.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('polymorph', 4, 'The target''s gear melds into the new form. The creature can''t activate, use, wield, or otherwise benefit from any of its equipment.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('polymorph', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('polymorph', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('polymorph', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('polymorph', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('polymorph', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('polymorph', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('polymorph', 3, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('polymorph', 'Polymorph', '60 feet', 'A caterpillar cocoon.', 0, 'Up to 1 hour', 1, '1 action', 4, 'transmutation', '/api/2014/spells/polymorph', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('power-word-kill', 0, 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('power-word-kill', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-kill', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-kill', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-kill', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-kill', 3, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('power-word-kill', 'Power Word Kill', '60 feet', 0, 'Instantaneous', 0, '1 action', 9, 'enchantment', '/api/2014/spells/power-word-kill');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('power-word-stun', 0, 'You speak a word of power that can overwhelm the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('power-word-stun', 1, 'The stunned target must make a constitution saving throw at the end of each of its turns. On a successful save, this stunning effect ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('power-word-stun', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-stun', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-stun', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-stun', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('power-word-stun', 3, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('power-word-stun', 'Power Word Stun', '60 feet', 0, 'Instantaneous', 0, '1 action', 8, 'enchantment', '/api/2014/spells/power-word-stun');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prayer-of-healing', 0, 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('prayer-of-healing', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prayer-of-healing', 0, 'V');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 2, '2d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 3, '3d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 4, '4d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 5, '5d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 6, '6d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 7, '7d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 8, '8d8 + MOD');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('prayer-of-healing', 9, '9d8 + MOD');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prayer-of-healing', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('prayer-of-healing', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('prayer-of-healing', 'Prayer of Healing', '30 feet', 0, 'Instantaneous', 0, '10 minutes', 2, 'evocation', '/api/2014/spells/prayer-of-healing');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 0, 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within ''range'':');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 1, 'You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 2, 'You instantaneously light or snuff out a candle, a torch, or a small campfire.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 3, 'You instantaneously clean or soil an object no larger than 1 cubic foot.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 4, 'You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 5, 'You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 6, 'You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prestidigitation', 7, 'If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time, and you can dismiss such an effect as an action.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prestidigitation', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prestidigitation', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prestidigitation', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prestidigitation', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prestidigitation', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prestidigitation', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('prestidigitation', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('prestidigitation', 'Prestidigitation', '10 feet', 0, '1 hour', 0, '1 action', 0, 'transmutation', '/api/2014/spells/prestidigitation');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 0, 'Eight multicolored rays of light flash from your hand. Each ray is a different color and has a different power and purpose. Each creature in a 60-foot cone must make a dexterity saving throw. For each target, roll a d8 to determine which color ray affects it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 1, '***1. Red.*** The target takes 10d6 fire damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 2, '***2. Orange.*** The target takes 10d6 acid damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 3, '***3. Yellow.*** The target takes 10d6 lightning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 4, '***4. Green.*** The target takes 10d6 poison damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 5, '***5. Blue.*** The target takes 10d6 cold damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 6, '***6. Indigo.*** On a failed save, the target is restrained. It must then make a constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails its save three times, it permanently turns to stone and is subjected to the petrified condition. The successes and failures don''t need to be consecutive; keep track of both until the target collects three of a kind.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 7, '***7. Violet.*** On a failed save, the target is blinded. It must then make a wisdom saving throw at the start of your next turn. A successful save ends the blindness. If it fails that save, the creature is transported to another plane of existence of the GM''s choosing and is no longer blinded. (Typically, a creature that is on a plane that isn''t its home plane is banished home, while other creatures are usually cast into the Astral or Ethereal planes.)');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-spray', 8, '***8. Special.*** The target is struck by two rays. Roll twice more, rerolling any 8.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prismatic-spray', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prismatic-spray', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prismatic-spray', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prismatic-spray', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('prismatic-spray', 'Prismatic Spray', 'Self', 0, 'Instantaneous', 0, '1 action', 7, 'evocation', '/api/2014/spells/prismatic-spray', 'dex', 'other', 'cone', 60, 'For each target, roll a d8 to determine which color ray affects it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 0, 'A shimmering, multicolored plane of light forms a vertical opaque wall--up to 90 feet long, 30 feet high, and 1 inch thick--centered on a point you can see within range. Alternatively, you can shape the wall into a sphere up to 30 feet in diameter centered on a point you choose within range. The wall remains in place for the duration. If you position the wall so that it passes through a space occupied by a creature, the spell fails, and your action and the spell slot are wasted.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 1, 'The wall sheds bright light out to a range of 100 feet and dim light for an additional 100 feet. You and creatures you designate at the time you cast the spell can pass through and remain near the wall without harm. If another creature that can see the wall moves to within 20 feet of it or starts its turn there, the creature must succeed on a constitution saving throw or become blinded for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 2, 'The wall consists of seven layers, each with a different color. When a creature attempts to reach into or pass through the wall, it does so one layer at a time through all the wall''s layers. As it passes or reaches through each layer, the creature must make a dexterity saving throw or be affected by that layer''s properties as described below.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 3, 'The wall can be destroyed, also one layer at a time, in order from red to violet, by means specific to each layer. Once a layer is destroyed, it remains so for the duration of the spell. A rod of cancellation destroys a prismatic wall, but an antimagic field has no effect on it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 4, '***1. Red.*** The creature takes 10d6 fire damage on a failed save, or half as much damage on a successful one. While this layer is in place, nonmagical ranged attacks can''t pass through the wall. The layer can be destroyed by dealing at least 25 cold damage to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 5, '***2. Orange.*** The creature takes 10d6 acid damage on a failed save, or half as much damage on a successful one. While this layer is in place, magical ranged attacks can''t pass through the wall. The layer is destroyed by a strong wind.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 6, '***3. Yellow.*** The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 60 force damage to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 7, '***4. Green.*** The creature takes 10d6 poison damage on a failed save, or half as much damage on a successful one. A passwall spell, or another spell of equal or greater level that can open a portal on a solid surface, destroys this layer.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 8, '***5. Blue.*** The creature takes 10d6 cold damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 25 fire damage to it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 9, '***6. Indigo.*** On a failed save, the creature is restrained. It must then make a constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails its save three times, it permanently turns to stone and is subjected to the petrified condition. The successes and failures don''t need to be consecutive; keep track of both until the creature collects three of a kind.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 10, 'While this layer is in place, spells can''t be cast through the wall. The layer is destroyed by bright light shed by a daylight spell or a similar spell of equal or higher level.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('prismatic-wall', 11, '***7. Violet.*** On a failed save, the creature is blinded. It must then make a wisdom saving throw at the start of your next turn. A successful save ends the blindness. If it fails that save, the creature is transported to another plane of the GM''s choosing and is no longer blinded. (Typically, a creature that is on a plane that isn''t its home plane is banished home, while other creatures are usually cast into the Astral or Ethereal planes.) This layer is destroyed by a dispel magic spell or a similar spell of equal or higher level that can end spells and magical effects.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prismatic-wall', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('prismatic-wall', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('prismatic-wall', 0, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('prismatic-wall', 'Prismatic Wall', '60 feet', 0, '10 minutes', 0, '1 action', 9, 'abjuration', '/api/2014/spells/prismatic-wall', 'line', 90);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 0, 'You make an area within range magically secure. The area is a cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration or until you use an action to dismiss it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 1, 'When you cast the spell, you decide what sort of security the spell provides, choosing any or all of the following properties:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 2, '- Sound can''t pass through the barrier at the edge of the warded area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 3, '- The barrier of the warded area appears dark and foggy, preventing vision (including darkvision) through it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 4, '- Sensors created by divination spells can''t appear inside the protected area or pass through the barrier at its perimeter.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 5, '- Creatures in the area can''t be targeted by divination spells.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 6, '- Nothing can teleport into or out of the warded area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 7, '- Planar travel is blocked within the warded area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('private-sanctum', 8, 'Casting this spell on the same spot every day for a year makes this effect permanent.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('private-sanctum', 0, 'When you cast this spell using a spell slot of 5th level or higher, you can increase the size of the cube by 100 feet for each slot level beyond 4th. Thus you could protect a cube that can be up to 200 feet on one side by using a spell slot of 5th level.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('private-sanctum', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('private-sanctum', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('private-sanctum', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('private-sanctum', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('private-sanctum', 'Private Sanctum', '120 feet', 'A thin sheet of lead, a piece of opaque glass, a wad of cotton or cloth, and powdered chrysolite.', 0, '24 hours', 0, '10 minutes', 4, 'abjuration', '/api/2014/spells/private-sanctum', 'cube', 100);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('produce-flame', 0, 'A flickering flame appears in your hand. The flame remains there for the duration and harms neither you nor your equipment. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The spell ends if you dismiss it as an action or if you cast it again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('produce-flame', 1, 'You can also attack with the flame, although doing so ends the spell. When you cast this spell, or as an action on a later turn, you can hurl the flame at a creature within 30 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 fire damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('produce-flame', 2, 'This spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('produce-flame', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('produce-flame', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('produce-flame', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('produce-flame', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('produce-flame', 'Produce Flame', 'Self', 0, '10 minutes', 0, '1 action', 0, 'ranged', 'fire', 'conjuration', '/api/2014/spells/produce-flame');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('programmed-illusion', 0, 'You create an illusion of an object, a creature, or some other visible phenomenon within range that activates when a specific condition occurs. The illusion is imperceptible until then. It must be no larger than a 30-foot cube, and you decide when you cast the spell how the illusion behaves and what sounds it makes. This scripted performance can last up to 5 minutes.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('programmed-illusion', 1, 'When the condition you specify occurs, the illusion springs into existence and performs in the manner you described. Once the illusion finishes performing, it disappears and remains dormant for 10 minutes. After this time, the illusion can be activated again.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('programmed-illusion', 2, 'The triggering condition can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the area. For example, you could create an illusion of yourself to appear and warn off others who attempt to open a trapped door, or you could set the illusion to trigger only when a creature says the correct word or phrase.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('programmed-illusion', 3, 'Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('programmed-illusion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('programmed-illusion', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('programmed-illusion', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('programmed-illusion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('programmed-illusion', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('programmed-illusion', 'Programmed Illusion', '120 feet', 'A bit of fleece and jade dust worth at least 25 gp.', 0, 'Until dispelled', 0, '1 action', 6, 'illusion', '/api/2014/spells/programmed-illusion', 'cube', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('project-image', 0, 'You create an illusory copy of yourself that lasts for the duration. The copy can appear at any location within range that you have seen before, regardless of intervening obstacles. The illusion looks and sounds like you but is intangible. If the illusion takes any damage, it disappears, and the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('project-image', 1, 'You can use your action to move this illusion up to twice your speed, and make it gesture, speak, and behave in whatever way you choose. It mimics your mannerisms perfectly.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('project-image', 2, 'You can see through its eyes and hear through its ears as if you were in its space. On your turn as a bonus action, you can switch from using its senses to using your own, or back again. While you are using its senses, you are blinded and deafened in regard to your own surroundings.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('project-image', 3, 'Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('project-image', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('project-image', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('project-image', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('project-image', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('project-image', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('project-image', 'Project Image', '500 miles', 'A small replica of you made from materials worth at least 5 gp.', 0, 'Up to 24 hours', 1, '1 action', 7, 'illusion', '/api/2014/spells/project-image');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('protection-from-energy', 0, 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-energy', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-energy', 1, 'S');
