INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-energy', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-energy', 2, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-energy', 3, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-energy', 4, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('protection-from-energy', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('protection-from-energy', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('protection-from-energy', 'Protection From Energy', 'Touch', 0, 'Up to 1 hour', 1, '1 action', 3, 'abjuration', '/api/2014/spells/protection-from-energy');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('protection-from-evil-and-good', 0, 'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('protection-from-evil-and-good', 1, 'The protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can''t be charmed, frightened, or possessed by them. If the target is already charmed, frightened, or possessed by such a creature, the target has advantage on any new saving throw against the relevant effect.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-evil-and-good', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-evil-and-good', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-evil-and-good', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-evil-and-good', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-evil-and-good', 1, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-evil-and-good', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-evil-and-good', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('protection-from-evil-and-good', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('protection-from-evil-and-good', 1, 'devotion');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('protection-from-evil-and-good', 'Protection from Evil and Good', 'Touch', 'Holy water or powdered silver and iron, which the spell consumes.', 0, 'Up to 10 minutes', 1, '1 action', 1, 'abjuration', '/api/2014/spells/protection-from-evil-and-good');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('protection-from-poison', 0, 'You touch a creature. If it is poisoned, you neutralize the poison. If more than one poison afflicts the target, you neutralize one poison that you know is present, or you neutralize one at random.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('protection-from-poison', 1, 'For the duration, the target has advantage on saving throws against being poisoned, and it has resistance to poison damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-poison', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('protection-from-poison', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-poison', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-poison', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-poison', 2, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('protection-from-poison', 3, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('protection-from-poison', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('protection-from-poison', 'Protection from Poison', 'Touch', 0, '1 hour', 0, '1 action', 2, 'abjuration', '/api/2014/spells/protection-from-poison');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('purify-food-and-drink', 0, 'All nonmagical food and drink within a 5-foot radius sphere centered on a point of your choice within range is purified and rendered free of poison and disease.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('purify-food-and-drink', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('purify-food-and-drink', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('purify-food-and-drink', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('purify-food-and-drink', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('purify-food-and-drink', 2, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('purify-food-and-drink', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('purify-food-and-drink', 'Purify Food and Drink', '10 feet', 1, 'Instantaneous', 0, '1 action', 1, 'transmutation', '/api/2014/spells/purify-food-and-drink');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('raise-dead', 0, 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature''s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('raise-dead', 1, 'This spell also neutralizes any poisons and cures nonmagical diseases that affected the creature at the time it died. This spell doesn''t, however, remove magical diseases, curses, or similar effects; if these aren''t first removed prior to casting the spell, they take effect when the creature returns to life. The spell can''t return an undead creature to life.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('raise-dead', 2, 'This spell closes all mortal wounds, but it doesn''t restore missing body parts. If the creature is lacking body parts or organs integral for its survival--its head, for instance--the spell automatically fails.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('raise-dead', 3, 'Coming back from the dead is an ordeal. The target takes a -4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('raise-dead', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('raise-dead', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('raise-dead', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('raise-dead', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('raise-dead', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('raise-dead', 2, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('raise-dead', 0, 'life');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('raise-dead', 'Raise Dead', 'Touch', 'A diamond worth at least 500gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 hour', 5, 'necromancy', '/api/2014/spells/raise-dead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ray-of-enfeeblement', 0, 'A black beam of enervating energy springs from your finger toward a creature within range. Make a ranged spell attack against the target. On a hit, the target deals only half damage with weapon attacks that use Strength until the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ray-of-enfeeblement', 1, 'At the end of each of the target''s turns, it can make a constitution saving throw against the spell. On a success, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ray-of-enfeeblement', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ray-of-enfeeblement', 1, 'S');
