INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ray-of-enfeeblement', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('ray-of-enfeeblement', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('ray-of-enfeeblement', 'Ray of Enfeeblement', '60 feet', 0, 'Up to 1 minute', 1, '1 action', 2, 'ranged', 'necromancy', '/api/2014/spells/ray-of-enfeeblement', 'con', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ray-of-frost', 0, 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('ray-of-frost', 1, 'The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ray-of-frost', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('ray-of-frost', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ray-of-frost', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('ray-of-frost', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('ray-of-frost', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('ray-of-frost', 'Ray of Frost', '60 feet', 0, 'Instantaneous', 0, '1 action', 0, 'ranged', 'cold', 'evocation', '/api/2014/spells/ray-of-frost');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('regenerate', 0, 'You touch a creature and stimulate its natural healing ability. The target regains 4d8 + 15 hit points. For the duration of the spell, the target regains 1 hit point at the start of each of its turns (10 hit points each minute).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('regenerate', 1, 'The target''s severed body members (fingers, legs, tails, and so on), if any, are restored after 2 minutes. If you have the severed part and hold it to the stump, the spell instantaneously causes the limb to knit to the stump.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('regenerate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('regenerate', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('regenerate', 2, 'M');
INSERT INTO spells_heal_at_slot_level (spells_index, key_level, "value") VALUES ('regenerate', 7, '4d8 + 15');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('regenerate', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('regenerate', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('regenerate', 2, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('regenerate', 'Regenerate', 'Touch', 'A prayer wheel and holy water.', 0, '1 hour', 0, '1 minute', 7, 'transmutation', '/api/2014/spells/regenerate');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 0, 'You touch a dead humanoid or a piece of a dead humanoid. Provided that the creature has been dead no longer than 10 days, the spell forms a new adult body for it and then calls the soul to enter that body. If the target''s soul isn''t free or willing to do so, the spell fails.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 1, 'The magic fashions a new body for the creature to inhabit, which likely causes the creature''s race to change. The GM rolls a d 100 and consults the following table to determine what form the creature takes when restored to life, or the GM chooses a form.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 2, '| d100 | Race |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 3, '|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 4, '| 01-04 | Dragonborn |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 5, '| 05-13 | Dwarf, hill |');
