INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 16, '| 77-96 | Human |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 17, '| 97-00 | Tiefling |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reincarnate', 18, 'The reincarnated creature recalls its former life and experiences. It retains the capabilities it had in its original form, except it exchanges its original race for the new one and changes its racial traits accordingly.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reincarnate', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reincarnate', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reincarnate', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('reincarnate', 0, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('reincarnate', 'Reincarnate', 'Touch', 'Rare oils and unguents worth at least 1,000 gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 hour', 5, 'transmutation', '/api/2014/spells/reincarnate');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('remove-curse', 0, 'At your touch, all curses affecting one creature or object end. If the object is a cursed magic item, its curse remains, but the spell breaks its owner''s attunement to the object so it can be removed or discarded.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('remove-curse', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('remove-curse', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('remove-curse', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('remove-curse', 1, 'paladin');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('remove-curse', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('remove-curse', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('remove-curse', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('remove-curse', 'Remove Curse', 'Touch', 0, 'Instantaneous', 0, '1 action', 3, 'abjuration', '/api/2014/spells/remove-curse');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resilient-sphere', 0, 'A sphere of shimmering force encloses a creature or object of Large size or smaller within range. An unwilling creature must make a dexterity saving throw. On a failed save, the creature is enclosed for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resilient-sphere', 1, 'Nothing--not physical objects, energy, or other spell effects--can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can''t be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resilient-sphere', 2, 'The sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can use its action to push against the sphere''s walls and thus roll the sphere at up to half the creature''s speed. Similarly, the globe can be picked up and moved by other creatures.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resilient-sphere', 3, 'A disintegrate spell targeting the globe destroys it without harming anything inside it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resilient-sphere', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resilient-sphere', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resilient-sphere', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('resilient-sphere', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('resilient-sphere', 'Resilient Sphere', '30 feet', 'A hemispherical piece of clear crystal and a matching hemispherical piece of gum arabic.', 0, 'Up to 1 minute', 1, '1 action', 4, 'evocation', '/api/2014/spells/resilient-sphere', 'dex', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resistance', 0, 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one saving throw of its choice. It can roll the die before or after making the saving throw. The spell then ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resistance', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resistance', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resistance', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('resistance', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('resistance', 1, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('resistance', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('resistance', 'Resistance', 'Touch', 'A miniature cloak.', 0, 'Up to 1 minute', 1, '1 action', 0, 'abjuration', '/api/2014/spells/resistance');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resurrection', 0, 'You touch a dead creature that has been dead for no more than a century, that didn''t die of old age, and that isn''t undead. If its soul is free and willing, the target returns to life with all its hit points.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resurrection', 1, 'This spell neutralizes any poisons and cures normal diseases afflicting the creature when it died. It doesn''t, however, remove magical diseases, curses, and the like; if such effects aren''t removed prior to casting the spell, they afflict the target on its return to life.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resurrection', 2, 'This spell closes all mortal wounds and restores any missing body parts.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resurrection', 3, 'Coming back from the dead is an ordeal. The target takes a -4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('resurrection', 4, 'Casting this spell to restore life to a creature that has been dead for one year or longer taxes you greatly. Until you finish a long rest, you can''t cast spells again, and you have disadvantage on all attack rolls, ability checks, and saving throws.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resurrection', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resurrection', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('resurrection', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('resurrection', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('resurrection', 1, 'cleric');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('resurrection', 'Resurrection', 'Touch', 'A diamond worth at least 1,000gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 hour', 7, 'necromancy', '/api/2014/spells/resurrection');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reverse-gravity', 0, 'This spell reverses gravity in a 50-foot-radius, 100-foot high cylinder centered on a point within range. All creatures and objects that aren''t somehow anchored to the ground in the area fall upward and reach the top of the area when you cast this spell. A creature can make a dexterity saving throw to grab onto a fixed object it can reach, thus avoiding the fall.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reverse-gravity', 1, 'If some solid object (such as a ceiling) is encountered in this fall, falling objects and creatures strike it just as they would during a normal downward fall. If an object or creature reaches the top of the area without striking anything, it remains there, oscillating slightly, for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('reverse-gravity', 2, 'At the end of the duration, affected objects and creatures fall back down.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reverse-gravity', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reverse-gravity', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('reverse-gravity', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('reverse-gravity', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('reverse-gravity', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('reverse-gravity', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('reverse-gravity', 'Reverse Gravity', '100 feet', 'A lodestone and iron filings.', 0, 'Up to 1 minute', 1, '1 action', 7, 'transmutation', '/api/2014/spells/reverse-gravity', 'dex', 'other', 'cylinder', 50, 'A creature can make a dexterity saving throw to grab onto a fixed object it can reach, thus avoiding the fall.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('revivify', 0, 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can''t return to life a creature that has died of old age, nor can it restore any missing body parts.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('revivify', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('revivify', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('revivify', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('revivify', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('revivify', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('revivify', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('revivify', 1, 'life');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('revivify', 'Revivify', 'Touch', 'Diamonds worth 300gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 action', 3, 'conjuration', '/api/2014/spells/revivify');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('rope-trick', 0, 'You touch a length of rope that is up to 60 feet long. One end of the rope then rises into the air until the whole rope hangs perpendicular to the ground. At the upper end of the rope, an invisible entrance opens to an extradimensional space that lasts until the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('rope-trick', 1, 'The extradimensional space can be reached by climbing to the top of the rope. The space can hold as many as eight Medium or smaller creatures. The rope can be pulled into the space, making the rope disappear from view outside the space.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('rope-trick', 2, 'Attacks and spells can''t cross through the entrance into or out of the extradimensional space, but those inside can see out of it as if through a 3-foot-by-5-foot window centered on the rope.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('rope-trick', 3, 'Anything inside the extradimensional space drops out when the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('rope-trick', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('rope-trick', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('rope-trick', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('rope-trick', 0, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('rope-trick', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('rope-trick', 'Rope Trick', 'Touch', 'Powdered corn extract and a twisted loop of parchment.', 0, '1 hour', 0, '1 action', 2, 'transmutation', '/api/2014/spells/rope-trick');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sacred-flame', 0, 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sacred-flame', 1, 'The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sacred-flame', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sacred-flame', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sacred-flame', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sacred-flame', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('sacred-flame', 'Sacred Flame', '60 feet', 0, 'Instantaneous', 0, '1 action', 0, 'radiant', 'evocation', '/api/2014/spells/sacred-flame', 'dex', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sanctuary', 0, 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn''t protect the warded creature from area effects, such as the explosion of a fireball.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sanctuary', 1, 'If the warded creature makes an attack or casts a spell that affects an enemy creature, this spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sanctuary', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sanctuary', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sanctuary', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sanctuary', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sanctuary', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sanctuary', 1, 'devotion');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('sanctuary', 'Sanctuary', '30 feet', 'A small silver mirror.', 0, '1 minute', 0, '1 bonus action', 1, 'abjuration', '/api/2014/spells/sanctuary');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scorching-ray', 0, 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scorching-ray', 1, 'Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('scorching-ray', 0, 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('scorching-ray', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('scorching-ray', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scorching-ray', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scorching-ray', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('scorching-ray', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('scorching-ray', 1, 'fiend');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url) VALUES ('scorching-ray', 'Scorching Ray', '120 feet', 0, 'Instantaneous', 0, '1 action', 2, 'fire', 'evocation', '/api/2014/spells/scorching-ray');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 0, 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it. If a target knows you''re casting this spell, it can fail the saving throw voluntarily if it wants to be observed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 1, '| Knowledge | Save Modifier |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 2, '|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 3, '| Secondhand (you have heard of the target) | +5 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 4, '| Firsthand (you have met the target) | +0 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 5, '| Familiar (you know the target well) | -5 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 6, '');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 7, '| Connection | Save Modifier |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 8, '|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 9, '| Likeness or picture | -2 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 10, '| Possession or garment | -4 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 11, '| Body part, lock of hair, bit of nail, or the like | -10 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 12, 'On a successful save, the target isn''t affected, and you can''t use this spell against it again for 24 hours.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 13, 'On a failed save, the spell creates an invisible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration. A creature that can see invisible objects sees the sensor as a luminous orb about the size of your fist.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('scrying', 14, 'Instead of targeting a creature, you can choose a location you have seen before as the target of this spell. When you do, the sensor appears at that location and doesn''t move.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('scrying', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('scrying', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('scrying', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scrying', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scrying', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scrying', 2, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scrying', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('scrying', 4, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('scrying', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('scrying', 'Scrying', 'Self', 'A focus worth at least 1,000 gp, such as a crystal ball, a silver mirror, or a font filled with holy water.', 0, 'Up to 10 minutes', 1, '10 minutes', 5, 'divination', '/api/2014/spells/scrying', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('secret-chest', 0, 'You hide a chest, and all its contents, on the Ethereal Plane. You must touch the chest and the miniature replica that serves as a material component for the spell. The chest can contain up to 12 cubic feet of nonliving material (3 feet by 2 feet by 2 feet).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('secret-chest', 1, 'While the chest remains on the Ethereal Plane, you can use an action and touch the replica to recall the chest. It appears in an unoccupied space on the ground within 5 feet of you. You can send the chest back to the Ethereal Plane by using an action and touching both the chest and the replica.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('secret-chest', 2, 'After 60 days, there is a cumulative 5 percent chance per day that the spell''s effect ends. This effect ends if you cast this spell again, if the smaller replica chest is destroyed, or if you choose to end the spell as an action. If the spell ends and the larger chest is on the Ethereal Plane, it is irretrievably lost.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('secret-chest', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('secret-chest', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('secret-chest', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('secret-chest', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('secret-chest', 'Secret Chest', 'Touch', 'An exquisite chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth at least 5,000 gp, and a Tiny replica made from the same materials worth at least 50 gp.', 0, 'Instantaneous', 0, '1 action', 4, 'conjuration', '/api/2014/spells/secret-chest');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('see-invisibility', 0, 'For the duration of the spell, you see invisible creatures and objects as if they were visible, and you can see through Ethereal. The ethereal objects and creatures appear ghostly translucent.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('see-invisibility', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('see-invisibility', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('see-invisibility', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('see-invisibility', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('see-invisibility', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('see-invisibility', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('see-invisibility', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('see-invisibility', 'See Invisibility', 'Self', 'A dash of talc and a small amount of silver powder.', 0, '1 hour', 0, '1 action', 2, 'divination', '/api/2014/spells/see-invisibility');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('seeming', 0, 'This spell allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. An unwilling target can make a charisma saving throw, and if it succeeds, it is unaffected by this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('seeming', 1, 'The spell disguises physical appearance as well as clothing, armor, weapons, and equipment. You can make each creature seem 1 foot shorter or taller and appear thin, fat, or in between. You can''t change a target''s body type, so you must choose a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you. The spell lasts for the duration, unless you use your action to dismiss it sooner.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('seeming', 2, 'The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to a creature''s outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel the creature''s head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('seeming', 3, 'A creature can use its action to inspect a target and make an Intelligence (Investigation) check against your spell save DC. If it succeeds, it becomes aware that the target is disguised.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('seeming', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('seeming', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('seeming', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('seeming', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('seeming', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('seeming', 'Seeming', '30 feet', 0, '8 hours', 0, '1 action', 5, 'illusion', '/api/2014/spells/seeming');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sending', 0, 'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sending', 1, 'You can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn''t arrive.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sending', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sending', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sending', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sending', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sending', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sending', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sending', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('sending', 'Sending', 'Unlimited', 'A short piece of fine copper wire.', 0, '1 round', 0, '1 action', 3, 'evocation', '/api/2014/spells/sending');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sequester', 0, 'By means of this spell, a willing creature or an object can be hidden away, safe from detection for the duration. When you cast the spell and touch the target, it becomes invisible and can''t be targeted by divination spells or perceived through scrying sensors created by divination spells.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sequester', 1, 'If the target is a creature, it falls into a state of suspended animation. Time ceases to flow for it, and it doesn''t grow older.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sequester', 2, 'You can set a condition for the spell to end early. The condition can be anything you choose, but it must occur or be visible within 1 mile of the target. Examples include "after 1,000 years" or "when the tarrasque awakens." This spell also ends if the target takes any damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sequester', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sequester', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sequester', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sequester', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('sequester', 'Sequester', 'Touch', 'A powder composed of diamond, emerald, ruby, and sapphire dust worth at least 5,000 gp, which the spell consumes.', 0, 'Until dispelled', 0, '1 action', 7, 'transmutation', '/api/2014/spells/sequester');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 0, 'You assume the form of a different creature for the duration. The new form can be of any creature with a challenge rating equal to your level or lower. The creature can''t be a construct or an undead, and you must have seen the sort of creature at least once. You transform into an average example of that creature, one without any class levels or the Spellcasting trait.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 1, 'Your game statistics are replaced by the statistics of the chosen creature, though you retain your alignment and Intelligence, Wisdom, and Charisma scores. You also retain all of your skill and saving throw proficiencies, in addition to gaining those of the creature. If the creature has the same proficiency as you and the bonus listed in its statistics is higher than yours, use the creature''s bonus in place of yours. You can''t use any legendary actions or lair actions of the new form.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 2, 'You assume the hit points and Hit Dice of the new form. When you revert to your normal form, you return to the number of hit points you had before you transformed. If you revert as a result of dropping to 0 hit points, any excess damage carries over to your normal form. As long as the excess damage doesn''t reduce your normal form to 0 hit points, you aren''t knocked unconscious.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 3, 'You retain the benefit of any features from your class, race, or other source and can use them, provided that your new form is physically capable of doing so. You can''t use any special senses you have (for example, darkvision) unless your new form also has that sense. You can only speak if the creature can normally speak.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 4, 'When you transform, you choose whether your equipment falls to the ground, merges into the new form, or is worn by it. Worn equipment functions as normal. The GM determines whether it is practical for the new form to wear a piece of equipment, based on the creature''s shape and size. Your equipment doesn''t change shape or size to match the new form, and any equipment that the new form can''t wear must either fall to the ground or merge into your new form. Equipment that merges has no effect in that state.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shapechange', 5, 'During this spell''s duration, you can use your action to assume a different form following the same restrictions and rules for the original form, with one exception: if your new form has more hit points than your current one, your hit points remain at their current value.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shapechange', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shapechange', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shapechange', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shapechange', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shapechange', 1, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('shapechange', 'Shapechange', 'Self', 'A jade circlet worth at least 1,500 gp, which you must place on your head before you cast the spell.', 0, 'Up to 1 hour', 1, '1 action', 9, 'transmutation', '/api/2014/spells/shapechange');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shatter', 0, 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shatter', 1, 'A non-magical item that is not worn or carried also suffers damage if it is in the area of the spell.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('shatter', 0, 'When you cast this spell using a 3 or higher level spell slot, the damage of the spell increases by 1d8 for each level of higher spell slot 2.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shatter', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shatter', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shatter', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shatter', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shatter', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shatter', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shatter', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('shatter', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('shatter', 'Shatter', '60 feet', 'A burst of mica.', 0, 'Instantaneous', 0, '1 action', 2, 'thunder', 'evocation', '/api/2014/spells/shatter', 'con', 'half', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shield', 0, 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shield', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shield', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shield', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shield', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('shield', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('shield', 'Shield', 'Self', 0, '1 round', 0, '1 reaction', 1, 'abjuration', '/api/2014/spells/shield');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shield-of-faith', 0, 'A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shield-of-faith', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shield-of-faith', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shield-of-faith', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shield-of-faith', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shield-of-faith', 1, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('shield-of-faith', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('shield-of-faith', 'Shield of Faith', '60 feet', 'A small parchment with a bit of holy text written on it.', 0, 'Up to 10 minutes', 1, '1 bonus action', 1, 'abjuration', '/api/2014/spells/shield-of-faith');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shillelagh', 0, 'The wood of a club or a quarterstaff you are holding is imbued with nature''s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon''s damage die becomes a d8. The weapon also becomes magical, if it isn''t already. The spell ends if you cast it again or if you let go of the weapon.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shillelagh', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shillelagh', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shillelagh', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shillelagh', 0, 'druid');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('shillelagh', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('shillelagh', 'Shillelagh', 'Touch', 'Mistletoe, a shamrock leaf, and a club or quarterstaff.', 0, '1 minute', 0, '1 bonus action', 0, 'transmutation', '/api/2014/spells/shillelagh');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shocking-grasp', 0, 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can''t take reactions until the start of its next turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('shocking-grasp', 1, 'The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shocking-grasp', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('shocking-grasp', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shocking-grasp', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('shocking-grasp', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('shocking-grasp', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('shocking-grasp', 'Shocking Grasp', 'Touch', 0, 'Instantaneous', 0, '1 action', 0, 'melee', 'lightning', 'evocation', '/api/2014/spells/shocking-grasp');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('silence', 0, 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('silence', 1, 'Casting a spell that includes a verbal component is impossible there.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('silence', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('silence', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silence', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silence', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silence', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('silence', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('silence', 1, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('silence', 'Silence', '120 feet', 1, 'Up to 10 minutes', 1, '1 action', 2, 'illusion', '/api/2014/spells/silence', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('silent-image', 0, 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn''t accompanied by sound, smell, or other sensory effects.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('silent-image', 1, 'You can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('silent-image', 2, 'Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('silent-image', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('silent-image', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('silent-image', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silent-image', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silent-image', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('silent-image', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('silent-image', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('silent-image', 'Silent Image', '60 feet', 'A bit of fleece.', 0, 'Up to 10 minutes', 1, '1 action', 1, 'illusion', '/api/2014/spells/silent-image', 'cube', 15);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('simulacrum', 0, 'You shape an illusory duplicate of one beast or humanoid that is within range for the entire casting time of the spell. The duplicate is a creature, partially real and formed from ice or snow, and it can take actions and otherwise be affected as a normal creature. It appears to be the same as the original, but it has half the creature''s hit point maximum and is formed without any equipment. Otherwise, the illusion uses all the statistics of the creature it duplicates.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('simulacrum', 1, 'The simulacrum is friendly to you and creatures you designate. It obeys your spoken commands, moving and acting in accordance with your wishes and acting on your turn in combat. The simulacrum lacks the ability to learn or become more powerful, so it never increases its level or other abilities, nor can it regain expended spell slots.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('simulacrum', 2, 'If the simulacrum is damaged, you can repair it in an alchemical laboratory, using rare herbs and minerals worth 100 gp per hit point it regains. The simulacrum lasts until it drops to 0 hit points, at which point it reverts to snow and melts instantly.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('simulacrum', 3, 'If you cast this spell again, any currently active duplicates you created with this spell are instantly destroyed.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('simulacrum', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('simulacrum', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('simulacrum', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('simulacrum', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('simulacrum', 'Simulacrum', 'Touch', 'Snow or ice in quantities sufficient to made a life-size copy of the duplicated creature; some hair, fingernail clippings, or other piece of that creature''s body placed inside the snow or ice; and powdered ruby worth 1,500 gp, sprinkled over the duplicate and consumed by the spell.', 0, 'Until dispelled', 0, '12 hours', 7, 'illusion', '/api/2014/spells/simulacrum');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleep', 0, 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleep', 1, 'Starting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleep', 2, 'Undead and creatures immune to being charmed aren''t affected by this spell.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('sleep', 0, 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleep', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleep', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleep', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleep', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleep', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleep', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sleep', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('sleep', 'Sleep', '90 feet', 'A pinch of fine sand, rose petals, or a cricket.', 0, '1 minute', 0, '1 action', 1, 'enchantment', '/api/2014/spells/sleep', 'sphere', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleet-storm', 0, 'Until the spell ends, freezing rain and sleet fall in a 20-foot-tall cylinder with a 40-foot radius centered on a point you choose within range. The area is heavily obscured, and exposed flames in the area are doused.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleet-storm', 1, 'The ground in the area is covered with slick ice, making it difficult terrain. When a creature enters the spell''s area for the first time on a turn or starts its turn there, it must make a dexterity saving throw. On a failed save, it falls prone.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sleet-storm', 2, 'If a creature is concentrating in the spell''s area, the creature must make a successful constitution saving throw against your spell save DC or lose concentration.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleet-storm', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleet-storm', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sleet-storm', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleet-storm', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleet-storm', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sleet-storm', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sleet-storm', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('sleet-storm', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('sleet-storm', 'Sleet Storm', '150 feet', 'A pinch of dust and a few drops of water.', 0, 'Up to 1 minute', 1, '1 action', 3, 'conjuration', '/api/2014/spells/sleet-storm', 'cylinder', 40);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('slow', 0, 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a wisdom saving throw or be affected by this spell for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('slow', 1, 'An affected target''s speed is halved, it takes a -2 penalty to AC and dexterity saving throws, and it can''t use reactions. On its turn, it can use either an action or a bonus action, not both. Regardless of the creature''s abilities or magic items, it can''t make more than one melee or ranged attack during its turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('slow', 2, 'If the creature attempts to cast a spell with a casting time of 1 action, roll a d20. On an 11 or higher, the spell doesn''t take effect until the creature''s next turn, and the creature must use its action on that turn to complete the spell. If it can''t, the spell is wasted.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('slow', 3, 'A creature affected by this spell makes another wisdom saving throw at the end of its turn. On a successful save, the effect ends for it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('slow', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('slow', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('slow', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('slow', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('slow', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('slow', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('slow', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('slow', 'Slow', '120 feet', 'A drop of molasses.', 0, 'Up to 1 minute', 1, '1 action', 3, 'transmutation', '/api/2014/spells/slow', 'wis', 'none', 'cube', 40, 'On failed save, the creature is slowed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spare-the-dying', 0, 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spare-the-dying', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spare-the-dying', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spare-the-dying', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('spare-the-dying', 'Spare the Dying', 'Touch', 0, 'Instantaneous', 0, '1 action', 0, 'necromancy', '/api/2014/spells/spare-the-dying');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-animals', 0, 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at a minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day. You might be able to persuade a beast to perform a small favor for you, at the GM''s discretion.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-animals', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-animals', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-animals', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-animals', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-animals', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('speak-with-animals', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('speak-with-animals', 'Speak with Animals', 'Self', 1, '10 minutes', 0, '1 action', 1, 'divination', '/api/2014/spells/speak-with-animals');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-dead', 0, 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can''t be undead. The spell fails if the corpse was the target of this spell within the last 10 days.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-dead', 1, 'Until the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are hostile to it or it recognizes you as an enemy. This spell doesn''t return the creature''s soul to its body, only its animating spirit. Thus, the corpse can''t learn new information, doesn''t comprehend anything that has happened since it died, and can''t speculate about future events.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-dead', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-dead', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-dead', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-dead', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-dead', 1, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('speak-with-dead', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('speak-with-dead', 'Speak with Dead', '10 feet', 'Burning incense.', 0, '10 minutes', 0, '1 action', 3, 'necromancy', '/api/2014/spells/speak-with-dead');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-plants', 0, 'You imbue plants within 30 feet of you with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell''s area within the past day, gaining information about creatures that have passed, weather, and other circumstances.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-plants', 1, 'You can also turn difficult terrain caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into difficult terrain that lasts for the duration, causing vines and branches to hinder pursuers, for example.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-plants', 2, 'Plants might be able to perform other tasks on your behalf, at the GM''s discretion. The spell doesn''t enable plants to uproot themselves and move about, but they can freely move branches, tendrils, and stalks.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-plants', 3, 'If a plant creature is in the area, you can communicate with it as if you shared a common language, but you gain no magical ability to influence it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('speak-with-plants', 4, 'This spell can cause the plants created by the entangle spell to release a restrained creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-plants', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('speak-with-plants', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-plants', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-plants', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('speak-with-plants', 2, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('speak-with-plants', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('speak-with-plants', 'Speak with Plants', 'Self', 0, '10 minutes', 0, '1 action', 3, 'transmutation', '/api/2014/spells/speak-with-plants', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spider-climb', 0, 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spider-climb', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spider-climb', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spider-climb', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spider-climb', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spider-climb', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spider-climb', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spider-climb', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spider-climb', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('spider-climb', 'Spider Climb', 'Touch', 'A drop of bitumen and a spider.', 0, 'Up to 1 hour', 1, '1 action', 2, 'transmutation', '/api/2014/spells/spider-climb');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spike-growth', 0, 'The ground in a 20-foot radius centered on a point within range twists and sprouts hard spikes and thorns. The area becomes difficult terrain for the duration. When a creature moves into or within the area, it takes 2d4 piercing damage for every 5 feet it travels.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spike-growth', 1, 'The transformation of the ground is camouflaged to look natural. Any creature that can''t see the area at the time the spell is cast can make a Wisdom (Perception) check against your spell save DC to recognize the terrain as hazardous before entering it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spike-growth', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spike-growth', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spike-growth', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spike-growth', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spike-growth', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spike-growth', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spike-growth', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('spike-growth', 'Spike Growth', '150 feet', 'Seven sharp thorns or seven small twigs, each sharpened to a point.', 0, 'Up to 10 minutes', 1, '1 action', 2, 'transmutation', '/api/2014/spells/spike-growth', 'cylinder', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spirit-guardians', 0, 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spirit-guardians', 1, 'When you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature''s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('spirit-guardians', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spirit-guardians', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spirit-guardians', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spirit-guardians', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spirit-guardians', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spirit-guardians', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('spirit-guardians', 'Spirit Guardians', 'Self', 'A holy symbol.', 0, 'Up to 10 minutes', 1, '1 action', 3, 'conjuration', '/api/2014/spells/spirit-guardians');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spiritual-weapon', 0, 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spiritual-weapon', 1, 'As a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('spiritual-weapon', 2, 'The weapon can take whatever form you choose. Clerics of deities who are associated with a particular weapon (as St. Cuthbert is known for his mace and Thor for his hammer) make this spell''s effect resemble that weapon.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('spiritual-weapon', 0, 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above the 2nd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spiritual-weapon', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('spiritual-weapon', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('spiritual-weapon', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spiritual-weapon', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('spiritual-weapon', 1, 'life');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('spiritual-weapon', 'Spiritual Weapon', '60 feet', 0, '1 minute', 0, '1 bonus action', 2, 'melee', 'force', 'evocation', '/api/2014/spells/spiritual-weapon');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('stinking-cloud', 0, 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('stinking-cloud', 1, 'Each creature that is completely within the cloud at the start of its turn must make a constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling. Creatures that don''t need to breathe or are immune to poison automatically succeed on this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('stinking-cloud', 2, 'A moderate wind (at least 10 miles per hour) disperses the cloud after 4 rounds. A strong wind (at least 20 miles per hour) disperses it after 1 round.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stinking-cloud', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stinking-cloud', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stinking-cloud', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stinking-cloud', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stinking-cloud', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stinking-cloud', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('stinking-cloud', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('stinking-cloud', 1, 'land');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('stinking-cloud', 2, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('stinking-cloud', 'Stinking Cloud', '90 feet', 'A rotten egg or several skunk cabbage leaves.', 0, 'Up to 1 minute', 1, '1 action', 3, 'conjuration', '/api/2014/spells/stinking-cloud', 'con', 'none', 'sphere', 20, 'On a failed save, the creature spends its action that turn retching and reeling.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('stone-shape', 0, 'You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape that suits your purpose. So, for example, you could shape a large rock into a weapon, idol, or coffer, or make a small passage through a wall, as long as the wall is less than 5 feet thick. You could also shape a stone door or its frame to seal the door shut. The object you create can have up to two hinges and a latch, but finer mechanical detail isn''t possible.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stone-shape', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stone-shape', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stone-shape', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stone-shape', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stone-shape', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stone-shape', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('stone-shape', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('stone-shape', 'Stone Shape', 'Touch', 'Soft clay, to be crudely worked into the desired shape for the stone object.', 0, 'Instantaneous', 0, '1 action', 4, 'transmutation', '/api/2014/spells/stone-shape');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('stoneskin', 0, 'This spell turns the flesh of a willing creature you touch as hard as stone. Until the spell ends, the target has resistance to nonmagical bludgeoning, piercing, and slashing damage.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stoneskin', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stoneskin', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('stoneskin', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stoneskin', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stoneskin', 1, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stoneskin', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('stoneskin', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('stoneskin', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('stoneskin', 'Stoneskin', 'Touch', 'Diamond dust worth 100 gp, which the spell consumes.', 0, 'Up to 1 hour', 1, '1 action', 4, 'abjuration', '/api/2014/spells/stoneskin');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 0, 'A churning storm cloud forms, centered on a point you can see and spreading to a radius of 360 feet. Lightning flashes in the area, thunder booms, and strong winds roar. Each creature under the cloud (no more than 5,000 feet beneath the cloud) when it appears must make a constitution saving throw. On a failed save, a creature takes 2d6 thunder damage and becomes deafened for 5 minutes.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 1, 'Each round you maintain concentration on this spell, the storm produces additional effects on your turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 2, '***Round 2.*** Acidic rain falls from the cloud. Each creature and object under the cloud takes 1d6 acid damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 3, '***Round 3.*** You call six bolts of lightning from the cloud to strike six creatures or objects of your choice beneath the cloud. A given creature or object can''t be struck by more than one bolt. A struck creature must make a dexterity saving throw. The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 4, '***Round 4.*** Hailstones rain down from the cloud. Each creature under the cloud takes 2d6 bludgeoning damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 5, '***Round 5-10.*** Gusts and freezing rain assail the area under the cloud. The area becomes difficult terrain and is heavily obscured. Each creature there takes 1d6 cold damage. Ranged weapon attacks in the area are impossible. The wind and rain count as a severe distraction for the purposes of maintaining concentration on spells. Finally, gusts of strong wind (ranging from 20 to 50 miles per hour) automatically disperse fog, mists, and similar phenomena in the area, whether mundane or magical.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('storm-of-vengeance', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('storm-of-vengeance', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('storm-of-vengeance', 'Storm of Vengeance', 'Sight', 0, 'Up to 1 minute', 1, '1 action', 9, 'thunder', 'conjuration', '/api/2014/spells/storm-of-vengeance', 'con', 'none', 'sphere', 360, 'On a failed save, a creature takes 2d6 thunder damage and becomes deafened for 5 minutes.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('suggestion', 0, 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can''t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act ends the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('suggestion', 1, 'The target must make a wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('suggestion', 2, 'You can also specify conditions that will trigger a special activity during the duration. For example, you might suggest that a knight give her warhorse to the first beggar she meets. If the condition isn''t met before the spell expires, the activity isn''t performed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('suggestion', 3, 'If you or any of your companions damage the target, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('suggestion', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('suggestion', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('suggestion', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('suggestion', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('suggestion', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('suggestion', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('suggestion', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('suggestion', 'Suggestion', '30 feet', 'A snake''s tongue and either a bit of honeycomb or a drop of sweet oil.', 0, 'Up to 8 hours', 1, '1 action', 2, 'enchantment', '/api/2014/spells/suggestion', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunbeam', 0, 'A beam of brilliant light flashes out from your hand in a 5-foot-wide, 60-foot-long line. Each creature in the line must make a constitution saving throw. On a failed save, a creature takes 6d8 radiant damage and is blinded until your next turn. On a successful save, it takes half as much damage and isn''t blinded by this spell. Undead and oozes have disadvantage on this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunbeam', 1, 'You can create a new line of radiance as your action on any turn until the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunbeam', 2, 'For the duration, a mote of brilliant radiance shines in your hand. It sheds bright light in a 30-foot radius and dim light for an additional 30 feet. This light is sunlight.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunbeam', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunbeam', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunbeam', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunbeam', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunbeam', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunbeam', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('sunbeam', 'Sunbeam', 'Self', 'A magnifying glass.', 0, 'Up to 1 minute', 1, '1 action', 6, 'radiant', 'evocation', '/api/2014/spells/sunbeam', 'con', 'half', 'line', 60, 'On a failed save, the creature is blinded until your next turn. On a successful save, it isn''t blinded by this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunburst', 0, 'Brilliant sunlight flashes in a 60-foot radius centered on a point you choose within range. Each creature in that light must make a constitution saving throw. On a failed save, a creature takes 12d6 radiant damage and is blinded for 1 minute. On a successful save, it takes half as much damage and isn''t blinded by this spell. Undead and oozes have disadvantage on this saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunburst', 1, 'A creature blinded by this spell makes another constitution saving throw at the end of each of its turns. On a successful save, it is no longer blinded.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('sunburst', 2, 'This spell dispels any darkness in its area that was created by a spell.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunburst', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunburst', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('sunburst', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunburst', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunburst', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('sunburst', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size, dc_desc) VALUES ('sunburst', 'Sunburst', '150 feet', 'Fire and a piece of sunstone.', 0, 'Instantaneous', 0, '1 action', 8, 'radiant', 'evocation', '/api/2014/spells/sunburst', 'con', 'half', 'cylinder', 60, 'On failure, the creature is also blinded for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 0, 'When you cast this spell, you inscribe a harmful glyph either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the glyph (such as a book, a scroll, or a treasure chest). If you choose a surface, the glyph can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 1, 'The glyph is nearly invisible, requiring an Intelligence (Investigation) check against your spell save DC to find it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 2, 'You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, the most typical triggers include touching or stepping on the glyph, removing another object covering it, approaching within a certain distance of it, or manipulating the object that holds it. For glyphs inscribed within an object, the most common triggers are opening the object, approaching within a certain distance of it, or seeing or reading the glyph.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 3, 'You can further refine the trigger so the spell is activated only under certain circumstances or according to a creature''s physical characteristics (such as height or weight), or physical kind (for example, the ward could be set to affect hags or shapechangers). You can also specify creatures that don''t trigger the glyph, such as those who say a certain password.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 4, 'When you inscribe the glyph, choose one of the options below for its effect. Once triggered, the glyph glows, filling a 60-foot-radius sphere with dim light for 10 minutes, after which time the spell ends. Each creature in the sphere when the glyph activates is targeted by its effect, as is a creature that enters the sphere for the first time on a turn or ends its turn there.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 5, '***Death.*** Each target must make a constitution saving throw, taking 10d 10 necrotic damage on a failed save, or half as much damage on a successful save.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 6, '***Discord.*** Each target must make a constitution saving throw. On a failed save, a target bickers and argues with other creatures for 1 minute. During this time, it is incapable of meaningful communication and has disadvantage on attack rolls and ability checks.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 7, '***Fear.*** Each target must make a wisdom saving throw and becomes frightened for 1 minute on a failed save. While frightened, the target drops whatever it is holding and must move at least 30 feet away from the glyph on each of its turns, if able.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 8, '***Hopelessness.*** Each target must make a charisma saving throw. On a failed save, the target is overwhelmed with despair for 1 minute. During this time, it can''t attack or target any creature with harmful abilities, spells, or other magical effects.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 9, '***Insanity.*** Each target must make an intelligence saving throw. On a failed save, the target is driven insane for 1 minute. An insane creature can''t take actions, can''t understand what other creatures say, can''t read, and speaks only in gibberish. The GM controls its movement, which is erratic.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 10, '***Pain.*** Each target must make a constitution saving throw and becomes incapacitated with excruciating pain for 1 minute on a failed save.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 11, '***Sleep.*** Each target must make a wisdom saving throw and falls unconscious for 10 minutes on a failed save. A creature awakens if it takes damage or if someone uses an action to shake or slap it awake.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('symbol', 12, '***Stunning.*** Each target must make a wisdom saving throw and becomes stunned for 1 minute on a failed save.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('symbol', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('symbol', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('symbol', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('symbol', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('symbol', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('symbol', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('symbol', 'Symbol', 'Touch', 'Mercury, phosphorus, and powdered diamond and opal with a total value of at least 1,000 gp, which the spell consumes.', 0, 'Until dispelled', 0, '1 minute', 7, 'abjuration', '/api/2014/spells/symbol', 'cube', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 0, 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round, or choose a new one at any time. If you switch targets, the prior target is no longer affected by the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 1, '***Creature.*** You can try to move a Huge or smaller creature. Make an ability check with your spellcasting ability contested by the creature''s Strength check. If you win the contest, you move the creature up to 30 feet in any direction, including upward but not beyond the range of this spell. Until the end of your next turn, the creature is restrained in your telekinetic grip. A creature lifted upward is suspended in mid-air.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 2, 'On subsequent rounds, you can use your action to attempt to maintain your telekinetic grip on the creature by repeating the contest.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 3, '***Object.*** You can try to move an object that weighs up to 1,000 pounds. If the object isn''t being worn or carried, you automatically move it up to 30 feet in any direction, but not beyond the range of this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 4, 'If the object is worn or carried by a creature, you must make an ability check with your spellcasting ability contested by that creature''s Strength check. If you succeed, you pull the object away from that creature and can move it up to 30 feet in any direction but not beyond the range of this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telekinesis', 5, 'You can exert fine control on objects with your telekinetic grip, such as manipulating a simple tool, opening a door or a container, stowing or retrieving an item from an open container, or pouring the contents from a vial.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('telekinesis', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('telekinesis', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('telekinesis', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('telekinesis', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('telekinesis', 'Telekinesis', '60 feet', 0, 'Up to 10 minutes', 1, '1 action', 5, 'transmutation', '/api/2014/spells/telekinesis', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telepathic-bond', 0, 'You forge a telepathic link among up to eight willing creatures of your choice within range, psychically linking each creature to all the others for the duration. Creatures with Intelligence scores of 2 or less aren''t affected by this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('telepathic-bond', 1, 'Until the spell ends, the targets can communicate telepathically through the bond whether or not they have a common language. The communication is possible over any distance, though it can''t extend to other planes of existence.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('telepathic-bond', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('telepathic-bond', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('telepathic-bond', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('telepathic-bond', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('telepathic-bond', 'Telepathic Bond', '30 feet', 'Pieces of eggshell from two different kinds of creatures', 1, '1 hour', 0, '1 action', 5, 'divination', '/api/2014/spells/telepathic-bond');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 0, 'This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can''t be held or carried by an unwilling creature.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 1, 'The destination you choose must be known to you, and it must be on the same plane of existence as you. Your familiarity with the destination determines whether you arrive there successfully. The GM rolls d100 and consults the table.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 2, '| Familiarity | Mishap | Similar Area | Off Target | On Target |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 3, '|---|---|---|---|---|');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 4, '| Permanent circle | -- | -- | -- | 01-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 5, '| Associated object | -- | -- | -- | 01-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 6, '| Very familiar | 01-05 | 06-13 | 14-24 | 25-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 7, '| Seen casually | 01-33 | 34-43 | 44-53 | 54-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 8, '| Viewed once | 01-43 | 44-53 | 54-73 | 74-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 9, '| Description | 01-43 | 44-53 | 54-73 | 74-100 |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 10, '| False destination | 01-50 | 51-100 | -- | -- |');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 11, '***Familiarity.*** "Permanent circle" means a permanent teleportation circle whose sigil sequence you know.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 12, '"Associated object" means that you possess an object taken from the desired destination within the last six months, such as a book from a wizard''s library, bed linen from a royal suite, or a chunk of marble from a lich''s secret tomb.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 13, '"Very familiar" is a place you have been very often, a place you have carefully studied, or a place you can see when you cast the spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 14, '"Seen casually" is someplace you have seen more than once but with which you aren''t very familiar.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 15, '"Viewed once" is a place you have seen once, possibly using magic.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 16, '"Description" is a place whose location and appearance you know through someone else''s description, perhaps from a map.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 17, '"False destination" is a place that doesn''t exist. Perhaps you tried to scry an enemy''s sanctum but instead viewed an illusion, or you are attempting to teleport to a familiar location that no longer exists.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 18, '***On Target.*** You and your group (or the target object) appear where you want to.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 19, '***Off Target.*** You and your group (or the target object) appear a random distance away from the destination in a random direction. Distance off target is 1d10 x 1d10 percent of the distance that was to be traveled. For example, if you tried to travel 120 miles, landed off target, and rolled a 5 and 3 on the two d10s, then you would be off target by 15 percent, or 18 miles. The GM determines the direction off target randomly by rolling a d8 and designating 1 as north, 2 as northeast, 3 as east, and so on around the points of the compass.  If you were teleporting to a coastal city and wound up 18 miles out at sea, you could be in trouble.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 20, '***Similar Area.*** You and your group (or the target object) wind up in a different area that''s visually or thematically similar to the target area. If you are heading for your home laboratory, for example, you might wind up in another wizard''s laboratory or in an alchemical supply shop that has many of the same tools and implements as your laboratory. Generally, you appear in the closest similar place, but since the spell has no range limit, you could conceivably wind up anywhere on the plane.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleport', 21, '***Mishap.*** The spell''s unpredictable magic results in a difficult journey. Each teleporting creature (or the target object) takes 3d10 force damage, and the GM rerolls on the table to see where you wind up (multiple mishaps can occur, dealing damage each time).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('teleport', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleport', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleport', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleport', 2, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('teleport', 'Teleport', '10 feet', 0, 'Instantaneous', 0, '1 action', 7, 'conjuration', '/api/2014/spells/teleport', 'cube', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleportation-circle', 0, 'As you cast the spell, you draw a 10-foot-diameter circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know and that is on the same plane of existence as you. A shimmering portal opens within the circle you drew and remains open until the end of your next turn. Any creature that enters the portal instantly appears within 5 feet of the destination circle or in the nearest unoccupied space if that space is occupied.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleportation-circle', 1, 'Many major temples, guilds, and other important places have permanent teleportation circles inscribed somewhere within their confines. Each such circle includes a unique sigil sequence--a string of magical runes arranged in a particular pattern. When you first gain the ability to cast this spell, you learn the sigil sequences for two destinations on the Material Plane, determined by the GM. You can learn additional sigil sequences during your adventures. You can commit a new sigil sequence to memory after studying it for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('teleportation-circle', 2, 'You can create a permanent teleportation circle by casting this spell in the same location every day for one year. You need not use the circle to teleport when you cast the spell in this way.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('teleportation-circle', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('teleportation-circle', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleportation-circle', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleportation-circle', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('teleportation-circle', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('teleportation-circle', 'Teleportation Circle', '10 feet', 'Rare chalks and inks infused with precious gems with 50 gp, which the spell consumes.', 0, '1 round', 0, '1 minute', 5, 'conjuration', '/api/2014/spells/teleportation-circle', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 0, 'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 1, '- Your voice booms up to three times as loud as normal for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 2, '- You cause flames to flicker, brighten, dim, or change color for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 3, '- You cause harmless tremors in the ground for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 4, '- You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 5, '- You instantaneously cause an unlocked door or window to fly open or slam shut.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 6, '- You alter the appearance of your eyes for 1 minute.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thaumaturgy', 7, 'If you cast this spell multiple times, you can have up to three of its 1-minute effects active at a time, and you can dismiss such an effect as an action.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('thaumaturgy', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('thaumaturgy', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('thaumaturgy', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('thaumaturgy', 'Thaumaturgy', '30 feet', 0, '1 minute', 0, '1 action', 0, 'transmutation', '/api/2014/spells/thaumaturgy');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thunderwave', 0, 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn''t pushed.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('thunderwave', 1, 'In addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the spell''s effect, and the spell emits a thunderous boom audible out to 300 feet.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('thunderwave', 0, 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('thunderwave', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('thunderwave', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('thunderwave', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('thunderwave', 1, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('thunderwave', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('thunderwave', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('thunderwave', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('thunderwave', 'Thunderwave', 'Self', 0, 'Instantaneous', 0, '1 action', 1, 'thunder', 'evocation', '/api/2014/spells/thunderwave', 'con', 'half', 'cube', 15);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('time-stop', 0, 'You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('time-stop', 1, 'This spell ends if one of the actions you use during this period, or any effects that you create during this period, affects a creature other than you or an object being worn or carried by someone other than you. In addition, the spell ends if you move to a place more than 1,000 feet from the location where you cast it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('time-stop', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('time-stop', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('time-stop', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('time-stop', 'Time Stop', 'Self', 0, 'Instantaneous', 0, '1 action', 9, 'transmutation', '/api/2014/spells/time-stop');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tiny-hut', 0, 'A 10-foot-radius immobile dome of force springs into existence around and above you and remains stationary for the duration. The spell ends if you leave its area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tiny-hut', 1, 'Nine creatures of Medium size or smaller can fit inside the dome with you. The spell fails if its area includes a larger creature or more than nine creatures. Creatures and objects within the dome when you cast this spell can move through it freely. All other creatures and objects are barred from passing through it. Spells and other magical effects can''t extend through the dome or be cast through it. The atmosphere inside the space is comfortable and dry, regardless of the weather outside.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tiny-hut', 2, 'Until the spell ends, you can command the interior to become dimly lit or dark. The dome is opaque from the outside, of any color you choose, but it is transparent from the inside.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tiny-hut', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tiny-hut', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tiny-hut', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tiny-hut', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tiny-hut', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('tiny-hut', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('tiny-hut', 'Tiny Hut', 'Self', 'A small crystal bead.', 1, '8 hours', 0, '1 minute', 3, 'evocation', '/api/2014/spells/tiny-hut', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tongues', 0, 'This spell grants the creature you touch the ability to understand any spoken language it hears. Moreover, when the target speaks, any creature that knows at least one language and can hear the target understands what it says.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tongues', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tongues', 1, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tongues', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tongues', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tongues', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tongues', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tongues', 4, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('tongues', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('tongues', 'Tongues', 'Touch', 'A small clay model of a ziggurat.', 0, '1 hour', 0, '1 action', 3, 'divination', '/api/2014/spells/tongues');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('transport-via-plants', 0, 'This spell creates a magical link between a Large or larger inanimate plant within range and another plant, at any distance, on the same plane of existence. You must have seen or touched the destination plant at least once before. For the duration, any creature can step into the target plant and exit from the destination plant by using 5 feet of movement.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('transport-via-plants', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('transport-via-plants', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('transport-via-plants', 0, 'druid');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('transport-via-plants', 'Transport via Plants', '10 feet', 0, '1 round', 0, '1 action', 6, 'conjuration', '/api/2014/spells/transport-via-plants');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tree-stride', 0, 'You gain the ability to enter a tree and move from inside it to inside another tree of the same kind within 500 feet. Both trees must be living and at least the same size as you. You must use 5 feet of movement to enter a tree. You instantly know the location of all other trees of the same kind within 500 feet and, as part of the move used to enter the tree, can either pass into one of those trees or step out of the tree you''re in. You appear in a spot of your choice within 5 feet of the destination tree, using another 5 feet of movement. If you have no movement left, you appear within 5 feet of the tree you entered.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('tree-stride', 1, 'You can use this transportation ability once per round for the duration. You must end each turn outside a tree.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tree-stride', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('tree-stride', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tree-stride', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('tree-stride', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('tree-stride', 0, 'land');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('tree-stride', 'Tree Stride', 'Self', 0, 'Up to 1 minute', 1, '1 action', 5, 'conjuration', '/api/2014/spells/tree-stride');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 0, 'Choose one creature or nonmagical object that you can see within range. You transform the creature into a different creature, the creature into an object, or the object into a creature (the object must be neither worn nor carried by another creature). The transformation lasts for the duration, or until the target drops to 0 hit points or dies. If you concentrate on this spell for the full duration, the transformation becomes permanent.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 1, 'Shapechangers aren''t affected by this spell. An unwilling creature can make a wisdom saving throw, and if it succeeds, it isn''t affected by this spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 2, '***Creature into Creature.*** If you turn a creature into another kind of creature, the new form can be any kind you choose whose challenge rating is equal to or less than the target''s (or its level, if the target doesn''t have a challenge rating). The target''s game statistics, including mental ability scores, are replaced by the statistics of the new form. It retains its alignment and personality.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 3, 'The target assumes the hit points of its new form, and when it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 4, 'The creature is limited in the actions it can perform by the nature of its new form, and it can''t speak, cast spells, or take any other action that requires hands or speech unless its new form is capable of such actions.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 5, 'The target''s gear melds into the new form. The creature can''t activate, use, wield, or otherwise benefit from any of its equipment.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 6, '***Object into Creature.*** You can turn an object into any kind of creature, as long as the creature''s size is no larger than the object''s size and the creature''s challenge rating is 9 or lower. The creature is friendly to you and your companions. It acts on each of your turns. You decide what action it takes and how it moves. The GM has the creature''s statistics and resolves all of its actions and movement.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 7, 'If the spell becomes permanent, you no longer control the creature. It might remain friendly to you, depending on how you have treated it.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-polymorph', 8, '***Creature into Object.*** If you turn a creature into an object, it transforms along with whatever it is wearing and carrying into that form. The creature''s statistics become those of the object, and the creature has no memory of time spent in this form, after the spell ends and it returns to its normal form.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-polymorph', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-polymorph', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-polymorph', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-polymorph', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-polymorph', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-polymorph', 2, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('true-polymorph', 'True Polymorph', '30 feet', 'A drop of mercury, a dollop of gum arabic, and a wisp of smoke.', 0, 'Up to 1 hour', 1, '1 action', 9, 'transmutation', '/api/2014/spells/true-polymorph');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-resurrection', 0, 'You touch a creature that has been dead for no longer than 200 years and that died for any reason except old age. If the creature''s soul is free and willing, the creature is restored to life with all its hit points.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-resurrection', 1, 'This spell closes all wounds, neutralizes any poison, cures all diseases, and lifts any curses affecting the creature when it died. The spell replaces damaged or missing organs and limbs.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-resurrection', 2, 'The spell can even provide a new body if the original no longer exists, in which case you must speak the creature''s name. The creature then appears in an unoccupied space you choose within 10 feet of you.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-resurrection', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-resurrection', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-resurrection', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-resurrection', 0, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-resurrection', 1, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('true-resurrection', 'True Resurrection', 'Touch', 'A sprinkle of holy water and diamonds worth at least 25,000gp, which the spell consumes.', 0, 'Instantaneous', 0, '1 hour', 9, 'necromancy', '/api/2014/spells/true-resurrection');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-seeing', 0, 'This spell gives the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-seeing', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-seeing', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-seeing', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-seeing', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-seeing', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-seeing', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-seeing', 3, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-seeing', 4, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('true-seeing', 'True Seeing', 'Touch', 'An ointment for the eyes that costs 25gp; is made from mushroom powder, saffron, and fat; and is consumed by the spell.', 0, '1 hour', 0, '1 action', 6, 'divination', '/api/2014/spells/true-seeing');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('true-strike', 0, 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target''s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn''t ended.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('true-strike', 0, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-strike', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-strike', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-strike', 2, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('true-strike', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('true-strike', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('true-strike', 'True Strike', '30 feet', 0, 'Up to 1 round', 1, '1 action', 0, 'divination', '/api/2014/spells/true-strike');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('unseen-servant', 0, 'This spell creates an invisible, mindless, shapeless force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 hit point, and a Strength of 2, and it can''t attack. If it drops to 0 hit points, the spell ends.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('unseen-servant', 1, 'Once on each of your turns as a bonus action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human servant could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring wine. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('unseen-servant', 2, 'If you command the servant to perform a task that would move it more than 60 feet away from you, the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('unseen-servant', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('unseen-servant', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('unseen-servant', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('unseen-servant', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('unseen-servant', 1, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('unseen-servant', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('unseen-servant', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('unseen-servant', 'Unseen Servant', '60 feet', 'A piece of string and a bit of wood.', 1, '1 hour', 0, '1 action', 1, 'conjuration', '/api/2014/spells/unseen-servant');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('vampiric-touch', 0, 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('vampiric-touch', 0, 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('vampiric-touch', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('vampiric-touch', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('vampiric-touch', 0, 'warlock');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('vampiric-touch', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('vampiric-touch', 0, 'lore');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, attack_type, damage_damage_type_index, school_index, url) VALUES ('vampiric-touch', 'Vampiric Touch', 'Self', 0, 'Up to 1 minute', 1, '1 action', 3, 'melee', 'necrotic', 'necromancy', '/api/2014/spells/vampiric-touch');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('vicious-mockery', 0, 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('vicious-mockery', 1, 'This spell''s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('vicious-mockery', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('vicious-mockery', 0, 'bard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success) VALUES ('vicious-mockery', 'Vicious Mockery', '60 feet', 0, 'Instantaneous', 0, '1 action', 0, 'psychic', 'enchantment', '/api/2014/spells/vicious-mockery', 'wis', 'none');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-fire', 0, 'You create a wall of fire on a solid surface within range. You can make the wall up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-fire', 1, 'When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-fire', 2, 'One side of the wall, selected by you when you cast this spell, deals 5d8 fire damage to each creature that ends its turn within 10 feet o f that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn or ends its turn there. The other side of the wall deals no damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-fire', 3, 'The other side of the wall deals no damage.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('wall-of-fire', 0, 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-fire', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-fire', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-fire', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-fire', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-fire', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-fire', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('wall-of-fire', 0, 'fiend');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('wall-of-fire', 'Wall of Fire', '120 feet', 'A small piece of phosphorus.', 0, 'Up to 1 minute', 1, '1 action', 4, 'fire', 'evocation', '/api/2014/spells/wall-of-fire', 'dex', 'half', 'line', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-force', 0, 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. In any form, the wall is 1/4 inch thick. It lasts for the duration. If the wall cuts through a creature''s space when it appears, the creature is pushed to one side of the wall (your choice which side).');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-force', 1, 'Nothing can physically pass through the wall. It is immune to all damage and can''t be dispelled by dispel magic. A disintegrate spell destroys the wall instantly, however. The wall also extends into the Ethereal Plane, blocking ethereal travel through the wall.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-force', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-force', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-force', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-force', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('wall-of-force', 'Wall of Force', '120 feet', 'A pinch of powder made by crushing a clear gemstone.', 0, 'Up to 10 minutes', 1, '1 action', 5, 'evocation', '/api/2014/spells/wall-of-force');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-ice', 0, 'You create a wall of ice on a solid surface within range. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-square panels. Each panel must be contiguous with another panel. In any form, the wall is 1 foot thick and lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-ice', 1, 'If the wall cuts through a creature''s space when it appears, the creature within its area is pushed to one side of the wall and must make a dexterity saving throw. On a failed save, the creature takes 10d6 cold damage, or half as much damage on a successful save.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-ice', 2, 'The wall is an object that can be damaged and thus breached. It has AC 12 and 30 hit points per 10-foot section, and it is vulnerable to fire damage. Reducing a 10-foot section of wall to 0 hit points destroys it and leaves behind a sheet of frigid air in the space the wall occupied. A creature moving through the sheet of frigid air for the first time on a turn must make a constitution saving throw. That creature takes 5d6 cold damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('wall-of-ice', 0, 'When you cast this spell using a spell slot of 7th level or higher, the damage the wall deals when it appears increases by 2d6, and the damage from passing through the sheet of frigid air increases by 1d6, for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-ice', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-ice', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-ice', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-ice', 0, 'wizard');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('wall-of-ice', 'Wall of Ice', '120 feet', 'A small piece of quartz.', 0, 'Up to 10 minutes', 1, '1 action', 6, 'cold', 'evocation', '/api/2014/spells/wall-of-ice', 'dex', 'half', 'sphere', 10);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 0, 'A nonmagical wall of solid stone springs into existence at a point you choose within range. The wall is 6 inches thick and is composed of ten 10-foot-by-10-foot panels. Each panel must be contiguous with at least one other panel. Alternatively, you can create 10-foot-by-20-foot panels that are only 3 inches thick.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 1, 'If the wall cuts through a creature''s space when it appears, the creature is pushed to one side of the wall (your choice). If a creature would be surrounded on all sides by the wall (or the wall and another solid surface), that creature can make a dexterity saving throw. On a success, it can use its reaction to move up to its speed so that it is no longer enclosed by the wall.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 2, 'The wall can have any shape you desire, though it can''t occupy the same space as a creature or object. The wall doesn''t need to be vertical or rest on any firm foundation. It must, however, merge with and be solidly supported by existing stone. Thus, you can use this spell to bridge a chasm or create a ramp.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 3, 'If you create a span greater than 20 feet in length, you must halve the size of each panel to create supports. You can crudely shape the wall to create crenellations, battlements, and so on.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 4, 'The wall is an object made of stone that can be damaged and thus breached. Each panel has AC 15 and 30 hit points per inch of thickness. Reducing a panel to 0 hit points destroys it and might cause connected panels to collapse at the GM''s discretion.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-stone', 5, 'If you maintain your concentration on this spell for its whole duration, the wall becomes permanent and can''t be dispelled. Otherwise, the wall disappears when the spell ends.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-stone', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-stone', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-stone', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-stone', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-stone', 1, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-stone', 2, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('wall-of-stone', 0, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('wall-of-stone', 'Wall of Stone', '120 feet', 'A small block of granite.', 0, 'Up to 10 minutes', 1, '1 action', 5, 'evocation', '/api/2014/spells/wall-of-stone');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-thorns', 0, 'You create a wall of tough, pliable, tangled brush bristling with needle-sharp thorns. The wall appears within range on a solid surface and lasts for the duration. You choose to make the wall up to 60 feet long, 10 feet high, and 5 feet thick or a circle that has a 20-foot diameter and is up to 20 feet high and 5 feet thick. The wall blocks line of sight.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-thorns', 1, 'When the wall appears, each creature within its area must make a dexterity saving throw. On a failed save, a creature takes 7d8 piercing damage, or half as much damage on a successful save.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wall-of-thorns', 2, 'A creature can move through the wall, albeit slowly and painfully. For every 1 foot a creature moves through the wall, it must spend 4 feet of movement. Furthermore, the first time a creature enters the wall on a turn or ends its turn there, the creature must make a dexterity saving throw. It takes 7d8 slashing damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_higher_level (spells_index, order_num, "value") VALUES ('wall-of-thorns', 0, 'When you cast this spell using a spell slot of 7th level or higher, both types of damage increase by 1d8 for each slot level above 6th.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-thorns', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-thorns', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wall-of-thorns', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wall-of-thorns', 0, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('wall-of-thorns', 'Wall of Thorns', '120 feet', 'A handful of thorns.', 0, 'Up to 10 minutes', 1, '1 action', 6, 'piercing', 'conjuration', '/api/2014/spells/wall-of-thorns', 'dex', 'half', 'line', 60);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('warding-bond', 0, 'This spell wards a willing creature you touch and creates a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has resistance to all damage. Also, each time it takes damage, you take the same amount of damage.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('warding-bond', 1, 'The spell ends if you drop to 0 hit points or if you and the target become separated by more than 60 feet.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('warding-bond', 2, 'It also ends if the spell is cast again on either of the connected creatures. You can also dismiss the spell as an action.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('warding-bond', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('warding-bond', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('warding-bond', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('warding-bond', 0, 'cleric');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('warding-bond', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('warding-bond', 'Warding Bond', 'Touch', 'A pair of platinum rings worth at least 50gp each, which you and the target must wear for the duration.', 0, '1 hour', 0, '1 action', 2, 'abjuration', '/api/2014/spells/warding-bond');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('water-breathing', 0, 'This spell gives a maximum of ten willing creatures within range and you can see, the ability to breathe underwater until the end of its term. Affected creatures also retain their normal breathing pattern.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-breathing', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-breathing', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-breathing', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('water-breathing', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('water-breathing', 1, 'ranger');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('water-breathing', 2, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('water-breathing', 3, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('water-breathing', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('water-breathing', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('water-breathing', 'Water Breathing', '30 feet', 'A short piece of reed or straw.', 1, '24 hours', 0, '1 action', 3, 'transmutation', '/api/2014/spells/water-breathing');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('water-walk', 0, 'This spell grants the ability to move across any liquid surface--such as water, acid, mud, snow, quicksand, or lava--as if it were harmless solid ground (creatures crossing molten lava can still take damage from the heat). Up to ten willing creatures you can see within range gain this ability for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('water-walk', 1, 'If you target a creature submerged in a liquid, the spell carries the target to the surface of the liquid at a rate of 60 feet per round.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-walk', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-walk', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('water-walk', 2, 'M');
