INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('water-walk', 'Water Walk', '30 feet', 'A piece of cork.', 1, '1 hour', 0, '1 action', 3, 'transmutation', '/api/2014/spells/water-walk');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('web', 0, 'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('web', 1, 'If the webs aren''t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the conjured web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('web', 2, 'Each creature that starts its turn in the webs or that enters them during its turn must make a dexterity saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('web', 3, 'A creature restrained by the webs can use its action to make a Strength check against your spell save DC. If it succeeds, it is no longer restrained.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('web', 4, 'The webs are flammable. Any 5-foot cube of webs exposed to fire burns away in 1 round, dealing 2d4 fire damage to any creature that starts its turn in the fire.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('web', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('web', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('web', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('web', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('web', 1, 'wizard');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('web', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('web', 1, 'land');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('web', 'Web', '60 feet', 'A bit of spiderweb.', 0, 'Up to 1 hour', 1, '1 action', 2, 'conjuration', '/api/2014/spells/web', 'cube', 20);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('weird', 0, 'Drawing on the deepest fears of a group of creatures, you create illusory creatures in their minds, visible only to them. Each creature in a 30-foot-radius sphere centered on a point of your choice within range must make a wisdom saving throw. On a failed save, a creature becomes frightened for the duration. The illusion calls on the creature''s deepest fears, manifesting its worst nightmares as an implacable threat. At the start of each of the frightened creature''s turns, it must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends for that creature.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('weird', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('weird', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('weird', 0, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('weird', 'Weird', '120 feet', 0, 'Up to 1 minute', 1, '1 action', 9, 'illusion', '/api/2014/spells/weird', 'wis', 'none', 'sphere', 30);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wind-walk', 0, 'You and up to ten willing creatures you can see within range assume a gaseous form for the duration, appearing as wisps of cloud. While in this cloud form, a creature has a flying speed of 300 feet and has resistance to damage from nonmagical weapons. The only actions a creature can take in this form are the Dash action or to revert to its normal form. Reverting takes 1 minute, during which time a creature is incapacitated and can''t move. Until the spell ends, a creature can revert to cloud form, which also requires the 1-minute transformation.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wind-walk', 1, 'If a creature is in cloud form and flying when the effect ends, the creature descends 60 feet per round for 1 minute until it lands, which it does safely. If it can''t land after 1 minute, the creature falls the remaining distance.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-walk', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-walk', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-walk', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wind-walk', 0, 'druid');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('wind-walk', 'Wind Walk', '30 feet', 'Fire and holy water.', 0, '8 hours', 0, '1 minute', 6, 'transmutation', '/api/2014/spells/wind-walk');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wind-wall', 0, 'A wall of strong wind rises from the ground at a point you choose within range. You can make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wind-wall', 1, 'When the wall appears, each creature within its area must make a strength saving throw. A creature takes 3d8 bludgeoning damage on a failed save, or half as much damage on a successful one.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wind-wall', 2, 'The strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can''t pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. (Boulders hurled by giants or siege engines, and similar projectiles, are unaffected.) Creatures in gaseous form can''t pass through it.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-wall', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-wall', 1, 'S');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wind-wall', 2, 'M');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wind-wall', 0, 'druid');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wind-wall', 1, 'ranger');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('wind-wall', 0, 'lore');
INSERT INTO spells ("index", name, range, material, ritual, duration, concentration, casting_time, level, damage_damage_type_index, school_index, url, dc_dc_type_index, dc_dc_success, area_of_effect_type, area_of_effect_size) VALUES ('wind-wall', 'Wind Wall', '120 feet', 'A tiny fan and a feather of exotic origin.', 0, 'Up to 1 minute', 1, '1 action', 3, 'bludgeoning', 'evocation', '/api/2014/spells/wind-wall', 'str', 'half', 'line', 50);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 0, 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 1, 'The basic use of this spell is to duplicate any other spell of 8th level or lower. You don''t need to meet any requirements in that spell, including costly components. The spell simply takes effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 2, 'Alternatively, you can create one of the following effects of your choice:');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 3, '- You create one object of up to 25,000 gp in value that isn''t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 4, '- You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 5, '- You grant up to ten creatures that you can see resistance to a damage type you choose.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 6, '- You grant up to ten creatures you can see immunity to a single spell or other magical effect for 8 hours. For instance, you could make yourself and all your companions immune to a lich''s life drain attack.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 7, '- You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result. For example, a wish spell could undo an opponent''s successful save, a foe''s critical hit, or a friend''s failed save. You can force the reroll to be made with advantage or disadvantage, and you can choose whether to use the reroll or the original roll.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 8, 'You might be able to achieve something beyond the scope of the above examples. State your wish to the GM as precisely as possible. The GM has great latitude in ruling what occurs in such an instance; the greater the wish, the greater the likelihood that something goes wrong. This spell might simply fail, the effect you desire might only be partly achieved, or you might suffer some unforeseen consequence as a result of how you worded the wish. For example, wishing that a villain were dead might propel you forward in time to a period when that villain is no longer alive, effectively removing you from the game. Similarly, wishing for a legendary magic item or artifact might instantly transport you to the presence of the item''s current owner.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('wish', 9, 'The stress of casting this spell to produce any effect other than duplicating another spell weakens you. After enduring that stress, each time you cast a spell until you finish a long rest, you take 1d10 necrotic damage per level of that spell. This damage can''t be reduced or prevented in any way. In addition, your Strength drops to 3, if it isn''t 3 or lower already, for 2d4 days. For each of those days that you spend resting and doing nothing more than light activity, your remaining recovery time decreases by 2 days. Finally, there is a 33 percent chance that you are unable to cast wish ever again if you suffer this stress.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('wish', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wish', 0, 'sorcerer');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('wish', 1, 'wizard');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url) VALUES ('wish', 'Wish', 'Self', 0, 'Instantaneous', 0, '1 action', 9, 'conjuration', '/api/2014/spells/wish');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('word-of-recall', 0, 'You and up to five willing creatures within 5 feet of you instantly teleport to a previously designated sanctuary. You and any creatures that teleport with you appear in the nearest unoccupied space to the spot you designated when you prepared your sanctuary (see below). If you cast this spell without first preparing a sanctuary, the spell has no effect.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('word-of-recall', 1, 'You must designate a sanctuary by casting this spell within a location, such as a temple, dedicated to or strongly linked to your deity. If you attempt to cast the spell in this manner in an area that isn''t dedicated to your deity, the spell has no effect.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('word-of-recall', 0, 'V');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('word-of-recall', 0, 'cleric');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('word-of-recall', 'Word of Recall', '5 feet', 0, 'Instantaneous', 0, '1 action', 6, 'conjuration', '/api/2014/spells/word-of-recall', 'sphere', 5);
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('zone-of-truth', 0, 'You create a magical zone that guards against deception in a 15-foot-radius sphere centered on a point of your choice within range. Until the spell ends, a creature that enters the spell''s area for the first time on a turn or starts its turn there must make a Charisma saving throw. On a failed save, a creature can''t speak a deliberate lie while in the radius. You know whether each creature succeeds or fails on its saving throw.');
INSERT INTO spells_desc (spells_index, order_num, "value") VALUES ('zone-of-truth', 1, 'An affected creature is aware of the spell and can thus avoid answering questions to which it would normally respond with a lie. Such a creature can remain evasive in its answers as long as it remains within the boundaries of the truth.');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('zone-of-truth', 0, 'V');
INSERT INTO spells_components (spells_index, order_num, "value") VALUES ('zone-of-truth', 1, 'S');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('zone-of-truth', 0, 'bard');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('zone-of-truth', 1, 'cleric');
INSERT INTO spells_classes (spells_index, order_num, classes_index) VALUES ('zone-of-truth', 2, 'paladin');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('zone-of-truth', 0, 'lore');
INSERT INTO spells_subclasses (spells_index, order_num, subclasses_index) VALUES ('zone-of-truth', 1, 'devotion');
INSERT INTO spells ("index", name, range, ritual, duration, concentration, casting_time, level, school_index, url, area_of_effect_type, area_of_effect_size) VALUES ('zone-of-truth', 'Zone of Truth', '60 feet', 0, '10 minutes', 0, '1 action', 2, 'enchantment', '/api/2014/spells/zone-of-truth', 'sphere', 15);
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('berserker', 0, 'For some barbarians, rage is a means to an end--that end being violence. The Path of the Berserker is a path of untrammeled fury, slick with blood. As you enter the berserker''s rage, you thrill in the chaos of battle, heedless of your own health or well-being.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('berserker', 'barbarian', 'Berserker', 'Primal Path', '/api/2014/subclasses/berserker/levels', '/api/2014/subclasses/berserker');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('lore', 0, 'Bards of the College of Lore know something about most things, collecting bits of knowledge from sources as diverse as scholarly tomes and peasant tales. Whether singing folk ballads in taverns or elaborate compositions in royal courts, these bards use their gifts to hold audiences spellbound. When the applause dies down, the audience members might find themselves questioning everything they held to be true, from their faith in the priesthood of the local temple to their loyalty to the king. The loyalty of these bards lies in the pursuit of beauty and truth, not in fealty to a monarch or following the tenets of a deity. A noble who keeps such a bard as a herald or advisor knows that the bard would rather be honest than politic. The college''s members gather in libraries and sometimes in actual colleges, complete with classrooms and dormitories, to share their lore with one another. They also meet at festivals or affairs of state, where they can expose corruption, unravel lies, and poke fun at self-important figures of authority.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('lore', 'bard', 'Lore', 'Bard College', '/api/2014/subclasses/lore/levels', '/api/2014/subclasses/lore');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('life', 0, 'The Life domain focuses on the vibrant positive energy--one of the fundamental forces of the universe--that sustains all life. The gods of life promote vitality and health through healing the sick and wounded, caring for those in need, and driving away the forces of death and undeath. Almost any non-evil deity can claim influence over this domain, particularly agricultural deities, sun gods, gods of healing or endurance, and gods of home and community.');
INSERT INTO subclasses_spells_prerequisites (subclasses_spells_index, order_num, levels_index) VALUES ('life', 0, 'cleric-1');
