INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('land', 'druid', 'Land', 'Druid Circle', '/api/2014/subclasses/land/levels', '/api/2014/subclasses/land');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('champion', 0, 'The archetypal Champion focuses on the development of raw physical power honed to deadly perfection. Those who model themselves on this archetype combine rigorous training with physical excellence to deal devastating blows.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('champion', 'fighter', 'Champion', 'Martial Archetype', '/api/2014/subclasses/champion/levels', '/api/2014/subclasses/champion');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('open-hand', 0, 'Monks of the Way of the Open Hand are the ultimate masters of martial arts combat, whether armed or unarmed. They learn techniques to push and trip their opponents, manipulate ki to heal damage to their bodies, and practice advanced meditation that can protect them from harm.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('open-hand', 'monk', 'Open Hand', 'Monastic Tradition', '/api/2014/subclasses/open-hand/levels', '/api/2014/subclasses/open-hand');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('devotion', 0, 'The Oath of Devotion binds a paladin to the loftiest ideals of justice, virtue, and order. Sometimes called cavaliers, white knights, or holy warriors, these paladins meet the ideal of the knight in shining armor, acting with honor in pursuit of justice and the greater good. They hold themselves to the highest standards of conduct, and some, for better or worse, hold the rest of the world to the same standards. Many who swear this oath are devoted to gods of law and good and use their gods'' tenets as the measure of their devotion. They hold angels--the perfect servants of good--as their ideals, and incorporate images of angelic wings into their helmets or coats of arms.');
INSERT INTO subclasses_spells_prerequisites (subclasses_spells_index, order_num, levels_index) VALUES ('devotion', 0, 'paladin-3');
INSERT INTO subclasses_spells (subclasses_index, order_num, spell_index) VALUES ('devotion', 0, 'protection-from-evil-and-good');
