INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('devotion', 'paladin', 'Devotion', 'Sacred Oath', '/api/2014/subclasses/devotion/levels', '/api/2014/subclasses/devotion');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('hunter', 0, 'Emulating the Hunter archetype means accepting your place as a bulwark between civilization and the terrors of the wilderness. As you walk the Hunter''s path, you learn specialized techniques for fighting the threats you face, from rampaging ogres and hordes of orcs to towering giants and terrifying dragons.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('hunter', 'ranger', 'Hunter', 'Ranger Archetype', '/api/2014/subclasses/hunter/levels', '/api/2014/subclasses/hunter');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('thief', 0, 'You hone your skills in the larcenous arts. Burglars, bandits, cutpurses, and other criminals typically follow this archetype, but so do rogues who prefer to think of themselves as professional treasure seekers, explorers, delvers, and investigators. In addition to improving your agility and stealth, you learn skills useful for delving into ancient ruins, reading unfamiliar languages, and using magic items you normally couldn''t employ.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('thief', 'rogue', 'Thief', 'Roguish Archetype', '/api/2014/subclasses/thief/levels', '/api/2014/subclasses/thief');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('draconic', 0, 'Your innate magic comes from draconic magic that was mingled with your blood or that of your ancestors. Most often, sorcerers with this origin trace their descent back to a mighty sorcerer of ancient times who made a bargain with a dragon or who might even have claimed a dragon parent. Some of these bloodlines are well established in the world, but most are obscure. Any given sorcerer could be the first of a new bloodline, as a result of a pact or some other exceptional circumstance.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('draconic', 'sorcerer', 'Draconic', 'Sorcerous Origin', '/api/2014/subclasses/draconic/levels', '/api/2014/subclasses/draconic');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('fiend', 0, 'You have made a pact with a fiend from the lower planes of existence, a being whose aims are evil, even if you strive against those aims. Such beings desire the corruption or destruction of all things, ultimately including you. Fiends powerful enough to forge a pact include demon lords such as Demogorgon, Orcus, Fraz''Urb-luu, and Baphomet; archdevils such as Asmodeus, Dispater, Mephistopheles, and Belial; pit fiends and balors that are especially mighty; and ultroloths and other lords of the yugoloths.');
INSERT INTO subclasses_spells_prerequisites (subclasses_spells_index, order_num, levels_index) VALUES ('fiend', 0, 'warlock-1');
