INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('fiend', 'warlock', 'Fiend', 'Otherworldly Patron', '/api/2014/subclasses/fiend/levels', '/api/2014/subclasses/fiend');
INSERT INTO subclasses_desc (subclasses_index, order_num, "value") VALUES ('evocation', 0, 'You focus your study on magic that creates powerful elemental effects such as bitter cold, searing flame, rolling thunder, crackling lightning, and burning acid. Some evokers find employment in military forces, serving as artillery to blast enemy armies from afar. Others use their spectacular power to protect the weak, while some seek their own gain as bandits, adventurers, or aspiring tyrants.');
INSERT INTO subclasses ("index", class_index, name, subclass_flavor, subclass_levels, url) VALUES ('evocation', 'wizard', 'Evocation', 'Arcane Tradition', '/api/2014/subclasses/evocation/levels', '/api/2014/subclasses/evocation');
