INSERT INTO subraces ("index", name, race_index, "desc", url) VALUES ('hill-dwarf', 'Hill Dwarf', 'dwarf', 'As a hill dwarf, you have keen senses, deep intuition, and remarkable resilience.', '/api/2014/subraces/hill-dwarf');
INSERT INTO subraces_ability_bonuses (subraces_index, order_num, ability_score_index, bonus) VALUES ('high-elf', 0, 'int', 1);
