INSERT INTO subraces ("index", name, race_index, "desc", url) VALUES ('high-elf', 'High Elf', 'elf', 'As a high elf, you have a keen mind and a mastery of at least the basics of magic. In many fantasy gaming worlds, there are two kinds of high elves. One type is haughty and reclusive, believing themselves to be superior to non-elves and even other elves. The other type is more common and more friendly, and often encountered among humans and other races.', '/api/2014/subraces/high-elf');
INSERT INTO subraces_ability_bonuses (subraces_index, order_num, ability_score_index, bonus) VALUES ('lightfoot-halfling', 0, 'cha', 1);
INSERT INTO subraces_racial_traits (subraces_index, order_num, traits_index) VALUES ('lightfoot-halfling', 0, 'naturally-stealthy');
INSERT INTO subraces ("index", name, race_index, "desc", url) VALUES ('lightfoot-halfling', 'Lightfoot Halfling', 'halfling', 'As a lightfoot halfling, you can easily hide from notice, even using other people as cover. You''re inclined to be affable and get along well with others. Lightfoots are more prone to wanderlust than other halflings, and often dwell alongside other races or take up a nomadic life.', '/api/2014/subraces/lightfoot-halfling');
