INSERT INTO subraces ("index", name, race_index, "desc", url) VALUES ('rock-gnome', 'Rock Gnome', 'gnome', 'As a rock gnome, you have a natural inventiveness and hardiness beyond that of other gnomes.', '/api/2014/subraces/rock-gnome');
