INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('darkvision', 3, 'half-elf');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('darkvision', 4, 'half-orc');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('darkvision', 5, 'tiefling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('darkvision', 0, 'You have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You cannot discern color in darkness, only shades of gray.');
INSERT INTO traits ("index", name, url) VALUES ('darkvision', 'Darkvision', '/api/2014/traits/darkvision');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('dwarven-resilience', 0, 'dwarf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('dwarven-resilience', 0, 'You have advantage on saving throws against poison, and you have resistance against poison damage.');
INSERT INTO traits ("index", name, url) VALUES ('dwarven-resilience', 'Dwarven Resilience', '/api/2014/traits/dwarven-resilience');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('dwarven-combat-training', 0, 'dwarf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('dwarven-combat-training', 0, 'You have proficiency with the battleaxe, handaxe, light hammer, and warhammer.');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('dwarven-combat-training', 0, 'battleaxes');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('dwarven-combat-training', 1, 'handaxes');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('dwarven-combat-training', 2, 'light-hammers');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('dwarven-combat-training', 3, 'warhammers');
INSERT INTO traits ("index", name, url) VALUES ('dwarven-combat-training', 'Dwarven Combat Training', '/api/2014/traits/dwarven-combat-training');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('tool-proficiency', 0, 'dwarf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tool-proficiency', 0, 'You gain proficiency with the artisan''s tools of your choice: smith''s tools, brewer''s supplies, or mason''s tools.');
INSERT INTO traits ("index", name, url, proficiency_choices_choose, proficiency_choices_type, proficiency_choices_from_option_set_type) VALUES ('tool-proficiency', 'Tool Proficiency', '/api/2014/traits/tool-proficiency', 1, 'proficiencies', 'options_array');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('stonecunning', 0, 'dwarf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('stonecunning', 0, 'Whenever you make an Intelligence (History) check related to the origin of stonework, you are considered proficient in the History skill and add double your proficiency bonus to the check, instead of your normal proficiency bonus.');
INSERT INTO traits ("index", name, url) VALUES ('stonecunning', 'Stonecunning', '/api/2014/traits/stonecunning');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('dwarven-toughness', 0, 'hill-dwarf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('dwarven-toughness', 0, 'Your hit point maximum increases by 1, and it increases by 1 every time you gain a level.');
INSERT INTO traits ("index", name, url) VALUES ('dwarven-toughness', 'Dwarven Toughness', '/api/2014/traits/dwarven-toughness');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('keen-senses', 0, 'elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('keen-senses', 0, 'You have proficiency in the Perception skill.');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('keen-senses', 0, 'skill-perception');
INSERT INTO traits ("index", name, url) VALUES ('keen-senses', 'Keen Senses', '/api/2014/traits/keen-senses');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('fey-ancestry', 0, 'elf');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('fey-ancestry', 1, 'half-elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('fey-ancestry', 0, 'You have advantage on saving throws against being charmed, and magic cannot put you to sleep.');
INSERT INTO traits ("index", name, url) VALUES ('fey-ancestry', 'Fey Ancestry', '/api/2014/traits/fey-ancestry');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('trance', 0, 'elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('trance', 0, 'Elves do not need to sleep. Instead, they meditate deeply, remaining semiconscious, for 4 hours a day. (The Common word for such meditation is "trance.") While meditating, you can dream after a fashion; such dreams are actually mental exercises that have become reflexive through years of practice. After resting this way, you gain the same benefit that a human does from 8 hours of sleep.');
INSERT INTO traits ("index", name, url) VALUES ('trance', 'Trance', '/api/2014/traits/trance');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('elf-weapon-training', 0, 'high-elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('elf-weapon-training', 0, 'You have proficiency with the longsword, shortsword, shortbow, and longbow.');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('elf-weapon-training', 0, 'longswords');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('elf-weapon-training', 1, 'shortswords');
