INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('elf-weapon-training', 3, 'longbows');
INSERT INTO traits ("index", name, url) VALUES ('elf-weapon-training', 'Elf Weapon Training', '/api/2014/traits/elf-weapon-training');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('high-elf-cantrip', 0, 'high-elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('high-elf-cantrip', 0, 'You know one cantrip of your choice form the wizard spell list. Intelligence is your spellcasting ability for it.');
INSERT INTO traits ("index", name, url, trait_specific_spell_options_choose, trait_specific_spell_options_from_option_set_type, trait_specific_spell_options_type) VALUES ('high-elf-cantrip', 'High Elf Cantrip', '/api/2014/traits/high-elf-cantrip', 1, 'options_array', 'spell');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('extra-language', 0, 'high-elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('extra-language', 0, 'You can speak, read, and write one extra language of your choice.');
INSERT INTO traits ("index", name, url, language_options_choose, language_options_type, language_options_from_option_set_type) VALUES ('extra-language', 'Extra Language', '/api/2014/traits/extra-language', 1, 'languages', 'options_array');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('lucky', 0, 'halfling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('lucky', 0, 'When you roll a 1 on the d20 for an attack roll, ability check, or saving throw, you can reroll the die and must use the new roll.');
INSERT INTO traits ("index", name, url) VALUES ('lucky', 'Lucky', '/api/2014/traits/lucky');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('brave', 0, 'halfling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('brave', 0, 'You have advantage on saving throw against being frightened.');
INSERT INTO traits ("index", name, url) VALUES ('brave', 'Brave', '/api/2014/traits/brave');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('halfling-nimbleness', 0, 'halfling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('halfling-nimbleness', 0, 'You can move through the space of any creature that is of a size larger than yours.');
INSERT INTO traits ("index", name, url) VALUES ('halfling-nimbleness', 'Halfling Nimbleness', '/api/2014/traits/halfling-nimbleness');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('naturally-stealthy', 0, 'lightfoot-halfling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('naturally-stealthy', 0, 'You can attempt to hide even when you are obscured only by a creature that is at least one size larger than you.');
INSERT INTO traits ("index", name, url) VALUES ('naturally-stealthy', 'Naturally Stealthy', '/api/2014/traits/naturally-stealthy');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('draconic-ancestry', 0, 'dragonborn');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('draconic-ancestry', 0, 'You have draconic ancestry. Choose one type of dragon from the Draconic Ancestry table. Your breath weapon and damage resistance are determined by the dragon type, as shown in the table.');
INSERT INTO traits ("index", name, url, trait_specific_subtrait_options_choose, trait_specific_subtrait_options_from_option_set_type, trait_specific_subtrait_options_type) VALUES ('draconic-ancestry', 'Draconic Ancestry', '/api/2014/traits/draconic-ancestry', 1, 'options_array', 'trait');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('draconic-ancestry-black', 0, 'dragonborn');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('draconic-ancestry-black', 0, 'You have draconic ancestry. Choose one type of dragon from the Draconic Ancestry table. Your breath weapon and damage resistance are determined by the dragon type, as shown in the table.');
INSERT INTO traits ("index", name, url, parent_index, trait_specific_damage_type_index, trait_specific_breath_weapon_name, trait_specific_breath_weapon_desc, trait_specific_breath_weapon_area_of_effect_size, trait_specific_breath_weapon_area_of_effect_type, trait_specific_breath_weapon_usage_type, trait_specific_breath_weapon_usage_times, trait_specific_breath_weapon_dc_dc_type_index, trait_specific_breath_weapon_dc_success_type) VALUES ('draconic-ancestry-black', 'Draconic Ancestry (Black)', '/api/2014/traits/draconic-ancestry-black', 'draconic-ancestry', 'acid', 'Breath Weapon', 'You can use your action to exhale destructive energy. Your draconic ancestry determines the size, shape, and damage type of the exhalation. When you use your breath weapon, each creature in the area of the exhalation must make a saving throw, the type of which is determined by your draconic ancestry. The DC for this saving throw equals 8 + your Constitution modifier + your proficiency bonus. A creature takes 2d6 damage on a failed save, and half as much damage on a successful one. The damage increases to 3d6 at 6th level, 4d6 at 11th level, and 5d6 at 16th level. After you use your breath weapon, you can''t use it again until you complete a short or long rest.', 30, 'line', 'per rest', 1, 'dex', 'half');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('draconic-ancestry-blue', 0, 'dragonborn');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('draconic-ancestry-blue', 0, 'You have draconic ancestry. Choose one type of dragon from the Draconic Ancestry table. Your breath weapon and damage resistance are determined by the dragon type, as shown in the table.');
