INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('breath-weapon', 0, 'You can use your action to exhale destructive energy. Your draconic ancestry determines the size, shape, and damage type of the exhalation.');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('breath-weapon', 1, 'When you use your breath weapon, each creature in the area of the exhalation must make a saving throw, the type of which is determined by your draconic ancestry. The DC for this saving throw equals 8 + your Constitution modifier + your proficiency bonus. A creature takes 2d6 damage on a failed save, and half as much damage on a successful one. The damage increases to 3d6 at 6th level, 4d6 at 11th level, and 5d6 at 16th level.');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('breath-weapon', 2, 'After you use your breath weapon, you cannot use it again until you complete a short or long rest.');
INSERT INTO traits ("index", name, url) VALUES ('breath-weapon', 'Breath Weapon', '/api/2014/traits/breath-weapon');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('damage-resistance', 0, 'dragonborn');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('damage-resistance', 0, 'You have resistance to the damage type associated with your draconic ancestry.');
INSERT INTO traits ("index", name, url) VALUES ('damage-resistance', 'Damage Resistance', '/api/2014/traits/damage-resistance');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('gnome-cunning', 0, 'gnome');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('gnome-cunning', 0, 'You have advantage on all Intelligence, Wisdom, and Charisma saving throws against magic.');
INSERT INTO traits ("index", name, url) VALUES ('gnome-cunning', 'Gnome Cunning', '/api/2014/traits/gnome-cunning');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('artificers-lore', 0, 'rock-gnome');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('artificers-lore', 0, 'Whenever you make an Intelligence (History) check related to magic items, alchemical objects, or technological devices, you can add twice your proficiency bonus, instead of any proficiency bonus you normally apply.');
INSERT INTO traits ("index", name, url) VALUES ('artificers-lore', 'Artificer''s Lore', '/api/2014/traits/artificers-lore');
INSERT INTO traits_subraces (traits_index, order_num, subraces_index) VALUES ('tinker', 0, 'rock-gnome');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tinker', 0, 'You have proficiency with artisan''s tools (tinker''s tools). Using those tools, you can spend 1 hour and 10 gp worth of materials to construct a Tiny clockwork device (AC 5, 1 hp). The device ceases to function after 24 hours (unless you spend 1 hour repairing it to keep the device functioning), or when you use your action to dismantle it; at that time, you can reclaim the materials used to create it. You can have up to three such devices active at a time.');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tinker', 1, 'When you create a device, choose one of the following options:');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tinker', 2, 'Clockwork Toy: This toy is a clockwork animal, monster, or person, such as a frog, mouse, bird, dragon, or soldier. When placed on the ground, the toy moves 5 feet across the ground on each of your turns in a random direction. It makes noises as appropriate to the creature it represents.');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tinker', 3, 'Fire Starter: The device produces a miniature flame, which you can use to light a candle, torch, or campfire. Using the device requires your action.');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('tinker', 4, 'Music Box: When opened, this music box plays a single song at a moderate volume. The box stops playing when it reaches the song''s end or when it is closed.');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('tinker', 0, 'tinkers-tools');
INSERT INTO traits ("index", name, url) VALUES ('tinker', 'Tinker', '/api/2014/traits/tinker');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('skill-versatility', 0, 'half-elf');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('skill-versatility', 0, 'You gain proficiency in two skills of your choice.');
INSERT INTO traits ("index", name, url, proficiency_choices_choose, proficiency_choices_type, proficiency_choices_from_option_set_type) VALUES ('skill-versatility', 'Skill Versatility', '/api/2014/traits/skill-versatility', 2, 'proficiencies', 'options_array');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('menacing', 0, 'half-orc');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('menacing', 0, 'You gain proficiency in the Intimidation skill.');
INSERT INTO traits_proficiencies (traits_index, order_num, proficiencies_index) VALUES ('menacing', 0, 'skill-intimidation');
INSERT INTO traits ("index", name, url) VALUES ('menacing', 'Menacing', '/api/2014/traits/menacing');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('relentless-endurance', 0, 'half-orc');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('relentless-endurance', 0, 'When you are reduced to 0 hit points but not killed outright, you can drop to 1 hit point instead. you cannot use this feature again until you finish a long rest.');
INSERT INTO traits ("index", name, url) VALUES ('relentless-endurance', 'Relentless Endurance', '/api/2014/traits/relentless-endurance');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('savage-attacks', 0, 'half-orc');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('savage-attacks', 0, 'When you score a critical hit with a melee weapon attack, you can roll one of the weapon''s damage dice one additional time and add it to the extra damage of the critical hit.');
INSERT INTO traits ("index", name, url) VALUES ('savage-attacks', 'Savage Attacks', '/api/2014/traits/savage-attacks');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('hellish-resistance', 0, 'tiefling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('hellish-resistance', 0, 'You have resistance to fire damage.');
INSERT INTO traits ("index", name, url) VALUES ('hellish-resistance', 'Hellish Resistance', '/api/2014/traits/hellish-resistance');
INSERT INTO traits_races (traits_index, order_num, races_index) VALUES ('infernal-legacy', 0, 'tiefling');
INSERT INTO traits_desc (traits_index, order_num, "value") VALUES ('infernal-legacy', 0, 'You know the thaumaturgy cantrip. When you reach 3rd level, you can cast the hellish rebuke spell as a 2nd-level spell once with this trait and regain the ability to do so when you finish a long rest. When you reach 5th level, you can cast the darkness spell once with this trait and regain the ability to do so when you finish a long rest. Charisma is your spellcasting ability for these spells.');
INSERT INTO traits ("index", name, url) VALUES ('infernal-legacy', 'Infernal Legacy', '/api/2014/traits/infernal-legacy');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('ammunition', 0, 'You can use a weapon that has the ammunition property to make a ranged attack only if you have ammunition to fire from the weapon. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon).');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('ammunition', 1, 'At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. If you use a weapon that has the ammunition property to make a melee attack, you treat the weapon as an improvised weapon (see "Improvised Weapons" later in the section). A sling must be loaded to deal any damage when used in this way.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('ammunition', 'Ammunition', '/api/2014/weapon-properties/ammunition');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('finesse', 0, 'When making an attack with a finesse weapon, you use your choice of your Strength or Dexterity modifier for the attack and damage rolls. You must use the same modifier for both rolls.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('finesse', 'Finesse', '/api/2014/weapon-properties/finesse');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('heavy', 0, 'Small creatures have disadvantage on attack rolls with heavy weapons. A heavy weapon''s size and bulk make it too large for a Small creature to use effectively.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('heavy', 'Heavy', '/api/2014/weapon-properties/heavy');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('light', 0, 'A light weapon is small and easy to handle, making it ideal for use when fighting with two weapons.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('light', 'Light', '/api/2014/weapon-properties/light');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('loading', 0, 'Because of the time required to load this weapon, you can fire only one piece of ammunition from it when you use an action, bonus action, or reaction to fire it, regardless of the number of attacks you can normally make.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('loading', 'Loading', '/api/2014/weapon-properties/loading');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('reach', 0, 'This weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for opportunity attacks with it.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('reach', 'Reach', '/api/2014/weapon-properties/reach');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('special', 0, 'A weapon with the special property has unusual rules governing its use, explained in the weapon''s description (see "Special Weapons" later in this section).');
INSERT INTO weapon_properties ("index", name, url) VALUES ('special', 'Special', '/api/2014/weapon-properties/special');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('thrown', 0, 'If a weapon has the thrown property, you can throw the weapon to make a ranged attack. If the weapon is a melee weapon, you use the same ability modifier for that attack roll and damage roll that you would use for a melee attack with the weapon. For example, if you throw a handaxe, you use your Strength, but if you throw a dagger, you can use either your Strength or your Dexterity, since the dagger has the finesse property.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('thrown', 'Thrown', '/api/2014/weapon-properties/thrown');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('two-handed', 0, 'This weapon requires two hands when you attack with it.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('two-handed', 'Two-Handed', '/api/2014/weapon-properties/two-handed');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('versatile', 0, 'This weapon can be used with one or two hands. A damage value in parentheses appears with the property--the damage when the weapon is used with two hands to make a melee attack.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('versatile', 'Versatile', '/api/2014/weapon-properties/versatile');
INSERT INTO weapon_properties_desc (weapon_properties_index, order_num, "value") VALUES ('monk', 0, 'Monks gain several benefits while unarmed or wielding only monk weapons while they aren''t wearing armor or wielding shields.');
INSERT INTO weapon_properties ("index", name, url) VALUES ('monk', 'Monk', '/api/2014/weapon-properties/monk');
